# Automation JSON mapping logic
class AutomationJSONMapper:
    """Handles automatic mapping of script uploads to Automation JSON structure"""
    
    def __init__(self, main_app):
        self.main_app = main_app
        self.script_mappings = {}  # {script_id: {script_name, placeholder, source_tab, question_text}}
    
    def add_script_mapping(self, script_id, script_name, placeholder, source_tab, question_text):
        """Add a script mapping to the automation JSON"""
        self.script_mappings[script_id] = {
            'script_name': script_name,
            'placeholder': placeholder,
            'source_tab': source_tab,
            'question_text': question_text
        }
        
        print(f"DEBUG: Added script mapping - {script_name} from {source_tab}")
        
        # Automatically update the appropriate automation tab
        if source_tab == 'Sections 1–7':
            # Sections 1-7 scripts go to Essential Questions
            self.update_essential_questions(script_id, script_name, placeholder, question_text)
        elif source_tab == 'Section 8 Test Plan':
            # Section 8 scripts go to Execution Step Questions (only when scripts are uploaded)
            self.update_execution_step_questions(script_id, script_name, placeholder, question_text)
        elif source_tab == 'Section 11 Test Execution':
            # Section 11 scripts go to Execution Step Questions
            self.update_execution_step_questions(script_id, script_name, placeholder, question_text)
    
    def update_essential_questions(self, script_id, script_name, placeholder, question_text):
        """Update Essential Questions tab with script mapping"""
        try:
            if not hasattr(self.main_app, 'essential_questions'):
                return
            
            # Check if this question already exists
            existing_question = None
            for question_info in self.main_app.essential_questions:
                if question_info["question_edit"].toPlainText() == question_text:
                    existing_question = question_info
                    break
            
            if existing_question:
                # Update existing question with script information
                existing_question["type_combo"].setCurrentText("command_execution")
                if hasattr(existing_question["widget"], 'script_status_label'):
                    existing_question["widget"].script_status_label.setText(f"✅ {script_name} uploaded")
                if hasattr(existing_question["widget"], 'script_path'):
                    existing_question["widget"].script_path = script_name
            else:
                # Create new question entry
                self.main_app.add_essential_question_with_script(question_text, script_name, placeholder)
                
        except Exception as e:
            print(f"Error updating essential questions: {e}")
    
    def update_execution_step_questions(self, script_id, script_name, placeholder, question_text):
        """Update Execution Step Questions tab with script mapping"""
        try:
            if not hasattr(self.main_app, 'execution_step_questions'):
                return
            
            print(f"DEBUG: Processing script upload for question: {question_text}")
            print(f"DEBUG: Script name: {script_name}")
            
            # Check if this question already exists
            existing_questions = []
            for step_data in self.main_app.execution_step_questions:
                for question_block in step_data.get('question_blocks', []):
                    if hasattr(question_block, 'question_edit'):
                        # Handle both QLineEdit and QTextEdit
                        if hasattr(question_block.question_edit, 'text'):
                            question_text_from_edit = question_block.question_edit.text()
                        elif hasattr(question_block.question_edit, 'toPlainText'):
                            question_text_from_edit = question_block.question_edit.toPlainText()
                        else:
                            question_text_from_edit = ""
                        
                        if question_text_from_edit == question_text:
                            existing_questions.append((step_data, question_block))
            
            print(f"DEBUG: Found {len(existing_questions)} existing questions with same text")
            
            if existing_questions:
                # Find the first existing question that doesn't have a script yet
                target_question = None
                for step_data, question_block in existing_questions:
                    if hasattr(question_block, 'script_name_edit'):
                        script_name_from_edit = question_block.script_name_edit.text()
                        if not script_name_from_edit or script_name_from_edit.strip() == "":
                            target_question = (step_data, question_block)
                            break
                
                if target_question:
                    # Update the existing question that doesn't have a script
                    step_data, question_block = target_question
                    print(f"DEBUG: Updating existing question without script: {question_text}")
                    
                    # Update the question block with script information
                    if hasattr(question_block, 'question_type_combo'):
                        question_block.question_type_combo.setCurrentText("command_execution")
                    if hasattr(question_block, 'script_name_edit'):
                        question_block.script_name_edit.setText(script_name)
                    if hasattr(question_block, 'script_status_label'):
                        question_block.script_status_label.setText(f"✅ {script_name} uploaded")
                    if hasattr(question_block, 'placeholder_edit') and placeholder:
                        question_block.placeholder_edit.setText(placeholder)
                        print(f"DEBUG: Set placeholder '{placeholder}' for existing question")
                    
                    print(f"DEBUG: Successfully updated existing question with script: {script_name}")
                    
                    # Refresh the Execution Step Questions page to show the updated question
                    if hasattr(self.main_app, 'load_execution_questions_from_section_11'):
                        self.main_app.load_execution_questions_from_section_11()
                        print(f"DEBUG: Refreshed Execution Step Questions page")
                else:
                    # All existing questions already have scripts, check if this exact script already exists
                    # Allow multiple uploads of the same script with different placeholders
                    script_already_exists = False
                    for step_data, question_block in existing_questions:
                        if hasattr(question_block, 'script_name_edit'):
                            script_name_from_edit = question_block.script_name_edit.text()
                            if script_name_from_edit == script_name:
                                # Check if the placeholder is also the same
                                if hasattr(question_block, 'placeholder_edit'):
                                    existing_placeholder = question_block.placeholder_edit.text()
                                    if existing_placeholder == placeholder:
                                        script_already_exists = True
                                        print(f"DEBUG: Script {script_name} with placeholder {placeholder} already exists in question")
                                        break
                    
                    if not script_already_exists:
                        print(f"DEBUG: All existing questions have scripts, but this script is new. Creating new question block for script: {script_name}")
                        # Create a completely new step entry for this script (duplicate the question)
                        if existing_questions:
                            # Use the first existing question's step_data as template
                            template_step_data = existing_questions[0][0]
                            
                            # Create a new step data entry
                            new_step_data = {
                                'case_data': template_step_data['case_data'].copy(),
                                'step_number': len(self.main_app.execution_step_questions) + 1,
                                'step_text': template_step_data['step_text'],
                                'question_blocks': [],
                                'source_section': template_step_data.get('source_section', 'Section 11')
                            }
                            
                            # Create new question block using the existing method
                            new_question_block = self.main_app.create_question_block(
                                new_step_data['step_number'],
                                new_step_data['step_text'],
                                new_step_data['case_data'],
                                1  # question number
                            )
                            
                            # Set up the new question block with script information
                            if hasattr(new_question_block, 'question_edit'):
                                if hasattr(new_question_block.question_edit, 'setText'):
                                    new_question_block.question_edit.setText(question_text)
                                elif hasattr(new_question_block.question_edit, 'setPlainText'):
                                    new_question_block.question_edit.setPlainText(question_text)
                            if hasattr(new_question_block, 'question_type_combo'):
                                new_question_block.question_type_combo.setCurrentText("command_execution")
                            if hasattr(new_question_block, 'script_name_edit'):
                                new_question_block.script_name_edit.setText(script_name)
                            if hasattr(new_question_block, 'script_status_label'):
                                new_question_block.script_status_label.setText(f"✅ {script_name} uploaded")
                            if hasattr(new_question_block, 'placeholder_edit') and placeholder:
                                new_question_block.placeholder_edit.setText(placeholder)
                                print(f"DEBUG: Set placeholder '{placeholder}' for new question")
                            
                            # Also update the screenshot name with the placeholder
                            if hasattr(new_question_block, 'screenshot_name_edit') and placeholder:
                                new_question_block.screenshot_name_edit.setText(placeholder)
                                print(f"DEBUG: Set screenshot name to '{placeholder}' for new question")
                            
                            # Add question block to new step data
                            new_step_data['question_blocks'].append(new_question_block)
                        
                            # Add new step data to execution step questions
                            self.main_app.execution_step_questions.append(new_step_data)
                            
                            # Add to UI
                            if hasattr(self.main_app, 'execution_questions_layout'):
                                self.main_app.execution_questions_layout.addWidget(new_question_block)
                                print(f"DEBUG: Added new question block to execution questions layout")
                            else:
                                print(f"DEBUG: execution_questions_layout not found")
                            
                            print(f"DEBUG: Successfully created new execution step question with script")
                            
                            # Refresh the Execution Step Questions page to show the new question
                            if hasattr(self.main_app, 'load_execution_questions_from_section_11'):
                                self.main_app.load_execution_questions_from_section_11()
                                print(f"DEBUG: Refreshed Execution Step Questions page")
                    else:
                        print(f"Script {script_name} with placeholder {placeholder} is already associated with this question")
            else:
                print(f"DEBUG: No existing questions found, creating new execution step question")
                # Create new execution step question entry
                self.main_app.add_execution_step_question_with_script(question_text, script_name, placeholder)
                
                # Refresh the Execution Step Questions page to show the new question
                if hasattr(self.main_app, 'load_execution_questions_from_section_11'):
                    self.main_app.load_execution_questions_from_section_11()
                    print(f"DEBUG: Refreshed Execution Step Questions page")
                
        except Exception as e:
            print(f"Error updating execution step questions: {e}")
            import traceback
            traceback.print_exc()
    
    def get_automation_json(self):
        """Generate the automation JSON structure"""
        automation_data = {
            "script_mappings": [],
            "essential_questions": [],
            "execution_step_questions": []
        }
        
        # Add script mappings
        for script_id, mapping in self.script_mappings.items():
            automation_data["script_mappings"].append({
                "script_id": script_id,
                "script_name": mapping["script_name"],
                "placeholder": mapping["placeholder"],
                "source_tab": mapping["source_tab"],
                "question_text": mapping["question_text"]
            })
        
        # Add essential questions data
        if hasattr(self.main_app, 'essential_questions'):
            automation_data["essential_questions"] = self.main_app.get_essential_questions_data()
        
        # Add execution step questions data
        if hasattr(self.main_app, 'execution_step_questions'):
            automation_data["execution_step_questions"] = self.main_app.get_execution_step_questions_data()
        
        return automation_data
    
    def remove_script_mapping(self, script_id):
        """Remove a script mapping"""
        if script_id in self.script_mappings:
            del self.script_mappings[script_id]
    
    def clear_all_mappings(self):
        """Clear all script mappings"""
        self.script_mappings.clear()

class ScrollableComboBox(QComboBox):
    """Custom ComboBox that handles scroll events properly"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
    
    def wheelEvent(self, event):
        """Override wheel event to prevent page scrolling when combo box is focused"""
        # Only handle wheel events when the combo box is focused or its popup is open
        if self.hasFocus() or self.view().isVisible():
            # Let the combo box handle its own scrolling
            super().wheelEvent(event)
            event.accept()
        else:
            # Pass the event to parent for normal page scrolling
            event.ignore()
