# --- Logging Setup ---
def setup_security_logging():
    """Setup logging to save debug logs to ~/.wingzai/logs/ with timestamps"""
    try:
        # Create logs directory
        logs_dir = os.path.expanduser("~/.wingzai/logs")
        os.makedirs(logs_dir, exist_ok=True)
        
        # Create log filename with timestamp
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        log_filename = f"security_report_generator_{timestamp}.log"
        log_path = os.path.join(logs_dir, log_filename)
        
        # Clear any existing handlers to avoid conflicts
        for handler in logging.root.handlers[:]:
            logging.root.removeHandler(handler)
        
        # Configure logging
        logging.basicConfig(
            level=logging.DEBUG,
            format='%(asctime)s - %(levelname)s - %(message)s',
            handlers=[
                logging.FileHandler(log_path, encoding='utf-8'),
                logging.StreamHandler(sys.stdout)  # Also log to console
            ],
            force=True  # Force reconfiguration
        )
        
        # Create logger for security report generator
        logger = logging.getLogger('security_report_generator')
        logger.setLevel(logging.DEBUG)
        logger.info(f"Security Report Generator logging initialized. Log file: {log_path}")
        
        return logger
    except Exception as e:
        print(f"Failed to setup logging: {e}")
        return None

# Initialize logging
security_logger = setup_security_logging()

def log_debug(message):
    """Log debug message to both file and console"""
    if security_logger:
        security_logger.debug(message)
    else:
        print(f"DEBUG: {message}")

def log_info(message):
    """Log info message to both file and console"""
    if security_logger:
        security_logger.info(message)
    else:
        print(f"INFO: {message}")

def log_warning(message):
    """Log warning message to both file and console"""
    if security_logger:
        security_logger.warning(message)
    else:
        print(f"WARNING: {message}")

def log_error(message):
    """Log error message to both file and console"""
    if security_logger:
        security_logger.error(message)
    else:
        print(f"ERROR: {message}")

def load_1_json_config():
    """
    Load configuration from 1.json file.
    Returns a dictionary with configuration data or default values if file doesn't exist.
    """
    # Try multiple possible locations for 1.json
    possible_paths = [
        os.path.expanduser('~/1.json'),  # Home directory (primary for .deb installation)
        os.path.join(os.getcwd(), '1.json'),  # Explicit current directory
        '1.json',  # Current directory (fallback)
        os.path.join(os.path.dirname(__file__), '1.json'),  # Same directory as this script
        os.path.join(os.path.dirname(os.path.dirname(__file__)), '1.json'),  # Parent directory
    ]
    
    default_config = {
        "base_url": "https://wingzai.deltaphi.in/",
        "token": "",
        "testcase_id": "",
        "testcase_name": "",
        "machine_ip": "",
        "target_ip": "",
        "ssh_username": "",
        "ssh_password": "",
        "dut_ip": "192.168.1.2",
        "fortiap_ip": "192.168.1.2",
        "fortigate_ip": "192.168.1.1"
    }
    
    for config_file_path in possible_paths:
        try:
            if os.path.exists(config_file_path):
                with open(config_file_path, 'r') as f:
                    config = json.load(f)
                    # Merge with defaults to ensure all keys exist
                    for key, value in default_config.items():
                        if key not in config:
                            config[key] = value
                    log_debug(f"Loaded 1.json config from: {config_file_path}")
                    return config
        except Exception as e:
            log_warning(f"Failed to load 1.json config from {config_file_path}: {e}")
            continue
    
    log_warning("1.json config file not found in any expected location, using default values")
    return default_config


