class LibreOfficeEmbedder:
    """Class to handle LibreOffice Writer embedding into PyQt6 application"""
    
    def __init__(self, parent=None):
        self.parent = parent
        self.libreoffice_process = None
        self.window_id = None
        self.embedded_widget = None
        self.is_embedded = False
        
    def launch_libreoffice_writer(self):
        """Launch LibreOffice Writer as a separate process"""
        try:
            # Try different LibreOffice command variations
            libreoffice_commands = [
                ["libreoffice", "--writer"],
                ["libreoffice", "--writer", "--norestore"],
                ["soffice", "--writer"],
                ["soffice", "--writer", "--norestore"],
                ["libreoffice7.6", "--writer"],
                ["libreoffice7.5", "--writer"],
                ["libreoffice7.4", "--writer"],
                ["libreoffice7.3", "--writer"],
                ["libreoffice7.2", "--writer"],
                ["libreoffice7.1", "--writer"],
                ["libreoffice7.0", "--writer"],
            ]
            
            # Try to find LibreOffice executable
            libreoffice_path = None
            for cmd in libreoffice_commands:
                try:
                    # Check if command exists
                    result = subprocess.run(cmd[:1], capture_output=True, timeout=5)
                    if result.returncode == 0 or "LibreOffice" in result.stdout.decode() or "LibreOffice" in result.stderr.decode():
                        libreoffice_path = cmd
                        break
                except (subprocess.TimeoutExpired, FileNotFoundError):
                    continue
            
            # If not found in PATH, try common installation paths
            if not libreoffice_path:
                common_paths = [
                    r"C:\Program Files\LibreOffice\program\soffice.exe",
                    r"C:\Program Files (x86)\LibreOffice\program\soffice.exe",
                    "/usr/bin/libreoffice",
                    "/usr/bin/soffice",
                    "/opt/libreoffice/program/soffice",
                    "/Applications/LibreOffice.app/Contents/MacOS/soffice",
                ]
                
                for path in common_paths:
                    if os.path.exists(path):
                        libreoffice_path = [path, "--writer"]
                        break
            
            if not libreoffice_path:
                print("❌ LibreOffice not found in PATH or common installation locations")
                return False
            
            print(f"✅ Found LibreOffice at: {libreoffice_path[0]}")
            
            # Launch LibreOffice Writer
            self.libreoffice_process = subprocess.Popen(
                libreoffice_path,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE
            )
            
            # Wait a moment for the window to appear
            time.sleep(3)
            
            # Find the LibreOffice Writer window
            self.window_id = self.find_libreoffice_window()
            
            if self.window_id:
                print(f"✅ LibreOffice Writer launched successfully. Window ID: {self.window_id}")
                return True
            else:
                print("❌ Could not find LibreOffice Writer window")
                return False
                
        except Exception as e:
            print(f"❌ Error launching LibreOffice Writer: {e}")
            return False
    
    def find_libreoffice_window(self):
        """Find the LibreOffice Writer window ID (platform-specific)"""
        if platform.system() == "Windows" and WINDOWS_AVAILABLE:
            return self.find_libreoffice_window_windows()
        elif platform.system() == "Linux":
            return self.find_libreoffice_window_linux()
        else:
            print(f"❌ Window finding not supported on {platform.system()}")
            return None
    
    def find_libreoffice_window_windows(self):
        """Find LibreOffice Writer window on Windows with improved detection"""
        try:
            print("🔍 Searching for LibreOffice windows on Windows...")
            
            # Method 1: Find window by process ID if we have a process
            if self.libreoffice_process and self.libreoffice_process.pid:
                print(f"🔍 Searching by process ID: {self.libreoffice_process.pid}")
                def enum_windows_callback(hwnd, windows):
                    if win32gui.IsWindowVisible(hwnd):
                        try:
                            _, window_pid = win32process.GetWindowThreadProcessId(hwnd)
                            if window_pid == self.libreoffice_process.pid:
                                window_text = win32gui.GetWindowText(hwnd)
                                window_class = win32gui.GetClassName(hwnd)
                                if window_text:  # Only windows with titles
                                    print(f"Found LibreOffice window by PID: '{window_text}' (ID: {hwnd}, PID: {window_pid}, Class: {window_class})")
                                    windows.append((hwnd, window_text, window_class))
                        except Exception as e:
                            print(f"Error getting window PID: {e}")
                    return True
                
                windows = []
                win32gui.EnumWindows(enum_windows_callback, windows)
                
                if windows:
                    print(f"✅ Found {len(windows)} LibreOffice windows by process ID")
                    # Return the main LibreOffice window (usually the one with the most descriptive title)
                    main_window = max(windows, key=lambda x: len(x[1]))
                    return main_window[0]
            
            # Method 2: Search by window title and class with more comprehensive matching
            print("🔍 Searching by window title and class...")
            def enum_windows_callback(hwnd, windows):
                if win32gui.IsWindowVisible(hwnd):
                    try:
                        window_text = win32gui.GetWindowText(hwnd)
                        window_class = win32gui.GetClassName(hwnd)
                        
                        # More comprehensive LibreOffice window detection
                        libreoffice_indicators = [
                            "LibreOffice Writer", 
                            "LibreOffice Calc",
                            "LibreOffice Impress",
                            "LibreOffice Draw",
                            "LibreOffice Base",
                            "LibreOffice Math",
                            "LibreOffice",
                            "Writer",
                            "Calc",
                            "Impress",
                            "Draw",
                            "Base",
                            "Math",
                            "Untitled",
                            "preview_document.docx",
                            "soffice",
                            "soffice.bin"
                        ]
                        
                        # Check if window title contains LibreOffice indicators
                        title_match = any(indicator.lower() in window_text.lower() for indicator in libreoffice_indicators)
                        
                        # Check if window class is LibreOffice-related
                        class_match = any(indicator.lower() in window_class.lower() for indicator in [
                            "libreoffice", "soffice", "swriter", "scalc", "simpress", "sdraw", "sbase", "smath"
                        ])
                        
                        if title_match or class_match:
                            windows.append((hwnd, window_text, window_class))
                            print(f"Found potential LibreOffice window: '{window_text}' (ID: {hwnd}, Class: {window_class})")
                    except Exception as e:
                        print(f"Error examining window {hwnd}: {e}")
                return True
            
            windows = []
            win32gui.EnumWindows(enum_windows_callback, windows)
            
            if windows:
                print(f"✅ Found {len(windows)} potential LibreOffice windows by title/class")
                
                # Prioritize windows: Writer > main LibreOffice > others
                writer_windows = [w for w in windows if "writer" in w[1].lower() or "writer" in w[2].lower()]
                if writer_windows:
                    print(f"✅ Found {len(writer_windows)} Writer windows")
                    return writer_windows[0][0]
                
                # If no Writer windows, return the first LibreOffice window
                return windows[0][0]
            else:
                print("❌ No LibreOffice windows found by title/class")
            
            # Method 3: Search for any visible windows that might be LibreOffice
            print("🔍 Searching for any visible windows that might be LibreOffice...")
            def enum_windows_callback(hwnd, windows):
                if win32gui.IsWindowVisible(hwnd):
                    try:
                        window_text = win32gui.GetWindowText(hwnd)
                        window_class = win32gui.GetClassName(hwnd)
                        
                        # Look for windows that are likely LibreOffice based on size and characteristics
                        if len(window_text) > 0 and len(window_text) < 200:  # Reasonable title length
                            rect = win32gui.GetWindowRect(hwnd)
                            width = rect[2] - rect[0]
                            height = rect[3] - rect[1]
                            
                            # LibreOffice windows are typically large
                            if width > 800 and height > 600:
                                windows.append((hwnd, window_text, window_class))
                                print(f"Found large window candidate: '{window_text}' (ID: {hwnd}, Class: {window_class}, Size: {width}x{height})")
                    except Exception as e:
                        pass
                return True
            
            windows = []
            win32gui.EnumWindows(enum_windows_callback, windows)
            
            if windows:
                print(f"✅ Found {len(windows)} large window candidates")
                # Return the largest window
                largest_window = max(windows, key=lambda x: (win32gui.GetWindowRect(x[0])[2] - win32gui.GetWindowRect(x[0])[0]) * 
                                                          (win32gui.GetWindowRect(x[0])[3] - win32gui.GetWindowRect(x[0])[1]))
                return largest_window[0]
            
            print("❌ No LibreOffice windows found after comprehensive search")
            return None
            
        except Exception as e:
            print(f"❌ Error finding LibreOffice window on Windows: {e}")
            return None
    
    def find_libreoffice_window_linux(self):
        """Find LibreOffice Writer window on Linux"""
        try:
            # Use wmctrl to find LibreOffice windows
            result = subprocess.run(
                ["wmctrl", "-lp"],
                capture_output=True,
                text=True
            )
            
            if result.returncode == 0:
                lines = result.stdout.split('\n')
                for line in lines:
                    # More flexible matching for LibreOffice windows
                    if any(keyword in line.lower() for keyword in [
                        "libreoffice", 
                        "writer", 
                        "soffice",
                        "untitled"
                    ]):
                        parts = line.split()
                        if len(parts) >= 1:
                            window_id = int(parts[0], 16)  # Convert hex to int
                            print(f"Found LibreOffice window: {line.strip()} (ID: {window_id})")
                            return window_id
            
            print("❌ No LibreOffice windows found with wmctrl")
            return None
            
        except Exception as e:
            print(f"❌ Error finding LibreOffice window on Linux: {e}")
            return None
    
    def embed_window(self, parent_layout):
        """Embed the LibreOffice window into the parent layout with improved error handling"""
        if not self.window_id:
            print("❌ No LibreOffice window ID available")
            return False
        
        try:
            print(f"🔧 Attempting to embed LibreOffice window ID: {self.window_id}")
            
            # Verify window still exists and is valid
            if platform.system() == "Windows" and WINDOWS_AVAILABLE:
                try:
                    if not win32gui.IsWindow(self.window_id):
                        print("❌ Window ID is no longer valid")
                        return False
                    
                    # Get window information for debugging
                    window_text = win32gui.GetWindowText(self.window_id)
                    window_class = win32gui.GetClassName(self.window_id)
                    print(f"🔍 Embedding window: '{window_text}' (Class: {window_class})")
                    
                    # Set window style for embedding on Windows
                    try:
                        style = win32gui.GetWindowLong(self.window_id, win32con.GWL_EXSTYLE)
                        new_style = style | win32con.WS_EX_MDICHILD
                        win32gui.SetWindowLong(self.window_id, win32con.GWL_EXSTYLE, new_style)
                        print("✅ Window style set for embedding")
                        
                        # Force window to update
                        win32gui.SetWindowPos(self.window_id, 0, 0, 0, 0, 0, 
                                            win32con.SWP_NOMOVE | win32con.SWP_NOSIZE | win32con.SWP_FRAMECHANGED)
                    except Exception as e:
                        print(f"⚠️ Could not set window style: {e}")
                        # Continue anyway, as this might not be critical
                        
                except Exception as e:
                    print(f"❌ Error verifying window: {e}")
                    return False
            
            # Create QWindow from the window ID
            print("🔧 Creating QWindow from window ID...")
            lo_window = QWindow.fromWinId(self.window_id)
            
            if not lo_window:
                print("❌ Failed to create QWindow from window ID")
                return False
            
            # Create container widget
            print("🔧 Creating container widget...")
            self.embedded_widget = QWidget.createWindowContainer(lo_window)
            
            if not self.embedded_widget:
                print("❌ Failed to create container widget")
                return False
            
            # Set size policy to expand
            self.embedded_widget.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
            
            # Add to parent layout
            print("🔧 Adding widget to parent layout...")
            parent_layout.addWidget(self.embedded_widget)
            
            # Force layout update
            parent_layout.update()
            
            # Mark as embedded
            self.is_embedded = True
            print("✅ LibreOffice Writer embedded successfully")
            
            # Give the window a moment to settle
            QTimer.singleShot(1000, lambda: self._post_embed_cleanup())
            
            return True
            
        except Exception as e:
            print(f"❌ Error embedding LibreOffice window: {e}")
            import traceback
            traceback.print_exc()
            return False
    
    def _post_embed_cleanup(self):
        """Perform cleanup tasks after successful embedding"""
        try:
            if platform.system() == "Windows" and WINDOWS_AVAILABLE and self.window_id:
                # Ensure the window is properly positioned and visible
                try:
                    win32gui.ShowWindow(self.window_id, win32con.SW_SHOW)
                    print("✅ Window visibility ensured after embedding")
                except Exception as e:
                    print(f"⚠️ Could not ensure window visibility: {e}")
        except Exception as e:
            print(f"⚠️ Post-embed cleanup error: {e}")
    
    def remove_embedded_window(self):
        """Remove the embedded LibreOffice window"""
        if self.embedded_widget:
            self.embedded_widget.setParent(None)
            self.embedded_widget = None
            self.is_embedded = False
            print("✅ LibreOffice Writer window removed")
    
    def close_libreoffice(self):
        """Close the LibreOffice process"""
        if self.libreoffice_process:
            self.libreoffice_process.terminate()
            try:
                self.libreoffice_process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                self.libreoffice_process.kill()
            self.libreoffice_process = None
            print("✅ LibreOffice Writer closed")
    
    def force_close_all_libreoffice(self):
        """Force close all LibreOffice processes to prevent conflicts"""
        try:
            if platform.system() == "Windows":
                # Use taskkill to force close all LibreOffice processes
                subprocess.run(["taskkill", "/f", "/im", "soffice.exe"], 
                             capture_output=True, timeout=10)
                subprocess.run(["taskkill", "/f", "/im", "soffice.bin"], 
                             capture_output=True, timeout=10)
                subprocess.run(["taskkill", "/f", "/im", "libreoffice.exe"], 
                             capture_output=True, timeout=10)
                print("✅ Force closed all LibreOffice processes on Windows")
            else:
                # Use pkill on Unix-like systems
                subprocess.run(["pkill", "-f", "libreoffice"], 
                             capture_output=True, timeout=10)
                subprocess.run(["pkill", "-f", "soffice"], 
                             capture_output=True, timeout=10)
                print("✅ Force closed all LibreOffice processes on Unix")
            
            # Wait a moment for processes to fully terminate
            time.sleep(3)
            
        except Exception as e:
            print(f"⚠️ Error force closing LibreOffice processes: {e}")
    
    def is_libreoffice_running(self):
        """Check if LibreOffice is currently running"""
        try:
            if platform.system() == "Windows":
                # Check for LibreOffice processes on Windows
                result = subprocess.run(["tasklist", "/FI", "IMAGENAME eq soffice.exe"], 
                                      capture_output=True, text=True, timeout=5)
                if "soffice.exe" in result.stdout:
                    return True
                
                result = subprocess.run(["tasklist", "/FI", "IMAGENAME eq libreoffice.exe"], 
                                      capture_output=True, text=True, timeout=5)
                if "libreoffice.exe" in result.stdout:
                    return True
            else:
                # Check for LibreOffice processes on Unix
                result = subprocess.run(["pgrep", "-f", "libreoffice"], 
                                      capture_output=True, timeout=5)
                if result.returncode == 0:
                    return True
                
                result = subprocess.run(["pgrep", "-f", "soffice"], 
                                      capture_output=True, timeout=5)
                if result.returncode == 0:
                    return True
            
            return False
            
        except Exception as e:
            print(f"⚠️ Error checking if LibreOffice is running: {e}")
            return False
    
    def wait_for_libreoffice_ready(self, max_wait_time=30):
        """Wait for LibreOffice to be fully ready and responsive"""
        print(f"⏳ Waiting for LibreOffice to be ready (max {max_wait_time}s)...")
        
        start_time = time.time()
        while time.time() - start_time < max_wait_time:
            # Check if process is running
            if not self.is_libreoffice_running():
                print("❌ LibreOffice process is not running")
                return False
            
            # Try to find the window
            window_id = self.find_libreoffice_window()
            if window_id:
                print(f"✅ LibreOffice is ready! Found window ID: {window_id}")
                return True
            
            # Wait a bit before trying again
            time.sleep(2)
            print("⏳ Still waiting for LibreOffice to be ready...")
        
        print("❌ LibreOffice did not become ready within the timeout period")
        return False
    
    def replace_document(self, new_doc_path):
        """Replace the current document with a new one"""
        try:
            if not self.is_embedded:
                return False
            
            # Use LibreOffice command line to open the new document
            libreoffice_commands = [
                ["libreoffice", "--writer", new_doc_path],
                ["soffice", "--writer", new_doc_path],
                ["libreoffice7.6", "--writer", new_doc_path],
                ["libreoffice7.5", "--writer", new_doc_path],
                ["libreoffice7.4", "--writer", new_doc_path],
                ["libreoffice7.3", "--writer", new_doc_path],
                ["libreoffice7.2", "--writer", new_doc_path],
                ["libreoffice7.1", "--writer", new_doc_path],
                ["libreoffice7.0", "--writer", new_doc_path],
            ]
            
            for cmd in libreoffice_commands:
                try:
                    subprocess.run(cmd, check=True, timeout=10)
                    print(f"✅ Document replaced: {new_doc_path}")
                    return True
                except (subprocess.TimeoutExpired, FileNotFoundError, subprocess.CalledProcessError):
                    continue
            
            return False
            
        except Exception as e:
            print(f"❌ Error replacing document: {e}")
            return False
    
    def open_document(self, doc_path):
        """Open a document in LibreOffice"""
        try:
            if not os.path.exists(doc_path):
                print(f"❌ Document not found: {doc_path}")
                return False
            
            # Use LibreOffice command line to open the document
            libreoffice_commands = [
                ["libreoffice", "--writer", doc_path],
                ["soffice", "--writer", doc_path],
                ["libreoffice7.6", "--writer", doc_path],
                ["libreoffice7.5", "--writer", doc_path],
                ["libreoffice7.4", "--writer", doc_path],
                ["libreoffice7.3", "--writer", doc_path],
                ["libreoffice7.2", "--writer", doc_path],
                ["libreoffice7.1", "--writer", doc_path],
                ["libreoffice7.0", "--writer", doc_path],
            ]
            
            for cmd in libreoffice_commands:
                try:
                    subprocess.run(cmd, check=True, timeout=10)
                    print(f"✅ Document opened: {doc_path}")
                    return True
                except (subprocess.TimeoutExpired, FileNotFoundError, subprocess.CalledProcessError):
                    continue
            
            return False
            
        except Exception as e:
            print(f"❌ Error opening document: {e}")
            return False
    
    def check_libreoffice_installation(self):
        """Check if LibreOffice is properly installed and accessible"""
        print("🔍 Checking LibreOffice installation...")
        
        # Try different LibreOffice command variations
        libreoffice_commands = [
            ["libreoffice", "--version"],
            ["soffice", "--version"],
            ["libreoffice7.6a", "--version"],
            ["libreoffice7.5", "--version"],
            ["libreoffice7.4", "--version"],
            ["libreoffice7.3", "--version"],
            ["libreoffice7.2", "--version"],
            ["libreoffice7.1", "--version"],
            ["libreoffice7.0", "--version"],
        ]
        
        # Try to find LibreOffice executable
        for cmd in libreoffice_commands:
            try:
                result = subprocess.run(cmd, capture_output=True, timeout=10, text=True)
                if result.returncode == 0:
                    print(f"✅ LibreOffice found: {cmd[0]}")
                    print(f"   Version info: {result.stdout.strip()}")
                    return True, cmd[0]
            except (subprocess.TimeoutExpired, FileNotFoundError):
                continue
        
        # Check common installation paths
        common_paths = [
            r"C:\Program Files\LibreOffice\program\soffice.exe",
            r"C:\Program Files (x86)\LibreOffice\program\soffice.exe",
            "/usr/bin/libreoffice",
            "/usr/bin/soffice",
            "/opt/libreoffice/program/soffice",
            "/Applications/LibreOffice.app/Contents/MacOS/soffice",
        ]
        
        for path in common_paths:
            if os.path.exists(path):
                print(f"✅ LibreOffice found at: {path}")
                return True, path
        
        print("❌ LibreOffice not found in PATH or common locations")
        return False, None





