class DocumentHelper:
    """Helper class for document formatting and generation"""
    
    @staticmethod
    def set_font_style(run, font_name='Calibri', font_size=12, bold=False, italic=False):
        font = run.font
        font.name = font_name
        font.size = Pt(font_size)
        font.bold = bold
        font.italic = italic
        run._element.rPr.rFonts.set(qn('w:eastAsia'), font_name)
    
    @staticmethod
    def add_paragraph(doc, text, font_size=12, bold=False, italic=False, align='left'):
        para = doc.add_paragraph()
        run = para.add_run(text)
        DocumentHelper.set_font_style(run, font_size=font_size, bold=bold, italic=italic)
        para.alignment = 1 if align == 'center' else 0  # 1=center, 0=left
        return para
    
    @staticmethod
    def add_mixed_paragraph(doc, label, value, label_style, value_style):
        para = doc.add_paragraph()
        run_label = para.add_run(label)
        DocumentHelper.set_font_style(run_label, **label_style)
        run_value = para.add_run(value)
        DocumentHelper.set_font_style(run_value, **value_style)
        para.alignment = 0  # left
    
    @staticmethod
    def add_numbered_list(doc, items):
        for item in items:
            para = doc.add_paragraph(item, style='List Number')
            for run in para.runs:
                DocumentHelper.set_font_style(run, font_name='Calibri', font_size=12, bold=False)


    # 📄 Export and Background File Handling Feature
    @staticmethod
    def sanitize_folder_name(name):
        """Sanitize test case name for use as folder name
        
        Args:
            name: Original test case name
            
        Returns:
            Sanitized folder name safe for filesystem
        """
        import re
        from datetime import datetime
        
        # Remove or replace invalid characters
        # First replace forward slashes with underscores to prevent path splitting
        sanitized = name.replace('/', '_')
        # Then replace other invalid characters
        sanitized = re.sub(r'[<>:"\\|?*]', '_', sanitized)
        # Remove extra spaces and replace with underscores
        sanitized = re.sub(r'\s+', '_', sanitized)
        # Remove leading/trailing underscores and dots
        sanitized = sanitized.strip('_.')
        # Limit length to avoid filesystem issues
        if len(sanitized) > 100:
            sanitized = sanitized[:100]
        # Ensure it's not empty
        if not sanitized:
            sanitized = f"test_case_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
        
        return sanitized
    
    @staticmethod
    def create_test_case_structure(test_case_name, project_root=None):
        """Create folder structure for test case in background
        
        Args:
            test_case_name: Name of the test case
            project_root: Root directory of the project. If None, uses current directory.
            
        Returns:
            Dictionary with paths to created folders
        """
        if project_root is None:
            project_root = os.getcwd()
        
        # Sanitize test case name
        sanitized_name = DocumentHelper.sanitize_folder_name(test_case_name)
        
        # Create folder structure
        tmp_dir = os.path.join(project_root, "tmp")
        test_case_dir = os.path.join(tmp_dir, sanitized_name)
        
        folders = {
            'tmp': tmp_dir,
            'test_case': test_case_dir,
            'configuration': os.path.join(test_case_dir, "configuration"),
            'report': os.path.join(test_case_dir, "report"),
            'raw_logs': os.path.join(test_case_dir, "raw_logs")
        }
        
        # Create all folders
        for folder_name, folder_path in folders.items():
            try:
                os.makedirs(folder_path, exist_ok=True)
                print(f"✅ Created folder: {folder_path}")
            except Exception as e:
                print(f"❌ Error creating folder {folder_path}: {e}")
                raise

        # Create Input folder in home directory
        input_folder_path = os.path.expanduser("~/Input")
        try:
            os.makedirs(input_folder_path, exist_ok=True)
            print(f"✅ Created/verified Input folder: {input_folder_path}")
        except Exception as e:
            print(f"❌ Error creating Input folder: {e}")
        
        return folders
    
    @staticmethod
    def copy_exported_file(source_path, test_case_folders):
        """Copy exported file to report folder
        
        Args:
            source_path: Path to the exported file
            test_case_folders: Dictionary with folder paths from create_test_case_structure
            
        Returns:
            Path to the copied file
        """
        try:
            filename = os.path.basename(source_path)
            destination_path = os.path.join(test_case_folders['report'], filename)
            
            shutil.copy2(source_path, destination_path)
            print(f"✅ Copied exported file to: {destination_path}")
            
            return destination_path
        except Exception as e:
            print(f"❌ Error copying exported file: {e}")
            raise
    
    @staticmethod
    def extract_images_from_docx(docx_path, test_case_folders):
        """Extract all images from DOCX file and save to raw_logs folder
        
        Args:
            docx_path: Path to the DOCX file
            test_case_folders: Dictionary with folder paths from create_test_case_structure
            
        Returns:
            List of extracted image paths
        """
        extracted_images = []
        
        try:
            import zipfile
            from docx import Document
            
            # Open DOCX as ZIP file to extract images
            with zipfile.ZipFile(docx_path, 'r') as docx_zip:
                # List all files in the DOCX
                file_list = docx_zip.namelist()
                
                # Find image files
                image_files = [f for f in file_list if f.startswith('word/media/') and 
                             any(f.lower().endswith(ext) for ext in ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff'])]
                
                # Extract each image
                for i, image_file in enumerate(image_files, 1):
                    try:
                        # Get file extension
                        _, ext = os.path.splitext(image_file)
                        if not ext:
                            ext = '.png'  # Default extension
                        
                        # Create unique filename
                        image_filename = f"image_{i:03d}{ext}"
                        image_path = os.path.join(test_case_folders['raw_logs'], image_filename)
                        
                        # Extract image
                        with docx_zip.open(image_file) as source, open(image_path, 'wb') as target:
                            target.write(source.read())
                        
                        extracted_images.append(image_path)
                        print(f"✅ Extracted image: {image_path}")
                        
                    except Exception as e:
                        print(f"❌ Error extracting image {image_file}: {e}")
                        continue
            
            print(f"✅ Total images extracted: {len(extracted_images)}")
            return extracted_images
            
        except Exception as e:
            print(f"❌ Error extracting images from DOCX: {e}")
            return extracted_images
    
    @staticmethod
    def save_configuration_data(config_data, test_case_folders):
        """Save configuration data to configuration folder
        
        Args:
            config_data: Configuration data dictionary
            test_case_folders: Dictionary with folder paths from create_test_case_structure
            
        Returns:
            Path to saved configuration file
        """
        try:
            import json
            from datetime import datetime
            
            # Create configuration filename with timestamp
            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
            config_filename = f"test_config_{timestamp}.json"
            config_path = os.path.join(test_case_folders['configuration'], config_filename)
            
            # Filter configuration data to only include required sections
            filtered_config = DocumentHelper.filter_configuration_for_export(config_data)
            
            # Add metadata to config
            config_with_metadata = {
                'export_timestamp': datetime.now().isoformat(),
                'test_case_name': config_data.get('report_title', 'Unknown Test Case'),
                'configuration': filtered_config
            }
            
            # Save configuration as JSON
            with open(config_path, 'w', encoding='utf-8') as f:
                json.dump(config_with_metadata, f, indent=2, default=str, ensure_ascii=False)
            
            print(f"✅ Saved filtered configuration to: {config_path}")
            return config_path
            
        except Exception as e:
            print(f"❌ Error saving configuration: {e}")
            raise
    
    @staticmethod
    def filter_configuration_for_export(config_data):
        """Filter configuration data to only include required sections for export
        
        Args:
            config_data: Full configuration data dictionary
            
        Returns:
            Filtered configuration data with only required sections
        """
        filtered_config = {}
        
        # 1. Report Information
        filtered_config['report_title'] = config_data.get('report_title', '')
        filtered_config['report_number'] = config_data.get('report_number', '')
        filtered_config['template_path'] = config_data.get('template_path', '')
        filtered_config['itsar_section'] = config_data.get('itsar_section', '')
        filtered_config['security_req'] = config_data.get('security_req', '')
        filtered_config['req_description'] = config_data.get('req_description', '')
        filtered_config['test_objective'] = config_data.get('test_objective', '')
        filtered_config['export_path'] = config_data.get('export_path', '')
        filtered_config['export_filename'] = config_data.get('export_filename', '')
        
        # 2. DUT Configuration
        filtered_config['dut_fields'] = config_data.get('dut_fields', [])
        filtered_config['hash_sections'] = config_data.get('hash_sections', [])
        filtered_config['hash_section_heading'] = config_data.get('hash_section_heading', '')
        filtered_config['itsar_fields'] = config_data.get('itsar_fields', [])
        
        # 3. Section 8 – Test Plan
        filtered_config['test_plan_overview'] = config_data.get('test_plan_overview', '')
        filtered_config['test_scenarios_heading'] = config_data.get('test_scenarios_heading', '')
        filtered_config['test_bed_diagram_heading'] = config_data.get('test_bed_diagram_heading', '')
        filtered_config['tools_required_heading'] = config_data.get('tools_required_heading', '')
        filtered_config['test_execution_steps_heading'] = config_data.get('test_execution_steps_heading', '')
        filtered_config['expected_results_heading'] = config_data.get('expected_results_heading', '')
        filtered_config['expected_format_evidence_heading'] = config_data.get('expected_format_evidence_heading', '')
        filtered_config['test_scenarios'] = config_data.get('test_scenarios', [])
        filtered_config['test_bed_images'] = config_data.get('test_bed_images', [])
        filtered_config['tools_required'] = config_data.get('tools_required', [])
        
        # 4. Section 1–7
        filtered_config['sections_1_7'] = config_data.get('sections_1_7', {})
        
        # 5. Section 11 – Test Execution
        filtered_config['execution_steps'] = config_data.get('execution_steps', [])
        filtered_config['manual_execution_steps'] = config_data.get('manual_execution_steps', [])
        filtered_config['test_execution_cases'] = config_data.get('test_execution_cases', [])
        
        # 6. Section 12 – Test Case Result
        filtered_config['expected_results'] = config_data.get('expected_results', [])
        filtered_config['evidence_format'] = config_data.get('evidence_format', [])
        filtered_config['test_case_results'] = config_data.get('test_case_results', [])
        filtered_config['screenshots'] = config_data.get('screenshots', [])
        filtered_config['section_scripts'] = config_data.get('section_scripts', {})
        
        # 7. Additional required fields
        filtered_config['interfaces'] = config_data.get('interfaces', [])
        
        # Clean up hardcoded values - only keep user-entered data
        filtered_config = DocumentHelper.clean_hardcoded_values(filtered_config)
        
        return filtered_config
    
    @staticmethod
    def clean_hardcoded_values(config_data):
        """Remove hardcoded values and only keep user-entered data
        
        Args:
            config_data: Configuration data dictionary
            
        Returns:
            Cleaned configuration data with only user-entered values
        """
        cleaned_config = config_data.copy()
        
        # Clean test scenarios - remove only specific hardcoded long descriptions
        if 'test_scenarios' in cleaned_config:
            cleaned_scenarios = []
            for scenario in cleaned_config['test_scenarios']:
                description = scenario.get('description', '')
                # Only remove if it's the exact hardcoded long description
                if not DocumentHelper.is_hardcoded_scenario_description(description):
                    cleaned_scenarios.append(scenario)
            cleaned_config['test_scenarios'] = cleaned_scenarios
        
        # Clean test execution cases - clean individual fields instead of removing entire cases
        if 'test_execution_cases' in cleaned_config:
            for case in cleaned_config['test_execution_cases']:
                # Clean individual fields instead of removing entire cases
                test_case_name = case.get('test_case_name', '')
                if DocumentHelper.is_hardcoded_scenario_description(test_case_name):
                    case['test_case_name'] = ''
                
                # Clean other fields if they are hardcoded
                itsar_description = case.get('itsar_description', '')
                if DocumentHelper.is_hardcoded_scenario_description(itsar_description):
                    case['itsar_description'] = ''
                
                test_case_description = case.get('test_case_description', '')
                if DocumentHelper.is_hardcoded_scenario_description(test_case_description):
                    case['test_case_description'] = ''
                
                test_objective = case.get('test_objective', '')
                if DocumentHelper.is_hardcoded_scenario_description(test_objective):
                    case['test_objective'] = ''
                
                test_observations = case.get('test_observations', '')
                if DocumentHelper.is_hardcoded_scenario_description(test_observations):
                    case['test_observations'] = ''
                
                evidence_provided = case.get('evidence_provided', '')
                if DocumentHelper.is_hardcoded_scenario_description(evidence_provided):
                    case['evidence_provided'] = ''
        
        # Clean evidence format - remove only specific hardcoded values
        if 'evidence_format' in cleaned_config:
            cleaned_evidence = []
            for evidence in cleaned_config['evidence_format']:
                # Only remove specific hardcoded evidence formats
                if not DocumentHelper.is_hardcoded_evidence_format(evidence):
                    cleaned_evidence.append(evidence)
            cleaned_config['evidence_format'] = cleaned_evidence
        
        # Clean test case results - remove only hardcoded test case numbers, keep user entries
        if 'test_case_results' in cleaned_config:
            cleaned_results = []
            for result in cleaned_config['test_case_results']:
                test_case_no = result.get('test_case_no', '')
                pass_fail = result.get('pass_fail', '')
                remarks = result.get('remarks', '')
                
                # Keep if user has entered a test case number, only remove if it's completely empty or hardcoded
                if test_case_no != '' and test_case_no not in ['1.9.4.1', '1.12.1.1']:
                    cleaned_results.append(result)
            cleaned_config['test_case_results'] = cleaned_results
        
        # Clean execution steps - remove only exact "test" steps, keep user entries
        if 'execution_steps' in cleaned_config:
            cleaned_steps = []
            for step_group in cleaned_config['execution_steps']:
                steps = step_group.get('steps', [])
                # Keep if any step is not exactly "test"
                if steps and not all(step.strip().lower() == 'test' for step in steps):
                    cleaned_steps.append(step_group)
            cleaned_config['execution_steps'] = cleaned_steps
        
        # Clean test execution cases steps - remove only exact "test" steps
        if 'test_execution_cases' in cleaned_config:
            for case in cleaned_config['test_execution_cases']:
                if 'execution_steps' in case:
                    steps = case['execution_steps']
                    # Only remove if all steps are exactly "test"
                    if steps and all(step.strip().lower() == 'test' for step in steps):
                        case['execution_steps'] = []
                
                # Clean steps_data - remove only exact "test" steps
                if 'steps_data' in case:
                    cleaned_steps_data = []
                    for step_data in case['steps_data']:
                        step_text = step_data.get('step_text', '')
                        # Keep if step is not exactly "test"
                        if step_text.strip().lower() != 'test':
                            cleaned_steps_data.append(step_data)
                    case['steps_data'] = cleaned_steps_data
        
        # Clean tools required - remove only specific hardcoded tool versions
        if 'tools_required' in cleaned_config:
            cleaned_tools = []
            for tool in cleaned_config['tools_required']:
                # Only remove specific hardcoded tool versions
                if not DocumentHelper.is_hardcoded_tool(tool):
                    cleaned_tools.append(tool)
            cleaned_config['tools_required'] = cleaned_tools
        
        # Clean sections 1-7 - remove only specific hardcoded default content
        if 'sections_1_7' in cleaned_config:
            sections = cleaned_config['sections_1_7']
            for section_key in sections:
                section = sections[section_key]
                if 'content' in section:
                    content = section['content']
                    # Only remove specific hardcoded content
                    if DocumentHelper.is_hardcoded_section_content(content):
                        section['content'] = ''
                
                if 'text' in section:
                    text = section['text']
                    # Only remove specific hardcoded text
                    if DocumentHelper.is_hardcoded_section_content(text):
                        section['text'] = ''
        
        return cleaned_config
    
    @staticmethod
    def is_hardcoded_scenario_description(text):
        """Check if text is the specific hardcoded scenario description"""
        if not text or len(text) < 200:
            return False
        
        # Check for the exact hardcoded long description
        hardcoded_text = "verify that remote access to the cpe for troubleshooting or alarm maintenance is limited to authorized users, and all remote activities are logged with parameter user id, timestamp, interface type, event level (e.g., critical, major, minor), and result type (e.g., success, failure)."
        return text.lower().strip() == hardcoded_text
    
    @staticmethod
    def is_hardcoded_evidence_format(text):
        """Check if text is a hardcoded evidence format"""
        if not text:
            return False
        
        hardcoded_formats = [
            "screenshot of burp suit pro, nessus, nmap and firefox",
            "screenshot of burp suite",
            "screenshot of nessus",
            "screenshot of nmap"
        ]
        return text.lower().strip() in hardcoded_formats
    
    @staticmethod
    def is_hardcoded_tool(text):
        """Check if text is a hardcoded tool version"""
        if not text:
            return False
        
        hardcoded_tools = [
            "firefox v (136.0.1)",
            "burp suite v (2025.2.3)",
            "firefox (latest version)",
            "burp suite professional",
            "nmap",
            "nessus scanner"
        ]
        return text.lower().strip() in hardcoded_tools
    
    @staticmethod
    def is_hardcoded_section_content(text):
        """Check if text is hardcoded section content"""
        if not text:
            return False
        
        hardcoded_content = [
            "section 1.9 vulnerability testing requirements",
            "1.9.4: vulnerability scanning",
            "the system shall be tested for known vulnerabilities using automated scanning tools.",
            "dut configured with ssh and https services enabled.",
            "network connectivity established, scanning tools installed.",
            "identify and document all security vulnerabilities in the system.",
            "all vulnerabilities identified and documented with remediation plans.",
            "screenshots of scanning tools and results."
        ]
        return text.lower().strip() in hardcoded_content
    
    @staticmethod
    def handle_export_with_background_operations(export_path, filename, config_data, project_root=None):
        """Handle complete export process with background file operations
        
        Args:
            export_path: User-specified export directory
            filename: Export filename
            config_data: Configuration data for the document
            project_root: Project root directory
            
        Returns:
            Dictionary with operation results and paths
        """
        results = {
            'success': False,
            'primary_export_path': None,
            'test_case_folders': None,
            'backup_file_path': None,
            'extracted_images': [],
            'config_file_path': None,
            'errors': []
        }
        
        try:
            # 1. Get test case name from config
            test_case_name = config_data.get('report_title', 'Unknown_Test_Case')
            
            # 2. Primary export path
            primary_export_path = os.path.join(export_path, filename)
            results['primary_export_path'] = primary_export_path
            
            # 3. Create test case folder structure
            print("🗂️ Creating test case folder structure...")
            test_case_folders = DocumentHelper.create_test_case_structure(test_case_name, project_root)
            results['test_case_folders'] = test_case_folders
            
            # 4. Save configuration data
            print("💾 Saving configuration data...")
            config_file_path = DocumentHelper.save_configuration_data(config_data, test_case_folders)
            results['config_file_path'] = config_file_path
            
            # Note: The actual document generation happens in the calling function
            # After the document is generated, call post_export_operations
            
            results['success'] = True
            print("✅ Background operations setup completed successfully")
            
        except Exception as e:
            error_msg = f"Background operations failed: {str(e)}"
            results['errors'].append(error_msg)
            print(f"❌ {error_msg}")
        
        return results
    
    @staticmethod
    def post_export_operations(primary_export_path, test_case_folders):
        """Perform post-export operations after document is generated
        
        Args:
            primary_export_path: Path to the primary exported file
            test_case_folders: Dictionary with folder paths from create_test_case_structure
            
        Returns:
            Dictionary with post-export operation results
        """
        results = {
            'backup_file_path': None,
            'extracted_images': [],
            'errors': []
        }
        
        try:
            # 5. Copy exported file to report folder
            print("📑 Copying exported file to report folder...")
            backup_file_path = DocumentHelper.copy_exported_file(primary_export_path, test_case_folders)
            results['backup_file_path'] = backup_file_path
            
            # 6. Extract images from DOCX (if it's a DOCX file)
            if primary_export_path.lower().endswith('.docx'):
                print("🖼️ Extracting images from document...")
                extracted_images = DocumentHelper.extract_images_from_docx(primary_export_path, test_case_folders)
                results['extracted_images'] = extracted_images
            
            print("✅ Post-export operations completed successfully")
            
        except Exception as e:
            error_msg = f"Post-export operations failed: {str(e)}"
            results['errors'].append(error_msg)
            print(f"❌ {error_msg}")
        
        return results
    
    # 🗂️ File Manager Methods for Files Tab
    @staticmethod
    def get_tmp_directory_tree(project_root=None):
        """Get directory tree structure for tmp folder
        
        Args:
            project_root: Project root directory
            
        Returns:
            Dictionary with directory tree structure
        """
        if project_root is None:
            project_root = os.getcwd()
        
        tmp_dir = os.path.join(project_root, "tmp")
        
        if not os.path.exists(tmp_dir):
            return {'path': tmp_dir, 'exists': False, 'children': []}
        
        def build_tree(path):
            """Recursively build directory tree"""
            items = []
            try:
                for item in sorted(os.listdir(path)):
                    item_path = os.path.join(path, item)
                    stat_info = os.stat(item_path)
                    
                    item_data = {
                        'name': item,
                        'path': item_path,
                        'relative_path': os.path.relpath(item_path, tmp_dir),
                        'is_directory': os.path.isdir(item_path),
                        'size': stat_info.st_size if not os.path.isdir(item_path) else 0,
                        'modified': stat_info.st_mtime,
                        'modified_str': datetime.fromtimestamp(stat_info.st_mtime).strftime('%Y-%m-%d %H:%M:%S')
                    }
                    
                    if os.path.isdir(item_path):
                        item_data['children'] = build_tree(item_path)
                    
                    items.append(item_data)
            except PermissionError:
                pass
            
            return items
        
        return {
            'path': tmp_dir,
            'exists': True,
            'children': build_tree(tmp_dir)
        }
    
    @staticmethod
    def create_folder_in_tmp(folder_name, parent_path, project_root=None):
        """Create new folder in tmp directory
        
        Args:
            folder_name: Name of the new folder
            parent_path: Parent directory path (relative to tmp)
            project_root: Project root directory
            
        Returns:
            Success status and message
        """
        try:
            if project_root is None:
                project_root = os.getcwd()
            
            tmp_dir = os.path.join(project_root, "tmp")
            
            # Ensure parent_path is within tmp directory
            if parent_path:
                full_parent_path = os.path.join(tmp_dir, parent_path)
            else:
                full_parent_path = tmp_dir
            
            # Security check: ensure we're within tmp directory
            if not os.path.abspath(full_parent_path).startswith(os.path.abspath(tmp_dir)):
                return False, "Access denied: Cannot create folder outside tmp directory"
            
            # Sanitize folder name
            sanitized_name = DocumentHelper.sanitize_folder_name(folder_name)
            new_folder_path = os.path.join(full_parent_path, sanitized_name)
            
            os.makedirs(new_folder_path, exist_ok=True)
            return True, f"Folder '{sanitized_name}' created successfully"
            
        except Exception as e:
            return False, f"Failed to create folder: {str(e)}"
    
    @staticmethod
    def delete_file_or_folder(relative_path, project_root=None):
        """Delete file or folder from tmp directory
        
        Args:
            relative_path: Path relative to tmp directory
            project_root: Project root directory
            
        Returns:
            Success status and message
        """
        try:
            if project_root is None:
                project_root = os.getcwd()
            
            tmp_dir = os.path.join(project_root, "tmp")
            full_path = os.path.join(tmp_dir, relative_path)
            
            # Security check: ensure we're within tmp directory
            if not os.path.abspath(full_path).startswith(os.path.abspath(tmp_dir)):
                return False, "Access denied: Cannot delete files outside tmp directory"
            
            if not os.path.exists(full_path):
                return False, "File or folder does not exist"
            
            if os.path.isdir(full_path):
                shutil.rmtree(full_path)
                return True, f"Folder deleted successfully"
            else:
                os.remove(full_path)
                return True, f"File deleted successfully"
                
        except Exception as e:
            return False, f"Failed to delete: {str(e)}"
    
    @staticmethod
    def rename_file_or_folder(relative_path, new_name, project_root=None):
        """Rename file or folder in tmp directory
        
        Args:
            relative_path: Current path relative to tmp directory
            new_name: New name for the file/folder
            project_root: Project root directory
            
        Returns:
            Success status and message
        """
        try:
            if project_root is None:
                project_root = os.getcwd()
            
            tmp_dir = os.path.join(project_root, "tmp")
            old_path = os.path.join(tmp_dir, relative_path)
            
            # Security check: ensure we're within tmp directory
            if not os.path.abspath(old_path).startswith(os.path.abspath(tmp_dir)):
                return False, "Access denied: Cannot rename files outside tmp directory"
            
            if not os.path.exists(old_path):
                return False, "File or folder does not exist"
            
            # Sanitize new name
            sanitized_name = DocumentHelper.sanitize_folder_name(new_name)
            parent_dir = os.path.dirname(old_path)
            new_path = os.path.join(parent_dir, sanitized_name)
            
            if os.path.exists(new_path):
                return False, "A file or folder with that name already exists"
            
            os.rename(old_path, new_path)
            return True, f"Renamed to '{sanitized_name}' successfully"
            
        except Exception as e:
            return False, f"Failed to rename: {str(e)}"
    
    @staticmethod
    def copy_file_or_folder(source_relative_path, dest_relative_path, project_root=None):
        """Copy file or folder within tmp directory
        
        Args:
            source_relative_path: Source path relative to tmp directory
            dest_relative_path: Destination path relative to tmp directory
            project_root: Project root directory
            
        Returns:
            Success status and message
        """
        try:
            if project_root is None:
                project_root = os.getcwd()
            
            tmp_dir = os.path.join(project_root, "tmp")
            source_path = os.path.join(tmp_dir, source_relative_path)
            dest_path = os.path.join(tmp_dir, dest_relative_path)
            
            # Security checks
            if not os.path.abspath(source_path).startswith(os.path.abspath(tmp_dir)):
                return False, "Access denied: Cannot copy from outside tmp directory"
            
            if not os.path.abspath(dest_path).startswith(os.path.abspath(tmp_dir)):
                return False, "Access denied: Cannot copy to outside tmp directory"
            
            if not os.path.exists(source_path):
                return False, "Source file or folder does not exist"
            
            if os.path.exists(dest_path):
                return False, "Destination already exists"
            
            # Ensure destination directory exists
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            
            if os.path.isdir(source_path):
                shutil.copytree(source_path, dest_path)
                return True, "Folder copied successfully"
            else:
                shutil.copy2(source_path, dest_path)
                return True, "File copied successfully"
                
        except Exception as e:
            return False, f"Failed to copy: {str(e)}"
    
    @staticmethod
    def get_file_content_preview(relative_path, project_root=None, max_size=1024*1024):
        """Get preview content for text files
        
        Args:
            relative_path: Path relative to tmp directory
            project_root: Project root directory
            max_size: Maximum file size for preview (1MB default)
            
        Returns:
            Dictionary with preview information
        """
        try:
            if project_root is None:
                project_root = os.getcwd()
            
            tmp_dir = os.path.join(project_root, "tmp")
            full_path = os.path.join(tmp_dir, relative_path)
            
            # Security check
            if not os.path.abspath(full_path).startswith(os.path.abspath(tmp_dir)):
                return {'success': False, 'error': 'Access denied'}
            
            if not os.path.exists(full_path) or os.path.isdir(full_path):
                return {'success': False, 'error': 'File does not exist or is a directory'}
            
            file_size = os.path.getsize(full_path)
            if file_size > max_size:
                return {'success': False, 'error': f'File too large ({file_size} bytes)'}
            
            # Determine file type
            _, ext = os.path.splitext(full_path.lower())
            
            result = {
                'success': True,
                'file_size': file_size,
                'extension': ext,
                'is_text': ext in ['.txt', '.json', '.xml', '.csv', '.log', '.md', '.py', '.js', '.html', '.css'],
                'is_image': ext in ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff'],
                'content': None
            }
            
            if result['is_text']:
                try:
                    with open(full_path, 'r', encoding='utf-8') as f:
                        content = f.read()
                        # Limit preview to first 10000 characters
                        if len(content) > 10000:
                            result['content'] = content[:10000] + "\n\n... (truncated)"
                        else:
                            result['content'] = content
                except UnicodeDecodeError:
                    result['content'] = "[Binary file - cannot preview]"
            
            return result
            
        except Exception as e:
            return {'success': False, 'error': str(e)}


class CommandExecutor(QThread):
    """Thread for executing system commands safely"""
    
    command_finished = pyqtSignal(str, str)  # stdout, stderr
    command_error = pyqtSignal(str)
    
    def __init__(self, command):
        super().__init__()
        self.command = command
    
    def run(self):
        try:
            process = subprocess.Popen(
                self.command,
                shell=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True
            )
            stdout, stderr = process.communicate()
            self.command_finished.emit(stdout, stderr)
        except Exception as e:
            self.command_error.emit(str(e))

class DragDropWidget(QWidget):
    """Widget that accepts drag and drop for images"""
    
    files_dropped = pyqtSignal(list)
    
    def __init__(self):
        super().__init__()
        self.setAcceptDrops(True)
    
    def dragEnterEvent(self, event):
        if event.mimeData() and event.mimeData().hasUrls():
            event.acceptProposedAction()
    
    def dropEvent(self, event):
        files = []
        if event.mimeData() and event.mimeData().urls():
            for url in event.mimeData().urls():
                if url.isLocalFile():
                    file_path = url.toLocalFile()
                    if file_path.lower().endswith(('.png', '.jpg', '.jpeg', '.gif', '.bmp')):
                        files.append(file_path)
        if files:
            self.files_dropped.emit(files)

class ContextMenuTextEdit(QTextEdit):
    """Custom text edit with right-click context menu for copy/paste"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.customContextMenuRequested.connect(self.show_context_menu)
    
    def show_context_menu(self, position):
        """Show custom context menu with copy and paste options"""
        context_menu = QMenu(self)
        
        # Copy action
        copy_action = QAction("Copy", self)
        copy_action.setShortcut("Ctrl+C")
        copy_action.triggered.connect(self.copy_selected_text)
        context_menu.addAction(copy_action)
        
        # Paste action
        paste_action = QAction("Paste", self)
        paste_action.setShortcut("Ctrl+V")
        paste_action.triggered.connect(self.paste_text)
        context_menu.addAction(paste_action)
        
        # Cut action
        cut_action = QAction("Cut", self)
        cut_action.setShortcut("Ctrl+X")
        cut_action.triggered.connect(self.cut_selected_text)
        context_menu.addAction(cut_action)
        
        # Select All action
        select_all_action = QAction("Select All", self)
        select_all_action.setShortcut("Ctrl+A")
        select_all_action.triggered.connect(self.select_all_text)
        context_menu.addAction(select_all_action)
        
        # Show context menu at cursor position
        context_menu.exec(self.mapToGlobal(position))
    
    def copy_selected_text(self):
        """Copy selected text to clipboard"""
        cursor = self.textCursor()
        if cursor.hasSelection():
            selected_text = cursor.selectedText()
            clipboard = QApplication.clipboard()
            clipboard.setText(selected_text)
    
    def paste_text(self):
        """Paste text from clipboard"""
        clipboard = QApplication.clipboard()
        text = clipboard.text()
        if text:
            cursor = self.textCursor()
            cursor.insertText(text)
    
    def cut_selected_text(self):
        """Cut selected text to clipboard"""
        cursor = self.textCursor()
        if cursor.hasSelection():
            selected_text = cursor.selectedText()
            clipboard = QApplication.clipboard()
            clipboard.setText(selected_text)
            cursor.removeSelectedText()
    
    def select_all_text(self):
        """Select all text in the widget"""
        cursor = self.textCursor()
        cursor.select(cursor.SelectionType.Document)
        self.setTextCursor(cursor)

class TerminalTextEdit(QTextEdit):
    """Custom text edit for terminal functionality"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.parent_terminal = parent
        self.command_buffer = ""
        self.prompt_position = 0
        
        # Ensure we always have a prompt when focused
        self.focusInEvent = self.ensure_prompt_on_focus
    
    def keyPressEvent(self, event):
        if event.key() == Qt.Key.Key_Return or event.key() == Qt.Key.Key_Enter:
            # Get current cursor position
            cursor = self.textCursor()
            cursor.movePosition(cursor.MoveOperation.End)
            
            # Get the current line
            cursor.movePosition(cursor.MoveOperation.StartOfLine, cursor.MoveMode.KeepAnchor)
            current_line = cursor.selectedText()
            
            # Find the command (everything after the last $)
            if '$ ' in current_line:
                command = current_line.split('$ ')[-1]
                if command.strip():
                    # Execute the command
                    if self.parent_terminal:
                        self.parent_terminal.execute_command(command.strip())
                    
                    # Add new prompt
                    cursor.movePosition(cursor.MoveOperation.End)
                    self.setTextCursor(cursor)
                    self.insertPlainText('\n$ ')
                else:
                    # Just add new prompt if no command
                    cursor.movePosition(cursor.MoveOperation.End)
                    self.setTextCursor(cursor)
                    self.insertPlainText('\n$ ')
            else:
                # Add prompt if no $ found
                cursor.movePosition(cursor.MoveOperation.End)
                self.setTextCursor(cursor)
                self.insertPlainText('\n$ ')
        else:
            # Handle normal typing
            super().keyPressEvent(event)
    
    def ensure_prompt_on_focus(self, event):
        """Ensure there's always a prompt when the terminal is focused"""
        # Check if the last character is not a prompt
        cursor = self.textCursor()
        cursor.movePosition(cursor.MoveOperation.End)
        
        # Get the last line
        cursor.movePosition(cursor.MoveOperation.StartOfLine, cursor.MoveMode.KeepAnchor)
        last_line = cursor.selectedText()
        
        # If the last line doesn't end with $, add a prompt
        if not last_line.endswith('$ '):
            cursor.movePosition(cursor.MoveOperation.End)
            self.setTextCursor(cursor)
            self.insertPlainText('\n$ ')
        
        # Call the parent focusInEvent
        super().focusInEvent(event)

class TerminalTab(QWidget):
    """Individual terminal tab widget"""
    
    def __init__(self, tab_name="Terminal"):
        super().__init__()
        self.tab_name = tab_name
        self.process = None
        self.command_history = []
        self.last_command_output = ""
        self.init_ui()
        self.start_terminal()
    
    def init_ui(self):
        """Initialize the terminal UI"""
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        
        # Terminal output display
        self.terminal_output = TerminalTextEdit(self)
        self.terminal_output.setStyleSheet("""
            QTextEdit {
                background-color: #000000;
                color: #ffffff;
                font-family: 'Courier New', monospace;
                font-size: 12px;
                border: none;
                padding: 10px;
            }
        """)
        self.terminal_output.setReadOnly(False)  # Allow typing directly in terminal
        layout.addWidget(self.terminal_output)
        
        # Bottom control area - only screenshot button
        bottom_layout = QHBoxLayout()
        
        # Screenshot button
        screenshot_btn = QPushButton("📷 Screenshot")
        screenshot_btn.setStyleSheet("""
            QPushButton {
                background-color: #ff6b35;
                color: #ffffff;
                border: none;
                padding: 5px 15px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #e55a2b;
            }
        """)
        screenshot_btn.clicked.connect(self.capture_last_command)
        bottom_layout.addWidget(screenshot_btn)
        
        bottom_layout.addStretch()
        layout.addLayout(bottom_layout)
    
    def start_terminal(self):
        """Start the terminal process"""
        try:
            self.process = QProcess()
            self.process.setProcessChannelMode(QProcess.ProcessChannelMode.MergedChannels)
            self.process.readyReadStandardOutput.connect(self.read_output)
            self.process.finished.connect(self.process_finished)
            
            # Start bash shell
            self.process.start("bash", [])
            
            # Clear terminal and show clean initial prompt
            self.terminal_output.clear()
            self.terminal_output.append("$ ")
            
        except Exception as e:
            self.terminal_output.clear()
            self.terminal_output.append(f"Error starting terminal: {str(e)}\n")
            self.terminal_output.append("$ ")
    
    def execute_command(self, command):
        """Execute a command"""
        if command.strip():
            # Store command in history
            self.command_history.append(command.strip())
            
            # Display command in terminal (without extra $ since prompt is already shown)
            self.terminal_output.append(command)
            
            # Send command to process
            if self.process and self.process.state() == QProcess.ProcessState.Running:
                self.process.write(f"{command}\n".encode())
    
    def handle_text_change(self):
        """Handle text changes in the terminal"""
        # This method can be used for additional text processing if needed
        pass
    
    def read_output(self):
        """Read output from the process"""
        if self.process:
            output = self.process.readAllStandardOutput().data().decode()
            self.terminal_output.append(output)
            self.last_command_output = output
            # Auto-scroll to bottom
            scrollbar = self.terminal_output.verticalScrollBar()
            scrollbar.setValue(scrollbar.maximum())
    
    def process_finished(self, exit_code, exit_status):
        """Handle process completion"""
        self.terminal_output.append(f"\nProcess finished with exit code: {exit_code}")
    
    def capture_last_command(self):
        """Capture screenshot of the last command and its output"""
        if not self.command_history:
            QMessageBox.information(self, "No Command", "No commands have been executed yet.")
            return
        
        try:
            # Get the last command and its output
            last_command = self.command_history[-1]
            
            # Use the enhanced screenshot capture method
            from screenshot_annotation_tool import ScreenshotCaptureTool
            screenshot_path = ScreenshotCaptureTool.capture_terminal_output_screenshot(
                self.terminal_output, 
                last_command, 
                self
            )
            
            if screenshot_path:
                # Add the screenshot to the main application's screenshot list
                main_app = self.window()
                if hasattr(main_app, 'add_screenshots'):
                    main_app.add_screenshots([screenshot_path])
                    QMessageBox.information(self, "Success", f"Screenshot captured and saved as: {os.path.basename(screenshot_path)}")
                else:
                    QMessageBox.information(self, "Success", f"Screenshot captured and saved as: {screenshot_path}")
            else:
                QMessageBox.information(self, "Cancelled", "Screenshot capture was cancelled.")
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to capture screenshot: {str(e)}")
    
    def show_screenshot_annotation(self, pixmap, command_name):
        """Show screenshot annotation dialog"""
        dialog = ScreenshotAnnotationDialog(pixmap, command_name, self)
        dialog.exec()
    
    def closeEvent(self, event):
        """Clean up process on close"""
        if self.process:
            self.process.terminate()
            self.process.waitForFinished(3000)  # Wait up to 3 seconds
        super().closeEvent(event)

class AnnotatedLabel(QLabel):
    """Custom label for smooth annotation drawing"""
    
    def __init__(self, pixmap, parent=None):
        super().__init__(parent)
        self.original_pixmap = pixmap
        self.current_pixmap = pixmap.copy()
        self.setPixmap(self.current_pixmap)
        self.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.setMinimumSize(600, 400)
        
        self.drawing = False
        self.last_pos = None
        self.parent_dialog = parent
        
    def mousePressEvent(self, event):
        """Handle mouse press for drawing"""
        if event.button() == Qt.MouseButton.LeftButton:
            self.drawing = True
            # Convert widget coordinates to pixmap coordinates
            pos = self.convert_to_pixmap_coords(event.pos())
            self.last_pos = pos
            # Start drawing immediately
            self.start_drawing(pos)
    
    def mouseMoveEvent(self, event):
        """Handle mouse move for drawing"""
        if self.drawing and self.last_pos and self.parent_dialog:
            # Convert widget coordinates to pixmap coordinates
            pos = self.convert_to_pixmap_coords(event.pos())
            self.continue_drawing(pos)
    
    def mouseReleaseEvent(self, event):
        """Handle mouse release"""
        if event.button() == Qt.MouseButton.LeftButton:
            self.drawing = False
            self.last_pos = None
    
    def convert_to_pixmap_coords(self, widget_pos):
        """Convert widget coordinates to pixmap coordinates"""
        # Get the current pixmap size
        pixmap_size = self.pixmap().size()
        # Get the label size
        label_size = self.size()
        
        # Calculate scaling factors
        scale_x = pixmap_size.width() / label_size.width()
        scale_y = pixmap_size.height() / label_size.height()
        
        # Convert coordinates
        pixmap_x = int(widget_pos.x() * scale_x)
        pixmap_y = int(widget_pos.y() * scale_y)
        
        return QPoint(pixmap_x, pixmap_y)
    
    def start_drawing(self, pos):
        """Start drawing at position"""
        if self.parent_dialog:
            tool = self.parent_dialog.current_tool
            color = self.parent_dialog.current_color
            
            # Create a new pixmap for drawing
            new_pixmap = self.original_pixmap.copy()
            painter = QPainter(new_pixmap)
            painter.setPen(QPen(color, 3))
            
            if tool == "highlight":
                # For highlight, just mark the start point
                painter.drawPoint(pos)
            elif tool == "box":
                # For box, draw a small rectangle at start
                painter.drawRect(QRect(pos.x()-1, pos.y()-1, 2, 2))
            elif tool == "line":
                # For line, mark the start point
                painter.drawPoint(pos)
            
            painter.end()
            self.current_pixmap = new_pixmap
            self.setPixmap(self.current_pixmap)
    
    def continue_drawing(self, pos):
        """Continue drawing to position"""
        if self.parent_dialog and self.last_pos:
            tool = self.parent_dialog.current_tool
            color = self.parent_dialog.current_color
            
            # Create a new pixmap for drawing
            new_pixmap = self.original_pixmap.copy()
            painter = QPainter(new_pixmap)
            painter.setPen(QPen(color, 3))
            
            if tool == "highlight":
                # Draw line from start to current position
                painter.drawLine(self.last_pos, pos)
            elif tool == "box":
                # Draw rectangle from start to current position
                rect = QRect(self.last_pos, pos)
                painter.drawRect(rect)
            elif tool == "line":
                # Draw straight line from start to current position
                painter.drawLine(self.last_pos, pos)
            
            painter.end()
            self.current_pixmap = new_pixmap
            self.setPixmap(self.current_pixmap)
    
    def clear_annotations(self):
        """Clear all annotations"""
        self.current_pixmap = self.original_pixmap.copy()
        self.setPixmap(self.current_pixmap)
    
    def get_annotated_pixmap(self):
        """Get the current pixmap with annotations"""
        return self.current_pixmap

class ScreenshotAnnotationDialog(QDialog):
    """Dialog for annotating screenshots"""
    
    def __init__(self, pixmap, command_name, parent=None):
        super().__init__(parent)
        self.pixmap = pixmap
        self.command_name = command_name
        self.annotations = []
        self.current_tool = "box"  # highlight, box, line - box as default
        self.current_color = QColor(255, 0, 0)  # Red
        self.drawing = False
        self.last_pos = None
        
        self.init_ui()
    
    def init_ui(self):
        """Initialize the annotation dialog UI"""
        self.setWindowTitle(f"Annotate Screenshot - {self.command_name}")
        self.setGeometry(100, 100, 800, 600)
        
        layout = QVBoxLayout(self)
        
        # Toolbar
        toolbar = QHBoxLayout()
        
        # Tool selection
        tool_label = QLabel("Tool:")
        toolbar.addWidget(tool_label)
        
        self.tool_combo = ScrollableComboBox()
        self.tool_combo.addItems(["Highlight", "Box", "Line"])
        self.tool_combo.setCurrentText("Box")  # Set box as default
        self.tool_combo.currentTextChanged.connect(self.change_tool)
        toolbar.addWidget(self.tool_combo)
        
        # Color selection
        color_label = QLabel("Color:")
        toolbar.addWidget(color_label)
        
        self.color_combo = ScrollableComboBox()
        self.color_combo.addItems(["Red", "Green", "Blue", "Yellow", "Orange", "Purple"])
        self.color_combo.currentTextChanged.connect(self.change_color)
        toolbar.addWidget(self.color_combo)
        
        # Clear button
        clear_btn = QPushButton("Clear All")
        clear_btn.clicked.connect(self.clear_annotations)
        toolbar.addWidget(clear_btn)
        
        # Save button
        save_btn = QPushButton("Save")
        save_btn.clicked.connect(self.save_annotated_screenshot)
        toolbar.addWidget(save_btn)
        
        toolbar.addStretch()
        layout.addLayout(toolbar)
        
        # Screenshot display area
        self.screenshot_label = AnnotatedLabel(self.pixmap, self)
        layout.addWidget(self.screenshot_label)
    
    def change_tool(self, tool_name):
        """Change the current annotation tool"""
        self.current_tool = tool_name.lower()
    
    def change_color(self, color_name):
        """Change the current annotation color"""
        color_map = {
            "Red": QColor(255, 0, 0),
            "Green": QColor(0, 255, 0),
            "Blue": QColor(0, 0, 255),
            "Yellow": QColor(255, 255, 0),
            "Orange": QColor(255, 165, 0),
            "Purple": QColor(128, 0, 128)
        }
        self.current_color = color_map.get(color_name, QColor(255, 0, 0))
    
    def clear_annotations(self):
        """Clear all annotations"""
        self.screenshot_label.clear_annotations()
    
    def save_annotated_screenshot(self):
        """Save the annotated screenshot"""
        try:
            # Get the current pixmap with annotations
            annotated_pixmap = self.screenshot_label.get_annotated_pixmap()
            
            # Generate filename
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            filename = f"terminal_screenshot_{self.command_name}_{timestamp}.png"
            
            # Save the screenshot
            if annotated_pixmap.save(filename):
                QMessageBox.information(self, "Success", f"Screenshot saved as: {filename}")
                self.accept()
            else:
                QMessageBox.critical(self, "Error", "Failed to save screenshot")
                
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to save screenshot: {str(e)}")

class EmbeddedTerminalWidget(QWidget):
    """Enhanced embedded terminal widget with tabs and splitting"""
    
    def __init__(self):
        super().__init__()
        self.terminal_tabs = []
        self.current_tab_index = 0
        self.init_ui()
    
    def init_ui(self):
        """Initialize the terminal UI with tabs and splitting"""
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        
        # Control buttons at the top
        control_layout = QHBoxLayout()
        
        # Add new tab button
        add_tab_btn = QPushButton("➕ New Tab")
        add_tab_btn.setStyleSheet("""
            QPushButton {
                background-color: #2e7d32;
                color: #ffffff;
                border: none;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #388e3c;
            }
        """)
        add_tab_btn.clicked.connect(self.add_new_tab)
        control_layout.addWidget(add_tab_btn)
        
        # Split buttons
        split_h_btn = QPushButton("↔ Split Horizontal")
        split_h_btn.setStyleSheet("""
            QPushButton {
                background-color: #1976d2;
                color: #ffffff;
                border: none;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #1565c0;
            }
        """)
        split_h_btn.clicked.connect(lambda: self.split_terminal("horizontal"))
        control_layout.addWidget(split_h_btn)
        
        split_v_btn = QPushButton("↕ Split Vertical")
        split_v_btn.setStyleSheet("""
            QPushButton {
                background-color: #1976d2;
                color: #ffffff;
                border: none;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #1565c0;
            }
        """)
        split_v_btn.clicked.connect(lambda: self.split_terminal("vertical"))
        control_layout.addWidget(split_v_btn)
        
        control_layout.addStretch()
        layout.addLayout(control_layout)
        
        # Tab bar below controls
        self.tab_bar = QTabWidget()
        self.tab_bar.setTabsClosable(True)
        self.tab_bar.tabCloseRequested.connect(self.close_tab)
        self.tab_bar.currentChanged.connect(self.tab_changed)
        layout.addWidget(self.tab_bar)
        
        # Add initial tab
        self.add_new_tab()
    
    def add_new_tab(self):
        """Add a new terminal tab"""
        tab_count = len(self.terminal_tabs) + 1
        tab_name = f"Terminal {tab_count}"
        
        terminal_tab = TerminalTab(tab_name)
        self.terminal_tabs.append(terminal_tab)
        
        self.tab_bar.addTab(terminal_tab, tab_name)
        self.tab_bar.setCurrentWidget(terminal_tab)
        self.current_tab_index = len(self.terminal_tabs) - 1
    
    def close_tab(self, index):
        """Close a terminal tab"""
        if len(self.terminal_tabs) > 1:
            self.tab_bar.removeTab(index)
            self.terminal_tabs.pop(index)
            self.current_tab_index = min(self.current_tab_index, len(self.terminal_tabs) - 1)
        else:
            QMessageBox.information(self, "Cannot Close", "At least one terminal tab must remain open.")
    
    def tab_changed(self, index):
        """Handle tab change"""
        self.current_tab_index = index
    
    def split_terminal(self, direction):
        """Split the terminal (placeholder for future implementation)"""
        QMessageBox.information(self, "Split Feature", 
                              f"Terminal splitting in {direction} direction will be implemented in a future version.")


