    def get_next_placeholder(self):
        """Get the next placeholder value and increment counter"""
        # Use parent's placeholder counter if available, otherwise use local one
        if hasattr(self.parent, 'placeholder_counter'):
            placeholder = f"Placeholder_{self.parent.placeholder_counter}"
            self.parent.placeholder_counter += 1
        else:
            # Initialize parent's placeholder counter if it doesn't exist
            if hasattr(self, 'parent') and self.parent:
                self.parent.placeholder_counter = 1
                placeholder = f"Placeholder_{self.parent.placeholder_counter}"
                self.parent.placeholder_counter += 1
            else:
                # Ensure local placeholder_counter is initialized
                if not hasattr(self, 'placeholder_counter'):
                    self.placeholder_counter = 1
            placeholder = f"Placeholder_{self.placeholder_counter}"
            self.placeholder_counter += 1
        return placeholder
    
    def get_next_script_number(self):
        """Get the next script number and increment counter"""
        # Use parent's script counter if available, otherwise use local one
        if hasattr(self.parent, 'script_counter'):
            self.parent.script_counter += 1
            return self.parent.script_counter
        else:
            self.script_counter += 1
            return self.script_counter
    
    def _is_placeholder_content(self, content):
        """Check if content is a placeholder and extract inner content"""
        if not content:
            return False, ""
        
        # More specific placeholder detection to avoid false positives
        # Only detect as placeholder if it matches specific patterns exactly
        
        # Handle [Placeholder: content] format - most specific
        if content.strip().startswith('[') and 'Placeholder:' in content and content.strip().endswith(']'):
            # Extract content between "Placeholder:" and "]"
            start_idx = content.find('Placeholder:') + len('Placeholder:')
            end_idx = content.rfind(']')
            if start_idx > 0 and end_idx > start_idx:
                inner_content = content[start_idx:end_idx].strip()
                return True, inner_content
        
        # Handle Placeholder_content format
        if content.startswith('Placeholder_'):
            inner_content = content[len('Placeholder_'):]
            return True, inner_content
        
        # Handle _content_placeholder_ format
        if content.startswith('_') and content.endswith('_placeholder'):
            inner_content = content[1:-len('_placeholder')]
            return True, inner_content
        
        # Handle _content_ format (wrapped in underscores)
        if content.strip().startswith('_') and content.strip().endswith('_') and len(content.strip()) > 2:
            inner_content = content.strip()[1:-1]
            return True, inner_content
        
        # Handle specific hardcoded placeholders
        if content.strip() == 'dfd':
            return True, 'dfd'
        
        # If content contains "placeholder" but doesn't match specific patterns,
        # it's likely user content, not a placeholder
        return False, ""
    
    def _parse_mixed_content(self, content):
        """Parse mixed content and separate into content and placeholder parts"""
        if not content:
            return "", ""
        
        # Check if the entire content is a placeholder
        is_placeholder, inner_content = self._is_placeholder_content(content)
        if is_placeholder:
            return "", inner_content
        
        # Handle mixed content on the same line (e.g., "content [Placeholder: placeholder]")
        # First, try to find [Placeholder: ...] pattern in the content
        import re
        placeholder_pattern = r'\[Placeholder:\s*([^\]]+)\]'
        placeholder_matches = re.findall(placeholder_pattern, content)
        
        if placeholder_matches:
            # Extract placeholder content
            placeholder_content = '\n'.join(placeholder_matches)
            
            # Remove placeholder parts from content
            content_without_placeholder = re.sub(placeholder_pattern, '', content).strip()
            
            return content_without_placeholder, placeholder_content
        
        # If no [Placeholder: ...] found, try line-by-line parsing
        lines = content.split('\n')
        content_parts = []
        placeholder_parts = []
        
        for line in lines:
            line = line.strip()
            if not line:
                continue
                
            # Check if this line is a placeholder
            is_line_placeholder, line_inner_content = self._is_placeholder_content(line)
            
            if is_line_placeholder:
                placeholder_parts.append(line_inner_content)
            else:
                content_parts.append(line)
        
        # Join the parts
        final_content = '\n'.join(content_parts) if content_parts else ""
        final_placeholder = '\n'.join(placeholder_parts) if placeholder_parts else ""
        
        return final_content, final_placeholder
    
    def _clean_content_for_display(self, content):
        """Clean content by removing placeholder text for GUI display"""
        if not content:
            return ""
        
        # Remove [Placeholder: ...] patterns from content
        import re
        placeholder_pattern = r'\[Placeholder:\s*[^\]]+\]'
        cleaned_content = re.sub(placeholder_pattern, '', content).strip()
        
        return cleaned_content

    def _extract_placeholder_from_mixed_content(self, content):
        """Extract placeholder content from mixed content for GUI display"""
        if not content:
            return ""
        
        # Handle mixed content on the same line (e.g., "content [Placeholder: placeholder]")
        # First, try to find [Placeholder: ...] pattern in the content
        import re
        placeholder_pattern = r'\[Placeholder:\s*([^\]]+)\]'
        placeholder_matches = re.findall(placeholder_pattern, content)
        
        if placeholder_matches:
            # Extract placeholder content
            placeholder_content = '\n'.join(placeholder_matches)
            return placeholder_content
        
        # If no [Placeholder: ...] found, try line-by-line parsing
        lines = content.split('\n')
        placeholder_parts = []
        
        for line in lines:
            line = line.strip()
            if not line:
                continue
                
            # Check if this line is a placeholder
            is_line_placeholder, line_inner_content = self._is_placeholder_content(line)
            
            if is_line_placeholder and line_inner_content:
                placeholder_parts.append(line_inner_content)
        
        # Join placeholder parts
        return '\n'.join(placeholder_parts) if placeholder_parts else ""

    def get_code_folder_path(self):
        """Get the correct code folder path: tmp/<testcase_name>/code/"""
        try:
            # Get the testcase name from parent
            if hasattr(self.parent, 'get_test_case_title'):
                testcase_name = self.parent.get_test_case_title()
            else:
                # Fallback: try to get from 1.json
                try:
                    import json
                    config_path = os.path.expanduser('~/1.json')
                    if os.path.exists(config_path):
                        with open(config_path, 'r', encoding='utf-8') as f:
                            config = json.load(f)
                            testcase_name = config.get('testcase_title', 'test_case')
                    else:
                        testcase_name = 'test_case'
                except Exception as e:
                    print(f"Error reading testcase name from 1.json: {e}")
                    testcase_name = 'test_case'
            
            # Clean the testcase name for use as directory name
            import re
            # First replace forward slashes with underscores to prevent path splitting
            clean_name = testcase_name.replace('/', '_')
            # Then replace other invalid characters
            clean_name = re.sub(r'[<>:"\\|?*]', '_', clean_name)
            clean_name = clean_name.strip()
            if not clean_name:
                clean_name = "test_case"
            
            # Create the path structure: tmp/<testcase_name>/code/
            project_dir = os.path.join(os.getcwd(), "tmp", clean_name)
            code_dir = os.path.join(project_dir, "code")
            
            # Create directories if they don't exist
            os.makedirs(code_dir, exist_ok=True)
            
            print(f"DEBUG: Created code folder: {code_dir}")
            print(f"DEBUG: Project directory: {project_dir}")
            print(f"DEBUG: Using testcase name: {clean_name}")
            
            return code_dir
            
        except Exception as e:
            print(f"Error creating code folder: {e}")
            # Fallback to tmp directory
            temp_dir = os.path.join(os.getcwd(), "tmp")
            os.makedirs(temp_dir, exist_ok=True)
            return temp_dir
    
