        button_layout.addStretch()
        button_layout.addWidget(cancel_button)
        button_layout.addWidget(ok_button)
        
        layout.addLayout(button_layout)
        
        # Connect button signals
        result = {"description": "", "ok": False, "skip": False}
        
        def on_ok():
            description = input_field.text().strip()
            if not description:
                # If user enters empty text, use a default placeholder
                description = self.get_next_placeholder()
                print(f"DEBUG: Empty description provided, using default: '{description}'")
            result["description"] = description
            result["ok"] = True
            dialog.accept()
        
        def on_skip():
            result["description"] = self.get_next_placeholder()
            result["skip"] = True
            dialog.accept()
        
        def on_cancel():
            dialog.reject()
        
        ok_button.clicked.connect(on_ok)
        skip_button.clicked.connect(on_skip)
        cancel_button.clicked.connect(on_cancel)
        
        # Set focus to input field
        input_field.setFocus()
        
        # Show dialog
        dialog.exec()
        
        return result
    

        
