    def create_placeholder_widget(self, placeholder_text):
        """Create an interactive placeholder widget"""
        widget = QWidget()
        widget.setStyleSheet("""
            QWidget {
                background-color: #3a3a3a;
                border: 1px solid #555555;
                border-radius: 4px;
                padding: 4px;
            }
            QWidget:hover {
                background-color: #404040;
                border: 1px solid #666666;
            }
        """)
        
        layout = QHBoxLayout(widget)
        layout.setContentsMargins(8, 4, 8, 4)
        layout.setSpacing(8)
        
        # Editable text field
        text_edit = QLineEdit(placeholder_text)
        text_edit.setPlaceholderText("Enter placeholder text here...")
        text_edit.setStyleSheet("""
            QLineEdit {
                background-color: #2a2a2a;
                border: 1px solid #ff9800;
                border-radius: 3px;
                padding: 6px;
                color: #ff9800;
                font-style: italic;
                font-size: 12px;
                caret-color: #ff9800;
            }
            QLineEdit:hover {
                border: 2px solid #ffb74d;
                background-color: #3a3a3a;
            }
            
            QLineEdit:focus {
                border: 2px solid #ff9800;
                background-color: #2c2c2c;
            }
        """)
        text_edit.textChanged.connect(lambda: self.update_placeholder_text(widget, text_edit.text()))
        layout.addWidget(text_edit)
        
        # Delete button
        delete_btn = QPushButton("🗑️")
        delete_btn.setMaximumSize(24, 24)
        delete_btn.setStyleSheet("""
            QPushButton {
                background-color: #dc3545;
                color: #ffffff;
                border: none;
                border-radius: 3px;
                font-size: 10px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #c82333;
            }
            QPushButton:pressed {
                background-color: #bd2130;
            }
        """)
        delete_btn.clicked.connect(lambda: self.remove_placeholder_widget(widget))
        layout.addWidget(delete_btn)
        
        return widget
    
    def remove_placeholder_widget(self, widget):
        """Remove a placeholder widget"""
        try:
            # Find the placeholder data for this widget in all sections
            sections = ['section_1', 'section_2', 'section_3', 'section_4', 'section_5', 'section_6', 'section_7']
            
            for section in sections:
                placeholders_attr = f'{section}_placeholders'
                layout_attr = f'{section}_placeholder_layout'
                
                if hasattr(self, placeholders_attr):
                    placeholders = getattr(self, placeholders_attr)
                    placeholders = [p for p in placeholders if p.get("widget") != widget]
                    setattr(self, placeholders_attr, placeholders)
                
                # Remove the widget from the appropriate layout
                if hasattr(self, layout_attr):
                    layout = getattr(self, layout_attr)
                    layout.removeWidget(widget)
                    widget.setParent(None)
                    widget.deleteLater()
                    print(f"Removed placeholder widget from {section}")
                    return
                
        except Exception as e:
            print(f"Error removing placeholder widget: {e}")
    
    def update_placeholder_text(self, widget, new_text):
        """Update placeholder text when edited"""
        try:
            # Update the stored data for all sections
            sections = ['section_1', 'section_2', 'section_3', 'section_4', 'section_5', 'section_6', 'section_7']
            
            for section in sections:
                placeholders_attr = f'{section}_placeholders'
                if hasattr(self, placeholders_attr):
                    placeholders = getattr(self, placeholders_attr)
                    for placeholder in placeholders:
                        if placeholder.get("widget") == widget:
                            placeholder["placeholder"] = new_text
                            print(f"Updated placeholder text for {section}: {new_text}")
                            return
        except Exception as e:
            print(f"Error updating placeholder text: {e}")
    
