    def get_section_1_placeholder_text(self):
        """Get all placeholder text as a single string for storage"""
        if hasattr(self, 'section_1_placeholders') and self.section_1_placeholders:
            return '\n'.join([p["placeholder"] for p in self.section_1_placeholders])
        return ""
    
    def load_section_1_placeholders(self, placeholder_text):
        """Load placeholders from text into the widget system"""
        try:
            # Clear existing widgets
            if hasattr(self, 'section_1_placeholder_layout'):
                # Remove all existing widgets
                while self.section_1_placeholder_layout.count():
                    child = self.section_1_placeholder_layout.takeAt(0)
                    if child.widget():
                        child.widget().setParent(None)
                        child.widget().deleteLater()
            
            # Clear stored data
            if hasattr(self, 'section_1_placeholders'):
                self.section_1_placeholders.clear()
            
            # Load placeholders from text
            if placeholder_text:
                placeholders = placeholder_text.split('\n')
                for placeholder in placeholders:
                    if placeholder.strip():
                        # Create widget for this placeholder
                        placeholder_widget = self.create_placeholder_widget(placeholder.strip())
                        
                        # Add to layout
                        self.section_1_placeholder_layout.addWidget(placeholder_widget)
                        
                        # Store placeholder data
                        if not hasattr(self, 'section_1_placeholders'):
                            self.section_1_placeholders = []
                        
                        placeholder_info = {
                            "placeholder": placeholder.strip(),
                            "image_path": None,
                            "widget": placeholder_widget
                        }
                        self.section_1_placeholders.append(placeholder_info)
                        
        except Exception as e:
            print(f"Error loading section 1 placeholders: {e}")
    

        
