    def get_section_2_placeholder_text(self):
        """Get all placeholder text as a single string for storage"""
        print(f"🔍 DEBUG: get_section_2_placeholder_text called")
        print(f"🔍 DEBUG: section_2_placeholders exists: {hasattr(self, 'section_2_placeholders')}")
        if hasattr(self, 'section_2_placeholders'):
            print(f"🔍 DEBUG: section_2_placeholders content: {self.section_2_placeholders}")
        if hasattr(self, 'section_2_placeholders') and self.section_2_placeholders:
            try:
                # Safely extract placeholder text, filtering out any deleted widgets
                valid_placeholders = []
                for p in self.section_2_placeholders:
                    if isinstance(p, dict) and "placeholder" in p:
                        # Check if the widget still exists and is valid
                        if "widget" in p and p["widget"] and hasattr(p["widget"], 'isVisible'):
                            try:
                                # Test if widget is still accessible
                                p["widget"].isVisible()
                                valid_placeholders.append(p["placeholder"])
                            except:
                                # Widget was deleted, skip it
                                continue
                        elif "placeholder" in p:
                            # If widget is deleted but we have the text, use it
                            valid_placeholders.append(p["placeholder"])
                
                if valid_placeholders:
                    result = '\n'.join(valid_placeholders)
                    print(f"🔍 DEBUG: get_section_2_placeholder_text returning: '{result}'")
                    return result
            except Exception as e:
                print(f"🔍 DEBUG: Error in get_section_2_placeholder_text: {e}")
                # Fallback: try to extract just the placeholder text if available
                try:
                    fallback_placeholders = []
                    for p in self.section_2_placeholders:
                        if isinstance(p, dict) and "placeholder" in p:
                            fallback_placeholders.append(p["placeholder"])
                    if fallback_placeholders:
                        result = '\n'.join(fallback_placeholders)
                        print(f"🔍 DEBUG: get_section_2_placeholder_text fallback returning: '{result}'")
                        return result
                except:
                    pass
        
        print(f"🔍 DEBUG: get_section_2_placeholder_text returning empty string")
        return ""
    
    def load_section_2_placeholders(self, placeholder_text):
        """Load placeholders from text into the widget system"""
