    def get_section_3_placeholder_text(self):
        """Get all placeholder text as a single string for storage"""
        print(f"🔍 DEBUG: get_section_3_placeholder_text called")
        print(f"🔍 DEBUG: section_3_placeholders exists: {hasattr(self, 'section_3_placeholders')}")
        if hasattr(self, 'section_3_placeholders'):
            print(f"🔍 DEBUG: section_3_placeholders content: {self.section_3_placeholders}")
        if hasattr(self, 'section_3_placeholders') and self.section_3_placeholders:
            try:
                # Safely extract placeholder text, filtering out any deleted widgets
                valid_placeholders = []
                for p in self.section_3_placeholders:
                    if isinstance(p, dict) and "placeholder" in p:
                        # Check if the widget still exists and is valid
                        if "widget" in p and p["widget"] and hasattr(p["widget"], 'isVisible'):
                            try:
                                # Test if widget is still accessible
                                p["widget"].isVisible()
                                valid_placeholders.append(p["placeholder"])
                            except:
                                # Widget was deleted, skip it
                                continue
                        elif "placeholder" in p:
                            # If widget is deleted but we have the text, use it
                            valid_placeholders.append(p["placeholder"])
                
                if valid_placeholders:
                    result = '\n'.join(valid_placeholders)
                    print(f"🔍 DEBUG: get_section_3_placeholder_text returning: '{result}'")
                    return result
            except Exception as e:
                print(f"🔍 DEBUG: Error in get_section_3_placeholder_text: {e}")
                # Fallback: try to extract just the placeholder text if available
                try:
                    fallback_placeholders = []
                    for p in self.section_3_placeholders:
                        if isinstance(p, dict) and "placeholder" in p:
                            fallback_placeholders.append(p["placeholder"])
                    if fallback_placeholders:
                        result = '\n'.join(fallback_placeholders)
                        print(f"🔍 DEBUG: get_section_3_placeholder_text fallback returning: '{result}'")
                        return result
                except:
                    pass
        
        print(f"🔍 DEBUG: get_section_3_placeholder_text returning empty string")
        return ""
    
    def load_section_3_placeholders(self, placeholder_text):
        """Load placeholders from text into the widget system"""
        try:
            # Clear existing widgets
            if hasattr(self, 'section_3_placeholder_layout'):
                # Remove all existing widgets
                while self.section_3_placeholder_layout.count():
                    child = self.section_3_placeholder_layout.takeAt(0)
                    if child.widget():
                        child.widget().setParent(None)
                        child.widget().deleteLater()
            
            # Clear stored data
            if hasattr(self, 'section_3_placeholders'):
                self.section_3_placeholders.clear()
            
            # Load placeholders from text
            if placeholder_text:
                placeholders = placeholder_text.split('\n')
                for placeholder in placeholders:
                    if placeholder.strip():
                        # Create widget for this placeholder
                        placeholder_widget = self.create_placeholder_widget(placeholder.strip())
                        
                        # Add to layout
                        self.section_3_placeholder_layout.addWidget(placeholder_widget)
                        
                        # Store placeholder data
                        if not hasattr(self, 'section_3_placeholders'):
                            self.section_3_placeholders = []
                        
                        placeholder_info = {
                            "placeholder": placeholder.strip(),
                            "image_path": None,
                            "widget": placeholder_widget
                        }
                        self.section_3_placeholders.append(placeholder_info)
        
        except Exception as e:
            print(f"Error loading section 3 placeholders: {e}")

