    def remove_section_4_pair_placeholder(self, pair_info, placeholder_info):
        """Remove a placeholder from a specific section 4 pair"""
        try:
            # Remove from pair's placeholders list
            if 'placeholders' in pair_info and placeholder_info in pair_info['placeholders']:
                pair_info['placeholders'].remove(placeholder_info)
            
            # Remove the widget from the layout
            if 'placeholders_layout' in pair_info:
                # Find and remove the widget
                for i in range(pair_info['placeholders_layout'].count()):
                    item = pair_info['placeholders_layout'].itemAt(i)
                    if item and item.widget():
                        widget = item.widget()
                        # Check if this widget contains the placeholder label
                        for child in widget.findChildren(QLabel):
                            if placeholder_info['placeholder'] in child.text():
                                widget.setParent(None)
                                break
            
            print(f"DEBUG: Removed placeholder '{placeholder_info['placeholder']}' from section 4 pair")
                    
        except Exception as e:
            print(f"Error removing section 4 placeholder from pair: {e}")
    
