    def toggle_image_upload(self):
        """Toggle image upload functionality"""
        if self.image_upload_toggle.isChecked():
            self.script_upload_toggle.setChecked(False)
            self.upload_image_btn.setVisible(True)
            self.upload_script_btn.setVisible(False)
            self.upload_info_label.setText("Image upload enabled. Click 'Upload Image' to select an image file.")
        else:
            self.upload_image_btn.setVisible(False)
            self.upload_info_label.setText("Select an upload option above to enable upload functionality")
    
    def toggle_script_upload(self):
        """Toggle script upload functionality"""
        if self.script_upload_toggle.isChecked():
            self.image_upload_toggle.setChecked(False)
            self.upload_image_btn.setVisible(False)
            self.upload_script_btn.setVisible(True)
            self.upload_info_label.setText("Script upload enabled. Click 'Upload Script' to add a Python script with description.")
        else:
            self.upload_script_btn.setVisible(False)
            self.upload_info_label.setText("Select an upload option above to enable upload functionality")
    
    def upload_section_6_image(self):
        """Upload image for Section 6"""
        file_path, _ = QFileDialog.getOpenFileName(
            self.parent,
            "Select Image for Section 6",
            "",
            "Image Files (*.png *.jpg *.jpeg *.bmp *.gif)"
        )
        
        if file_path:
            # Copy file to rawlogs directory to avoid deleting original user file
            original_filename = os.path.basename(file_path)
            rawlogs_dir = self.parent.get_rawlogs_folder_path()
            unique_filename = self.parent.get_unique_filename(rawlogs_dir, original_filename)
            tmp_path = os.path.join(rawlogs_dir, unique_filename)
            
            try:
                import shutil
                shutil.copy2(file_path, tmp_path)
                print(f"Copied {file_path} to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self.parent, "Error", f"Failed to copy file: {e}")
                return
            
            image_info = {
                'path': tmp_path,  # Use the copied file path, not the original
                'filename': original_filename,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create image widget
            image_widget = QWidget()
            image_layout = QHBoxLayout(image_widget)
            
            # Image preview
            image_label = QLabel(f"📷 {image_info['filename']}")
            image_layout.addWidget(image_label)
            
            # Remove button
            image_layout.addWidget(image_info['remove_btn'])
            image_layout.addStretch()
            
            # Connect remove button - use closure to capture image_info by value
            def create_remove_handler(img_info):
                return lambda: self.remove_section_6_image(img_info)
            image_info['remove_btn'].clicked.connect(create_remove_handler(image_info))
            
            # Add to container
            self.section_6_images_list.append(image_info)
            self.section_6_images_layout.addWidget(image_widget)
            
            QMessageBox.information(
                self.parent,
                "Image Uploaded",
                f"Image '{image_info['filename']}' uploaded successfully and will be inserted into the document."
            )
    
    def remove_section_6_image(self, image_info):
        """Remove an image from Section 6"""
        if image_info in self.section_6_images_list:
            # Delete the file from filesystem
            try:
                # Use absolute path for file deletion
                file_path = image_info.get('absolute_path', image_info['path'])
                if os.path.exists(file_path):
                    os.remove(file_path)
                    print(f"Deleted image file: {file_path}")
                else:
                    # Fallback to relative path if absolute path doesn't exist
                    if os.path.exists(image_info['path']):
                        os.remove(image_info['path'])
                        print(f"Deleted image file: {image_info['path']}")
            except Exception as e:
                print(f"Error deleting image file {image_info.get('absolute_path', image_info['path'])}: {e}")

            # Remove from list
            self.section_6_images_list.remove(image_info)
            # Remove the widget from layout
            for i in range(self.section_6_images_layout.count()):
                widget = self.section_6_images_layout.itemAt(i).widget()
                if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                    self.section_6_images_layout.removeWidget(widget)
                    widget.setParent(None)
                    widget.deleteLater()
                    print(f"✅ Removed section 6 image widget from UI: {image_info.get('filename', 'Unknown')}")
                    break
    
