    def upload_section_6_script(self):
        """Upload script for Section 6 with description input"""
        # Show custom dialog with skip button for Section 6 (only placeholder)
        result = self.show_placeholder_dialog(self.parent)
        
        if result["ok"] or result["skip"]:
            placeholder = result["description"]
            # Use the preconditions text as the subheading
            subheading = self.section_6_edit.toPlainText().strip() if self.section_6_edit else "Preconditions"
            
            # Now show file picker for the script
            file_path, _ = QFileDialog.getOpenFileName(
                self.parent,
                "Select Python Script for Section 6",
                "",
                "Python Files (*.py)"
            )
            
            if file_path:
                # Validate file extension
                if not file_path.lower().endswith('.py'):
                    QMessageBox.warning(self.parent, "Invalid File", "Please select a Python script (.py file)")
                    return
                
                # Copy file to code directory with original filename
                original_filename = os.path.basename(file_path)
                
                # Save to correct code folder: tmp/<testcase_name>/code/
                code_dir = self.parent.get_code_folder_path()
                script_filename = self.parent.get_unique_filename(code_dir, original_filename)
                script_path = os.path.join(code_dir, script_filename)
                
                # Copy the file to code directory
                import shutil
                shutil.copy2(file_path, script_path)
                
                # Generate script name with incremental numbering
                script_number = self.get_next_script_number()
                script_name = f"script{script_number}.py"
                
                script_info = {
                    'path': script_path,
                    'filename': script_filename,
                    'original_filename': original_filename,  # Keep original name for display
                    'description': placeholder,
                    'subheading': subheading,
                    'script_name': script_name,
                    'is_pasted': False,
                    'remove_btn': QPushButton("🗑️ Remove")
                }
                
                # Create script widget
                script_widget = QWidget()
                script_layout = QVBoxLayout(script_widget)
                
                # Script info
                info_layout = QHBoxLayout()
                display_name = script_info.get('original_filename', script_info['filename'])
                if script_info.get('is_pasted', False):
                    display_name += " (Pasted)"
                info_layout.addWidget(QLabel(f"📄 {display_name}"))
                info_layout.addStretch()
                
                # Execute button
                execute_btn = QPushButton("▶ Execute")
                execute_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #007bff;
                        color: white;
                        border: none;
                        border-radius: 3px;
                        padding: 4px 8px;
                        font-weight: bold;
                    }
                    QPushButton:hover {
                        background-color: #0056b3;
                    }
                    QPushButton:pressed {
                        background-color: #004085;
                    }
                """)
                execute_btn.clicked.connect(lambda: self.execute_section_script(6, script_info))
                info_layout.addWidget(execute_btn)
                
                # Remove button
                script_layout.addLayout(info_layout)
                script_layout.addWidget(script_info['remove_btn'])
                # Use closure to capture script_info by value
                def create_remove_handler(script_info_param):
                    return lambda: self.remove_section_6_script(script_info_param)
                script_info['remove_btn'].clicked.connect(create_remove_handler(script_info))
                
                # Description display
                desc_label = QLabel(f"Description: {placeholder}")
                desc_label.setStyleSheet("color: #666; font-style: italic;")
                script_layout.addWidget(desc_label)
                
                # Subheading display
                subheading_label = QLabel(f"Subheading: {subheading}")
                subheading_label.setStyleSheet("color: #666; font-style: italic;")
                script_layout.addWidget(subheading_label)
                
                # Add to container
                self.section_6_scripts_list.append(script_info)
                self.section_6_scripts_layout.addWidget(script_widget)
                
                # Add to Essential Questions
                if hasattr(self.parent, 'add_essential_question_with_script'):
                    self.parent.add_essential_question_with_script(subheading, original_filename, placeholder)
                
                # Trigger automation mapping for Section 6
                script_id = str(uuid.uuid4())
                placeholder_name = f"script_{original_filename.replace('.py', '')}"
                
                # Add to automation mapper through parent
                if hasattr(self.parent, 'automation_mapper'):
                    self.parent.automation_mapper.add_script_mapping(
                        script_id, 
                        original_filename, 
                        placeholder_name, 
                        "Section 6 Preconditions", 
                        subheading
                    )
                    
                    QMessageBox.information(
                        self.parent,
                        "Script Uploaded",
                        f"Script '{original_filename}' uploaded and copied to tmp directory.\n\n"
                        f"• Document Placeholder: {placeholder}\n"
                        f"• Subheading: {subheading}\n"
                        f"• Script Name: {script_name}\n\n"
                        f"Essential Questions have been automatically updated to include this script."
                    )
    
    def remove_section_6_script(self, script_info):
        """Remove a script from Section 6 - handles UI, file deletion, and JSON cleanup"""
        try:
            # Check if script exists in the list
            if hasattr(self, 'section_6_scripts_list') and script_info in self.section_6_scripts_list:
                # 1. Delete the file from filesystem
                try:
                    # Use absolute path for file deletion
                    file_path = script_info.get('absolute_path', script_info['path'])
                    if os.path.exists(file_path):
                        os.remove(file_path)
                        print(f"✓ Deleted file: {file_path}")
                    else:
                        # Fallback to relative path if absolute path doesn't exist
                        if os.path.exists(script_info['path']):
                            os.remove(script_info['path'])
                            print(f"✓ Deleted file: {script_info['path']}")
                        else:
                            print(f"⚠ File not found: {file_path}")
                except Exception as e:
                    print(f"✗ Error deleting file {file_path}: {e}")
                
                # 2. Remove from UI list
                self.section_6_scripts_list.remove(script_info)
                print(f"✓ Removed from section_6_scripts_list")
                
                # 3. Remove widget from UI layout
                if hasattr(self, 'section_6_scripts_layout'):
                    for i in range(self.section_6_scripts_layout.count()):
                        widget = self.section_6_scripts_layout.itemAt(i).widget()
                        if widget and widget.findChild(QLabel):
                            label = widget.findChild(QLabel)
                            if label and (script_info['filename'] in label.text() or 
                                        script_info.get('original_filename', '') in label.text()):
                                widget.setParent(None)
                                widget.deleteLater()
                                print(f"✓ Removed widget from UI")
                                break
                
                # 4. Remove corresponding essential question if it exists
                script_name = script_info.get('script_name', '')
                if script_name and hasattr(self.parent, 'essential_questions'):
                    for question_info in self.parent.essential_questions[:]:
                        if (question_info.get("script_name_edit") and 
                            question_info["script_name_edit"].text() == script_name):
                            # Remove the essential question widget
                            if hasattr(self.parent, 'questions_container'):
                                self.parent.questions_container.removeWidget(question_info["widget"])
                                question_info["widget"].deleteLater()
                            self.parent.essential_questions.remove(question_info)
                            # Renumber remaining questions
                            if hasattr(self.parent, 'renumber_essential_questions'):
                                self.parent.renumber_essential_questions()
                            print(f"✓ Removed essential question: {script_name}")
                            break
                
                # 5. Update JSON data if parent has the method
                if hasattr(self.parent, 'update_json_data'):
                    try:
                        self.parent.update_json_data()
                        print(f"✓ Updated JSON data")
                    except Exception as e:
                        print(f"⚠ Error updating JSON data: {e}")
                
                # 6. Show success message
                display_name = script_info.get('original_filename', script_info['filename'])
                QMessageBox.information(
                    self.parent,
                    "Script Removed",
                    f"Script '{display_name}' has been removed successfully.\n\n"
                    f"✓ File deleted from filesystem\n"
                    f"✓ Removed from UI\n"
                    f"✓ Removed from JSON data\n"
                    f"✓ Removed essential question"
                )
            else:
                print(f"⚠ Script not found in section_6_scripts_list")
                QMessageBox.warning(
                    self.parent,
                    "Script Not Found",
                    f"Script '{script_info.get('filename', 'Unknown')}' was not found in the list."
                )
                
        except Exception as e:
            print(f"✗ Error in remove_section_6_script: {e}")
            QMessageBox.critical(
                self.parent,
                "Error",
                f"Failed to remove script: {str(e)}"
            )
    
    def add_section_6_note(self):
        """Add a note for Section 6"""
        # Create a dialog to get the note text
        note_text, ok = QInputDialog.getMultiLineText(
            self.parent,
            "Add Note",
            "Enter your note:",
            ""
        )
        
        if ok and note_text.strip():
            # Create note info
            note_info = {
                "id": str(len(self.section_6_notes_list) + 1),
                "text": note_text.strip(),
                "timestamp": QDateTime.currentDateTime().toString("yyyy-MM-dd hh:mm:ss")
            }
            
            # Add to section 6 notes list
            self.section_6_notes_list.append(note_info)
            
            # Create and display the note widget
            self.create_section_6_note_widget(note_info)
            
            print(f"DEBUG: Added note to Section 6: {note_info}")
    
    def create_section_6_note_widget(self, note_info):
        """Create a note widget for Section 6 with edit and remove buttons"""
        # Create note widget container
        note_widget = QWidget()
        note_widget.setStyleSheet("""
            QWidget {
                background-color: #f8f9fa;
                border: 1px solid #dee2e6;
                border-radius: 4px;
                margin: 2px 0px;
                padding: 8px;
            }
        """)
        
        note_layout = QHBoxLayout(note_widget)
        note_layout.setContentsMargins(8, 8, 8, 8)
        
        # Note text with red "Note:" prefix and bold description
        note_text_widget = QLabel()
        note_text_widget.setWordWrap(True)
        note_text_widget.setStyleSheet("""
            QLabel {
                color: #000000;
                font-size: 12px;
                line-height: 1.4;
            }
        """)
        
        # Format the note text with red "Note:" prefix and bold description
        formatted_text = f'<span style="color: #dc3545; font-weight: bold;">Note:</span> <span style="font-weight: bold;">{note_info["text"]}</span>'
        note_text_widget.setText(formatted_text)
        note_text_widget.setTextFormat(Qt.TextFormat.RichText)
        
        note_layout.addWidget(note_text_widget, 1)
        
        # Button container
        button_layout = QHBoxLayout()
        button_layout.setSpacing(4)
        
        # Edit button
        edit_btn = QPushButton("✏️")
        edit_btn.setMaximumSize(30, 30)
        edit_btn.setStyleSheet("""
            QPushButton {
                background-color: #ffc107;
                color: #000000;
                border: none;
                border-radius: 4px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #e0a800;
            }
        """)
        edit_btn.setToolTip("Edit Note")
        edit_btn.clicked.connect(lambda: self.edit_section_6_note(note_info, note_widget))
        
        # Remove button
        remove_btn = QPushButton("🗑️")
        remove_btn.setMaximumSize(30, 30)
        remove_btn.setStyleSheet("""
            QPushButton {
                background-color: #dc3545;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #c82333;
            }
        """)
        remove_btn.setToolTip("Remove Note")
        remove_btn.clicked.connect(lambda: self.remove_section_6_note(note_info, note_widget))
        
        button_layout.addWidget(edit_btn)
        button_layout.addWidget(remove_btn)
        note_layout.addLayout(button_layout)
        
        # Store reference to the widget in note_info
        note_info['widget'] = note_widget
        
        # Add to Section 6 notes container
        self.section_6_notes_layout.addWidget(note_widget)
    
    def edit_section_6_note(self, note_info, note_widget):
        """Edit an existing Section 6 note"""
        # Get current note text
        current_text = note_info['text']
        
        # Create edit dialog
        new_text, ok = QInputDialog.getMultiLineText(
            self.parent,
            "Edit Note",
            "Edit your note:",
            current_text
        )
        
        if ok and new_text.strip():
            # Update note info
            note_info['text'] = new_text.strip()
            note_info['timestamp'] = QDateTime.currentDateTime().toString("yyyy-MM-dd hh:mm:ss")
            
            # Update the widget display
            note_text_widget = note_widget.findChild(QLabel)
            if note_text_widget:
                formatted_text = f'<span style="color: #dc3545; font-weight: bold;">Note:</span> <span style="font-weight: bold;">{new_text.strip()}</span>'
                note_text_widget.setText(formatted_text)
            
            print(f"DEBUG: Updated Section 6 note: {note_info}")
    
    def remove_section_6_note(self, note_info, note_widget):
        """Remove a Section 6 note"""
        # Remove from notes list
        self.section_6_notes_list = [n for n in self.section_6_notes_list if n['id'] != note_info['id']]
        
        # Remove widget from layout
        note_widget.setParent(None)
        note_widget.deleteLater()
        
        print(f"DEBUG: Removed Section 6 note: {note_info}")
    
