    def toggle_section_2_image_upload(self):
        """Toggle image upload functionality for Section 2"""
        if self.section_2_image_upload_toggle.isChecked():
            self.section_2_script_upload_toggle.setChecked(False)
            self.section_2_upload_image_btn.setVisible(True)
            self.section_2_upload_script_btn.setVisible(False)
