    def remove_section_1_script(self, script_info):
        """Remove a script from Section 1 - handles UI, file deletion, and JSON cleanup"""
        try:
            # Check if script exists in the list
            if hasattr(self, 'section_1_scripts_list') and script_info in self.section_1_scripts_list:
                # 1. Delete the file from filesystem
                try:
                    file_path = script_info.get('path', '')
                    if file_path and os.path.exists(file_path):
                        os.remove(file_path)
                        print(f"✓ Deleted file: {file_path}")
                    else:
                        print(f"⚠ File not found or no path: {file_path}")
                except Exception as e:
                    print(f"✗ Error deleting file {file_path}: {e}")
                
                # 2. Remove from UI list
                self.section_1_scripts_list.remove(script_info)
                print(f"✓ Removed from section_1_scripts_list")
                
                # 3. Remove widget from UI layout
                if hasattr(self, 'section_1_scripts_layout'):
                    for i in range(self.section_1_scripts_layout.count()):
                        widget = self.section_1_scripts_layout.itemAt(i).widget()
                        if widget and widget.findChild(QLabel):
                            label = widget.findChild(QLabel)
                            if label and (script_info['filename'] in label.text() or 
                                        script_info.get('original_filename', '') in label.text()):
                                widget.setParent(None)
                                widget.deleteLater()
                                print(f"✓ Removed widget from UI")
                                break
                
                # 4. Remove corresponding essential question if it exists
                script_name = script_info.get('script_name', '')
                if script_name and hasattr(self.parent, 'essential_questions'):
                    for question_info in self.parent.essential_questions[:]:
                        if (question_info.get("script_name_edit") and 
                            question_info["script_name_edit"].text() == script_name):
                            # Remove the essential question widget
                            if hasattr(self.parent, 'questions_container'):
                                self.parent.questions_container.removeWidget(question_info["widget"])
                                question_info["widget"].deleteLater()
                            self.parent.essential_questions.remove(question_info)
                            # Renumber remaining questions
                            if hasattr(self.parent, 'renumber_essential_questions'):
                                self.parent.renumber_essential_questions()
                            print(f"✓ Removed essential question: {script_name}")
                            break
                
                # 5. Update JSON data if parent has the method
                if hasattr(self.parent, 'update_json_data'):
                    try:
                        self.parent.update_json_data()
                        print(f"✓ Updated JSON data")
                    except Exception as e:
                        print(f"⚠ Error updating JSON data: {e}")
                
                # 6. Show success message
                display_name = script_info.get('original_filename', script_info['filename'])
                QMessageBox.information(
                    self.parent,
                    "Script Removed",
                    f"Script '{display_name}' has been removed successfully.\n\n"
                    f"✓ File deleted from filesystem\n"
                    f"✓ Removed from UI\n"
                    f"✓ Removed from JSON data\n"
                    f"✓ Removed essential question"
                )
            else:
                print(f"⚠ Script not found in section_1_scripts_list")
                QMessageBox.warning(
                    self.parent,
                    "Script Not Found",
                    f"Script '{script_info.get('filename', 'Unknown')}' was not found in the list."
                )
                
        except Exception as e:
            print(f"✗ Error in remove_section_1_script: {e}")
            QMessageBox.critical(
                self.parent,
                "Error",
                f"Failed to remove script: {str(e)}"
            )
    
