    def upload_section_4_image(self, pair_info):
        """Upload image for Section 4"""
        file_path, _ = QFileDialog.getOpenFileName(
            self.parent, "Select Image", "", "Image Files (*.png *.jpg *.jpeg *.gif *.bmp)"
        )
        
        if file_path:
            # Validate file extension
            valid_extensions = ['.png', '.jpg', '.jpeg', '.gif', '.bmp']
            if not any(file_path.lower().endswith(ext) for ext in valid_extensions):
                QMessageBox.warning(self.parent, "Invalid File", "Please select a valid image file")
                return
            
            # Copy file to rawlogs directory to avoid deleting original user file
            original_filename = os.path.basename(file_path)
            rawlogs_dir = self.parent.get_rawlogs_folder_path()
            unique_filename = self.parent.get_unique_filename(rawlogs_dir, original_filename)
            tmp_path = os.path.join(rawlogs_dir, unique_filename)
            
            try:
                import shutil
                shutil.copy2(file_path, tmp_path)
                print(f"Copied {file_path} to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self.parent, "Error", f"Failed to copy file: {e}")
                return
            
            image_info = {
                'path': tmp_path,  # Use the copied file path, not the original
                'filename': original_filename,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create image widget
            image_widget = QWidget()
            image_layout = QHBoxLayout(image_widget)
            
            # Filename label
            filename_label = QLabel(f"📷 {image_info['filename']}")
            filename_label.setStyleSheet("color: #17a2b8; font-weight: bold;")
            image_layout.addWidget(filename_label)
            
            # Remove button
            image_info['remove_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            image_info['remove_btn'].clicked.connect(lambda: self.remove_section_4_image(pair_info, image_info))
            image_layout.addWidget(image_info['remove_btn'])
            
            image_layout.addStretch()
            
            # Add to container
            if 'images_list' not in pair_info:
                pair_info['images_list'] = []
            pair_info['images_list'].append(image_info)
            pair_info['images_layout'].addWidget(image_widget)
            
            # Also add to section's image list for export
            self.section_4_images_list.append(image_info)
            
            QMessageBox.information(
                self.parent,
                "Image Uploaded",
                f"Image '{image_info['filename']}' uploaded successfully."
            )
    
    def remove_section_4_image(self, pair_info, image_info):
        """Remove an image from Section 4"""
        if 'images_list' in pair_info and image_info in pair_info['images_list']:
            pair_info['images_list'].remove(image_info)
            # Remove the widget from layout
            for i in range(pair_info['images_layout'].count()):
                widget = pair_info['images_layout'].itemAt(i).widget()
                if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                    pair_info['images_layout'].removeWidget(widget)
                    widget.setParent(None)
                    widget.deleteLater()
                    print(f"✅ Removed section 4 image widget from UI: {image_info.get('filename', 'Unknown')}")
                    break
            
            # Also remove from section's image list
            if image_info in self.section_4_images_list:
                self.section_4_images_list.remove(image_info)
    
    def upload_section_4_script(self, pair_info):
        """Upload script for Section 4"""
        # Show custom dialog with skip button
        result = self.show_placeholder_dialog(self.parent)
        
        if not result["ok"] and not result["skip"]:
            return
        
        placeholder = result["description"]
        print(f"🔍 DEBUG Section 4: Got placeholder from dialog: '{placeholder}'")
        # Use the subheading text as the question name
        subheading = pair_info['text_edit'].toPlainText().strip() if pair_info.get('text_edit') else "DUT Confirmation Details"
        print(f"🔍 DEBUG Section 4: Subheading: '{subheading}'")
        
        file_path, _ = QFileDialog.getOpenFileName(
            self.parent, "Select Python Script", "", "Python Files (*.py)"
        )
        
        if file_path:
            # Validate file extension
            if not file_path.lower().endswith('.py'):
                QMessageBox.warning(self.parent, "Invalid File", "Please select a Python script (.py file)")
                return
            
            # Copy file to correct code folder: tmp/<testcase_name>/code/ with original filename
            original_filename = os.path.basename(file_path)
            
            # Use the correct code folder path
            code_dir = self.parent.get_code_folder_path()
            unique_filename = self.parent.get_unique_filename(code_dir, original_filename)
            tmp_path = os.path.join(code_dir, unique_filename)
            
            try:
                shutil.copy2(file_path, tmp_path)
                print(f"Copied {file_path} to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self.parent, "Error", f"Failed to copy file: {e}")
                return
            
            # Generate script name with incremental numbering
            script_number = self.get_next_script_number()
            script_name = f"script{script_number}.py"
            
            script_info = {
                'path': tmp_path,
                'filename': unique_filename,
                'original_filename': original_filename,
                'description': placeholder,
                'placeholder': placeholder,  # Store placeholder separately for document generation
                'subheading': subheading,
                'script_name': script_name,
                'is_pasted': False,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            print(f"🔍 DEBUG Section 4: Created script_info with placeholder: '{placeholder}'")
            
            # Create script widget
            script_widget = QWidget()
            script_layout = QHBoxLayout(script_widget)
            
            # Filename label
            filename_label = QLabel(f"📄 {original_filename}")
            filename_label.setStyleSheet("color: #28a745; font-weight: bold;")
            script_layout.addWidget(filename_label)
            
            # Remove button
            script_info['remove_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            script_info['remove_btn'].clicked.connect(lambda: self.remove_section_4_script(pair_info, script_info))
            script_layout.addWidget(script_info['remove_btn'])
            
            script_layout.addStretch()
            
            # Add to container
            if 'upload_scripts_list' not in pair_info:
                pair_info['upload_scripts_list'] = []
            pair_info['upload_scripts_list'].append(script_info)
            pair_info['upload_scripts_layout'].addWidget(script_widget)
            
            # Add to Essential Questions
            if hasattr(self.parent, 'add_essential_question_with_script'):
                self.parent.add_essential_question_with_script(subheading, original_filename, placeholder)
            
            # Trigger automation mapping for Sections 1-7
            script_id = str(uuid.uuid4())
            placeholder_name = f"script_{original_filename.replace('.py', '')}"
            
            # Add to automation mapper through parent
            if hasattr(self.parent, 'automation_mapper'):
                self.parent.automation_mapper.add_script_mapping(
                    script_id, 
                    original_filename, 
                    placeholder_name, 
                    "Section 4 DUT Confirmation", 
                    subheading
                )
            
            QMessageBox.information(
                self.parent,
                "Script Uploaded",
                f"Script '{original_filename}' uploaded and copied to tmp directory.\n\n"
                f"• Document Placeholder: {placeholder}\n"
                f"• Subheading: {subheading}\n"
                f"• Script Name: {script_name}\n\n"
                f"Essential Questions have been automatically updated to include this script."
            )
    
    def remove_section_4_script(self, pair_info, script_info):
        """Remove a script from Section 4"""
        if 'upload_scripts_list' in pair_info and script_info in pair_info['upload_scripts_list']:
            # Delete the file from tmp directory
            try:
                if os.path.exists(script_info['path']):
                    os.remove(script_info['path'])
                    print(f"Deleted file: {script_info['path']}")
            except Exception as e:
                print(f"Error deleting file {script_info['path']}: {e}")
            
            # Remove from list
            pair_info['upload_scripts_list'].remove(script_info)
            
            # Remove the widget from layout
            for i in range(pair_info['upload_scripts_layout'].count()):
                widget = pair_info['upload_scripts_layout'].itemAt(i).widget()
                if widget and widget.findChild(QLabel):
                    label = widget.findChild(QLabel)
                    if label and (script_info['filename'] in label.text() or 
                                script_info.get('original_filename', '') in label.text()):
                        widget.setParent(None)
                        break
            
            # Remove corresponding essential question if it exists
            script_name = script_info.get('script_name', '')
            if script_name and hasattr(self.parent, 'essential_questions'):
                for question_info in self.parent.essential_questions[:]:
                    if (question_info.get("script_name_edit") and 
                        question_info["script_name_edit"].text() == script_name):
                        # Remove the essential question
                        self.parent.questions_container.removeWidget(question_info["widget"])
                        question_info["widget"].deleteLater()
                        self.parent.essential_questions.remove(question_info)
                        # Renumber remaining questions
                        self.parent.renumber_essential_questions()
                        break
            
            # Show success message
            display_name = script_info.get('original_filename', script_info['filename'])
            QMessageBox.information(
                self.parent,
                "Script Removed",
                f"Script '{display_name}' has been removed and the file deleted.\n\n"
                f"Corresponding essential question has also been removed."
            )
    
    def paste_section_4_script(self, pair_info):
        """Paste script for Section 4 with textarea input"""
        # Create a dialog for pasting script content
        dialog = QDialog(self.parent)
        dialog.setWindowTitle("Paste Python Script")
        dialog.setGeometry(400, 300, 600, 400)
        
        layout = QVBoxLayout(dialog)
        
        # Instructions label
        instructions = QLabel("Paste your Python script code below:")
        instructions.setStyleSheet("font-weight: bold; margin-bottom: 10px;")
        layout.addWidget(instructions)
        
        # Textarea for pasting script
        script_textarea = ContextMenuTextEdit()
        script_textarea.setPlaceholderText("Paste your Python script here...\n\nExample:\ndef hello_world():\n    print('Hello, World!')\n\nhello_world()")
        script_textarea.setStyleSheet("""
            QTextEdit {
                background-color: #2b2b2b;
                color: #ffffff;
                border: 1px solid #444444;
                border-radius: 4px;
                padding: 8px;
                font-family: 'Consolas', 'Monaco', monospace;
                font-size: 12px;
            }
        """)
        layout.addWidget(script_textarea)
        
        # Button layout
        button_layout = QHBoxLayout()
        
        # Cancel button
        cancel_btn = QPushButton("Cancel")
        cancel_btn.setStyleSheet("""
            QPushButton {
                background-color: #6c757d;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #5a6268;
            }
        """)
        cancel_btn.clicked.connect(dialog.reject)
        button_layout.addWidget(cancel_btn)
        
        button_layout.addStretch()
        
        # OK button
        ok_btn = QPushButton("OK")
        ok_btn.setStyleSheet("""
            QPushButton {
                background-color: #28a745;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #218838;
            }
        """)
        ok_btn.clicked.connect(dialog.accept)
        button_layout.addWidget(ok_btn)
        
        layout.addLayout(button_layout)
        
        if dialog.exec() == QDialog.DialogCode.Accepted:
            script_content = script_textarea.toPlainText().strip()
            
            if not script_content:
                QMessageBox.warning(self.parent, "Empty Script", "Please paste some script content.")
                return
            
            # Clean up the script content
            script_content = textwrap.dedent(script_content)
            script_content = script_content.rstrip()
            script_content = script_content.replace('\t', '    ')
            
            # Save to correct code folder: tmp/<testcase_name>/code/
            unique_id = str(uuid.uuid4())[:8]
            filename = f"pasted_script_{unique_id}.py"
            
            # Use the correct code folder path
            code_dir = self.parent.get_code_folder_path()
            tmp_path = os.path.join(code_dir, filename)
            
            try:
                with open(tmp_path, 'w', encoding='utf-8') as f:
                    f.write(script_content)
                print(f"Saved pasted script to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self.parent, "Error", f"Failed to save script: {e}")
                return
            
            # Show custom dialog with skip button
            result = self.show_placeholder_dialog(self.parent)
            
            if not result["ok"] and not result["skip"]:
                # Clean up the temporary file if user cancels
                try:
                    if os.path.exists(tmp_path):
                        os.remove(tmp_path)
                except:
                    pass
                return
            
            placeholder = result["description"]
            # Use the subheading text as the question name
            subheading = pair_info['text_edit'].toPlainText().strip() if pair_info.get('text_edit') else "DUT Confirmation Details"
            
            # Generate script name with incremental numbering
            script_number = self.get_next_script_number()
            script_name = f"script{script_number}.py"
            
            script_info = {
                'path': tmp_path,
                'filename': filename,
                'description': placeholder,
                'subheading': subheading,
                'script_name': script_name,
                'is_pasted': True,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create script widget
            script_widget = QWidget()
            script_layout = QHBoxLayout(script_widget)
            
            # Filename label
            filename_label = QLabel(f"📄 {filename} (Pasted)")
            filename_label.setStyleSheet("color: #007bff; font-weight: bold;")
            script_layout.addWidget(filename_label)
            
            # Remove button
            script_info['remove_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            script_info['remove_btn'].clicked.connect(lambda: self.remove_section_4_script(pair_info, script_info))
            script_layout.addWidget(script_info['remove_btn'])
            
            script_layout.addStretch()
            
            # Add to container
            if 'upload_scripts_list' not in pair_info:
                pair_info['upload_scripts_list'] = []
            pair_info['upload_scripts_list'].append(script_info)
            pair_info['upload_scripts_layout'].addWidget(script_widget)
            
            # Add to Essential Questions
            if hasattr(self.parent, 'add_essential_question_with_script'):
                self.parent.add_essential_question_with_script(subheading, filename, placeholder)
            
            QMessageBox.information(
                self.parent,
                "Script Pasted",
                f"Script '{filename}' has been pasted, saved to tmp directory.\n\n"
                f"• Document Placeholder: {placeholder}\n"
                f"• Subheading: {subheading}\n"
                f"• Script Name: {script_name}\n\n"
                f"Essential Questions have been automatically updated to include this script."
            )
    

    
