    def add_interface_row(self):
        """Add a new row to the interface table"""
        if hasattr(self, 'interface_table'):
            row_position = self.interface_table.rowCount()
            self.interface_table.insertRow(row_position)
            
            # Add empty items to the new row
            for col in range(4):
                self.interface_table.setItem(row_position, col, QTableWidgetItem(""))
    def remove_interface_row(self):
        """Remove selected row from the interface table"""
        if hasattr(self, 'interface_table'):
            current_row = self.interface_table.currentRow()
            if current_row >= 0:
                self.interface_table.removeRow(current_row)
                
    def refresh_interfaces(self):
        """Refresh interface table from system"""
        if hasattr(self, 'interface_table'):
            # Clear existing data - no hardcoded values
            self.interface_table.setRowCount(0)
                    
    def add_section_script(self, section_number):
        """Add Python script to a specific section"""
        file_path, _ = QFileDialog.getOpenFileName(
            self.parent,
            f"Select Python Script for Section {section_number}",
            "",
            "Python Files (*.py)"
        )
        
        if file_path:
            # Validate file extension
            if not file_path.lower().endswith('.py'):
                QMessageBox.warning(self.parent, "Invalid File", "Please select a Python script (.py file)")
                return
            
            script_info = {
                'path': file_path,
                'filename': os.path.basename(file_path),
                'description': '',  # Add description field
                'placeholder': '',  # Store placeholder separately for export
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create script widget
            script_widget = QWidget()
            script_layout = QHBoxLayout(script_widget)
            
            # Script preview
            script_label = QLabel(f"📄 {script_info['filename']}")
            script_layout.addWidget(script_label)
            
            # Execute button
            execute_btn = QPushButton("▶ Execute")
            execute_btn.setStyleSheet("""
                QPushButton {
                    background-color: #007bff;
                    color: white;
                    border: none;
                    border-radius: 3px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #0056b3;
                }
                QPushButton:pressed {
                    background-color: #004085;
                }
            """)
            execute_btn.clicked.connect(lambda: self.execute_section_script(section_number, script_info))
            script_layout.addWidget(execute_btn)
            
            # Remove button
            script_layout.addWidget(script_info['remove_btn'])
            script_layout.addStretch()
            
            # Connect remove button
            script_info['remove_btn'].clicked.connect(lambda: self.remove_section_script(section_number, script_info))
            
            # Get the appropriate container and list for the section
            if section_number == 4 and hasattr(self, 'section_4_scripts_container'):
                container = self.section_4_scripts_layout
                self.section_4_scripts_list.append(script_info)
            elif section_number == 6 and hasattr(self, 'section_6_scripts_container'):
                container = self.section_6_scripts_layout
                self.section_6_scripts_list.append(script_info)
            else:
                return
            
            # Add to container
            container.addWidget(script_widget)
    
    def execute_all_section_scripts(self, section_number):
        """Execute all scripts for a specific section sequentially"""
        if section_number == 6 and hasattr(self, 'section_6_scripts_list'):
            scripts = self.section_6_scripts_list
        else:
            QMessageBox.information(self.parent, "No Scripts", "No scripts found for this section")
            return
        
        if not scripts:
            QMessageBox.information(self.parent, "No Scripts", "No scripts to execute")
            return
        
        try:
            from script_executor import SafeScriptExecutor
            
            executor = SafeScriptExecutor()
            script_paths = [script['path'] for script in scripts]
            results = executor.execute_scripts_sequentially(script_paths)
            
            # Create results dialog
            results_dialog = QDialog(self.parent)
            results_dialog.setWindowTitle(f"Section {section_number} Script Execution Results")
            results_dialog.setGeometry(400, 300, 700, 500)
            
            layout = QVBoxLayout(results_dialog)
            
            # Summary
            successful = sum(1 for r in results if r.success)
            total = len(results)
            summary_label = QLabel(f"Executed {total} scripts: {successful} successful, {total - successful} failed")
            summary_label.setStyleSheet("font-weight: bold; font-size: 14px;")
            layout.addWidget(summary_label)
            
            # Detailed results
            results_text = ContextMenuTextEdit()
            results_text.setReadOnly(True)
            
            for i, (script, result) in enumerate(zip(scripts, results)):
                results_text.append(f"=== Script {i+1}: {script['filename']} ===\n")
                results_text.append(f"Status: {'✅ Success' if result.success else '❌ Failed'}\n")
                results_text.append(f"Execution time: {result.execution_time:.2f} seconds\n")
                results_text.append(f"Exit code: {result.exit_code}\n")
                
                if result.stdout:
                    results_text.append("--- STDOUT ---\n")
                    results_text.append(result.stdout + "\n")
                
                if result.stderr:
                    results_text.append("--- STDERR ---\n")
                    results_text.append(result.stderr + "\n")
                
                if result.error_message:
                    results_text.append(f"Error: {result.error_message}\n")
                
                results_text.append("\n")
            
            layout.addWidget(results_text)
            
            # Close button
            close_btn = QPushButton("Close")
            close_btn.clicked.connect(results_dialog.accept)
            layout.addWidget(close_btn)
            
            results_dialog.exec()
            
        except Exception as e:
            QMessageBox.critical(self.parent, "Execution Error", f"Failed to execute scripts: {str(e)}")
    
    def execute_section_script(self, section_number, script_info):
        """Execute a Python script for a specific section"""
        try:
            from script_executor import SafeScriptExecutor
            
            executor = SafeScriptExecutor()
            result = executor.execute_script(script_info['path'])
            
            # Create output dialog
            output_dialog = QDialog(self.parent)
            output_dialog.setWindowTitle(f"Script Execution Results - {script_info['filename']}")
            output_dialog.setGeometry(400, 300, 600, 400)
            
            layout = QVBoxLayout(output_dialog)
            
            # Status
            status_label = QLabel("✅ Script executed successfully!" if result.success else "❌ Script execution failed!")
            status_label.setStyleSheet("font-weight: bold; font-size: 14px;")
            layout.addWidget(status_label)
            
            # Details
            details_text = ContextMenuTextEdit()
            details_text.setReadOnly(True)
            
            details = f"Script: {script_info['filename']}\n"
            details += f"Execution time: {result.execution_time:.2f} seconds\n"
            details += f"Exit code: {result.exit_code}\n\n"
            
            if result.stdout:
                details += "--- STDOUT ---\n"
                details += result.stdout + "\n\n"
            
            if result.stderr:
                details += "--- STDERR ---\n"
                details += result.stderr + "\n\n"
            
            if result.error_message:
                details += f"Error: {result.error_message}\n"
            
            details_text.setPlainText(details)
            layout.addWidget(details_text)
            
            # Close button
            close_btn = QPushButton("Close")
            close_btn.clicked.connect(output_dialog.accept)
            layout.addWidget(close_btn)
            
            output_dialog.exec()
            
        except Exception as e:
            QMessageBox.critical(self.parent, "Execution Error", f"Failed to execute script: {str(e)}")
    
    def remove_section_script(self, section_number, script_info):
        """Remove a script from a specific section"""
        if section_number == 4 and hasattr(self, 'section_4_scripts_list'):
            if script_info in self.section_4_scripts_list:
                self.section_4_scripts_list.remove(script_info)
                # Remove the widget from layout
                for i in range(self.section_4_scripts_layout.count()):
                    widget = self.section_4_scripts_layout.itemAt(i).widget()
                    if widget and widget.findChild(QLabel) and script_info['filename'] in widget.findChild(QLabel).text():
                        widget.setParent(None)
                        break
        elif section_number == 6 and hasattr(self, 'section_6_scripts_list'):
            if script_info in self.section_6_scripts_list:
                self.section_6_scripts_list.remove(script_info)
                # Remove the widget from layout
                for i in range(self.section_6_scripts_layout.count()):
                    widget = self.section_6_scripts_layout.itemAt(i).widget()
                    if widget and widget.findChild(QLabel) and script_info['filename'] in widget.findChild(QLabel).text():
                        widget.setParent(None)
                        break
                    
