    # Section 4 Interfaces Table Methods
    def add_section_4_interface_row(self):
        """Add a new row to the Section 4 interfaces table"""
        if hasattr(self, 'section_4_interfaces_table'):
            row_position = self.section_4_interfaces_table.rowCount()
            self.section_4_interfaces_table.insertRow(row_position)
            
            # Add empty items for each column
            for col in range(4):
                item = QTableWidgetItem("")
                # Set consistent font for text items
                font = QFont()
                font.setFamily("Segoe UI")
                font.setPointSize(12)
                item.setFont(font)
                # Set text flags to ensure proper display
                item.setTextAlignment(Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft)
                self.section_4_interfaces_table.setItem(row_position, col, item)
            
            # Dynamically adjust table height based on number of rows
            self.adjust_section_4_table_height()
            
            # Trigger live preview update
            self.trigger_live_preview_update()

    def remove_section_4_interface_row(self):
        """Remove selected row from the Section 4 interfaces table"""
        if hasattr(self, 'section_4_interfaces_table'):
            current_row = self.section_4_interfaces_table.currentRow()
            if current_row >= 0:
                self.section_4_interfaces_table.removeRow(current_row)
                # Dynamically adjust table height based on number of rows
                self.adjust_section_4_table_height()
                # Trigger live preview update
                self.trigger_live_preview_update()

    def on_section_4_interface_table_changed(self):
        """Handle changes in the Section 4 interfaces table"""
        # Trigger live preview update when table data changes
        self.trigger_live_preview_update()



    def ensure_consistent_font_styling(self):
        """Ensure all table items have consistent font styling"""
        if not hasattr(self, 'section_4_interfaces_table'):
            return
        
        # Set consistent font for all text items
        font = QFont()
        font.setFamily("Segoe UI")
        font.setPointSize(12)
        
        for row in range(self.section_4_interfaces_table.rowCount()):
            for col in range(self.section_4_interfaces_table.columnCount()):
                item = self.section_4_interfaces_table.item(row, col)
                if item:
                    item.setFont(font)
                    # Set text alignment to ensure proper display
                    item.setTextAlignment(Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft)

    def get_section_4_interface_data(self):
        """Get Section 4 interfaces table data in JSON format"""
        interfaces_data = []
        
        if hasattr(self, 'section_4_interfaces_table'):
            for row in range(self.section_4_interfaces_table.rowCount()):
                interface_data = {}
                
                # Get data from each column
                for col in range(4):
                    item = self.section_4_interfaces_table.item(row, col)
                    if item:
                        if col == 0:
                            interface_data['interface'] = item.text()
                        elif col == 1:
                            interface_data['ports'] = item.text()
                        elif col == 2:
                            interface_data['type'] = item.text()
                        elif col == 3:
                            interface_data['name'] = item.text()
                    else:
                        if col == 0:
                            interface_data['interface'] = ""
                        elif col == 1:
                            interface_data['ports'] = ""
                        elif col == 2:
                            interface_data['type'] = ""
                        elif col == 3:
                            interface_data['name'] = ""
                
                # Only add row if at least one field has data
                if any(interface_data.values()):
                    interfaces_data.append(interface_data)
        
        return interfaces_data

    def load_section_4_interface_data(self, interfaces_data):
        """Load Section 4 interfaces table data from JSON format"""
        if not hasattr(self, 'section_4_interfaces_table'):
            return
        
        # Clear existing table
        self.section_4_interfaces_table.setRowCount(0)
        
        # Load description text
        if hasattr(self, 'section_4_interfaces_desc'):
            desc_text = interfaces_data.get('interfaces_desc', '')
            self.section_4_interfaces_desc.setPlainText(desc_text)
        
        # Load interface data
        interfaces = interfaces_data.get('interfaces', [])
        for interface in interfaces:
            if isinstance(interface, dict):
                row_position = self.section_4_interfaces_table.rowCount()
                self.section_4_interfaces_table.insertRow(row_position)
                
                # Set data for each column
                for col in range(4):
                    item = QTableWidgetItem(str(interface.get(['interface', 'ports', 'type', 'name'][col], '')))
                    # Set consistent font for text items
                    font = QFont()
                    font.setFamily("Segoe UI")
                    font.setPointSize(12)
                    item.setFont(font)
                    # Set text flags to ensure proper display
                    item.setTextAlignment(Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft)
                    self.section_4_interfaces_table.setItem(row_position, col, item)
            
            # Adjust table height after loading data
            self.adjust_section_4_table_height()

    def adjust_section_4_table_height(self):
        """Dynamically adjust the Section 4 interfaces table height based on number of rows"""
        if not hasattr(self, 'section_4_interfaces_table'):
            return
        
        # Calculate required height based on number of rows
        row_count = self.section_4_interfaces_table.rowCount()
        row_height = 50  # Increased row height for better text visibility
        header_height = 60  # Increased header height
        
        # Minimum height for at least 3 rows, or actual rows if more
        min_rows = max(3, row_count)
        required_height = header_height + (min_rows * row_height)
        
        # Set the table height
        self.section_4_interfaces_table.setFixedHeight(required_height)
        
        # Force layout update to ensure proper expansion
        if hasattr(self, 'section_4_interfaces_table'):
            self.section_4_interfaces_table.updateGeometry()

    def validate_section_4_interfaces(self):
        """Validate that Section 4 interfaces table has at least one row with data"""
        if not hasattr(self, 'section_4_interfaces_table'):
            return False
        
        # Check if there's at least one row with data
        for row in range(self.section_4_interfaces_table.rowCount()):
            has_data = False
            for col in range(4):
                item = self.section_4_interfaces_table.item(row, col)
                if item and item.text().strip():
                    has_data = True
                    break
            
            if has_data:
                return True
        
        return False

