    def remove_section_5_image_from_pair(self, pair_info, image_info):
        """Remove an image from a specific text-image pair"""
        if image_info in pair_info['images_list']:
            pair_info['images_list'].remove(image_info)
            # Remove the widget from layout
            for i in range(pair_info['images_layout'].count()):
                widget = pair_info['images_layout'].itemAt(i).widget()
                if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                    pair_info['images_layout'].removeWidget(widget)
                    widget.setParent(None)
                    widget.deleteLater()
                    print(f"✅ Removed section 5 image widget from UI: {image_info.get('filename', 'Unknown')}")
                    break
            
            # Also remove from section's image list
            if image_info in self.section_5_images_list:
                self.section_5_images_list.remove(image_info)
                    
    def remove_section_5_pair(self, pair_info):
        """Remove a text-image pair from Section 5"""
        if pair_info in self.section_5_pairs:
            self.section_5_pairs.remove(pair_info)
            # Remove the widget from layout
            for i in range(self.section_5_pairs_layout.count()):
                widget = self.section_5_pairs_layout.itemAt(i).widget()
                if widget and widget.findChild(QTextEdit) == pair_info['text_edit']:
                    widget.setParent(None)
                    break 

