    def paste_section_5_script(self, pair_info):
        """Paste script for Section 5"""
        # Create a dialog for pasting script content
        dialog = QDialog(self.parent)
        dialog.setWindowTitle("Paste Python Script")
        dialog.setGeometry(400, 300, 600, 400)
        
        layout = QVBoxLayout(dialog)
        
        # Instructions label
        instructions = QLabel("Paste your Python script code below:")
        instructions.setStyleSheet("font-weight: bold; margin-bottom: 10px;")
        layout.addWidget(instructions)
        
        # Textarea for pasting script
        script_textarea = QTextEdit()
        script_textarea.setPlaceholderText("Paste your Python script here...\n\nExample:\ndef hello_world():\n    print('Hello, World!')\n\nhello_world()")
        script_textarea.setStyleSheet("""
            QTextEdit {
                background-color: #2b2b2b;
                color: #ffffff;
                border: 1px solid #444444;
                border-radius: 4px;
                padding: 8px;
                font-family: 'Consolas', 'Monaco', monospace;
                font-size: 12px;
            }
        """)
        layout.addWidget(script_textarea)
        
        # Button layout
        button_layout = QHBoxLayout()
        
        # Cancel button
        cancel_button = QPushButton("Cancel")
        cancel_button.setStyleSheet("""
            QPushButton {
                background-color: #6c757d;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #5a6268;
            }
        """)
        cancel_button.clicked.connect(dialog.reject)
        button_layout.addWidget(cancel_button)
        
        button_layout.addStretch()
        
        # OK button
        ok_button = QPushButton("OK")
        ok_button.setStyleSheet("""
            QPushButton {
                background-color: #28a745;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #218838;
            }
        """)
        ok_button.clicked.connect(dialog.accept)
        button_layout.addWidget(ok_button)
        
        layout.addLayout(button_layout)
        
        # Show dialog
        if dialog.exec() != QDialog.DialogCode.Accepted:
            return
        
        # Get script content from textarea
        script_content = script_textarea.toPlainText().strip()
        
        if not script_content:
            QMessageBox.warning(self.parent, "Empty Script", "Please paste some script content.")
            return
        
        try:
            # Create temporary file for pasted script
            unique_id = str(uuid.uuid4())[:8]
            script_filename = f"pasted_{unique_id}_script.py"
            script_path = os.path.join("tmp", script_filename)
            
            os.makedirs("tmp", exist_ok=True)
            
            # Write script content to file
            with open(script_path, 'w', encoding='utf-8') as f:
                f.write(script_content)
            
            # Now show placeholder dialog
            result = self.show_placeholder_dialog(self.parent)
            
            if not result["ok"] and not result["skip"]:
                # Clean up the temporary file if user cancels
                try:
                    if os.path.exists(script_path):
                        os.remove(script_path)
                except:
                    pass
                return
            
            placeholder = result["description"]
            # Use the subheading text as the question name
            subheading = pair_info['text_edit'].toPlainText().strip() if pair_info.get('text_edit') else "DUT Configuration"
            
            script_number = self.get_next_script_number()
            script_name = f"script{script_number}.py"
            
            script_info = {
                'path': script_path,
                'filename': script_filename,
                'description': placeholder,
                'placeholder': placeholder,  # Store placeholder separately for export
                'subheading': subheading,
                'script_name': script_name,
                'is_pasted': True,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create script widget
            script_widget = QWidget()
            script_layout = QHBoxLayout(script_widget)
            
            # Filename label
            filename_label = QLabel(f"📄 {script_filename} (Pasted)")
            filename_label.setStyleSheet("color: #b95a30; font-weight: bold;")
            script_layout.addWidget(filename_label)
            
            # Remove button
            script_info['remove_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            script_info['remove_btn'].clicked.connect(lambda: self.remove_section_5_script(pair_info, script_info))
            script_layout.addWidget(script_info['remove_btn'])
            
            script_layout.addStretch()
            
            # Add to container
            if 'upload_scripts_list' not in pair_info:
                pair_info['upload_scripts_list'] = []
            pair_info['upload_scripts_list'].append(script_info)
            pair_info['scripts_layout'].addWidget(script_widget)
            
            # Add to Essential Questions
            if hasattr(self.parent, 'add_essential_question_with_script'):
                self.parent.add_essential_question_with_script(subheading, original_filename, placeholder)
            
            QMessageBox.information(
                self.parent,
                "Script Pasted",
                f"Script '{script_filename}' pasted successfully.\n\n"
                f"• Document Placeholder: {placeholder}\n"
                f"• Subheading: {subheading}\n"
                f"• Script Name: {script_name}\n\n"
                f"Essential Questions have been automatically updated to include this script."
            )
            
        except Exception as e:
            QMessageBox.critical(
                self.parent,
                "Paste Error",
                f"Failed to process pasted script: {str(e)}"
            )

    def remove_section_5_script(self, pair_info, script_info):
        """Remove a script from Section 5"""
        if 'upload_scripts_list' in pair_info and script_info in pair_info['upload_scripts_list']:
            # Delete the file from tmp directory
            try:
                if os.path.exists(script_info['path']):
                    os.remove(script_info['path'])
                    print(f"Deleted file: {script_info['path']}")
            except Exception as e:
                print(f"Error deleting file {script_info['path']}: {e}")
            
            # Remove from list
            pair_info['upload_scripts_list'].remove(script_info)
            
            # Remove widget from layout
            for i in range(pair_info['scripts_layout'].count()):
                widget = pair_info['scripts_layout'].itemAt(i).widget()
                if widget and widget.findChild(QLabel) and script_info['filename'] in widget.findChild(QLabel).text():
                    widget.setParent(None)
                    break 
            
            # Remove corresponding essential question if it exists
            script_name = script_info.get('script_name', '')
            if script_name and hasattr(self.parent, 'essential_questions'):
                for question_info in self.parent.essential_questions[:]:
                    if (question_info.get("script_name_edit") and 
                        question_info["script_name_edit"].text() == script_name):
                        # Remove the essential question
                        self.parent.questions_container.removeWidget(question_info["widget"])
                        question_info["widget"].deleteLater()
                        self.parent.essential_questions.remove(question_info)
                        # Renumber remaining questions
                        self.parent.renumber_essential_questions()
                        break
            
            # Show success message
            display_name = script_info.get('original_filename', script_info['filename'])
            QMessageBox.information(
                self.parent,
                "Script Removed",
                f"Script '{display_name}' has been removed and the file deleted.\n\n"
                f"Corresponding essential question has also been removed."
            ) 

    def remove_section_image(self, section_number, image_info):
        """Remove an image from a specific section"""
        section_name = f"section_{section_number}"
        images_list_name = f"{section_name}_images_list"
        images_layout_name = f"{section_name}_images_layout"

        if hasattr(self, images_list_name):
            images_list = getattr(self, images_list_name)
            if image_info in images_list:
                # Delete file from filesystem
                try:
                    if os.path.exists(image_info.get('absolute_path', image_info['path'])):
                        os.remove(image_info.get('absolute_path', image_info['path']))
                except Exception as e:
                    print(f"Error deleting file: {e}")

                # Remove from list
                images_list.remove(image_info)

                # Remove the widget from layout
                if hasattr(self, images_layout_name):
                    images_layout = getattr(self, images_layout_name)
                    for i in range(images_layout.count()):
                        widget = images_layout.itemAt(i).widget()
                        if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                            widget.setParent(None)
                            break
                    
