    def resolve_import_path(self, relative_path):
        """Resolve relative path to absolute path for import"""
        # Handle dict vs string input - defensive programming
        if isinstance(relative_path, dict):
            relative_path = relative_path.get('path', '')
        
        if not relative_path or not isinstance(relative_path, (str, bytes)):
            return None
        
        # If it's already an absolute path, return as is
        if os.path.isabs(relative_path):
            return relative_path
        
        # Get project directory from parent
        project_dir = getattr(self.parent, 'import_project_dir', os.getcwd())
        
        # Handle different path patterns
        if relative_path.startswith("code/"):
            # Script file
            filename = relative_path[5:]  # Remove "code/" prefix
            resolved_path = os.path.join(project_dir, "code", filename)
        elif relative_path.startswith("raw_logs/"):
            # Image file
            filename = relative_path[9:]  # Remove "raw_logs/" prefix
            resolved_path = os.path.join(project_dir, "raw_logs", filename)
        else:
            # Try to resolve as relative to project directory
            resolved_path = os.path.join(project_dir, relative_path)
        
        print(f"DEBUG: Resolving path '{relative_path}' to '{resolved_path}'")
        return resolved_path
    
    def remove_section_5_pair_image(self, pair_info, image_info):
        """Remove an image from a Section 5 pair"""
        if 'images_list' in pair_info and image_info in pair_info['images_list']:
            pair_info['images_list'].remove(image_info)
            # Remove the widget from layout
            if 'images_container' in pair_info and pair_info['images_container']:
                for i in range(pair_info['images_container'].layout().count()):
                    widget = pair_info['images_container'].layout().itemAt(i).widget()
                    if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                        pair_info['images_container'].layout().removeWidget(widget)
                        widget.setParent(None)
                        widget.deleteLater()
                        print(f"✅ Removed section 5 pair image widget from UI: {image_info.get('filename', 'Unknown')}")
                        break
        
        # Delete the file from tmp directory
        try:
            if os.path.exists(image_info['path']):
                os.remove(image_info['path'])
                print(f"Deleted file: {image_info['path']}")
        except Exception as e:
            print(f"Error deleting file {image_info['path']}: {e}")
    
    def remove_section_5_pair_script(self, pair_info, script_info):
        """Remove a script from a Section 5 pair"""
        if 'upload_scripts_list' in pair_info and script_info in pair_info['upload_scripts_list']:
            pair_info['upload_scripts_list'].remove(script_info)
            # Remove the widget from layout
            if 'scripts_container' in pair_info and pair_info['scripts_container']:
                for i in range(pair_info['scripts_container'].layout().count()):
                    widget = pair_info['scripts_container'].layout().itemAt(i).widget()
                    if widget and widget.findChild(QLabel) and script_info['filename'] in widget.findChild(QLabel).text():
                        pair_info['scripts_container'].layout().removeWidget(widget)
                        widget.setParent(None)
                        widget.deleteLater()
                        print(f"✅ Removed section 5 pair script widget from UI: {script_info.get('filename', 'Unknown')}")
                        break
        
        # Delete the file from tmp directory
        try:
            if os.path.exists(script_info['path']):
                os.remove(script_info['path'])
                print(f"Deleted file: {script_info['path']}")
        except Exception as e:
            print(f"Error deleting file {script_info['path']}: {e}")
    
