    def _resolve_import_path(self, file_path):
        """
        Resolve file path for import, handling both absolute and relative paths
        
        Args:
            file_path: The file path to resolve
            
        Returns:
            Resolved absolute file path
        """
        if not file_path:
            return ""
        
        # If it's already an absolute path and exists, use it
        if os.path.isabs(file_path) and os.path.exists(file_path):
            return file_path
        
        # Detect the project directory for path resolution
        if hasattr(self, 'import_project_dir'):
            project_dir = self.import_project_dir
        else:
            # Fallback: try to find project directory from current working directory
            project_dir = os.getcwd()
        
        # Try to resolve relative paths
        possible_paths = [
            file_path,  # Original path
            os.path.join(project_dir, file_path),  # Project directory
            os.path.join(project_dir, "tmp", file_path),  # tmp directory
            os.path.join(project_dir, "tmp", "raw_logs", file_path),  # raw_logs directory
            os.path.join(project_dir, "tmp", "code", file_path),  # code directory
        ]
        
        # Handle different path patterns
        if file_path.startswith("code/"):
            # Script file
            filename = file_path[5:]  # Remove "code/" prefix
            possible_paths.extend([
                os.path.join(project_dir, "code", filename),
                os.path.join(project_dir, "tmp", "code", filename)
            ])
        elif file_path.startswith("raw_logs/"):
            # Image file
            filename = file_path[9:]  # Remove "raw_logs/" prefix
            possible_paths.extend([
                os.path.join(project_dir, "raw_logs", filename),
                os.path.join(project_dir, "tmp", "raw_logs", filename)
            ])
        
        for path in possible_paths:
            if os.path.exists(path):
                print(f"DEBUG: Resolved path '{file_path}' to '{path}'")
                return path
        
        # If no path found, return the original path (will be handled by caller)
        print(f"DEBUG: Could not resolve path '{file_path}'")
        return file_path
    
    def load_testcase_context(self):
        """Load testcase context from environment variables or config file"""
        try:
            # Try to get from environment variables first
            self.current_testcase_id = os.environ.get('TESTCASE_ID')
            self.current_project_id = os.environ.get('PROJECT_ID')
            self.token = os.environ.get('AUTH_TOKEN')
            self.base_url = os.environ.get('BASE_URL')
            
            # If not in environment, try to read from config file
            if not self.current_testcase_id:
                try:
                    with open('client.conf.json', 'r') as f:
                        config = json.load(f)
                        self.current_testcase_id = config.get('testcase_id')
                        self.current_project_id = config.get('project_id')
                        self.token = config.get('token')
                        self.base_url = config.get('base_url')
                except Exception as e:
                    print(f"Could not load testcase context from config: {e}")
            
            # Set default base URL if not found
            if not self.base_url:
                # Try to get base_url from 1.json as fallback
                try:
                    config_path = os.path.expanduser('~/1.json')
                    with open(config_path, 'r') as f:
                        config = json.load(f)
                        self.base_url = config.get('base_url')
                        if self.base_url:
                            print(f"Using base_url from 1.json: {self.base_url}")
                        else:
                            print("No base_url found in 1.json")
                except Exception as e:
                    print(f"Error reading base_url from 1.json: {e}")
                    self.base_url = None
            
            print(f"Loaded testcase context: testcase_id={self.current_testcase_id}, project_id={self.current_project_id}")
            
        except Exception as e:
            print(f"Error loading testcase context: {e}")
    
    def set_testcase_context(self, testcase_id, project_id=None, token=None, base_url=None):
        """Set the current testcase context"""
        self.current_testcase_id = testcase_id
        if project_id:
            self.current_project_id = project_id
        if token:
            self.token = token
        if base_url:
            self.base_url = base_url
        
        # Save to config file
        try:
            config = {}
            try:
                with open('client.conf.json', 'r', encoding='utf-8') as f:
                    config = json.load(f)
            except:
                pass
            
            config['testcase_id'] = self.current_testcase_id
            config['project_id'] = self.current_project_id
            config['token'] = self.token
            config['base_url'] = self.base_url
            
            with open('client.conf.json', 'w') as f:
                json.dump(config, f, indent=2)
                
            print(f"Saved testcase context: testcase_id={self.current_testcase_id}")
            
        except Exception as e:
            print(f"Error saving testcase context: {e}")
        
    def get_next_placeholder(self):
        """Get the next placeholder value and increment counter"""
        # Initialize placeholder counter if not exists
        if not hasattr(self, 'placeholder_counter'):
            self.placeholder_counter = 1
        
        # Check existing placeholders to avoid conflicts
        existing_placeholders = self.get_all_existing_placeholders()
        
        # Find the next available placeholder number
        while f"Placeholder_{self.placeholder_counter}" in existing_placeholders:
            self.placeholder_counter += 1
        
        placeholder = f"Placeholder_{self.placeholder_counter}"
        print(f"DEBUG: get_next_placeholder called, counter={self.placeholder_counter}, returning='{placeholder}'")
        print(f"DEBUG: Existing placeholders: {existing_placeholders}")
        self.placeholder_counter += 1
        return placeholder
    
    def get_all_existing_placeholders(self):
        """Get all existing placeholders from various sources to avoid conflicts"""
        existing_placeholders = set()
        
        # Check essential questions
        if hasattr(self, 'essential_questions'):
            for question in self.essential_questions:
                if hasattr(question, 'placeholder_edit') and question.placeholder_edit:
                    try:
                        placeholder_text = question.placeholder_edit.text().strip()
                        if placeholder_text:
                            existing_placeholders.add(placeholder_text)
                    except RuntimeError:
                        pass  # Widget deleted
        
        # Check execution step questions
        if hasattr(self, 'execution_step_questions'):
            for step_data in self.execution_step_questions:
                for question_block in step_data.get('question_blocks', []):
                    if hasattr(question_block, 'placeholder_edit') and question_block.placeholder_edit:
                        try:
                            placeholder_text = question_block.placeholder_edit.text().strip()
                            if placeholder_text:
                                existing_placeholders.add(placeholder_text)
                        except RuntimeError:
                            pass  # Widget deleted
        
        # Check global step scripts
        if hasattr(self, '_global_step_scripts'):
            for step_key, scripts in self._global_step_scripts.items():
                for script in scripts:
                    if 'placeholder' in script and script['placeholder']:
                        existing_placeholders.add(script['placeholder'])
        
        # Check step widgets
        if hasattr(self, 'step_widgets'):
            for step_key, step_data in self.step_widgets.items():
                if 'upload_scripts_list' in step_data:
                    for script in step_data['upload_scripts_list']:
                        if 'placeholder' in script and script['placeholder']:
                            existing_placeholders.add(script['placeholder'])
        
        print(f"DEBUG: Found {len(existing_placeholders)} existing placeholders: {list(existing_placeholders)}")
        return existing_placeholders
    
    def collect_all_section_placeholders(self):
        """Collect all placeholders from all sections and add them to automatic_images array"""
        print("DEBUG: Starting comprehensive placeholder collection from all sections")
        
        # Initialize automatic_images if it doesn't exist
        if not hasattr(self, 'automatic_images'):
            self.automatic_images = []
        
        # Track collected placeholders to avoid duplicates
        collected_placeholders = set()
        
        # Collect from existing automatic_images to avoid duplicates
        for placeholder_info in self.automatic_images:
            if isinstance(placeholder_info, dict) and 'placeholder' in placeholder_info:
                collected_placeholders.add(placeholder_info['placeholder'])
        
        print(f"DEBUG: Starting with {len(collected_placeholders)} existing placeholders in automatic_images")
        
        # 1. Collect from Sections 1-7
        sections_1_7_placeholders = []
        for section_num in range(1, 8):
            method_name = f'get_section_{section_num}_placeholder_text'
            if hasattr(self, method_name):
                try:
                    placeholder_text = getattr(self, method_name)()
                    if placeholder_text and placeholder_text.strip():
                        # Split by newlines to get individual placeholders
                        section_placeholders = [p.strip() for p in placeholder_text.split('\n') if p.strip()]
                        sections_1_7_placeholders.extend(section_placeholders)
                        print(f"DEBUG: Section {section_num} placeholders: {section_placeholders}")
                except Exception as e:
                    print(f"DEBUG: Error getting section {section_num} placeholders: {e}")
        
        # 2. Collect from DUT Configuration (scenario_placeholders)
        dut_placeholders = []
        if hasattr(self, 'scenario_placeholders'):
            for section_name, placeholders_list in self.scenario_placeholders.items():
                for placeholder_info in placeholders_list:
                    if isinstance(placeholder_info, dict) and 'placeholder' in placeholder_info:
                        dut_placeholders.append(placeholder_info['placeholder'])
                        print(f"DEBUG: DUT Configuration placeholder from {section_name}: {placeholder_info['placeholder']}")
        
        # 3. Collect from Section 8 Test Plan (step_widgets)
        section_8_placeholders = []
        if hasattr(self, 'step_widgets'):
            for step_key, step_data in self.step_widgets.items():
                # Check placeholders_list
                if 'placeholders_list' in step_data:
                    for placeholder_info in step_data['placeholders_list']:
                        if isinstance(placeholder_info, dict) and 'name' in placeholder_info:
                            section_8_placeholders.append(placeholder_info['name'])
                            print(f"DEBUG: Section 8 placeholder from step {step_key}: {placeholder_info['name']}")
                
                # Check upload_scripts_list for placeholders
                if 'upload_scripts_list' in step_data:
                    for script_info in step_data['upload_scripts_list']:
                        if isinstance(script_info, dict) and 'placeholder' in script_info and script_info['placeholder']:
                            section_8_placeholders.append(script_info['placeholder'])
                            print(f"DEBUG: Section 8 script placeholder from step {step_key}: {script_info['placeholder']}")
        
        # 4. Collect from Section 11 Test Execution (execution_questions and step_widgets)
        section_11_placeholders = []
        if hasattr(self, 'execution_questions'):
            for question in self.execution_questions:
                if hasattr(question, 'placeholder_edit') and question.placeholder_edit:
                    try:
                        placeholder_text = question.placeholder_edit.text().strip()
                        if placeholder_text:
                            section_11_placeholders.append(placeholder_text)
                            print(f"DEBUG: Section 11 execution question placeholder: {placeholder_text}")
                    except RuntimeError:
                        pass  # Widget deleted
        
        # Combine all placeholders
        all_new_placeholders = sections_1_7_placeholders + dut_placeholders + section_8_placeholders + section_11_placeholders
        
        # Add new placeholders to automatic_images (avoiding duplicates)
        new_placeholders_added = 0
        for placeholder_text in all_new_placeholders:
            if placeholder_text and placeholder_text not in collected_placeholders:
                placeholder_info = {
                    "placeholder": placeholder_text,
                    "image_path": None
                }
                self.automatic_images.append(placeholder_info)
                collected_placeholders.add(placeholder_text)
                new_placeholders_added += 1
                print(f"DEBUG: Added new placeholder to automatic_images: {placeholder_text}")
        
        print(f"DEBUG: Placeholder collection complete!")
        print(f"DEBUG: - Sections 1-7 placeholders: {len(sections_1_7_placeholders)}")
        print(f"DEBUG: - DUT Configuration placeholders: {len(dut_placeholders)}")
        print(f"DEBUG: - Section 8 placeholders: {len(section_8_placeholders)}")
        print(f"DEBUG: - Section 11 placeholders: {len(section_11_placeholders)}")
        print(f"DEBUG: - New placeholders added: {new_placeholders_added}")
        print(f"DEBUG: - Total placeholders in automatic_images: {len(self.automatic_images)}")
        
        return new_placeholders_added
    
    def get_next_script_number(self):
        """Get the next script number and increment counter"""
        self.script_counter += 1
        return self.script_counter
    
    def add_placeholder(self):
        """Add a placeholder to the automatic_images array in memory"""
        placeholder_name, ok = QInputDialog.getText(
            self, 
            "Add Placeholder", 
            "Enter placeholder name:",
            QLineEdit.EchoMode.Normal
        )
        
        if ok and placeholder_name.strip():
            placeholder_info = {
                "placeholder": placeholder_name.strip(),
                "image_path": None
            }
            self.automatic_images.append(placeholder_info)
            
            # Update all scenario placeholder displays
            self.update_all_scenario_placeholder_displays()
            
            # Debug output
            print(f"DEBUG: Added placeholder: {placeholder_info}")
            print(f"DEBUG: Total placeholders: {len(self.automatic_images)}")
            
            QMessageBox.information(
                self,
                "Placeholder Added",
                f"Placeholder '{placeholder_name.strip()}' has been added to memory.\n\nCurrent placeholders: {len(self.automatic_images)}"
            )
    

    
