    def add_section_11_placeholder(self, step_data):
        """Add a placeholder to a Section 11 test execution step"""
        try:
            # Prompt user for placeholder name
            placeholder_name, ok = QInputDialog.getText(
                self, 
                "Add Placeholder", 
                "Enter placeholder name:",
                QLineEdit.EchoMode.Normal
            )
            
            if ok and placeholder_name.strip():
                placeholder_name = placeholder_name.strip()
                
                # Create placeholder info
                placeholder_info = {
                    'name': placeholder_name,
                    'type': 'placeholder',
                    'is_placeholder': True
                }
                print("12187: ", placeholder_info)
                
                # Add to step data
                if 'placeholders_list' not in step_data:
                    step_data['placeholders_list'] = []
                step_data['placeholders_list'].append(placeholder_info)
                print(f"DEBUG: Added placeholder '{placeholder_name}' to step_data['placeholders_list']")
                print(f"DEBUG: step_data['placeholders_list'] now has {len(step_data['placeholders_list'])} items")
                print(f"DEBUG: step_data keys: {list(step_data.keys())}")
                
                # Create placeholder widget
                placeholder_widget = QWidget()
                placeholder_layout = QHBoxLayout(placeholder_widget)
                
                # Placeholder label (similar to image/script display)
                placeholder_label = QLabel(f"📋 {placeholder_name}")
                placeholder_label.setStyleSheet("color: #6f42c1; font-weight: bold;")
                placeholder_layout.addWidget(placeholder_label)
                
                # Remove button
                remove_btn = QPushButton("🗑️ Remove")
                remove_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #dc3545;
                        color: white;
                        border: none;
                        border-radius: 4px;
                        padding: 4px 8px;
                        font-weight: bold;
                    }
                    QPushButton:hover {
                        background-color: #c82333;
                    }
                """)
                
                # Connect remove button
                remove_btn.clicked.connect(lambda checked, sd=step_data, ph=placeholder_info: self.remove_section_11_placeholder(sd, ph))
                placeholder_layout.addWidget(remove_btn)
                
                placeholder_layout.addStretch()
                
                # Store widget reference
                placeholder_info['widget'] = placeholder_widget
                
                # Add to UI
                if 'placeholders_layout' in step_data:
                    step_data['placeholders_layout'].addWidget(placeholder_widget)
                
                # Store placeholder in global storage for persistence across page navigation
                if not hasattr(self, '_global_step_placeholders'):
                    self._global_step_placeholders = {}
                
                # Get the step key for global storage
                case_number = step_data.get('case_number', 'unknown')
                step_index = step_data.get('step_index', 1)
                step_key = f"{case_number}_{step_index}"
                
                # Initialize global storage for this step if it doesn't exist
                if step_key not in self._global_step_placeholders:
                    self._global_step_placeholders[step_key] = []
                
                # Check if this placeholder already exists to avoid duplicates
                existing_placeholder_names = [ph.get('name', '') for ph in self._global_step_placeholders[step_key]]
                if placeholder_name not in existing_placeholder_names:
                    self._global_step_placeholders[step_key].append(placeholder_info.copy())
                    print(f"DEBUG: Stored placeholder '{placeholder_name}' in global storage for step {step_key}")
                else:
                    print(f"DEBUG: Placeholder '{placeholder_name}' already exists in global storage for step {step_key}")
                
                print(f"✅ Added placeholder '{placeholder_name}' to step {step_data.get('step_index', 'unknown')}")
                
                # Update execution step questions with the added placeholder
                self.update_execution_step_questions_with_placeholder(placeholder_name)
                
                # CRITICAL FIX: Ensure placeholder is also stored in the step_widgets dictionary
                if hasattr(self, 'step_widgets') and step_key in self.step_widgets:
                    stored_step_data = self.step_widgets[step_key]
                    print(f"DEBUG: step_widgets[{step_key}] has placeholders_list: {'placeholders_list' in stored_step_data}")
                    
                    # Initialize placeholders_list if it doesn't exist
                    if 'placeholders_list' not in stored_step_data:
                        stored_step_data['placeholders_list'] = []
                    
                    # Check if this placeholder already exists in step_widgets to avoid duplicates
                    existing_placeholder_names = [ph.get('name', '') for ph in stored_step_data['placeholders_list']]
                    if placeholder_name not in existing_placeholder_names:
                        stored_step_data['placeholders_list'].append(placeholder_info.copy())
                        print(f"DEBUG: Added placeholder '{placeholder_name}' to step_widgets[{step_key}]['placeholders_list']")
                    else:
                        print(f"DEBUG: Placeholder '{placeholder_name}' already exists in step_widgets[{step_key}]['placeholders_list']")
                    
                    print(f"DEBUG: step_widgets[{step_key}]['placeholders_list'] now has {len(stored_step_data['placeholders_list'])} items")
                    
                    # Also update the local step_data to keep them in sync
                    if 'placeholders_list' not in step_data:
                        step_data['placeholders_list'] = []
                    step_data['placeholders_list'] = stored_step_data['placeholders_list'].copy()
                    
                else:
                    print(f"DEBUG: step_key {step_key} not found in step_widgets")
                    print(f"DEBUG: Available step keys: {list(self.step_widgets.keys()) if hasattr(self, 'step_widgets') else 'No step_widgets'}")
                    
                    # If step_widgets doesn't exist, create it and store the step data
                    if not hasattr(self, 'step_widgets'):
                        self.step_widgets = {}
                    
                    # Ensure step_data has all required fields
                    if 'placeholders_list' not in step_data:
                        step_data['placeholders_list'] = []
                    
                    # Store the step data in step_widgets
                    self.step_widgets[step_key] = step_data.copy()
                    print(f"DEBUG: Created step_widgets[{step_key}] with placeholders_list")
                    
                    # Add placeholder to the newly created step data
                    self.step_widgets[step_key]['placeholders_list'].append(placeholder_info.copy())
                    print(f"DEBUG: Added placeholder '{placeholder_name}' to newly created step_widgets[{step_key}]['placeholders_list']")
                    print(f"DEBUG: Newly created step_widgets[{step_key}]['placeholders_list'] now has {len(self.step_widgets[step_key]['placeholders_list'])} items")
                    print(f"DEBUG: Newly created step_widgets[{step_key}]['placeholders_list'] content: {self.step_widgets[step_key]['placeholders_list']}")
                    
                    # Update the local step_data to keep them in sync
                    step_data['placeholders_list'] = self.step_widgets[step_key]['placeholders_list'].copy()
                
        except Exception as e:
            print(f"⚠️ Error adding Section 11 placeholder: {e}")
    
    def remove_section_11_placeholder(self, step_data, placeholder_info):
        """Remove a placeholder from a Section 11 test execution step"""
        try:
            # Remove from step data using name comparison instead of object identity
            if 'placeholders_list' in step_data:
                placeholder_name_to_remove = placeholder_info.get('name', '')
                step_data['placeholders_list'] = [
                    ph for ph in step_data['placeholders_list'] 
                    if ph.get('name') != placeholder_name_to_remove
                ]
            
            # Remove from global storage
            if hasattr(self, '_global_step_placeholders'):
                case_number = step_data.get('case_number', 'unknown')
                step_index = step_data.get('step_index', 1)
                step_key = f"{case_number}_{step_index}"
                
                if step_key in self._global_step_placeholders:
                    self._global_step_placeholders[step_key] = [
                        ph for ph in self._global_step_placeholders[step_key] 
                        if ph.get('name') != placeholder_info.get('name')
                    ]
            
            # Remove from step_widgets dictionary
            if hasattr(self, 'step_widgets'):
                case_number = step_data.get('case_number', 'unknown')
                step_index = step_data.get('step_index', 1)
                step_key = f"{case_number}_{step_index}"
                
                if step_key in self.step_widgets and 'placeholders_list' in self.step_widgets[step_key]:
                    self.step_widgets[step_key]['placeholders_list'] = [
                        ph for ph in self.step_widgets[step_key]['placeholders_list'] 
                        if ph.get('name') != placeholder_info.get('name')
                    ]
            
            # Remove UI widget if present
            widget = placeholder_info.get('widget')
            if widget is not None:
                widget.setParent(None)
                widget.deleteLater()
            
            # Force UI refresh
            self.update()
            
            # Remove from Execution Step Questions
            placeholder_name = placeholder_info.get('name', 'Unknown')
            step_number = step_data.get('step_number')
            self.remove_from_execution_step_questions('placeholder', placeholder_name, step_number)
            
            # Show success notification
            QMessageBox.information(
                self,
                "Placeholder Removed",
                f"Successfully removed placeholder:\n{placeholder_name}\n\n"
                f"✓ Removed from Section 11\n"
                f"✓ Removed from Execution Step Questions"
            )
            
            # Update status bar
            status_bar = self.statusBar()
            if status_bar:
                status_bar.showMessage(f"Removed placeholder: {placeholder_name}")
            
            print(f"✅ Removed placeholder '{placeholder_name}' from step {step_data.get('step_index', 'unknown')}")
                
        except Exception as e:
            print(f"⚠️ Error removing Section 11 placeholder: {e}")
            QMessageBox.critical(
                self,
                "Error",
                f"Failed to remove placeholder:\n{str(e)}"
            )
    
    def show_placeholder_dialog(self, parent=None):
        """Show dialog with skip button for document placeholder input"""
        if parent is None:
            parent = self
            
        dialog = QDialog(parent)
        dialog.setWindowTitle("Document Placeholder")
        dialog.setFixedSize(400, 200)
        dialog.setModal(True)
        
        layout = QVBoxLayout(dialog)
        
        # Label
        label = QLabel("Enter the document placeholder or related text:")
        layout.addWidget(label)
        
        # Input field
        input_field = QLineEdit()
        input_field.setPlaceholderText("Enter placeholder text...")
        layout.addWidget(input_field)
        
        # Button layout
        button_layout = QHBoxLayout()
        
        # Skip button
        skip_button = QPushButton("Skip")
        skip_button.setStyleSheet("""
            QPushButton {
                background-color: #28a745;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #218838;
            }
        """)
        
        # Cancel button
        cancel_button = QPushButton("Cancel")
        cancel_button.setStyleSheet("""
            QPushButton {
                background-color: #6c757d;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #5a6268;
            }
        """)
        
        # OK button
        ok_button = QPushButton("OK")
        ok_button.setStyleSheet("""
            QPushButton {
                background-color: #ff9800;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #e68900;
            }
        """)
        
        button_layout.addWidget(skip_button)
        button_layout.addStretch()
        button_layout.addWidget(cancel_button)
        button_layout.addWidget(ok_button)
        
        layout.addLayout(button_layout)
        
        # Connect button signals
        result = {"description": "", "ok": False, "skip": False}
        
        def on_ok():
            result["description"] = input_field.text()
            result["ok"] = True
            dialog.accept()
        
        def on_skip():
            result["description"] = self.get_next_placeholder()
            result["skip"] = True
            dialog.accept()
        
        def on_cancel():
            dialog.reject()
        
        ok_button.clicked.connect(on_ok)
        skip_button.clicked.connect(on_skip)
        cancel_button.clicked.connect(on_cancel)
        
        # Set focus to input field
        input_field.setFocus()
        
        # Show dialog
        dialog.exec()
        
        return result
        
