    def eventFilter(self, obj, event):
        """Event filter to handle combo box scroll events"""
        if event.type() == QEvent.Type.Wheel:
            # For wheel events, we need to check the widget that receives the event
            # QWheelEvent doesn't have a target() method, so we use the obj parameter
            target = obj
            
            if target:
                # Check if the target is a combo box or its popup list
                if isinstance(target, QComboBox) or hasattr(target, 'parent') and isinstance(target.parent(), QComboBox):
                    # Allow the combo box to handle its own scroll events
                    return False
                
                # Check if we're inside a combo box popup
                parent = target.parent()
                while parent:
                    if isinstance(parent, QComboBox):
                        # Allow combo box scroll events
                        return False
                    parent = parent.parent()
                
                # For other widgets, allow normal scroll behavior
                return False
        
        # For all other events, use default behavior
        return super().eventFilter(obj, event)
    
