    def update_template_info(self):
        """Update template information display"""
        template_path = self.template_path_field.text()
        if template_path and os.path.exists(template_path):
            try:
                # Use the template manager to validate and get info
                is_valid, message = self.template_manager.template_config.validate_template(template_path)
                if is_valid:
                    doc = self.template_manager.template_config.load_template(template_path)
                    if doc:
                        has_headers = len(doc.sections) > 0 and doc.sections[0].header.paragraphs
                        has_footers = len(doc.sections) > 0 and doc.sections[0].footer.paragraphs
                        
                        info_text = f"✅ Template loaded successfully\n"
                        info_text += f"📄 File: {os.path.basename(template_path)}\n"
                        info_text += f"📝 Headers: {'Yes' if has_headers else 'No'}\n"
                        info_text += f"📝 Footers: {'Yes' if has_footers else 'No'}\n"
                        info_text += f"🎨 Styles: {len(doc.styles)} available"
                        
                        self.template_info_label.setText(info_text)
                        self.template_info_label.setStyleSheet("color: #4caf50; font-style: normal; padding: 10px; background-color: #1a1a1a; border-radius: 4px; border: 1px solid #4caf50;")
                    else:
                        self.template_info_label.setText("❌ Failed to load template")
                        self.template_info_label.setStyleSheet("color: #f44336; font-style: normal; padding: 10px; background-color: #1a1a1a; border-radius: 4px; border: 1px solid #f44336;")
                else:
                    self.template_info_label.setText(f"❌ {message}")
                    self.template_info_label.setStyleSheet("color: #f44336; font-style: normal; padding: 10px; background-color: #1a1a1a; border-radius: 4px; border: 1px solid #f44336;")
                    
            except Exception as e:
                self.template_info_label.setText(f"❌ Error loading template: {str(e)}")
                self.template_info_label.setStyleSheet("color: #f44336; font-style: normal; padding: 10px; background-color: #1a1a1a; border-radius: 4px; border: 1px solid #f44336;")
        else:
            self.template_info_label.setText("No template file selected")
            self.template_info_label.setStyleSheet("color: #888; font-style: italic; padding: 10px; background-color: #2a2a2a; border-radius: 4px;")
            
    def create_document_from_template(self):
        """Create a document from the configured template"""
        try:
            # Configure the template manager with current settings
            header_config = {
                'left_text': self.header_left_text.text(),
                'center_text': self.header_center_text.text(),
                'right_text': self.header_right_text.text(),
                'logo_path': self.header_logo_path.text(),
                'show_logo': self.show_header_logo.isChecked()
            }
            
            footer_config = {
                'left_text': self.footer_left_text.text(),
                'center_text': self.footer_center_text.text(),
                'right_text': self.footer_right_text.text(),
                'address': self.footer_address.text(),
                'phone': self.footer_phone.text()
            }
            
            watermark_config = {
                'text': self.watermark_text.text(),
                'font_size': self.watermark_font_size.value(),
                'opacity': self.watermark_opacity.value(),
                'rotation': self.watermark_rotation.value()
            }
            
            # Configure template manager
            success = self.template_manager.configure_template(
                template_path=self.template_path_field.text(),
                header_config=header_config,
                footer_config=footer_config,
                watermark_config=watermark_config
            )
            
            if not success:
                QMessageBox.critical(self, "Configuration Error", "Failed to configure template settings.")
                return
            
            # Create document
            doc = self.template_manager.create_document_from_template()
            if doc:
                # Add some test content
                doc.add_heading('Test Document', 0)
                doc.add_paragraph('This is a test document created with the template manager.')
                
                # Save the document
                output_path, _ = QFileDialog.getSaveFileName(
                    self,
                    "Save Test Document",
                    f"test_document_{datetime.now().strftime('%Y%m%d_%H%M%S')}.docx",
                    "Word Documents (*.docx)"
                )
                
                if output_path:
                    doc.save(output_path)
                    QMessageBox.information(self, "Success", f"Test document created successfully:\n{output_path}")
                else:
                    QMessageBox.information(self, "Cancelled", "Document creation cancelled.")
            else:
                QMessageBox.critical(self, "Error", "Failed to create document from template.")
                
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to create document: {str(e)}")
            
