    def validate_template_file(self):
        """Validate the selected template file"""
        template_path = self.template_path_field.text()
        if not template_path:
            QMessageBox.warning(self, "No Template", "Please select a template file first.")
            return
            
        # Use the template manager to validate
        is_valid, message = self.template_manager.template_config.validate_template(template_path)
        
        if is_valid:
            try:
                doc = self.template_manager.template_config.load_template(template_path)
                if doc:
                    has_headers = len(doc.sections) > 0 and doc.sections[0].header.paragraphs
                    has_footers = len(doc.sections) > 0 and doc.sections[0].footer.paragraphs
                    
                    validation_msg = f"✅ Template validation successful!\n\n"
                    validation_msg += f"📄 File: {os.path.basename(template_path)}\n"
                    validation_msg += f"📝 Headers: {'✅ Found' if has_headers else '❌ Not found'}\n"
                    validation_msg += f"📝 Footers: {'✅ Found' if has_footers else '❌ Not found'}\n"
                    validation_msg += f"🎨 Styles: {len(doc.styles)} available\n\n"
                    validation_msg += f"This template can be used for report generation."
                    
                    QMessageBox.information(self, "Template Validation", validation_msg)
                else:
                    QMessageBox.critical(self, "Validation Failed", "Failed to load template file.")
            except Exception as e:
                QMessageBox.critical(self, "Validation Failed", f"Template file is corrupted or invalid:\n{str(e)}")
        else:
            QMessageBox.critical(self, "Validation Failed", message)
            
    def get_template_configuration_data(self):
        """Get all template configuration data"""
        return {
            'template_path': self.template_path_field.text(),
            'header_config': {
                'left_text': self.header_left_text.text(),
                'center_text': self.header_center_text.text(),
                'right_text': self.header_right_text.text(),
                'logo_path': self.header_logo_path.text(),
                'show_logo': self.show_header_logo.isChecked()
            },
            'footer_config': {
                'left_text': self.footer_left_text.text(),
                'center_text': self.footer_center_text.text(),
                'right_text': self.footer_right_text.text(),
                'address': self.footer_address.text(),
                'phone': self.footer_phone.text()
            },
            'watermark_config': {
                'text': self.watermark_text.text(),
                'font_size': self.watermark_font_size.value(),
                'opacity': self.watermark_opacity.value(),
                'rotation': self.watermark_rotation.value()
            },
            'timestamp': datetime.now().isoformat()
        }
        
    def set_template_configuration_data(self, config):
        """Set template configuration data from dictionary"""
        try:
            # Set template path
            if 'template_path' in config:
                self.template_path_field.setText(config['template_path'])
                if config['template_path']:
                    self.update_template_info()
            
            # Set header config
            if 'header_config' in config:
                header = config['header_config']
                self.header_left_text.setText(header.get('left_text', ''))
                self.header_center_text.setText(header.get('center_text', ''))
                self.header_right_text.setText(header.get('right_text', ''))
                self.header_logo_path.setText(header.get('logo_path', ''))
                self.show_header_logo.setChecked(header.get('show_logo', False))
            
            # Set footer config
            if 'footer_config' in config:
                footer = config['footer_config']
                self.footer_left_text.setText(footer.get('left_text', ''))
                self.footer_center_text.setText(footer.get('center_text', ''))
                self.footer_right_text.setText(footer.get('right_text', ''))
                self.footer_address.setText(footer.get('address', ''))
                self.footer_phone.setText(footer.get('phone', ''))
            
            # Set watermark config
            if 'watermark_config' in config:
                watermark = config['watermark_config']
                self.watermark_text.setText(watermark.get('text', ''))
                self.watermark_font_size.setValue(watermark.get('font_size', 48))
                self.watermark_opacity.setValue(watermark.get('opacity', 0.3))
                self.watermark_rotation.setValue(watermark.get('rotation', -45))
                
        except Exception as e:
            logging.error(f"Failed to set template configuration data: {str(e)}")
            
    def get_default_template_configuration(self):
        """Get default template configuration"""
        # Return empty config since document_template_config is not available
        return {}
        
    def browse_template(self):
        """Browse for DOCX template file"""
        file_path, _ = QFileDialog.getOpenFileName(
            self,
            "Select DOCX Template",
            "",
            "Word Documents (*.docx);;All Files (*)"
        )
        
        if file_path:
            self.template_path_edit.setText(file_path)
        self.update_preview()
        
    def preview_template_document(self):
        """Preview the template document"""
        template_path = self.template_path_edit.text()
        if not template_path or not os.path.exists(template_path):
            QMessageBox.warning(self, "Template Error", "Please select a valid DOCX template file.")
            return
            
        try:
            # Open the template file for preview
            import subprocess
            import sys
            
            if sys.platform == "win32":
                os.startfile(template_path)
            elif sys.platform == "darwin":
                subprocess.run(["open", template_path])
            else:
                subprocess.run(["xdg-open", template_path])
        except Exception as e:
            QMessageBox.warning(self, "Preview Error", f"Could not open template file: {e}")
            
    def preview_styled_document(self):
        """Preview the document with current styling settings"""
        try:
            # Prepare configuration data
            config_data = self.prepare_config_data()
            
            # Create a temporary file for preview
            import tempfile
            temp_file = tempfile.NamedTemporaryFile(suffix='.docx', delete=False)
            temp_path = temp_file.name
            temp_file.close()
            
            # Generate the styled document
            from enhanced_document_generator import EnhancedDocumentManager
            success, message = EnhancedDocumentManager.generate_enhanced_report(config_data, temp_path)
            
            if success:
                # Open the document with the default system application
                import subprocess
                import platform
                
                if platform.system() == "Windows":
                    os.startfile(temp_path)
                elif platform.system() == "Darwin":  # macOS
                    subprocess.run(["open", temp_path])
                else:  # Linux
                    subprocess.run(["xdg-open", temp_path])
                    
                QMessageBox.information(self, "Preview", f"Styled document preview opened successfully!\n\nFile: {temp_path}")
            else:
                QMessageBox.critical(self, "Preview Error", f"Failed to generate preview:\n{message}")
                
        except Exception as e:
            QMessageBox.critical(self, "Preview Error", f"Failed to create preview:\n{str(e)}")


        
