    def launch_and_embed_libreoffice(self):
        """Launch LibreOffice Writer and embed it into the preview panel"""
        try:
            # First check if LibreOffice is installed
            is_installed, libreoffice_path = self.libreoffice_embedder.check_libreoffice_installation()
            
            if not is_installed:
                QMessageBox.warning(self, "LibreOffice Not Found", 
                                  "LibreOffice is not installed or not found in PATH.\n\n"
                                  "Please install LibreOffice from https://www.libreoffice.org/download/\n"
                                  "or ensure it's added to your system PATH.")
                return
            
            # Launch LibreOffice Writer
            if self.libreoffice_embedder.launch_libreoffice_writer():
                # Enable embed button
                self.embed_lo_btn.setEnabled(True)
                self.launch_lo_btn.setText("LibreOffice Launched")
                self.launch_lo_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #28a745;
                        color: #ffffff;
                        border: none;
                        border-radius: 4px;
                        padding: 8px 12px;
                        font-size: 11px;
                        font-weight: bold;
                    }
                """)
                
                # Auto-embed after successful launch and open template
                QTimer.singleShot(1000, self.embed_libreoffice_window)
            else:
                QMessageBox.warning(self, "Launch Failed", 
                                  f"Failed to launch LibreOffice Writer.\n\n"
                                  f"Found LibreOffice at: {libreoffice_path}\n"
                                  f"Please check the console output for detailed error information.")
                
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Error launching LibreOffice: {str(e)}")
    
    def embed_libreoffice_window(self):
        """Embed the LibreOffice Writer window into the preview panel"""
        try:
            # Hide the preview browser
            self.preview_browser.hide()
            
            # Embed the LibreOffice window
            if self.libreoffice_embedder.embed_window(self.preview_content_layout):
                # Update button states
                self.embed_lo_btn.setEnabled(False)
                self.remove_lo_btn.setEnabled(True)
                self.embed_lo_btn.setText("✅ Embedded")
                
                # Open the uploaded template document if available
                template_path = self.template_path_edit.text()
                if template_path and os.path.exists(template_path):
                    # Wait a moment for LibreOffice to fully load, then open the document
                    QTimer.singleShot(2000, lambda: self.open_template_in_libreoffice(template_path))
                
                QMessageBox.information(self, "Success", 
                                      "LibreOffice Writer has been embedded into the preview panel!")
            else:
                # Show preview browser again if embedding failed
                self.preview_browser.show()
                QMessageBox.warning(self, "Embed Failed", 
                                  "Failed to embed LibreOffice Writer window.")
                
        except Exception as e:
            # Show preview browser again if embedding failed
            self.preview_browser.show()
            QMessageBox.critical(self, "Error", f"Error embedding LibreOffice: {str(e)}")
    
    def remove_libreoffice_window(self):
        """Remove the embedded LibreOffice Writer window"""
        try:
            # Remove the embedded window
            self.libreoffice_embedder.remove_embedded_window()
            
            # Show the preview browser again
            self.preview_browser.show()
            
            # Update button states
            self.embed_lo_btn.setEnabled(True)
            self.remove_lo_btn.setEnabled(False)
            self.embed_lo_btn.setText("🔗 Embed Writer")
            
            QMessageBox.information(self, "Removed", 
                                  "LibreOffice Writer window has been removed from the preview panel.")
                
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Error removing LibreOffice: {str(e)}")
    
    def open_template_in_libreoffice(self, template_path):
        """Open the template document in the embedded LibreOffice"""
        try:
            # Check if template file exists
            if not os.path.exists(template_path):
                QMessageBox.warning(self, "File Not Found", f"Template file not found: {template_path}")
                return
            
            # Get LibreOffice path
            is_installed, libreoffice_path = self.libreoffice_embedder.check_libreoffice_installation()
            if not is_installed:
                QMessageBox.warning(self, "LibreOffice Not Found", 
                                  "LibreOffice is not installed or not found in PATH.")
                return
            
            # Since the LibreOfficeEmbedder doesn't have document opening methods,
            # we need to close the current LibreOffice and relaunch it with the document
            if self.libreoffice_embedder.is_embedded:
                # Remove the embedded window
                self.libreoffice_embedder.remove_embedded_window()
                # Close LibreOffice
                self.libreoffice_embedder.close_libreoffice()
            
            # Launch LibreOffice with the template document
            import subprocess
            import platform
            
            # Convert path to absolute path and normalize
            abs_template_path = os.path.abspath(template_path)
            
            if platform.system() == "Windows":
                # On Windows, use the found LibreOffice path
                if libreoffice_path.endswith('.exe'):
                    libreoffice_cmd = [libreoffice_path, '--writer', abs_template_path]
                else:
                    libreoffice_cmd = [libreoffice_path, '--writer', abs_template_path]
                
                self.libreoffice_embedder.libreoffice_process = subprocess.Popen(
                    libreoffice_cmd,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    creationflags=subprocess.CREATE_NO_WINDOW
                )
            else:
                # On other platforms
                libreoffice_cmd = [libreoffice_path, '--writer', abs_template_path]
                self.libreoffice_embedder.libreoffice_process = subprocess.Popen(libreoffice_cmd)
            
            # Wait for LibreOffice to start
            time.sleep(3)
            
            # Find the new LibreOffice window
            self.libreoffice_embedder.window_id = self.libreoffice_embedder.find_libreoffice_window()
            
            if self.libreoffice_embedder.window_id:
                # Re-embed the window with the document
                if self.libreoffice_embedder.embed_window(self.preview_content_layout):
                    QMessageBox.information(self, "Success", 
                                          f"Template document '{os.path.basename(template_path)}' loaded in LibreOffice!")
                else:
                    QMessageBox.warning(self, "Warning", "LibreOffice launched with document but embedding failed.")
            else:
                QMessageBox.warning(self, "Warning", "LibreOffice launched with document but window not found.")
                
        except Exception as e:
            QMessageBox.warning(self, "Warning", f"Could not open template in LibreOffice: {str(e)}")
        
