    def update_dut_placeholder_display(self):
        """Update the placeholder display for DUT Details section"""
        try:
            if not hasattr(self, 'dut_placeholder_display'):
                return
            
            placeholder_list = self.dut_placeholder_display
            placeholder_list.clear()
            
            # Get placeholders for DUT Details section
            dut_placeholders = self._get_dut_config_placeholders_for_section("DUT Details")
            
            if dut_placeholders:
                for placeholder_info in dut_placeholders:
                    if isinstance(placeholder_info, dict) and 'placeholder' in placeholder_info:
                        placeholder_name = placeholder_info['placeholder']
                        
                        # Create custom widget for each placeholder
                        placeholder_widget = QWidget()
                        placeholder_layout = QHBoxLayout(placeholder_widget)
                        placeholder_layout.setContentsMargins(8, 6, 8, 6)
                        placeholder_layout.setSpacing(8)
                        
                        # Placeholder label
                        placeholder_label = QLabel(f"📄 {placeholder_name}")
                        placeholder_label.setStyleSheet("""
                            QLabel {
                                color: #ffffff;
                                font-size: 12px;
                                font-weight: bold;
                                padding: 8px;
                                background-color: #3c3c3e;
                                border: 1px solid #555555;
                                border-radius: 4px;
                            }
                        """)
                        placeholder_layout.addWidget(placeholder_label)
                        
                        # Remove button
                        remove_btn = QPushButton("Remove")
                        remove_btn.setMinimumSize(60, 25)
                        remove_btn.setMaximumSize(80, 25)
                        remove_btn.setStyleSheet("""
                            QPushButton {
                                background-color: #d32f2f;
                                color: #ffffff;
                                border: none;
                                border-radius: 4px;
                                font-size: 10px;
                                font-weight: bold;
                                padding: 4px 8px;
                            }
                            QPushButton:hover {
                                background-color: #b71c1c;
                            }
                            QPushButton:pressed {
                                background-color: #a00000;
                            }
                        """)
                        remove_btn.clicked.connect(lambda checked, p=placeholder_info: self.remove_placeholder_from_dut_config(p, "DUT Details"))
                        placeholder_layout.addWidget(remove_btn)
                        
                        placeholder_layout.addStretch()
                        
                        # Create list item with custom widget
                        item = QListWidgetItem()
                        item.setSizeHint(placeholder_widget.sizeHint())
                        placeholder_list.addItem(item)
                        placeholder_list.setItemWidget(item, placeholder_widget)
            else:
                empty_item = QListWidgetItem("No placeholders added for DUT Details yet")
                empty_item.setData(Qt.ItemDataRole.UserRole, "empty")
                placeholder_list.addItem(empty_item)
                
        except Exception as e:
            print(f"DEBUG: Error updating DUT placeholder display: {e}")
    
