    def _get_dut_config_placeholders_for_section(self, section_name):
        """Get placeholders for a specific DUT Configuration section"""
        try:
            if hasattr(self, 'scenario_placeholders') and self.scenario_placeholders:
                return self.scenario_placeholders.get(section_name, [])
            return []
        except Exception as e:
            print(f"DEBUG: Error getting DUT config placeholders for '{section_name}': {e}")
            return []
    
    def remove_placeholder_from_dut_config(self, placeholder_info, section_name):
        """Remove a placeholder from a specific DUT Configuration section"""
        try:
            if hasattr(self, 'scenario_placeholders') and section_name in self.scenario_placeholders:
                if placeholder_info in self.scenario_placeholders[section_name]:
                    self.scenario_placeholders[section_name].remove(placeholder_info)
                    print(f"DEBUG: Removed placeholder '{placeholder_info['placeholder']}' from DUT config section '{section_name}'")
            
            if hasattr(self, 'automatic_images') and placeholder_info in self.automatic_images:
                self.automatic_images.remove(placeholder_info)
                print(f"DEBUG: Removed placeholder '{placeholder_info['placeholder']}' from global list")
            
            # Update all DUT config placeholder displays
            self.update_dut_placeholder_display()
            self.update_hash_sections_placeholder_display()
            self.update_itsar_placeholder_display()
            
            QMessageBox.information(
                self,
                "Placeholder Removed",
                f"Placeholder '{placeholder_info['placeholder']}' has been removed from {section_name}."
            )
        except Exception as e:
            print(f"DEBUG: Error removing placeholder from DUT config: {e}")
            QMessageBox.warning(self, "Error", f"Failed to remove placeholder: {e}")
        
    def add_dut_field(self):
        """Add a new dynamic DUT field pair"""
        # Create label edit
        label_edit = QLineEdit()
        label_edit.setText(f"Field {len(self.dut_fields) + 1}:")
        label_edit.setStyleSheet("""
            QLineEdit {
                background-color: #232b3b;
                color: #ffffff;
                border: 1px solid #444444;
                border-radius: 4px;
                padding: 8px;
                font-size: 12px;
                caret-color: #ffffff;
                caret-color: #ffffff;
            }
            QLineEdit:hover {
                border: 2px solid #4fc3f7;
                background-color: #2a3441;
            }
            
            QLineEdit:focus {
                border-color: #2196f3;
            }
        """)
        
        # Create value edit
        value_edit = QLineEdit()
        value_edit.setPlaceholderText("Enter value...")
        value_edit.setStyleSheet("""
            QLineEdit {
                background-color: #232b3b;
                color: #ffffff;
                border: 1px solid #444444;
                border-radius: 4px;
                padding: 8px;
                font-size: 12px;
            caret-color: #ffffff;
            }
            QLineEdit:hover {
                border: 2px solid #4fc3f7;
                background-color: #2a3441;
            }
            QLineEdit:focus {
                border-color: #2196f3;
            }
        """)
        
        # Create Skip button
        skip_button = QPushButton("Skip")
        skip_button.setMaximumWidth(60)
        skip_button.setStyleSheet("""
            QPushButton {
                background-color: #28a745;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                padding: 4px 8px;
                font-size: 12px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #218838;
            }
            QPushButton:pressed {
                background-color: #1e7e34;
            }
        """)
        
        # Create remove button
        remove_button = QPushButton("🗑️")
        remove_button.setMaximumWidth(40)
        remove_button.setStyleSheet("""
            QPushButton {
                background-color: #d32f2f;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                padding: 4px;
                font-size: 12px;
            }
            QPushButton:hover {
                background-color: #b71c1c;
            }
        """)
        
        # Store field info
        field_info = {
            'label_edit': label_edit,
            'value_edit': value_edit,
            'skip_button': skip_button,
            'remove_button': remove_button,
            'field_type': 'dut'  # Add field type for identification
        }
        
        # Connect Skip button
        skip_button.clicked.connect(lambda: self.skip_dut_field(field_info))
        
        # Connect remove button
        remove_button.clicked.connect(lambda: self.remove_dut_field(field_info))
        
        # Connect to live preview
        label_edit.textChanged.connect(self.trigger_live_preview_update)
        value_edit.textChanged.connect(self.trigger_live_preview_update)
        
        # Add to form layout
        self.dut_form_layout.addRow(label_edit, value_edit)
        
        # Add Skip and remove buttons to the same row
        # We need to create a horizontal layout for the value, dropdown, skip button, and remove button
        value_layout = QHBoxLayout()
        value_layout.addWidget(value_edit)
        
        # Add upload functionality to the field
        self.add_upload_buttons_to_field(field_info, "dut")
        
        # Add upload dropdown to layout (near input box, before skip button)
        value_layout.addWidget(field_info['upload_dropdown_btn'])
        value_layout.addWidget(skip_button)
        value_layout.addWidget(remove_button)
        
        # Create a vertical layout to hold the value layout and the file containers
        field_container = QWidget()
        field_layout = QVBoxLayout(field_container)
        
        # Add the value layout (with input, dropdown, skip, remove buttons)
        field_layout.addLayout(value_layout)
        
        # Add display containers for uploaded files (similar to sections 1-7)
        # Scripts container
        field_info['scripts_container'] = QWidget()
        field_info['scripts_layout'] = QVBoxLayout(field_info['scripts_container'])
        field_info['scripts_list'] = []  # Store script info
        
        # Images container
        field_info['images_container'] = QWidget()
        field_info['images_layout'] = QVBoxLayout(field_info['images_container'])
        field_info['images_list'] = []  # Store image info
        
        # Add containers to the field layout (not form layout)
        field_layout.addWidget(field_info['scripts_container'])
        field_layout.addWidget(field_info['images_container'])
        
        # Remove the previous row and add the new one with the field container
        self.dut_form_layout.removeRow(value_edit)
        self.dut_form_layout.addRow(label_edit, field_container)
        
        # Add to fields list
        self.dut_fields.append(field_info)
        
        # Connect text change events
        label_edit.textChanged.connect(self.update_preview)
        value_edit.textChanged.connect(self.update_preview)
        
        return field_info

