    def add_upload_buttons_to_field(self, field_info, field_type="dut"):
        """Add upload dropdown menu to any field"""
        print(f"DEBUG: add_upload_buttons_to_field called for field_type: {field_type}")
        # Create dropdown button
        upload_dropdown_btn = QPushButton("▼")
        upload_dropdown_btn.setMaximumWidth(40)
        upload_dropdown_btn.setStyleSheet("""
            QPushButton {
                background-color: #6c757d;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                padding: 4px;
                font-size: 12px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #5a6268;
            }
        """)
        
        # Create dropdown menu
        upload_menu = QMenu()
        upload_menu.setStyleSheet("""
            QMenu {
                background-color: #2b2b2b;
                color: #ffffff;
                border: 1px solid #444444;
                border-radius: 4px;
                padding: 4px;
            }
            QMenu::item {
                padding: 8px 16px;
                border-radius: 2px;
            }
            QMenu::item:selected {
                background-color: #007bff;
            }
            QMenu::separator {
                height: 1px;
                background-color: #444444;
                margin: 4px 0px;
            }
        """)
        
        # Add menu items
        upload_image_action = upload_menu.addAction("📷 Upload Image")
        upload_menu.addSeparator()
        upload_script_action = upload_menu.addAction("📁 Upload Script")
        upload_menu.addSeparator()
        add_placeholder_action = upload_menu.addAction("➕ New Placeholder")
        upload_menu.addSeparator()
        add_note_action = upload_menu.addAction("📝 Add Note")
        
        # Connect dropdown button to menu
        upload_dropdown_btn.setMenu(upload_menu)
        
        # Store upload components in field_info
        field_info['upload_dropdown_btn'] = upload_dropdown_btn
        field_info['upload_menu'] = upload_menu
        field_info['field_type'] = field_type
        
        # Initialize upload lists
        field_info['images_list'] = []
        field_info['scripts_list'] = []
        field_info['notes_list'] = []
        
        # For sections 1, 2, 3, 7, we'll handle the lists in the upload methods
        # since the section-specific lists are created after this method is called
        
        # Connect menu actions to their respective functions
        upload_image_action.triggered.connect(lambda: self.upload_field_image(field_info))
        upload_script_action.triggered.connect(lambda: self.upload_field_script(field_info))
        add_placeholder_action.triggered.connect(lambda: self.add_field_placeholder(field_info))
        add_note_action.triggered.connect(lambda: self.add_field_note(field_info))
        
        # Show dropdown when field is focused
        if 'value_edit' in field_info:
            field_info['value_edit'].focusInEvent = lambda event: self.show_field_upload_dropdown(field_info)
            field_info['value_edit'].focusOutEvent = lambda event: self.hide_field_upload_dropdown(field_info)
        
        # For hash fields and DUT fields, show dropdown by default
        if field_type in ["hash", "direct_hash", "dut"]:
            field_info['upload_dropdown_btn'].show()
    
    def show_field_upload_dropdown(self, field_info):
        """Show upload dropdown for field"""
        if 'upload_dropdown_btn' in field_info:
            field_info['upload_dropdown_btn'].show()
    
    def hide_field_upload_dropdown(self, field_info):
        """Hide upload dropdown for field"""
        if 'upload_dropdown_btn' in field_info:
            field_info['upload_dropdown_btn'].hide()
    
    def upload_field_image(self, field_info):
        """Upload image for field"""
        print(f"DEBUG: upload_field_image called for field_type: {field_info.get('field_type', 'Field')}")
        file_path, _ = QFileDialog.getOpenFileName(
            self,
            f"Select Image for {field_info.get('field_type', 'Field')}",
            "",
            "Image Files (*.png *.jpg *.jpeg *.bmp *.gif)"
        )
        
        if file_path:
            # Validate file extension
            valid_extensions = ['.png', '.jpg', '.jpeg', '.bmp', '.gif']
            if not any(file_path.lower().endswith(ext) for ext in valid_extensions):
                QMessageBox.warning(self, "Invalid File", "Please select a valid image file")
                return
            
            # Copy file to rawlogs directory with original filename
            original_filename = os.path.basename(file_path)
            field_type = field_info.get('field_type', 'field')

            # Use the correct rawlogs folder path
            rawlogs_dir = self.get_rawlogs_folder_path()
            unique_filename = self.get_unique_filename(rawlogs_dir, original_filename)
            tmp_path = os.path.join(rawlogs_dir, unique_filename)
            
            try:
                shutil.copy2(file_path, tmp_path)
                print(f"Copied {file_path} to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to copy file: {e}")
                return
            
            # Create relative path for JSON storage
            testcase_name = self.get_test_case_title()
            import re
            # First replace forward slashes with underscores to prevent path splitting
            clean_name = testcase_name.replace('/', '_')
            # Then replace other invalid characters
            clean_name = re.sub(r'[<>:"\\|?*]', '_', clean_name)
            clean_name = clean_name.strip()
            if not clean_name:
                clean_name = "test_case"
            relative_path = f"tmp/{clean_name}/rawlogs/{unique_filename}"

            image_info = {
                'path': relative_path,  # Store relative path for JSON
                'absolute_path': tmp_path,  # Store absolute path for UI
                'filename': unique_filename,
                'original_filename': original_filename,
                'description': '',
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create image widget
            image_widget = QWidget()
            image_layout = QHBoxLayout(image_widget)
            
            # Filename label
            filename_label = QLabel(f"📷 {original_filename}")
            filename_label.setStyleSheet("color: #17a2b8; font-weight: bold;")
            image_layout.addWidget(filename_label)
            
            # Remove button
            image_info['remove_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            # Use closure to capture field_info and image_info by value
            def create_remove_handler(field_info_param, image_info_param):
                return lambda: self.remove_field_image(field_info_param, image_info_param)
            image_info['remove_btn'].clicked.connect(create_remove_handler(field_info, image_info))
            image_layout.addWidget(image_info['remove_btn'])
            
            image_layout.addStretch()
            
            # Add display widget to the appropriate container for sections 1, 2, 3, 7, dut, itsar
            field_type = field_info.get('field_type')
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
                # For sections 1-7, only add to section-specific lists (not field lists)
                if hasattr(self, 'sections_1_7_manager'):
                    sections_manager = self.sections_1_7_manager
                    
                    if field_type == 'section_1' and hasattr(sections_manager, 'section_1_images_layout'):
                        sections_manager.section_1_images_layout.addWidget(image_widget)
                        if hasattr(sections_manager, 'section_1_images_list'):
                            sections_manager.section_1_images_list.append(image_info)
                    elif field_type == 'section_2' and hasattr(sections_manager, 'section_2_images_layout'):
                        sections_manager.section_2_images_layout.addWidget(image_widget)
                        if hasattr(sections_manager, 'section_2_images_list'):
                            sections_manager.section_2_images_list.append(image_info)
                    elif field_type == 'section_3' and hasattr(sections_manager, 'section_3_images_layout'):
                        sections_manager.section_3_images_layout.addWidget(image_widget)
                        if hasattr(sections_manager, 'section_3_images_list'):
                            sections_manager.section_3_images_list.append(image_info)
                    elif field_type == 'section_7' and hasattr(sections_manager, 'section_7_images_layout'):
                        sections_manager.section_7_images_layout.addWidget(image_widget)
                        if hasattr(sections_manager, 'section_7_images_list'):
                            sections_manager.section_7_images_list.append(image_info)
            elif field_type in ['dut', 'itsar', 'hash', 'direct_hash', 'evidence']:
                # For DUT, ITSAR, hash fields, and evidence, add to their own containers
                if 'images_layout' in field_info:
                    field_info['images_layout'].addWidget(image_widget)
                    if 'images_list' in field_info:
                        field_info['images_list'].append(image_info)
            elif field_type == 'expected_result':
                # For expected results, add to their own containers
                if 'images_layout' in field_info:
                    field_info['images_layout'].addWidget(image_widget)
                    if 'images_list' in field_info:
                        field_info['images_list'].append(image_info)
                
                # Also store in the scenario's expected_result_field_info for proper export
                scenario_key_edit = field_info.get('scenario_key_edit')
                if scenario_key_edit:
                    # Find the scenario in test_scenarios list
                    for scenario in self.test_scenarios:
                        if scenario.get('key_edit') == scenario_key_edit:
                            # Initialize expected_result_field_info if it doesn't exist
                            if 'expected_result_field_info' not in scenario:
                                scenario['expected_result_field_info'] = {
                                    'images_list': [],
                                    'scripts_list': []
                                }
                            
                            # Add the image to the scenario's expected_result_field_info
                            if 'images_list' not in scenario['expected_result_field_info']:
                                scenario['expected_result_field_info']['images_list'] = []
                            scenario['expected_result_field_info']['images_list'].append(image_info)
                            print(f"DEBUG: Added image to scenario {scenario['key_edit'].text()} expected_result_field_info: {image_info['filename']}")
                            break
            elif field_type == 'test_bed_diagram':
                # For test bed diagram, add to the test bed images container
                print(f"DEBUG: Processing test_bed_diagram image upload")
                print(f"DEBUG: Has test_bed_images_layout: {hasattr(self, 'test_bed_images_layout')}")
                print(f"DEBUG: Has test_bed_diagram_data: {hasattr(self, 'test_bed_diagram_data')}")
                print(f"DEBUG: Has test_bed_images: {hasattr(self, 'test_bed_images')}")
                
                if hasattr(self, 'test_bed_images_layout'):
                    self.test_bed_images_layout.addWidget(image_widget)
                    print(f"DEBUG: Added image widget to test_bed_images_layout")
                    # Store in new structure
                    if hasattr(self, 'test_bed_diagram_data'):
                        self.test_bed_diagram_data['images'].append(image_info)
                        print(f"DEBUG: Added image to new structure: {image_info['filename']}")
                        print(f"DEBUG: New structure now has {len(self.test_bed_diagram_data['images'])} images")
                    else:
                        print(f"DEBUG: ERROR - test_bed_diagram_data structure not found!")
                    # Also store in old structure for backward compatibility
                    if hasattr(self, 'test_bed_images'):
                        self.test_bed_images.append(image_info)
            elif field_type == 'test_scenario':
                # For test scenarios, add to the scenario's images list
                # Find the scenario that this field belongs to
                scenario_key_edit = field_info.get('key_edit')
                if scenario_key_edit:
                    # Find the scenario in test_scenarios list
                    for scenario in self.test_scenarios:
                        if scenario.get('key_edit') == scenario_key_edit:
                            # Initialize images list if it doesn't exist
                            if 'images' not in scenario:
                                scenario['images'] = []
                            scenario['images'].append(image_info)
                            
                            # Create a container for images if it doesn't exist
                            if 'images_layout' not in scenario:
                                scenario['images_layout'] = QVBoxLayout()
                                # Add the images layout to the scenario widget
                                scenario_widget = scenario_key_edit.parent()
                                if scenario_widget:
                                    scenario_widget.layout().addLayout(scenario['images_layout'])
                            
                            scenario['images_layout'].addWidget(image_widget)
                            break
            elif field_type == 'tool_required':
                # For tools required, add to the tool's images list
                # Find the tool that this field belongs to
                value_edit = field_info.get('value_edit')
                if value_edit:
                    # Find the tool in tools_required list
                    for tool in self.tools_required:
                        if tool.get('tool_edit') == value_edit:
                            # Initialize images list if it doesn't exist
                            if 'images' not in tool:
                                tool['images'] = []
                            tool['images'].append(image_info)
                            
                            # Create a container for images if it doesn't exist
                            if 'images_layout' not in tool:
                                tool['images_layout'] = QVBoxLayout()
                                # Add the images layout to the tool widget
                                tool_widget = tool['tool_edit'].parent()
                                if tool_widget:
                                    tool_widget.layout().addLayout(tool['images_layout'])
                            
                            tool['images_layout'].addWidget(image_widget)
                            print(f"DEBUG: Added image to tool: {tool.get('tool_edit', '').text()}")
                            break
                else:
                        print(f"DEBUG: Tool not found for value_edit: {value_edit}")
                        print(f"DEBUG: Available tools: {[tool.get('tool_edit', '').text() for tool in self.tools_required]}")
            elif field_type == 'execution_step':
                print(f"DEBUG: ===== EXECUTION STEP IMAGE UPLOAD HANDLING =====")
                # For execution steps, add to the step's images list
                # Find the step that this field belongs to
                value_edit = field_info.get('value_edit')
                print(f"DEBUG: Execution step value_edit: {value_edit}")
                print(f"DEBUG: Execution step value_edit type: {type(value_edit)}")
                
                if value_edit:
                    print(f"DEBUG: Looking for execution step in test_scenarios...")
                    print(f"DEBUG: self.test_scenarios: {self.test_scenarios}")
                
                    # Find the step in test_scenarios list (execution steps are part of scenarios)
                    for scenario_index, scenario in enumerate(self.test_scenarios):
                        print(f"DEBUG: Checking scenario {scenario_index}: {scenario}")
                        for step_index, step in enumerate(scenario.get('steps', [])):
                            print(f"DEBUG: Checking step {step_index}: {step}")
                            print(f"DEBUG: step.get('step_edit'): {step.get('step_edit')}")
                            print(f"DEBUG: Comparing with value_edit: {value_edit}")
                            
                            if step.get('step_edit') == value_edit:
                                print(f"DEBUG: Found matching execution step!")
                                # Initialize images list if it doesn't exist
                                if 'images' not in step:
                                    step['images'] = []
                                    print(f"DEBUG: Initialized images list for step")
                                
                                step['images'].append(image_info)
                                print(f"DEBUG: Added image_info to step images: {image_info}")
                                
                                # Create a container for images if it doesn't exist
                                if 'images_layout' not in step:
                                    step['images_layout'] = QVBoxLayout()
                                    print(f"DEBUG: Created images_layout for step")
                                    # Add the images layout to the step widget
                                    step_widget = step['step_edit'].parent()
                                    if step_widget:
                                        step_widget.layout().addLayout(step['images_layout'])
                                        print(f"DEBUG: Added images_layout to step widget")
                                
                                step['images_layout'].addWidget(image_widget)
                                print(f"DEBUG: Added image widget to step images_layout")
                                print(f"DEBUG: Added image to execution step: {step.get('step_edit', '').text()}")
                                break
                        else:
                            continue
                    else:
                        print(f"DEBUG: Execution step not found for value_edit: {value_edit}")
                        print(f"DEBUG: Available execution steps: {[step.get('step_edit', '').text() for scenario in self.test_scenarios for step in scenario.get('steps', [])]}")
                else:
                    print(f"DEBUG: No value_edit found for execution step")
                print(f"DEBUG: ===== EXECUTION STEP IMAGE UPLOAD HANDLING COMPLETED =====")
            
            QMessageBox.information(
                self,
                "Image Uploaded",
                f"Image '{original_filename}' uploaded and copied to tmp directory.\n\n"
                f"File stored at: {tmp_path}\n"
                f"Relative path: {relative_path}\n"
                f"Field type: {field_type}"
            )
    
    def remove_field_image(self, field_info, image_info):
        """Remove an image from field"""
        field_type = field_info.get('field_type')
        
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
            # For sections 1-7, images are only stored in section-specific lists
            if hasattr(self, 'sections_1_7_manager'):
                sections_manager = self.sections_1_7_manager
                
                if field_type == 'section_1' and hasattr(sections_manager, 'section_1_images_list'):
                    if image_info in sections_manager.section_1_images_list:
                        sections_manager.section_1_images_list.remove(image_info)
