    def remove_restored_image(self, image_info, container, layout):
        """Remove a restored image from container"""
        # Remove from images_list if it exists
        if hasattr(container, 'images_list') and image_info in container.images_list:
            container.images_list.remove(image_info)
        
        # Remove widget from layout
        for i in range(layout.count()):
            widget = layout.itemAt(i).widget()
            if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                widget.setParent(None)
                break
    
    def remove_restored_script(self, script_info, container, layout):
        """Remove a restored script from container"""
        # Remove from scripts_list if it exists
        if hasattr(container, 'scripts_list') and script_info in container.scripts_list:
            container.scripts_list.remove(script_info)
        
        # Remove widget from layout
        for i in range(layout.count()):
            widget = layout.itemAt(i).widget()
            if widget and widget.findChild(QLabel) and script_info['filename'] in widget.findChild(QLabel).text():
                widget.setParent(None)
                break
    
    def upload_field_script(self, field_info):
        """Upload script for field - UPLOAD METHOD"""
        print(f"DEBUG: upload_field_script called for field_type: {field_info.get('field_type', 'Field')}")
        # Debug: Print field info to see what we're working with
        print(f"DEBUG: Upload field script called with field_type: {field_info.get('field_type', 'unknown')}")
        print(f"DEBUG: Field info keys: {list(field_info.keys())}")
        
        # Check if test_bed_diagram_data structure exists
        if hasattr(self, 'test_bed_diagram_data'):
            print(f"DEBUG: test_bed_diagram_data exists at start of upload: {self.test_bed_diagram_data}")
        else:
            print(f"DEBUG: ERROR - test_bed_diagram_data does not exist at start of upload!")
            # Try to initialize it
            self.test_bed_diagram_data = {
                'heading': '8.2. Test Bed Diagram',
                'images': [],
                'scripts': []
            }
            print(f"DEBUG: Re-initialized test_bed_diagram_data: {self.test_bed_diagram_data}")
        if field_info.get('field_type') == 'execution_step':
            print(f"DEBUG: Execution step field_info contains scenario_key_text: {field_info.get('scenario_key_text', 'NOT FOUND')}")
        
        # Show custom dialog with skip button - UPLOAD METHOD ONLY
        result = self.show_placeholder_dialog(self)
        
        if not result["ok"] and not result["skip"]:
            return
            
        placeholder = result["description"]
        # Use the field text as the question name
        field_type = field_info.get('field_type', 'field')
        
        # Special handling for execution steps - check first!
        if field_type == 'execution_step' and field_info.get('scenario_key_text'):
            field_text = field_info['scenario_key_text']
            print(f"DEBUG: Using scenario key text for execution step: '{field_text}'")
            subheading = field_text
            # Skip the rest of the logic and go directly to file dialog
            file_path, _ = QFileDialog.getOpenFileName(self, "Select Python Script", "", "Python Files (*.py)")
            if not file_path:
                return
        
        # Handle different widget types
        if field_info.get('value_edit'):
            value_edit = field_info['value_edit']
            if hasattr(value_edit, 'text'):  # QLineEdit
                field_text = value_edit.text().strip()
            elif hasattr(value_edit, 'toPlainText'):  # QTextEdit/ContextMenuTextEdit
                field_text = value_edit.toPlainText().strip()
            else:
                field_text = f"Section {field_type.split('_')[-1]}"
        else:
            field_text = f"Section {field_type.split('_')[-1]}"
        
        # Special handling for Sections 1, 2, 3, 7: Use the heading value from the section heading field
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7'] and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                # Default fallbacks for each section
                if field_type == 'section_1':
                    field_text = "ITSAR Section No & Name"
                elif field_type == 'section_2':
                    field_text = "Security Requirement No & Name"
                elif field_type == 'section_3':
                    field_text = "Requirement Description"
                else:  # section_7
                    field_text = "Test Objective"
            if not field_text:
                # Default fallbacks for each section
                if field_type == 'section_1':
                    field_text = "ITSAR Section No & Name"
                elif field_type == 'section_2':
                    field_text = "Security Requirement No & Name"
                elif field_type == 'section_3':
                    field_text = "Requirement Description"
                else:  # section_7
                    field_text = "Test Objective"
        
        # Special handling for DUT fields: Use the label value from the label field
        elif field_type == 'dut' and field_info.get('label_edit'):
            label_edit = field_info['label_edit']
            if hasattr(label_edit, 'text'):
                field_text = label_edit.text().strip()
            else:
                field_text = "DUT Field"
            if not field_text:
                field_text = "DUT Field"
        
        # Special handling for ITSAR fields: Use the key value from the key field
        elif field_type == 'itsar' and field_info.get('key_edit'):
            key_edit = field_info['key_edit']
            if hasattr(key_edit, 'text'):
                field_text = key_edit.text().strip()
            else:
                field_text = "ITSAR Field"
            if not field_text:
                field_text = "ITSAR Field"
        
        # Special handling for hash fields: Use the hash name from the hash_name_edit field
        elif field_type == 'hash' and field_info.get('hash_name_edit'):
            hash_name_edit = field_info['hash_name_edit']
            if hasattr(hash_name_edit, 'text'):
                field_text = hash_name_edit.text().strip()
            else:
                field_text = "Hash Field"
            if not field_text:
                field_text = "Hash Field"
        
        # Special handling for direct hash fields: Use the heading from the section
        elif field_type == 'direct_hash':
            # For direct hash fields, we need to get the heading from the parent section
            # Look for the heading_edit in the field info
            if field_info.get('heading_edit'):
                heading_edit = field_info['heading_edit']
                if hasattr(heading_edit, 'text'):
                    field_text = heading_edit.text().strip()
                else:
                    field_text = "Direct Hash Value"
            else:
                field_text = "Direct Hash Value"
            if not field_text:
                field_text = "Direct Hash Value"
        
        # Special handling for Section 8 Test Scenario fields: Use the key value from the key field
        elif field_type == 'test_scenario' and field_info.get('key_edit'):
            key_edit = field_info['key_edit']
            if hasattr(key_edit, 'text'):
                field_text = key_edit.text().strip()
            else:
                field_text = "Test Scenario"
            if not field_text:
                field_text = "Test Scenario"
        
        # Special handling for Section 8 Tool fields: Use the heading value from the heading field
        elif field_type == 'tool_required' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Tool Required"
            if not field_text:
                field_text = "Tool Required"
        
        # Special handling for Section 8 Execution Step fields: Use the step value directly
        elif field_type == 'execution_step' and field_info.get('value_edit'):
            value_edit = field_info['value_edit']
            if hasattr(value_edit, 'text'):
                field_text = value_edit.text().strip()
            else:
                field_text = "Execution Step"
            if not field_text:
                field_text = "Execution Step"
        
        # Special handling for Section 8 Evidence fields: Use the heading value from the heading field
        elif field_type == 'evidence' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Evidence"
            if not field_text:
                field_text = "Evidence"
        
        # Special handling for Section 8 Test Bed Diagram fields: Use the heading value from the heading field
        elif field_type == 'test_bed_diagram' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Test Bed Diagram"
            if not field_text:
                field_text = "Test Bed Diagram"
        
        # Special handling for Section 8 Execution Step fields: Use the scenario key as question text
        elif field_type == 'execution_step' and field_info.get('scenario_key_text'):
            field_text = field_info['scenario_key_text']
            print(f"DEBUG: Using scenario key text for execution step: '{field_text}'")
            if not field_text:
                field_text = "Execution Step"
                print(f"DEBUG: Field text was empty, using default: '{field_text}'")
        
        # Special handling for Section 8 Expected Result fields: Use the heading value from the heading field
        elif field_type == 'expected_result' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Expected Result"
            if not field_text:
                field_text = "Expected Result"
        
        subheading = field_text
        
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Select Python Script", "", "Python Files (*.py)"
        )
        
        if file_path:
            # Validate file extension
            if not file_path.lower().endswith('.py'):
                QMessageBox.warning(self, "Invalid File", "Please select a Python script (.py file)")
                return
            
            # Copy file to correct code folder: tmp/<testcase_name>/code/ with original filename
            original_filename = os.path.basename(file_path)
            field_type = field_info.get('field_type', 'field')
            
            # Use the correct code folder path
            code_dir = self.get_code_folder_path()
            unique_filename = self.get_unique_filename(code_dir, original_filename)
            tmp_path = os.path.join(code_dir, unique_filename)
            
            try:
                shutil.copy2(file_path, tmp_path)
                print(f"Copied {file_path} to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to copy file: {e}")
                return
            
            # Create relative path for JSON storage
            testcase_name = self.get_test_case_title()
            import re
            # First replace forward slashes with underscores to prevent path splitting
            clean_name = testcase_name.replace('/', '_')
            # Then replace other invalid characters
            clean_name = re.sub(r'[<>:"\\|?*]', '_', clean_name)
            clean_name = clean_name.strip()
            if not clean_name:
                clean_name = "test_case"
            relative_path = f"tmp/{clean_name}/code/{unique_filename}"
            
            # Generate script name with incremental numbering
            script_number = self.get_next_script_number()
            script_name = f"script{script_number}.py"
            
            script_info = {
                'path': relative_path,  # Store relative path for JSON
                'absolute_path': tmp_path,  # Store absolute path for UI
                'filename': unique_filename,
                'original_filename': original_filename,
                'description': placeholder,
                'subheading': subheading,
                'script_name': script_name,
                'is_pasted': False,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create script widget
            script_widget = QWidget()
            script_layout = QHBoxLayout(script_widget)
            
            # Filename label
            filename_label = QLabel(f"📄 {original_filename}")
            filename_label.setStyleSheet("color: #28a745; font-weight: bold;")
            script_layout.addWidget(filename_label)
            
            # Remove button
            script_info['remove_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            script_info['remove_btn'].clicked.connect(lambda: self.remove_field_script(field_info, script_info))
            script_layout.addWidget(script_info['remove_btn'])
            
            script_layout.addStretch()
            
            # Add display widget to the appropriate container for sections 1, 2, 3, 7, dut, itsar
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
                # For sections 1-7, only add to section-specific lists (not field lists)
                if hasattr(self, 'sections_1_7_manager'):
                    sections_manager = self.sections_1_7_manager
                    
                    if field_type == 'section_1' and hasattr(sections_manager, 'section_1_scripts_layout'):
                        sections_manager.section_1_scripts_layout.addWidget(script_widget)
                        if hasattr(sections_manager, 'section_1_scripts_list'):
                            sections_manager.section_1_scripts_list.append(script_info)
                    elif field_type == 'section_2' and hasattr(sections_manager, 'section_2_scripts_layout'):
                        sections_manager.section_2_scripts_layout.addWidget(script_widget)
                        if hasattr(sections_manager, 'section_2_scripts_list'):
                            sections_manager.section_2_scripts_list.append(script_info)
                    elif field_type == 'section_3' and hasattr(sections_manager, 'section_3_scripts_layout'):
                        sections_manager.section_3_scripts_layout.addWidget(script_widget)
                        if hasattr(sections_manager, 'section_3_scripts_list'):
                            sections_manager.section_3_scripts_list.append(script_info)
                    elif field_type == 'section_7' and hasattr(sections_manager, 'section_7_scripts_layout'):
                        sections_manager.section_7_scripts_layout.addWidget(script_widget)
                        if hasattr(sections_manager, 'section_7_scripts_list'):
                            sections_manager.section_7_scripts_list.append(script_info)
            elif field_type in ['dut', 'itsar', 'hash', 'direct_hash', 'evidence']:
                # For DUT, ITSAR, hash fields, and evidence, add to their own containers
                if 'scripts_layout' in field_info:
                    field_info['scripts_layout'].addWidget(script_widget)
                    if 'scripts_list' in field_info:
                        field_info['scripts_list'].append(script_info)
            elif field_type == 'expected_result':
                # For expected results, add to their own containers
                if 'scripts_layout' in field_info:
                    field_info['scripts_layout'].addWidget(script_widget)
                    if 'scripts_list' in field_info:
                        field_info['scripts_list'].append(script_info)
                
                # Also store in the scenario's expected_result_field_info for proper export
                scenario_key_edit = field_info.get('scenario_key_edit')
                if scenario_key_edit:
                    # Find the scenario in test_scenarios list
                    for scenario in self.test_scenarios:
                        if scenario.get('key_edit') == scenario_key_edit:
                            # Initialize expected_result_field_info if it doesn't exist
                            if 'expected_result_field_info' not in scenario:
                                scenario['expected_result_field_info'] = {
                                    'images_list': [],
                                    'scripts_list': []
                                }
                            
                            # Add the script to the scenario's expected_result_field_info
                            if 'scripts_list' not in scenario['expected_result_field_info']:
                                scenario['expected_result_field_info']['scripts_list'] = []
                            scenario['expected_result_field_info']['scripts_list'].append(script_info)
                            print(f"DEBUG: Added script to scenario {scenario['key_edit'].text()} expected_result_field_info: {script_info['filename']}")
                            break
            elif field_type == 'test_bed_diagram':
                # For test bed diagram, add to the test bed scripts container
                print(f"DEBUG: Processing test_bed_diagram upload")
                print(f"DEBUG: Has test_bed_scripts_layout: {hasattr(self, 'test_bed_scripts_layout')}")
                print(f"DEBUG: Has test_bed_diagram_data: {hasattr(self, 'test_bed_diagram_data')}")
                print(f"DEBUG: Has test_bed_scripts: {hasattr(self, 'test_bed_scripts')}")
                
                # Add to layout if available
                if hasattr(self, 'test_bed_images_layout'):
                    self.test_bed_images_layout.addWidget(script_widget)
                else:
                    print(f"DEBUG: ERROR - test_bed_images_layout not found!")
                
                # Store in new structure
                if hasattr(self, 'test_bed_diagram_data'):
                    self.test_bed_diagram_data['scripts'].append(script_info)
                    print(f"DEBUG: Added script to new structure: {script_info['filename']}")
                    print(f"DEBUG: New structure now has {len(self.test_bed_diagram_data['scripts'])} scripts")
                    print(f"DEBUG: New structure content: {self.test_bed_diagram_data}")
                else:
                    print(f"DEBUG: ERROR - test_bed_diagram_data structure not found!")
                
                # Also store in old structure for backward compatibility
                if hasattr(self, 'test_bed_scripts'):
                    self.test_bed_scripts.append(script_info)
                    print(f"DEBUG: Added script to old structure: {script_info['filename']}")
                    print(f"DEBUG: Old structure now has {len(self.test_bed_scripts)} scripts")
                else:
                    print(f"DEBUG: ERROR - test_bed_scripts structure not found!")
            elif field_type == 'test_scenario':
                # For test scenarios, add to the scenario's scripts list
                # Find the scenario that this field belongs to
                scenario_key_edit = field_info.get('key_edit')
                if scenario_key_edit:
                    # Find the scenario in test_scenarios list
                    for scenario in self.test_scenarios:
                        if scenario.get('key_edit') == scenario_key_edit:
                            # Initialize scripts list if it doesn't exist
                            if 'scripts' not in scenario:
                                scenario['scripts'] = []
                            scenario['scripts'].append(script_info)
                
                            # Create a container for scripts if it doesn't exist
                            if 'scripts_layout' not in scenario:
                                scenario['scripts_layout'] = QVBoxLayout()
                                # Add the scripts layout to the scenario widget
                                scenario_widget = scenario_key_edit.parent()
                                if scenario_widget:
                                    scenario_widget.layout().addLayout(scenario['scripts_layout'])
                            
                            scenario['scripts_layout'].addWidget(script_widget)
                            break
            elif field_type == 'tool_required':
                # For tools required, add to the tool's scripts list
                # Find the tool that this field belongs to
                value_edit = field_info.get('value_edit')
                if value_edit:
                    # Find the tool in tools_required list
                    for tool in self.tools_required:
                        if tool.get('tool_edit') == value_edit:
                            # Initialize scripts list if it doesn't exist
                            if 'scripts' not in tool:
                                tool['scripts'] = []
                            tool['scripts'].append(script_info)
                            
                            # Create a container for scripts if it doesn't exist
                            if 'scripts_layout' not in tool:
                                tool['scripts_layout'] = QVBoxLayout()
                                # Add the scripts layout to the tool widget
                                tool_widget = tool['tool_edit'].parent()
                                if tool_widget:
                                    tool_widget.layout().addLayout(tool['scripts_layout'])
                            
                            tool['scripts_layout'].addWidget(script_widget)
                            print(f"DEBUG: Added script to tool: {tool.get('tool_edit', '').text()}")
                            break
                else:
                        print(f"DEBUG: Tool not found for value_edit: {value_edit}")
                        print(f"DEBUG: Available tools: {[tool.get('tool_edit', '').text() for tool in self.tools_required]}")
            elif field_type == 'execution_step':
                print(f"DEBUG: ===== EXECUTION STEP SCRIPT UPLOAD HANDLING =====")
                print(f"DEBUG: EXECUTION STEP HANDLING REACHED!")
                # For execution steps, add to the step's scripts list
                # Find the step that this field belongs to
                value_edit = field_info.get('value_edit')
                print(f"DEBUG: Execution step value_edit: {value_edit}")
                print(f"DEBUG: Execution step value_edit type: {type(value_edit)}")
            
                if value_edit:
                    print(f"DEBUG: Looking for execution step in test_scenarios...")
                    print(f"DEBUG: self.test_scenarios: {self.test_scenarios}")
                    
                    # Find the step in test_scenarios list (execution steps are part of scenarios)
                    for scenario_index, scenario in enumerate(self.test_scenarios):
                        print(f"DEBUG: Checking scenario {scenario_index}: {scenario}")
                        for step_index, step in enumerate(scenario.get('steps', [])):
                            print(f"DEBUG: Checking step {step_index}: {step}")
                            print(f"DEBUG: step.get('step_edit'): {step.get('step_edit')}")
                            print(f"DEBUG: Comparing with value_edit: {value_edit}")
                            
                            if step.get('step_edit') == value_edit:
                                print(f"DEBUG: Found matching execution step!")
                                # Initialize scripts list if it doesn't exist
                                if 'scripts' not in step:
                                    step['scripts'] = []
                                    print(f"DEBUG: Initialized scripts list for step")
                                
                                step['scripts'].append(script_info)
                                print(f"DEBUG: Added script_info to step scripts: {script_info}")
                                
                                # Create a container for scripts if it doesn't exist
                                if 'scripts_layout' not in step:
                                    step['scripts_layout'] = QVBoxLayout()
                                    print(f"DEBUG: Created scripts_layout for step")
                                    # Add the scripts layout to the step widget
                                    step_widget = step['step_edit'].parent()
                                    if step_widget:
                                        step_widget.layout().addLayout(step['scripts_layout'])
                                        print(f"DEBUG: Added scripts_layout to step widget")
                                
                                step['scripts_layout'].addWidget(script_widget)
                                print(f"DEBUG: Added script widget to step scripts_layout")
                                print(f"DEBUG: Added script to execution step: {step.get('step_edit', '').text()}")
                                break
                        else:
                            continue
                        break
                    else:
                        print(f"DEBUG: Execution step not found for value_edit: {value_edit}")
                        print(f"DEBUG: Available execution steps: {[step.get('step_edit', '').text() for scenario in self.test_scenarios for step in scenario.get('steps', [])]}")
                else:
                    print(f"DEBUG: No value_edit found for execution step")
                print(f"DEBUG: ===== EXECUTION STEP SCRIPT UPLOAD HANDLING COMPLETED =====")
            elif field_type == 'expected_result':
                print(f"DEBUG: ===== EXPECTED RESULT SCRIPT UPLOAD HANDLING =====")
                # For expected results, add to the field's scripts list
                if 'scripts_list' in field_info:
                    field_info['scripts_list'].append(script_info)
                    print(f"DEBUG: Added script to expected result field info: {script_info}")
                
                # Create a container for scripts if it doesn't exist
                if 'scripts_layout' not in field_info:
                    field_info['scripts_layout'] = QVBoxLayout()
                    print(f"DEBUG: Created scripts_layout for expected result")
                    # Add the scripts layout to the field widget
                    value_edit = field_info.get('value_edit')
                    if value_edit and value_edit.parent():
                        value_edit.parent().layout().addLayout(field_info['scripts_layout'])
                        print(f"DEBUG: Added scripts_layout to expected result widget")
                
                field_info['scripts_layout'].addWidget(script_widget)
                print(f"DEBUG: Added script widget to expected result scripts_layout")
                print(f"DEBUG: ===== EXPECTED RESULT SCRIPT UPLOAD HANDLING COMPLETED =====")
            elif field_type == 'evidence':
                print(f"DEBUG: ===== EVIDENCE SCRIPT UPLOAD HANDLING =====")
                # For evidence, add to the field's scripts list
                if 'scripts_list' in field_info:
                    field_info['scripts_list'].append(script_info)
                    print(f"DEBUG: Added script to evidence field info: {script_info}")
                
                # Create a container for scripts if it doesn't exist
                if 'scripts_layout' not in field_info:
                    field_info['scripts_layout'] = QVBoxLayout()
                    print(f"DEBUG: Created scripts_layout for evidence")
                    # Add the scripts layout to the field widget
                    value_edit = field_info.get('value_edit')
                    if value_edit and value_edit.parent():
                        value_edit.parent().layout().addLayout(field_info['scripts_layout'])
                        print(f"DEBUG: Added scripts_layout to evidence widget")
                
                field_info['scripts_layout'].addWidget(script_widget)
                print(f"DEBUG: Added script widget to evidence scripts_layout")
                print(f"DEBUG: ===== EVIDENCE SCRIPT UPLOAD HANDLING COMPLETED =====")
            
            # Add to Essential Questions for sections 1, 2, 3, 7, dut, itsar, hash, direct_hash, section_8
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'add_essential_question_with_script'):
                self.add_essential_question_with_script(subheading, original_filename, placeholder)
            
            # Add to automation mapper for Sections 1, 2, 3, 7, dut, itsar, hash, direct_hash, section_8
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'automation_mapper'):
                script_id = str(uuid.uuid4())
                # Use the user's actual placeholder instead of generating a new one
                placeholder_name = placeholder  # Use the actual placeholder from user input or skip
                # Determine source tab based on field type
                if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
                    source_tab = "Sections 1–7"
                elif field_type in ['dut', 'itsar', 'hash', 'direct_hash']:
                    source_tab = "DUT Configuration"
                else:  # test_scenario, tool_required, execution_step, evidence, test_bed_diagram, expected_result
                    source_tab = "Section 8 Test Plan"
                self.automation_mapper.add_script_mapping(
                    script_id, 
                    original_filename, 
                    placeholder_name, 
                    source_tab, 
                    subheading
                )
            
            QMessageBox.information(
                self,
                "Script Uploaded",
                f"Script '{original_filename}' uploaded and copied to tmp directory.\n\n"
                f"• Document Placeholder: {placeholder}\n"
                f"• Subheading: {subheading}\n"
                f"• Script Name: {script_name}\n\n"
                f"Essential Questions have been automatically updated to include this script."
            )
    
    def _continue_upload_logic(self, field_info, placeholder, subheading, file_path):
        """Continue the upload logic after file selection"""
        # Validate file extension
        if not file_path.lower().endswith('.py'):
            QMessageBox.warning(self, "Invalid File", "Please select a Python script (.py file)")
            return
        
        # Copy file to code directory with original filename
        original_filename = os.path.basename(file_path)
        field_type = field_info.get('field_type', 'field')

        # Use the correct code folder path
        code_dir = self.get_code_folder_path()
        unique_filename = self.get_unique_filename(code_dir, original_filename)
        tmp_path = os.path.join(code_dir, unique_filename)
        
        try:
            shutil.copy2(file_path, tmp_path)
            print(f"Copied {file_path} to {tmp_path}")
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to copy file: {e}")
            return
        
        # Generate script name with incremental numbering
        script_number = self.get_next_script_number()
        script_name = f"script{script_number}.py"
        
        # Create relative path for JSON storage
        testcase_name = self.get_test_case_title()
        import re
        # First replace forward slashes with underscores to prevent path splitting
        clean_name = testcase_name.replace('/', '_')
        # Then replace other invalid characters
        clean_name = re.sub(r'[<>:"\\|?*]', '_', clean_name)
        clean_name = clean_name.strip()
        if not clean_name:
            clean_name = "test_case"
        relative_path = f"tmp/{clean_name}/code/{unique_filename}"

        script_info = {
            'path': relative_path,  # Store relative path for JSON
            'absolute_path': tmp_path,  # Store absolute path for UI
            'filename': unique_filename,
            'original_filename': original_filename,
            'description': placeholder,
            'placeholder': placeholder,  # Store placeholder separately for export
            'subheading': subheading,
            'script_name': script_name,
            'is_pasted': False,
            'remove_btn': QPushButton("🗑️ Remove")
        }
        
        # Create script widget
        script_widget = QWidget()
        script_layout = QHBoxLayout(script_widget)
        
        # Filename label
        filename_label = QLabel(f"📄 {original_filename}")
        filename_label.setStyleSheet("color: #28a745; font-weight: bold;")
        script_layout.addWidget(filename_label)
        
        # Remove button
        script_info['remove_btn'].setStyleSheet("""
            QPushButton {
                background-color: #dc3545;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 4px 8px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #c82333;
            }
        """)
        script_info['remove_btn'].clicked.connect(lambda: self.remove_field_script(field_info, script_info))
        script_layout.addWidget(script_info['remove_btn'])
        
        script_layout.addStretch()
        
        # Add to Essential Questions for sections 1, 2, 3, 7, dut, itsar, hash, direct_hash, section_8
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'add_essential_question_with_script'):
            self.add_essential_question_with_script(subheading, original_filename, placeholder)
        
        # Add to automation mapper for Sections 1, 2, 3, 7, dut, itsar, hash, direct_hash, section_8
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'automation_mapper'):
            script_id = str(uuid.uuid4())
            # Use the user's actual placeholder instead of generating a new one
            placeholder_name = placeholder  # Use the actual placeholder from user input or skip
            # Determine source tab based on field type
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
                source_tab = "Sections 1–7"
            elif field_type in ['dut', 'itsar', 'hash', 'direct_hash']:
                source_tab = "DUT Configuration"
            else:  # test_scenario, tool_required, execution_step, evidence, test_bed_diagram, expected_result
                source_tab = "Section 8 Test Plan"
            self.automation_mapper.add_script_mapping(
                script_id=script_id,
                script_name=original_filename,
                source_tab=source_tab,
                question_text=subheading,
                placeholder=placeholder_name
            )
        
        # Trigger live preview update
        self.trigger_live_preview_update()
        
        # Show success message
        QMessageBox.information(self, "Success", f"Script '{original_filename}' uploaded successfully!")
    
    def paste_field_script(self, field_info):
        """Paste script for field"""
        # Create a dialog for pasting script content
        dialog = QDialog(self)
        dialog.setWindowTitle("Paste Python Script")
        dialog.setGeometry(400, 300, 600, 400)
        
        layout = QVBoxLayout(dialog)
        
        # Instructions label
        instructions = QLabel("Paste your Python script code below:")
        instructions.setStyleSheet("font-weight: bold; margin-bottom: 10px;")
        layout.addWidget(instructions)
        
        # Textarea for pasting script
        script_textarea = QTextEdit()
        script_textarea.setPlaceholderText("Paste your Python script here...\n\nExample:\ndef hello_world():\n    print('Hello, World!')\n\nhello_world()")
        script_textarea.setStyleSheet("""
            QTextEdit {
                background-color: #2b2b2b;
                color: #ffffff;
                border: 1px solid #444444;
                border-radius: 4px;
                padding: 8px;
                font-family: 'Consolas', 'Monaco', monospace;
                font-size: 12px;
            }
        """)
        layout.addWidget(script_textarea)
        
        # Button layout
        button_layout = QHBoxLayout()
        
        # Cancel button
        cancel_button = QPushButton("Cancel")
        cancel_button.setStyleSheet("""
            QPushButton {
                background-color: #6c757d;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #5a6268;
            }
        """)
        cancel_button.clicked.connect(dialog.reject)
        button_layout.addWidget(cancel_button)
        
        button_layout.addStretch()
        
        # OK button
        ok_button = QPushButton("OK")
        ok_button.setStyleSheet("""
            QPushButton {
                background-color: #28a745;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 8px 16px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #218838;
            }
        """)
        ok_button.clicked.connect(dialog.accept)
        button_layout.addWidget(ok_button)
        
        layout.addLayout(button_layout)
        
        # Show dialog
        if dialog.exec() != QDialog.DialogCode.Accepted:
            return
        
        # Get script content from textarea
        script_content = script_textarea.toPlainText().strip()
        
        if not script_content:
            QMessageBox.warning(self, "Empty Script", "Please paste some script content.")
            return
        
        # Clean up the script content
        script_content = textwrap.dedent(script_content)
        script_content = script_content.rstrip()
        script_content = script_content.replace('\t', '    ')
        
        # Save to correct code folder: tmp/<testcase_name>/code/
        unique_id = str(uuid.uuid4())[:8]
        field_type = field_info.get('field_type', 'field')
        filename = f"{field_type}_pasted_script_{unique_id}.py"
        
        # Use the correct code folder path
        code_dir = self.get_code_folder_path()
        tmp_path = os.path.join(code_dir, filename)
        
        try:
            with open(tmp_path, 'w', encoding='utf-8') as f:
                f.write(script_content)
            print(f"Saved pasted script to {tmp_path}")
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to save script: {e}")
            return
        
        # Now show placeholder dialog
        result = self.show_placeholder_dialog(self)
        
        if not result["ok"] and not result["skip"]:
            return
            
        placeholder = result["description"]
        # Use the field text as the question name
        field_type = field_info.get('field_type', 'field')
        
        # Handle different widget types
        if field_info.get('value_edit'):
            value_edit = field_info['value_edit']
            if hasattr(value_edit, 'text'):  # QLineEdit
                field_text = value_edit.text().strip()
            elif hasattr(value_edit, 'toPlainText'):  # QTextEdit/ContextMenuTextEdit
                field_text = value_edit.toPlainText().strip()
            else:
                field_text = f"Section {field_type.split('_')[-1]}"
        else:
            field_text = f"Section {field_type.split('_')[-1]}"
        
        # Special handling for Sections 1, 2, 3, 7: Use the heading value from the section heading field
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7'] and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                # Default fallbacks for each section
                if field_type == 'section_1':
                    field_text = "ITSAR Section No & Name"
                elif field_type == 'section_2':
                    field_text = "Security Requirement No & Name"
                elif field_type == 'section_3':
                    field_text = "Requirement Description"
                else:  # section_7
                    field_text = "Test Objective"
            if not field_text:
                # Default fallbacks for each section
                if field_type == 'section_1':
                    field_text = "ITSAR Section No & Name"
                elif field_type == 'section_2':
                    field_text = "Security Requirement No & Name"
                elif field_type == 'section_3':
                    field_text = "Requirement Description"
                else:  # section_7
                    field_text = "Test Objective"
        
        # Special handling for DUT fields: Use the label value from the label field
        elif field_type == 'dut' and field_info.get('label_edit'):
            label_edit = field_info['label_edit']
            if hasattr(label_edit, 'text'):
                field_text = label_edit.text().strip()
            else:
                field_text = "DUT Field"
            if not field_text:
                field_text = "DUT Field"
        
        # Special handling for ITSAR fields: Use the key value from the key field
        elif field_type == 'itsar' and field_info.get('key_edit'):
            key_edit = field_info['key_edit']
            if hasattr(key_edit, 'text'):
                field_text = key_edit.text().strip()
            else:
                field_text = "ITSAR Field"
            if not field_text:
                field_text = "ITSAR Field"
        
        # Special handling for hash fields: Use the hash name from the hash_name_edit field
        elif field_type == 'hash' and field_info.get('hash_name_edit'):
            hash_name_edit = field_info['hash_name_edit']
            if hasattr(hash_name_edit, 'text'):
                field_text = hash_name_edit.text().strip()
            else:
                field_text = "Hash Field"
            if not field_text:
                field_text = "Hash Field"
        
        # Special handling for direct hash fields: Use the heading from the section
        elif field_type == 'direct_hash':
            # For direct hash fields, we need to get the heading from the parent section
            # Look for the heading_edit in the field info
            if field_info.get('heading_edit'):
                heading_edit = field_info['heading_edit']
                if hasattr(heading_edit, 'text'):
                    field_text = heading_edit.text().strip()
                else:
                    field_text = "Direct Hash Value"
            else:
                field_text = "Direct Hash Value"
            if not field_text:
                field_text = "Direct Hash Value"
        
        # Special handling for Section 8 Test Scenario fields: Use the key value from the key field
        elif field_type == 'test_scenario' and field_info.get('key_edit'):
            key_edit = field_info['key_edit']
            if hasattr(key_edit, 'text'):
                field_text = key_edit.text().strip()
            else:
                field_text = "Test Scenario"
            if not field_text:
                field_text = "Test Scenario"
        
        # Special handling for Section 8 Tool fields: Use the heading value from the heading field
        elif field_type == 'tool_required' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Tool Required"
            if not field_text:
                field_text = "Tool Required"
        
        # Special handling for Section 8 Execution Step fields: Use the step value directly
        elif field_type == 'execution_step' and field_info.get('value_edit'):
            value_edit = field_info['value_edit']
            if hasattr(value_edit, 'text'):
                field_text = value_edit.text().strip()
            else:
                field_text = "Execution Step"
            if not field_text:
                field_text = "Execution Step"
        
        # Special handling for Section 8 Evidence fields: Use the heading value from the heading field
        elif field_type == 'evidence' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Evidence"
            if not field_text:
                field_text = "Evidence"
        
        # Special handling for Section 8 Test Bed Diagram fields: Use the heading value from the heading field
        elif field_type == 'test_bed_diagram' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Test Bed Diagram"
            if not field_text:
                field_text = "Test Bed Diagram"
        
        # Special handling for Section 8 Execution Step fields: Use the scenario key as question text
        elif field_type == 'execution_step' and field_info.get('scenario_key_text'):
            field_text = field_info['scenario_key_text']
            print(f"DEBUG: Using scenario key text for execution step: '{field_text}'")
            if not field_text:
                field_text = "Execution Step"
                print(f"DEBUG: Field text was empty, using default: '{field_text}'")
        
        # Special handling for Section 8 Expected Result fields: Use the heading value from the heading field
        elif field_type == 'expected_result' and field_info.get('heading_edit'):
            heading_edit = field_info['heading_edit']
            if hasattr(heading_edit, 'text'):
                field_text = heading_edit.text().strip()
            else:
                field_text = "Expected Result"
            if not field_text:
                field_text = "Expected Result"
        
        subheading = field_text
        
        # Generate script name with incremental numbering
        script_number = self.get_next_script_number()
        script_name = f"script{script_number}.py"
        
        script_info = {
            'path': tmp_path,
            'filename': filename,
            'description': placeholder,
            'placeholder': placeholder,  # Store placeholder separately for export
            'subheading': subheading,
            'script_name': script_name,
            'is_pasted': True,
            'remove_btn': QPushButton("🗑️ Remove")
        }
        
        # Create script widget
        script_widget = QWidget()
        script_layout = QHBoxLayout(script_widget)
        
        # Filename label
        filename_label = QLabel(f"📄 {filename} (Pasted)")
        filename_label.setStyleSheet("color: #007bff; font-weight: bold;")
        script_layout.addWidget(filename_label)
        
        # Remove button
        script_info['remove_btn'].setStyleSheet("""
            QPushButton {
                background-color: #dc3545;
                color: white;
                border: none;
                border-radius: 4px;
                padding: 4px 8px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #c82333;
            }
        """)
        script_info['remove_btn'].clicked.connect(lambda: self.remove_field_script(field_info, script_info))
        script_layout.addWidget(script_info['remove_btn'])
        
        script_layout.addStretch()
        
        # Add to Essential Questions for sections 1, 2, 3, 7, dut, itsar, hash, direct_hash, section_8
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'add_essential_question_with_script'):
            self.add_essential_question_with_script(subheading, original_filename, placeholder)
        
        # Add to automation mapper for Sections 1, 2, 3, 7, dut, itsar, hash, direct_hash, section_8
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'automation_mapper'):
            script_id = str(uuid.uuid4())
            # Use the user's actual placeholder instead of generating a new one
            placeholder_name = placeholder  # Use the actual placeholder from user input or skip
            # Determine source tab based on field type
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
                source_tab = "Sections 1–7"
            elif field_type in ['dut', 'itsar', 'hash', 'direct_hash']:
                source_tab = "DUT Configuration"
            else:  # test_scenario, tool_required, execution_step, evidence, test_bed_diagram
                source_tab = "Section 8 Test Plan"
            self.automation_mapper.add_script_mapping(
                script_id, 
                filename, 
                placeholder_name, 
                source_tab, 
                subheading
            )
        
        # Add display widget to the appropriate container for sections 1, 2, 3, 7, dut, itsar
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
            # For sections 1-7, only add to section-specific lists (not field lists)
            if hasattr(self, 'sections_1_7_manager'):
                sections_manager = self.sections_1_7_manager
                
                if field_type == 'section_1' and hasattr(sections_manager, 'section_1_scripts_layout'):
                    sections_manager.section_1_scripts_layout.addWidget(script_widget)
                    if hasattr(sections_manager, 'section_1_scripts_list'):
                        sections_manager.section_1_scripts_list.append(script_info)
                elif field_type == 'section_2' and hasattr(sections_manager, 'section_2_scripts_layout'):
                    sections_manager.section_2_scripts_layout.addWidget(script_widget)
                    if hasattr(sections_manager, 'section_2_scripts_list'):
                        sections_manager.section_2_scripts_list.append(script_info)
                elif field_type == 'section_3' and hasattr(sections_manager, 'section_3_scripts_layout'):
                    sections_manager.section_3_scripts_layout.addWidget(script_widget)
                    if hasattr(sections_manager, 'section_3_scripts_list'):
                        sections_manager.section_3_scripts_list.append(script_info)
                elif field_type == 'section_7' and hasattr(sections_manager, 'section_7_scripts_layout'):
                    sections_manager.section_7_scripts_layout.addWidget(script_widget)
                    if hasattr(sections_manager, 'section_7_scripts_list'):
                        sections_manager.section_7_scripts_list.append(script_info)
        elif field_type in ['dut', 'itsar', 'hash', 'direct_hash']:
            # For DUT, ITSAR, and hash fields, add to their own containers
            if 'scripts_layout' in field_info:
                field_info['scripts_layout'].addWidget(script_widget)
                if 'scripts_list' in field_info:
                    field_info['scripts_list'].append(script_info)
        
        QMessageBox.information(
            self,
            "Script Pasted",
            f"Script '{filename}' has been pasted, saved to tmp directory.\n\n"
            f"• Document Placeholder: {placeholder}\n"
            f"• Subheading: {subheading}\n"
            f"• Script Name: {script_name}\n\n"
            f"Essential Questions have been automatically updated to include this script."
        )
    
    def remove_field_script(self, field_info, script_info):
        """Remove a script from field"""
        field_type = field_info.get('field_type')
        
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
            # For sections 1-7, scripts are only stored in section-specific lists
            if hasattr(self, 'sections_1_7_manager'):
                sections_manager = self.sections_1_7_manager
                
                if field_type == 'section_1' and hasattr(sections_manager, 'section_1_scripts_list'):
                    if script_info in sections_manager.section_1_scripts_list:
                        sections_manager.section_1_scripts_list.remove(script_info)
                        # Remove the widget from layout
                        for i in range(sections_manager.section_1_scripts_layout.count()):
                            widget = sections_manager.section_1_scripts_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                                widget.setParent(None)
                                break
                elif field_type == 'section_2' and hasattr(sections_manager, 'section_2_scripts_list'):
                    if script_info in sections_manager.section_2_scripts_list:
                        sections_manager.section_2_scripts_list.remove(script_info)
                        # Remove the widget from layout
                        for i in range(sections_manager.section_2_scripts_layout.count()):
                            widget = sections_manager.section_2_scripts_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                                widget.setParent(None)
                                break
                elif field_type == 'section_3' and hasattr(sections_manager, 'section_3_scripts_list'):
                    if script_info in sections_manager.section_3_scripts_list:
                        sections_manager.section_3_scripts_list.remove(script_info)
                        # Remove the widget from layout
                        for i in range(sections_manager.section_3_scripts_layout.count()):
                            widget = sections_manager.section_3_scripts_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                                widget.setParent(None)
                                break
                elif field_type == 'section_7' and hasattr(sections_manager, 'section_7_scripts_list'):
                    if script_info in sections_manager.section_7_scripts_list:
                        sections_manager.section_7_scripts_list.remove(script_info)
                        # Remove the widget from layout
                        for i in range(sections_manager.section_7_scripts_layout.count()):
                            widget = sections_manager.section_7_scripts_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                                widget.setParent(None)
                                break
        elif field_type in ['dut', 'itsar', 'hash', 'direct_hash']:
            # For DUT, ITSAR, and hash fields, remove from their own containers
            if 'scripts_list' in field_info and script_info in field_info['scripts_list']:
                field_info['scripts_list'].remove(script_info)
                # Remove the widget from layout
                if 'scripts_layout' in field_info:
                    for i in range(field_info['scripts_layout'].count()):
                        widget = field_info['scripts_layout'].itemAt(i).widget()
                        if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                            widget.setParent(None)
                            break
        elif field_type == 'test_bed_diagram':
            # For test bed diagram, remove from new structure first
            if hasattr(self, 'test_bed_diagram_data') and script_info in self.test_bed_diagram_data['scripts']:
                self.test_bed_diagram_data['scripts'].remove(script_info)
            # Also remove from old structure for backward compatibility
            if hasattr(self, 'test_bed_scripts') and script_info in self.test_bed_scripts:
                self.test_bed_scripts.remove(script_info)
            # Remove the widget from layout
            if hasattr(self, 'test_bed_images_layout'):
                for i in range(self.test_bed_images_layout.count()):
                    widget = self.test_bed_images_layout.itemAt(i).widget()
                    if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                        widget.setParent(None)
                        break
        elif field_type == 'test_scenario':
            # For test scenarios, remove from the scenario's scripts list
            scenario_key_edit = field_info.get('key_edit')
            if scenario_key_edit:
                for scenario in self.test_scenarios:
                    if scenario.get('key_edit') == scenario_key_edit:
                        if 'scripts' in scenario and script_info in scenario['scripts']:
                            scenario['scripts'].remove(script_info)
            # Remove the widget from layout
                        if 'scripts_layout' in scenario:
                            for i in range(scenario['scripts_layout'].count()):
                                widget = scenario['scripts_layout'].itemAt(i).widget()
                    if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                        widget.setParent(None)
                        print(f"DEBUG: Removed script widget from expected_results_layout")
                        break
                        break
        elif field_type == 'tool_required':
            # For tools required, remove from the tool's scripts list
            value_edit = field_info.get('value_edit')
            if value_edit:
                for tool in self.tools_required:
                    if tool.get('tool_edit') == value_edit:
                        if 'scripts' in tool and script_info in tool['scripts']:
                            tool['scripts'].remove(script_info)
                        # Remove the widget from layout
                        if 'scripts_layout' in tool:
                            for i in range(tool['scripts_layout'].count()):
                                widget = tool['scripts_layout'].itemAt(i).widget()
                                if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                                    widget.setParent(None)
                                    break
                        break
        elif field_type == 'execution_step':
            # For execution steps, remove from the step's scripts list
            value_edit = field_info.get('value_edit')
            if value_edit:
                for scenario in self.test_scenarios:
                    for step in scenario.get('steps', []):
                        if step.get('step_edit') == value_edit:
                            if 'scripts' in step and script_info in step['scripts']:
                                step['scripts'].remove(script_info)
                            # Remove the widget from layout
                            if 'scripts_layout' in step:
                                for i in range(step['scripts_layout'].count()):
                                    widget = step['scripts_layout'].itemAt(i).widget()
                                    if widget and widget.findChild(QLabel) and script_info.get('original_filename', '') in widget.findChild(QLabel).text():
                                        widget.setParent(None)
                                        break
                            break
                    else:
                        continue
                        break
            
            # Delete the file from tmp directory
            try:
                if os.path.exists(script_info['path']):
                    os.remove(script_info['path'])
                    print(f"Deleted file: {script_info['path']}")
            except Exception as e:
                print(f"Error deleting file {script_info['path']}: {e}")
            
            # Remove corresponding essential question if it exists
            script_name = script_info.get('script_name', '')
            field_type = field_info.get('field_type', '')
            if script_name and field_type in ['section_1', 'section_2', 'section_3', 'section_7', 'dut', 'itsar', 'hash', 'direct_hash', 'test_scenario', 'tool_required', 'execution_step', 'evidence', 'test_bed_diagram', 'expected_result'] and hasattr(self, 'essential_questions'):
                for question_info in self.essential_questions[:]:
                    if (question_info.get("script_name_edit") and 
                        question_info["script_name_edit"].text() == script_name):
                        # Remove the essential question
                        self.questions_container.removeWidget(question_info["widget"])
                        question_info["widget"].deleteLater()
                        self.essential_questions.remove(question_info)
                        # Renumber remaining questions
                        self.renumber_essential_questions()
                        break
            
            # Show success message
            display_name = script_info.get('original_filename', script_info['filename'])
            QMessageBox.information(
                self,
                "Script Removed",
                f"Script '{display_name}' has been removed and the file deleted.\n\n"
                f"Corresponding essential question has also been removed."
            )

    def add_field_placeholder(self, field_info):
        """Add placeholder for field with scenario context"""
        # Use the same input dialog as the existing add_placeholder function
        placeholder_name, ok = QInputDialog.getText(
            self, 
            "Add Placeholder", 
            "Enter new placeholder name:",
            QLineEdit.EchoMode.Normal
        )
        
        if ok and placeholder_name.strip():
            # Create placeholder info in the same format as existing automatic_images
            placeholder_info = {
                "placeholder": placeholder_name.strip(),
                "image_path": None
            }
            
            # Add to the automatic_images array (same as existing add_placeholder function)
            if not hasattr(self, 'automatic_images'):
                self.automatic_images = []
            
            self.automatic_images.append(placeholder_info)
            
            # Determine scenario context from field_info
            scenario_key = self.get_scenario_key_from_field_info(field_info)
            
            # Add to scenario-specific storage
            if scenario_key:
                if scenario_key not in self.scenario_placeholders:
                    self.scenario_placeholders[scenario_key] = []
                self.scenario_placeholders[scenario_key].append(placeholder_info)
                print(f"DEBUG: Added placeholder '{placeholder_name.strip()}' to scenario '{scenario_key}'")
            
            # Update all scenario placeholder displays
            self.update_all_scenario_placeholder_displays()
            
            # Debug output (same as existing function)
            print(f"DEBUG: Added placeholder: {placeholder_info}")
            print(f"DEBUG: Total placeholders: {len(self.automatic_images)}")
            print(f"DEBUG: Scenario-specific placeholders: {self.scenario_placeholders}")
            
            # Show success message (same as existing function)
            QMessageBox.information(
                self,
                "Placeholder Added",
                f"Placeholder '{placeholder_name.strip()}' has been added to memory.\n\nCurrent placeholders: {len(self.automatic_images)}"
            )
    
    def add_field_note(self, field_info):
        """Add a note for the field"""
        # Create a dialog to get the note text
        note_text, ok = QInputDialog.getMultiLineText(
            self,
            "Add Note",
            "Enter your note:",
            ""
        )
        
        if ok and note_text.strip():
            # Create note info
            note_info = {
                "id": str(len(field_info.get('notes_list', [])) + 1),
                "text": note_text.strip(),
                "timestamp": QDateTime.currentDateTime().toString("yyyy-MM-dd hh:mm:ss")
            }
            
            # Add to field's notes list
            if 'notes_list' not in field_info:
                field_info['notes_list'] = []
            field_info['notes_list'].append(note_info)
            
            # For sections, also add to section-specific notes list
            field_type = field_info.get('field_type')
            if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
                # Access section notes list directly from the main class
                notes_list_attr = f'{field_type}_notes_list'
                if not hasattr(self, notes_list_attr):
                    setattr(self, notes_list_attr, [])
                getattr(self, notes_list_attr).append(note_info)
                print(f"DEBUG: Added note to {notes_list_attr}: {note_info}")
            elif field_type in ['section_4', 'section_5', 'section_6']:
                # For sections 4-6, also add to section-specific notes list
                notes_list_attr = f'{field_type}_notes_list'
                if not hasattr(self, notes_list_attr):
                    setattr(self, notes_list_attr, [])
                getattr(self, notes_list_attr).append(note_info)
                print(f"DEBUG: Added note to {notes_list_attr}: {note_info}")
            elif field_type in ['test_scenario', 'tool_required', 'execution_step']:
                # For Section 8 fields, add to section_8_notes_list
                if not hasattr(self, 'section_8_notes_list'):
                    self.section_8_notes_list = []
                self.section_8_notes_list.append(note_info)
                print(f"DEBUG: Added note to section_8_notes_list: {note_info}")
            
            # Create and display the note widget
            self.create_note_widget(field_info, note_info)
            
            print(f"DEBUG: Added note to field: {note_info}")
    
    def create_note_widget(self, field_info, note_info):
        """Create a note widget with edit and remove buttons"""
        # Create note widget container
        note_widget = QWidget()
        note_widget.setStyleSheet("""
            QWidget {
                background-color: #f8f9fa;
                border: 1px solid #dee2e6;
                border-radius: 4px;
                margin: 2px 0px;
                padding: 8px;
            }
        """)
        
        note_layout = QHBoxLayout(note_widget)
        note_layout.setContentsMargins(8, 8, 8, 8)
        
        # Note text with red "Note:" prefix and bold description
        note_text_widget = QLabel()
        note_text_widget.setWordWrap(True)
        note_text_widget.setStyleSheet("""
            QLabel {
                color: #000000;
                font-size: 12px;
                line-height: 1.4;
            }
        """)
        
        # Format the note text with red "Note:" prefix and bold description
        formatted_text = f'<span style="color: #dc3545; font-weight: bold;">Note:</span> <span style="font-weight: bold;">{note_info["text"]}</span>'
        note_text_widget.setText(formatted_text)
        note_text_widget.setTextFormat(Qt.TextFormat.RichText)
        
        note_layout.addWidget(note_text_widget, 1)
        
        # Button container
        button_layout = QHBoxLayout()
        button_layout.setSpacing(4)
        
        # Edit button
        edit_btn = QPushButton("✏️")
        edit_btn.setMaximumSize(30, 30)
        edit_btn.setStyleSheet("""
            QPushButton {
                background-color: #ffc107;
                color: #000000;
                border: none;
                border-radius: 4px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #e0a800;
            }
        """)
        edit_btn.setToolTip("Edit Note")
        edit_btn.clicked.connect(lambda: self.edit_field_note(field_info, note_info, note_widget))
        
        # Remove button
        remove_btn = QPushButton("🗑️")
        remove_btn.setMaximumSize(30, 30)
        remove_btn.setStyleSheet("""
            QPushButton {
                background-color: #dc3545;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #c82333;
            }
        """)
        remove_btn.setToolTip("Remove Note")
        remove_btn.clicked.connect(lambda: self.remove_field_note(field_info, note_info, note_widget))
        
        button_layout.addWidget(edit_btn)
        button_layout.addWidget(remove_btn)
        note_layout.addLayout(button_layout)
        
        # Store reference to the widget in note_info
        note_info['widget'] = note_widget
        
        # Add to the appropriate container based on field type
        field_type = field_info.get('field_type')
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
            # For sections 1-7, add to section-specific layouts
            if hasattr(self, 'sections_1_7_manager'):
                sections_manager = self.sections_1_7_manager
                
                # Create notes layout if it doesn't exist
                notes_layout_attr = f'{field_type}_notes_layout'
                if not hasattr(sections_manager, notes_layout_attr):
                    # Create notes container and layout
                    notes_container_attr = f'{field_type}_notes_container'
                    if not hasattr(sections_manager, notes_container_attr):
                        notes_container = QWidget()
                        notes_container.setStyleSheet("margin-top: 8px;")
                        setattr(sections_manager, notes_container_attr, notes_container)
                        
                        # Add notes container to the main layout
                        # Find the parent layout and add the notes container
                        if hasattr(sections_manager, f'{field_type}_edit'):
                            parent_widget = getattr(sections_manager, f'{field_type}_edit').parent()
                            if parent_widget and hasattr(parent_widget, 'layout'):
                                parent_layout = parent_widget.layout()
                                if parent_layout:
                                    parent_layout.addWidget(notes_container)
                    
                    # Create notes layout
                    notes_layout = QVBoxLayout(getattr(sections_manager, notes_container_attr))
                    setattr(sections_manager, notes_layout_attr, notes_layout)
                
                # Add widget to the notes layout
                notes_layout = getattr(sections_manager, notes_layout_attr)
                notes_layout.addWidget(note_widget)
        elif field_type in ['dut', 'itsar', 'hash', 'direct_hash', 'evidence']:
            # For other field types, add to their own containers
            if 'notes_layout' in field_info:
                field_info['notes_layout'].addWidget(note_widget)
            else:
                # Create notes layout if it doesn't exist
                if 'value_edit' in field_info:
                    parent_widget = field_info['value_edit'].parent()
                    if parent_widget:
                        # Find or create a notes container
                        notes_container = getattr(field_info, 'notes_container', None)
                        if not notes_container:
                            notes_container = QWidget()
                            notes_container.setStyleSheet("margin-top: 8px;")
                            field_info['notes_container'] = notes_container
                            field_info['notes_layout'] = QVBoxLayout(notes_container)
                            
                            # Add notes container to the parent layout
                            parent_layout = parent_widget.layout()
                            if parent_layout:
                                parent_layout.addWidget(notes_container)
                        
                        field_info['notes_layout'].addWidget(note_widget)
    
    def edit_field_note(self, field_info, note_info, note_widget):
        """Edit an existing note"""
        # Get current note text
        current_text = note_info['text']
        
        # Create edit dialog
        new_text, ok = QInputDialog.getMultiLineText(
            self,
            "Edit Note",
            "Edit your note:",
            current_text
        )
        
        if ok and new_text.strip():
            # Update note info
            note_info['text'] = new_text.strip()
            note_info['timestamp'] = QDateTime.currentDateTime().toString("yyyy-MM-dd hh:mm:ss")
            
            # Update the widget display
            note_text_widget = note_widget.findChild(QLabel)
            if note_text_widget:
                formatted_text = f'<span style="color: #dc3545; font-weight: bold;">Note:</span> <span style="font-weight: bold;">{new_text.strip()}</span>'
                note_text_widget.setText(formatted_text)
            
            print(f"DEBUG: Updated note: {note_info}")
    
    def remove_field_note(self, field_info, note_info, note_widget):
        """Remove a note"""
        # Remove from notes list
        if 'notes_list' in field_info:
            field_info['notes_list'] = [n for n in field_info['notes_list'] if n['id'] != note_info['id']]
        
        # For sections, also remove from section-specific notes list
        field_type = field_info.get('field_type')
        if field_type in ['section_1', 'section_2', 'section_3', 'section_7']:
            # Access section notes list directly from the main class
            notes_list_attr = f'{field_type}_notes_list'
            if hasattr(self, notes_list_attr):
                notes_list = getattr(self, notes_list_attr)
                setattr(self, notes_list_attr, [n for n in notes_list if n['id'] != note_info['id']])
                print(f"DEBUG: Removed note from {notes_list_attr}")
        elif field_type in ['section_4', 'section_5', 'section_6']:
            # For sections 4-6, also remove from section-specific notes list
            notes_list_attr = f'{field_type}_notes_list'
            if hasattr(self, notes_list_attr):
                notes_list = getattr(self, notes_list_attr)
                setattr(self, notes_list_attr, [n for n in notes_list if n['id'] != note_info['id']])
                print(f"DEBUG: Removed note from {notes_list_attr}")
        elif field_type in ['test_scenario', 'tool_required', 'execution_step']:
            # For Section 8 fields, remove from section_8_notes_list
            if hasattr(self, 'section_8_notes_list'):
                self.section_8_notes_list = [n for n in self.section_8_notes_list if n['id'] != note_info['id']]
                print(f"DEBUG: Removed note from section_8_notes_list")
        
        # Remove widget from layout
        note_widget.setParent(None)
        note_widget.deleteLater()
        
        print(f"DEBUG: Removed note: {note_info}")
    
    def get_scenario_key_from_field_info(self, field_info):
        """Determine the scenario/section key from field_info context"""
        try:
            # Check if this is a test scenario field
            if field_info.get('field_type') == 'test_scenario':
                # Get the scenario key from the key_edit field
                key_edit = field_info.get('key_edit')
                if key_edit and hasattr(key_edit, 'text'):
                    scenario_key = key_edit.text().strip()
                    if scenario_key:
                        return scenario_key
                    else:
                        return "New Scenario"
            
            # Check if this field belongs to a specific scenario
            # Look for scenario context in the field_info
            if 'scenario_field_info' in field_info:
                scenario_field_info = field_info['scenario_field_info']
                key_edit = scenario_field_info.get('key_edit')
                if key_edit and hasattr(key_edit, 'text'):
                    scenario_key = key_edit.text().strip()
                    if scenario_key:
                        return scenario_key
                    else:
                        return "New Scenario"
            
            # Check for section-specific fields
            field_type = field_info.get('field_type')
            if field_type == 'test_bed_diagram':
                return "8.2. Test Bed Diagram"
            elif field_type == 'tools_required' or field_type == 'tool_required':
                return "8.3. Tools Required"
            elif field_type == 'execution_step':
                return "8.4. Test Execution Steps"
            elif field_type == 'expected_result':
                return "9. Expected Results for Pass"
            elif field_type == 'evidence' or field_type == 'evidence_format':
                return "10. Expected Format of Evidence"
            elif field_type == 'dut':
                return "DUT Details"
            elif field_type == 'hash' or field_type == 'hash_section':
                return "Hash Sections"
            elif field_type == 'itsar':
                return "ITSAR Information"
            
            # If no specific context found, return None (global placeholder)
            return None
            
        except Exception as e:
            print(f"DEBUG: Error getting scenario key from field_info: {e}")
            return None
    
    def update_hash_fields(self):
        """Update the hash fields based on the count"""
        current_count = len(self.hash_fields)
        target_count = self.hash_count_spinbox.value()
        
        # Add fields if needed
        while len(self.hash_fields) < target_count:
            self.add_hash_field()
        
        # Remove fields if needed
        while len(self.hash_fields) > target_count:
            if self.hash_fields:
                self.remove_hash_field(self.hash_fields[-1])

