    def remove_hash_section(self, section_info):
        """Remove a hash section"""
        if section_info in self.hash_sections:
            # Remove hash fields first to avoid QFormLayout errors
            for field_info in section_info['hash_fields'][:]:
                self.remove_section_hash_field(section_info, field_info)
            
            # Remove from layout
            self.hash_sections_layout.removeWidget(section_info['section_widget'])
            section_info['section_widget'].deleteLater()
            
            # Remove from list
            self.hash_sections.remove(section_info)
            
            # Update preview
            self.update_preview()

