        # Add fields if needed
        while len(section_info['hash_fields']) < target_count:
            self.add_section_hash_field(section_info)
        
        # Remove fields if needed
        while len(section_info['hash_fields']) > target_count:
            if section_info['hash_fields']:
                self.remove_section_hash_field(section_info, section_info['hash_fields'][-1])

