    def preview_launch_libreoffice_with_document(self, docx_path):
        """Launch LibreOffice with the specified document for preview page"""
        try:
            print(f"DEBUG: Preview Document - Launching LibreOffice with document: {docx_path}")
            
            # Use a more aggressive approach to launch LibreOffice
            abs_docx_path = os.path.abspath(docx_path)
            
            # Force close any existing LibreOffice instances to avoid conflicts
            self.libreoffice_embedder.force_close_all_libreoffice()
            
            # Also close our tracked process if it exists
            if hasattr(self.libreoffice_embedder, 'libreoffice_process') and self.libreoffice_embedder.libreoffice_process:
                self.libreoffice_embedder.close_libreoffice()
            
            # Get LibreOffice path
            is_installed, libreoffice_path = self.libreoffice_embedder.check_libreoffice_installation()
            
            # Launch LibreOffice with the document using specific flags
            libreoffice_cmd = [
                libreoffice_path, 
                '--writer', 
                '--norestore',  # Don't restore previous session
                '--nologo',     # Don't show splash screen
                '--nodefault',  # Don't load default document
                abs_docx_path
            ]
            
            print(f"DEBUG: Preview Document - Launch command: {' '.join(libreoffice_cmd)}")
            
            self.libreoffice_embedder.libreoffice_process = subprocess.Popen(
                libreoffice_cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                creationflags=subprocess.CREATE_NO_WINDOW if platform.system() == "Windows" else 0
            )
            
            # Update button to show launching status
            self.preview_launch_lo_btn.setText("🚀 Launching LibreOffice...")
            self.preview_launch_lo_btn.setStyleSheet("""
                QPushButton {
                    background-color: #17a2b8;
                    color: #ffffff;
                    border: none;
                    border-radius: 4px;
                    padding: 8px 12px;
                    font-size: 11px;
                    font-weight: bold;
                }
            """)
            
            # Wait for LibreOffice to start and then embed (increased wait time for better reliability)
            # Use a longer wait time and check if process is actually running
            def delayed_embed():
                if self.libreoffice_embedder.is_libreoffice_running():
                    self.preview_embed_libreoffice_with_document(os.path.basename(docx_path))
                else:
                    print("❌ LibreOffice process is not running after launch")
                    self.preview_launch_lo_btn.setText("❌ Launch Failed")
                    self.preview_launch_lo_btn.setStyleSheet("""
                        QPushButton {
                            background-color: #dc3545;
                            color: #ffffff;
                            border: none;
                            border-radius: 4px;
                            padding: 8px 12px;
                            font-size: 11px;
                            font-weight: bold;
                        }
                    """)
                    QMessageBox.warning(self, "Launch Failed", 
                                      "LibreOffice failed to start. Please check if LibreOffice is properly installed.")
            
            QTimer.singleShot(10000, delayed_embed)  # Increased to 10 seconds
            
        except Exception as e:
            print(f"DEBUG: Error launching LibreOffice with document: {str(e)}")
            QMessageBox.critical(self, "Error", f"Error launching LibreOffice: {str(e)}")
    
    def preview_embed_libreoffice_with_document(self, document_name):
        """Embed LibreOffice window in preview page after document is loaded"""
        try:
            print("DEBUG: Preview Document - Attempting to embed LibreOffice window...")
            
            # Wait for LibreOffice to be fully ready before attempting to find the window
            print("DEBUG: Preview Document - Waiting for LibreOffice to be ready...")
            if not self.libreoffice_embedder.wait_for_libreoffice_ready(max_wait_time=30):
                print("DEBUG: Preview Document - LibreOffice did not become ready, trying fallback method...")
                # Fallback: try the old retry mechanism
                self.libreoffice_embedder.window_id = None
                for attempt in range(3):  # Try up to 3 times with shorter waits
                    print(f"DEBUG: Preview Document - Fallback attempt {attempt + 1} to find LibreOffice window...")
                    self.libreoffice_embedder.window_id = self.libreoffice_embedder.find_libreoffice_window()
                    
                    if self.libreoffice_embedder.window_id:
                        print(f"DEBUG: Preview Document - Found LibreOffice window on fallback attempt {attempt + 1}")
                        break
                    else:
                        wait_time = 2 + (attempt * 1)  # Progressive wait: 2s, 3s, 4s
                        print(f"DEBUG: Preview Document - No window found on fallback attempt {attempt + 1}, waiting {wait_time} seconds...")
                        time.sleep(wait_time)
            else:
                # LibreOffice is ready, get the window ID
                self.libreoffice_embedder.window_id = self.libreoffice_embedder.find_libreoffice_window()
            
            if self.libreoffice_embedder.window_id:
                print(f"DEBUG: Preview Document - Found LibreOffice window ID: {self.libreoffice_embedder.window_id}")
                
                # Hide the preview browser first
                if hasattr(self, 'main_preview_browser'):
                    self.main_preview_browser.hide()
                    print("DEBUG: Preview Document - Hidden main preview browser")
                
                # Clear any existing widgets in the layout
                while self.preview_libreoffice_layout.count():
                    child = self.preview_libreoffice_layout.takeAt(0)
                    if child.widget():
                        child.widget().deleteLater()
                
                # Force layout update
                self.preview_libreoffice_layout.update()
                
                # Mark that LibreOffice is now embedded in preview page
                self.libreoffice_embedder.is_embedded = True
                self.libreoffice_embedder.current_layout = self.preview_libreoffice_layout
                
                # Embed the LibreOffice window in the preview page
                if self.libreoffice_embedder.embed_window(self.preview_libreoffice_layout):
                    # Update button to show success and enable refresh button
                    self.preview_launch_lo_btn.setText("LibreOffice Embedded")
                    self.preview_launch_lo_btn.setStyleSheet("""
                        QPushButton {
                            background-color: #28a745;
                            color: #ffffff;
                            border: none;
                            border-radius: 4px;
                            padding: 8px 12px;
                            font-size: 11px;
                            font-weight: bold;
                        }
                    """)
                    
                    # Enable refresh button now that LibreOffice is embedded
                    self.preview_refresh_btn.setEnabled(True)
                    
                    print(f"DEBUG: Preview Document - Successfully embedded LibreOffice with document: {document_name}")
                    # Don't show message box to avoid interrupting workflow
                    print(f"INFO: LibreOffice embedded successfully with populated document: {document_name}")
                else:
                    print("DEBUG: Preview Document - LibreOffice window found but embedding failed")
                    self.preview_launch_lo_btn.setText("⚠️ Embedding Failed")
                    self.preview_launch_lo_btn.setStyleSheet("""
                        QPushButton {
                            background-color: #ffc107;
                            color: #000000;
                            border: none;
                            border-radius: 4px;
                            padding: 8px 12px;
                            font-size: 11px;
                            font-weight: bold;
                        }
                    """)
                    QMessageBox.warning(self, "Embedding Failed", 
                                      "LibreOffice launched with document but embedding failed.\n"
                                      "The document is open in a separate LibreOffice window.")
            else:
                print("DEBUG: Preview Document - LibreOffice window not found after all attempts")
                self.preview_launch_lo_btn.setText("❌ Window Not Found")
                self.preview_launch_lo_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #dc3545;
                        color: #ffffff;
                        border: none;
                        border-radius: 4px;
                        padding: 8px 12px;
                        font-size: 11px;
                        font-weight: bold;
                    }
                """)
                # Update button to allow retry
                self.preview_launch_lo_btn.setText("🔄 Retry Embedding")
                self.preview_launch_lo_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #ffc107;
                        color: #000000;
                        border: none;
                        border-radius: 4px;
                        padding: 8px 12px;
                        font-size: 11px;
                        font-weight: bold;
                    }
                """)
                
                # Show more detailed error message with debugging information
                error_details = f"LibreOffice was launched but the window could not be found for embedding.\n\n"
                error_details += f"Debug Information:\n"
                error_details += f"• Process ID: {self.libreoffice_embedder.libreoffice_process.pid if self.libreoffice_embedder.libreoffice_process else 'None'}\n"
                error_details += f"• Document Path: {os.path.basename(docx_path) if 'docx_path' in locals() else 'Unknown'}\n"
                error_details += f"• Platform: {platform.system()}\n\n"
                error_details += f"This might happen if:\n"
                error_details += f"• LibreOffice is still starting up (try waiting longer)\n"
                error_details += f"• The document failed to open\n"
                error_details += f"• LibreOffice opened in a different mode\n"
                error_details += f"• Windows security blocked the embedding\n\n"
                error_details += f"Click '🔄 Retry Embedding' to try again with a longer wait time."
                
                QMessageBox.warning(self, "LibreOffice Window Not Found", error_details)
                
        except Exception as e:
            print(f"DEBUG: Error embedding LibreOffice: {str(e)}")
            QMessageBox.critical(self, "Error", f"Error embedding LibreOffice: {str(e)}")
    
