    def preview_refresh_embedded_document(self, updated_doc_path):
        """Update the existing embedded LibreOffice document with new content - SIMPLE APPROACH"""
        try:
            print(f"DEBUG: Preview Document - Refreshing embedded document: {updated_doc_path}")
            
            # Check if LibreOffice is embedded
            if not hasattr(self.libreoffice_embedder, 'is_embedded') or not self.libreoffice_embedder.is_embedded:
                print("DEBUG: LibreOffice not embedded, cannot refresh")
                return
            
            # SIMPLE METHOD: Just copy the updated document to the original location
            original_doc_path = os.path.join(
                self.export_path_edit.text() if hasattr(self, 'export_path_edit') else os.path.dirname(os.path.abspath(__file__)),
                "preview_document.docx"
            )
            
            try:
                # Copy the updated document to the original location
                import shutil
                shutil.copy2(updated_doc_path, original_doc_path)
                print(f"DEBUG: Document updated in place: {original_doc_path}")
                
                # Clean up the temporary updated file
                try:
                    os.remove(updated_doc_path)
                    print(f"DEBUG: Cleaned up temporary file: {updated_doc_path}")
                except:
                    pass
                
                # Show user message to manually refresh in LibreOffice
                QMessageBox.information(
                    self, 
                    "Document Updated", 
                    "The document has been updated with your latest changes!\n\n"
                    "To see the changes in LibreOffice, please:\n"
                    "1. Press Ctrl+R in LibreOffice, OR\n"
                    "2. Go to File → Reload"
                )
                
                return True
                
            except Exception as copy_error:
                print(f"DEBUG: Error updating document in place: {copy_error}")
                return False
            
        except Exception as e:
            print(f"DEBUG: Error refreshing embedded document: {str(e)}")
            return False
    
    def force_libreoffice_document_reload(self, doc_path):
        """Force LibreOffice to reload the document by restarting the embedded instance"""
        try:
            print(f"DEBUG: Force reloading LibreOffice document: {doc_path}")
            
            # Verify the document file exists and has content
            if not os.path.exists(doc_path):
                print(f"DEBUG: ERROR - Document file does not exist: {doc_path}")
                return False
            
            file_size = os.path.getsize(doc_path)
            print(f"DEBUG: Document file size: {file_size} bytes")
            
            if file_size == 0:
                print(f"DEBUG: ERROR - Document file is empty: {doc_path}")
                return False
            
            # Method 1: Restart the embedded LibreOffice instance with the updated document
            if hasattr(self.libreoffice_embedder, 'is_embedded') and self.libreoffice_embedder.is_embedded:
                print("DEBUG: Restarting embedded LibreOffice with updated document...")
                
                # Remove the current embedded window
                self.libreoffice_embedder.remove_embedded_window()
                
                # Close LibreOffice process
                if hasattr(self.libreoffice_embedder, 'close_libreoffice'):
                    self.libreoffice_embedder.close_libreoffice()
                
                # Wait for process to close
                time.sleep(3)  # Increased wait time
                
                # Launch LibreOffice with the updated document
                self.preview_launch_libreoffice_with_document(doc_path)
                
                print("DEBUG: Successfully restarted LibreOffice with updated document")
                return True
            
            # Method 2: If not embedded, just launch with updated document
            else:
                print("DEBUG: LibreOffice not embedded, launching with updated document...")
                self.preview_launch_libreoffice_with_document(doc_path)
                return True
            
        except Exception as e:
            print(f"DEBUG: Error in force_libreoffice_document_reload: {str(e)}")
            return False
    
