    def get_configuration_count(self):
        """Get the count of filled configuration fields"""
        try:
            if hasattr(self, 'get_dut_config_data'):
                config_data = self.get_dut_config_data()
                if config_data:
                    # Count non-empty configuration fields
                    filled_count = 0
                    for field in config_data:
                        # Check if key, label, or description is filled
                        if (field.get('key', '').strip() or 
                            field.get('label', '').strip() or 
                            field.get('description', '').strip()):
                            filled_count += 1
                    return filled_count
            return 0
        except Exception as e:
            print(f"Error getting configuration count: {e}")
            return 0
    
    def get_essential_questions_count(self):
        """Get the count of filled essential questions"""
        try:
            if hasattr(self, 'essential_questions'):
                count = 0
                for question in self.essential_questions:
                    if (question.get('question', '').strip() or 
                        question.get('answer', '').strip()):
                        count += 1
                return count
            return 0
        except Exception as e:
            print(f"Error getting essential questions count: {e}")
            return 0
    
    def get_execution_step_questions_count(self):
        """Get the count of filled execution step questions"""
        try:
            if hasattr(self, 'execution_step_questions'):
                count = 0
                for question in self.execution_step_questions:
                    if (question.get('question', '').strip() or 
                        question.get('answer', '').strip()):
                        count += 1
                return count
            return 0
        except Exception as e:
            print(f"Error getting execution step questions count: {e}")
            return 0
    
    def refresh_export_counts(self):
        """Refresh the counts displayed in the export page"""
        try:
            config_count = self.get_configuration_count()
            essential_count = self.get_essential_questions_count()
            execution_count = self.get_execution_step_questions_count()
            
            # Update labels if they exist
            for widget in self.findChildren(QLabel):
                if "Configuration (" in widget.text():
                    widget.setText(f"Configuration ({config_count} filled)")
                elif "Essential Questions (" in widget.text():
                    widget.setText(f"Essential Questions ({essential_count} filled)")
                elif "Execution Step Questions (" in widget.text():
                    widget.setText(f"Execution Step Questions ({execution_count} filled)")
                    
        except Exception as e:
            print(f"Error refreshing export counts: {e}")
    
    def unified_generate(self):
        """Unified generation method that handles all export types with organized folder structure"""
        try:
            # CRITICAL FIX: Collect all placeholders from all sections before generation
            print("DEBUG: Starting unified_generate - collecting all placeholders first")
            if hasattr(self, 'collect_all_section_placeholders'):
                new_placeholders_added = self.collect_all_section_placeholders()
                print(f"DEBUG: unified_generate - collected {new_placeholders_added} new placeholders")
            else:
                print("DEBUG: unified_generate - collect_all_section_placeholders method not found")
            
            # Show preview dialog first
            if not self.show_unified_generation_preview():
                return
            
            # Get selected options
            generate_template = self.generate_template_checkbox.isChecked()
            generate_script = self.generate_script_checkbox.isChecked()
            generate_template_json = self.generate_template_json_checkbox.isChecked()
            generate_automation_json = self.generate_automation_json_checkbox.isChecked()
            generate_images = self.generate_images_checkbox.isChecked()
            
            # Check if at least one option is selected
            if not any([generate_template, generate_script, generate_template_json, 
                       generate_automation_json, generate_images]):
                QMessageBox.warning(self, "Warning", "Please select at least one generation option.")
                return
            
            # Show progress
            self.export_progress.setVisible(True)
            self.export_progress.setValue(5)
            self.export_status.setText("Creating folder structure...")
            
            # Get test case title for folder name
            test_case_title = self.get_test_case_title()
            if not test_case_title:
                test_case_title = "test_case"
            
            # Create main test case folder inside tmp directory
            tmp_dir = os.path.join(os.getcwd(), "tmp")
            test_case_folder = os.path.join(tmp_dir, test_case_title)
            os.makedirs(test_case_folder, exist_ok=True)
            
            # Create subfolders
            code_folder = os.path.join(test_case_folder, "code")
            configuration_folder = os.path.join(test_case_folder, "configuration")
            raw_logs_folder = os.path.join(test_case_folder, "raw_logs")
            report_folder = os.path.join(test_case_folder, "report")
            
            os.makedirs(code_folder, exist_ok=True)
            os.makedirs(configuration_folder, exist_ok=True)
            os.makedirs(raw_logs_folder, exist_ok=True)
            os.makedirs(report_folder, exist_ok=True)
            
            self.export_progress.setValue(10)
            self.export_status.setText("Folder structure created successfully")
            
            # Generate template.docx if selected
            if generate_template:
                self.export_progress.setValue(20)
                self.export_status.setText("Generating DOCX report...")
                self.export_report_to_folder(report_folder)
            
            # Generate script if selected
            if generate_script:
                self.export_progress.setValue(40)
                self.export_status.setText("Generating script...")
                self.export_script_py_to_folder(code_folder)
            
            # Generate template JSON if selected
            if generate_template_json:
                self.export_progress.setValue(60)
                self.export_status.setText("Generating template JSON...")
                self.export_template_json_to_folder(configuration_folder)
            
            # Generate automation JSON if selected
            if generate_automation_json:
                self.export_progress.setValue(80)
                self.export_status.setText("Generating automation JSON...")
                self.export_automation_json_to_folder(configuration_folder)
            
            # Generate images if selected
            if generate_images:
                self.export_progress.setValue(90)
                self.export_status.setText("Processing images...")
                self.export_images_to_folder(raw_logs_folder)
            
            self.export_progress.setValue(100)
            self.export_status.setText(f"Generation completed successfully in tmp/ directory")
            
            success_msg = f"✅ All selected items have been generated successfully!\n\n"
            success_msg += f"📁 Test Case Folder: {test_case_folder}\n"
            success_msg += f"📍 Location: tmp/ directory in project folder\n\n"
            success_msg += f"📂 Generated Structure:\n"
            success_msg += f"   📄 code/ - Scripts and automation files\n"
            success_msg += f"   ⚙️ configuration/ - JSON configuration files\n"
            success_msg += f"   🖼️ raw_logs/ - Images and screenshots\n"
            success_msg += f"   📋 report/ - Generated DOCX report\n"
            
            QMessageBox.information(self, "Success", success_msg)
            
        except Exception as e:
            self.export_progress.setVisible(False)
            self.export_status.setText("Generation failed")
            QMessageBox.critical(self, "Error", f"Failed to generate items:\n{str(e)}")
        finally:
            self.export_progress.setVisible(False)
    
