    def get_test_case_title(self):
        """Get the test case title for folder naming"""
        try:
            # Try to get from report information
            if hasattr(self, 'report_title_edit') and self.report_title_edit.text().strip():
                return self.report_title_edit.text().strip()
            
            # Try to get from DUT configuration
            if hasattr(self, 'dut_name_edit') and self.dut_name_edit.text().strip():
                return self.dut_name_edit.text().strip()
            
            # Try to get from test plan
            if hasattr(self, 'test_plan_title_edit') and self.test_plan_title_edit.text().strip():
                return self.test_plan_title_edit.text().strip()
            
            # Default fallback
            return "test_case"
            
        except Exception as e:
            print(f"Error getting test case title: {e}")
            return "test_case"
    
    def get_code_folder_path(self):
        """Get the correct code folder path: tmp/<testcase_name>/code/"""
        try:
            # Get the testcase name
            testcase_name = self.get_test_case_title()
            
            # Clean the testcase name for use as directory name
            import re
            # First replace forward slashes with underscores to prevent path splitting
            clean_name = testcase_name.replace('/', '_')
            # Then replace other invalid characters
            clean_name = re.sub(r'[<>:"\\|?*]', '_', clean_name)
            clean_name = clean_name.strip()
            if not clean_name:
                clean_name = "test_case"
            
            # Create the path structure: tmp/<testcase_name>/code/
            project_dir = os.path.join(os.getcwd(), "tmp", clean_name)
            code_dir = os.path.join(project_dir, "code")
            
            # Create directories if they don't exist
            os.makedirs(code_dir, exist_ok=True)
            
            print(f"DEBUG: Created code folder: {code_dir}")
            print(f"DEBUG: Project directory: {project_dir}")
            print(f"DEBUG: Using testcase name: {clean_name}")
            
            return code_dir
            
        except Exception as e:
            print(f"Error creating code folder: {e}")
            # Fallback to tmp directory
            temp_dir = os.path.join(os.getcwd(), "tmp")
            os.makedirs(temp_dir, exist_ok=True)
            return temp_dir
    
