    def get_unique_filename(self, directory, original_filename):
        """Get a unique filename by appending a suffix if the file already exists"""
        base_name, ext = os.path.splitext(original_filename)
        counter = 1
        filename = original_filename
        
        while os.path.exists(os.path.join(directory, filename)):
            filename = f"{base_name}_{counter}{ext}"
            counter += 1
        
        return filename
    
    def export_report_to_folder(self, report_folder):
        """Export report to specific folder"""
        try:
            # Get filename from UI
            filename = self.export_filename_edit.text()
            if not filename.endswith('.docx'):
                filename += '.docx'
            
            # Set the output path to the report folder
            output_path = os.path.join(report_folder, filename)
            
            # Prepare configuration data
            config_data = self.prepare_config_data()
            
            # Generate the report using existing logic
            success, message = EnhancedDocumentManager.generate_enhanced_report(config_data, output_path)
            
            if not success:
                raise Exception(f"Failed to generate report: {message}")
                
        except Exception as e:
            print(f"Error exporting report to folder: {e}")
            raise
    
    def export_script_py_to_folder(self, code_folder):
        """Export script.py to specific folder"""
        try:
            # Initialize the ExportCodeAndFilesPages class if not already done
            if not hasattr(self, 'export_code_pages'):
                self.export_code_pages = ExportCodeAndFilesPages(self)
            
            # Generate script content
            script_content = self.export_code_pages.generate_script_py_content()
            
            # Save to code folder
            script_path = os.path.join(code_folder, "script.py")
            with open(script_path, 'w', encoding='utf-8') as f:
                f.write(script_content)
                
        except Exception as e:
            print(f"Error exporting script to folder: {e}")
            raise
    
    def export_template_json_to_folder(self, configuration_folder):
        """Export template JSON to specific folder using EnhancedExportImport"""
        try:
            # Import EnhancedExportImport
            from enhanced_export_import import EnhancedExportImport
            
            # Get test case name
            test_case_name = self.get_test_case_title()
            
            # Create the tmp folder structure
            tmp_folder = os.path.join(os.getcwd(), "tmp")
            test_case_folder = os.path.join(tmp_folder, test_case_name)
            
            # Initialize EnhancedExportImport
            export_import = EnhancedExportImport(test_case_folder, parent_app=self)
            
            # Prepare the data for export using our new system
            app_data = self.prepare_app_data_for_enhanced_export()
            
            # Check for missing fields before export
            missing_fields = export_import.get_missing_fields_report(app_data)
            if missing_fields:
                print("⚠️ Missing or empty fields detected:")
                for field in missing_fields:
                    print(f"  - {field}")
                print("Continuing with export...")
            
            # Export the complete configuration
            success, message = export_import.export_complete_configuration(app_data)
            
            if not success:
                raise Exception(f"Failed to export configuration: {message}")
                
                 # Section 8 media processing (scripts/images) mirroring Section 11 behavior
            try:
                from section8_media_handler import Section8MediaHandler
                section8_handler = Section8MediaHandler(self)
                
                # Define the template_config_path for Section 8 media processing
                template_config_path = os.path.join(test_case_folder, "configuration", "template_config.json")
                
                # Reload the on-disk template_config to update with Section 8 media
                refreshed_template = {}
                if os.path.exists(template_config_path):
                    with open(template_config_path, 'r', encoding='utf-8') as f:
                        refreshed_template = json.load(f)

                # Copy Section 8 media and update template_config using the same pattern as Section 11
                refreshed_template = section8_handler.copy_section8_media_on_export(test_case_folder, refreshed_template)

                # Save updated template_config.json
                with open(template_config_path, 'w', encoding='utf-8') as f:
                    json.dump(refreshed_template, f, indent=2, ensure_ascii=False)
                print("✅ Updated template_config.json with Section 8 media")
            except Exception as e:
                print(f"⚠️ Section 8 media processing failed: {e}")
                
        except Exception as e:
            print(f"Error exporting template JSON to folder: {e}")
            raise
    
