    def get_execution_steps_data(self):
        """Get execution steps data for ConfigManager"""
        try:
            # Return execution steps from test_scenarios (Section 8.4)
            if hasattr(self, 'test_scenarios') and self.test_scenarios:
                execution_steps = []
                print(f"🔍 DEBUG: Processing {len(self.test_scenarios)} test scenarios for execution steps")
                
                for i, scenario in enumerate(self.test_scenarios):
                    try:
                        # Get scenario key and description
                        scenario_key = scenario['key_edit'].text() if 'key_edit' in scenario and scenario['key_edit'] else ""
                        scenario_description = self.get_scenario_description(scenario)
                        
                        # Skip scenarios that have placeholder text, empty descriptions, or empty keys
                        if (scenario_description == "Enter scenario description here..." or 
                            not scenario_description.strip() or 
                            not scenario_key.strip()):
                            print(f"🔍 DEBUG: Skipping scenario {i} - has placeholder text, empty description, or empty key")
                            continue
                        
                        print(f"🔍 DEBUG: Scenario {i}: key='{scenario_key}', description='{scenario_description[:50]}...'")
                        
                        scenario_steps = {
                            'Custom_input': [],
                            'scenario_key': scenario_key,
                            'scenario_description': scenario_description,
                            'steps': [],
                            'images': [],
                            'scripts': [],
                            'placeholders': []
                        }
                        
                        # Custom input collection removed - no longer available in UI

                        # Add steps for this scenario (skip empty entries)
                        if 'steps' in scenario and scenario['steps']:
                            for step_info in scenario['steps']:
                                try:
                                    if 'step_edit' in step_info and step_info['step_edit']:
                                        text = step_info['step_edit'].text()
                                        if text:
                                            scenario_steps['steps'].append(text)
                                except RuntimeError:
                                    # Widget has been deleted, skip this step
                                    continue
                        
                        # Always add the scenario to execution_steps, even if it has no steps
                        execution_steps.append(scenario_steps)
                        print(f"🔍 DEBUG: Added scenario {i} to execution steps with {len(scenario_steps['steps'])} steps")
                        
                    except Exception as scenario_error:
                        print(f"🔍 DEBUG: Error processing scenario {i}: {scenario_error}")
                        continue
                
                print(f"🔍 DEBUG: Total execution steps created: {len(execution_steps)}")
                return execution_steps
            return []
        except Exception as e:
            print(f"Error getting execution steps data: {e}")
            return []
    
