    def get_all_images_data(self):
        """Get all images data for ConfigManager"""
        try:
            images = []

            # Collect images from various sources
            if hasattr(self, 'dut_images'):
                images.extend(self.dut_images)
            if hasattr(self, 'hash_images'):
                images.extend(self.hash_images)
            if hasattr(self, 'itsar_images'):
                images.extend(self.itsar_images)
            if hasattr(self, 'test_bed_images'):
                images.extend(self.test_bed_images)

            # Extract only serializable data, exclude UI widgets
            serializable_images = []
            for image in images:
                if isinstance(image, dict):
                    serializable_image = {}
                    for key, value in image.items():
                        # Skip UI widgets and other non-serializable objects
                        if key not in ['remove_btn'] and not hasattr(value, '__call__'):
                            serializable_image[key] = value
                    serializable_images.append(serializable_image)

            return serializable_images
        except Exception as e:
            print(f"Error getting all images data: {e}")
            return []
    
