    def map_question_type_to_json_format(self, ui_question_type):
        """Map UI question type display names to JSON format"""
        mapping = {
            "Yes / No": "yes_no",
            "Text Input": "text_input", 
            "Multiple Choice": "multiple_choice",
            "File Upload": "upload",
            "Command Input": "command_input",
            "command_execution": "command_execution"
        }
        return mapping.get(ui_question_type, ui_question_type.lower().replace(" ", "_"))
    
    def export_automation_json_to_folder(self, configuration_folder):
        """Export automation JSON to specific folder with new structure"""
        try:
            # Initialize the ExportCodeAndFilesPages class if not already done
            if not hasattr(self, 'export_code_pages'):
                self.export_code_pages = ExportCodeAndFilesPages(self)
            
            # Get essential questions data and extract the actual data from widgets
            essential_questions = []
            if hasattr(self, 'essential_questions') and self.essential_questions:
                for question_info in self.essential_questions:
                    try:
                        # Extract data from the question widget
                        question_data = {
                            "id": int(question_info.get("id_edit", {}).text()) if hasattr(question_info.get("id_edit"), 'text') else 0,
                            "question": question_info.get("question_edit", {}).toPlainText() if hasattr(question_info.get("question_edit"), 'toPlainText') else "",
                            "help_text": question_info.get("help_edit", {}).toPlainText() if hasattr(question_info.get("help_edit"), 'toPlainText') else "",
                            "error_message": question_info.get("error_edit", {}).text() if hasattr(question_info.get("error_edit"), 'text') else "",
                            "question_type": self.map_question_type_to_json_format(question_info.get("type_combo", {}).currentText() if hasattr(question_info.get("type_combo"), 'currentText') else "Yes / No"),
                            "script_name": question_info.get("script_name_edit", {}).text() if hasattr(question_info.get("script_name_edit"), 'text') else "",
                            "icon_info": {
                                "show_icon": question_info.get("show_icon_checkbox", {}).isChecked() if hasattr(question_info.get("show_icon_checkbox"), 'isChecked') else False,
                                "title": question_info.get("icon_title_edit", {}).text() if hasattr(question_info.get("icon_title_edit"), 'text') else "",
                                "content": question_info.get("icon_content_edit", {}).toPlainText() if hasattr(question_info.get("icon_content_edit"), 'toPlainText') else ""
                            },
                            "screenshot_line_number": question_info.get("expected_lines_spinner", {}).value() if hasattr(question_info.get("expected_lines_spinner"), 'value') else 0,
                            "dir_way": question_info.get("screenshot_dir_way_combo", {}).currentText() if hasattr(question_info.get("screenshot_dir_way_combo"), 'currentText') else "start",
                            "placeholder": question_info.get("screenshot_name_edit", {}).text() if hasattr(question_info.get("screenshot_name_edit"), 'text') else ""
                        }
                        essential_questions.append(question_data)
                    except Exception as e:
                        print(f"Error extracting essential question data: {e}")
                        continue
            
            # Get execution steps data and extract the actual data from widgets
            execution_steps_data = []
            if hasattr(self, 'execution_step_questions') and self.execution_step_questions:
                for step_data in self.execution_step_questions:
                    try:
                        # Extract data from each question block in the step
                        for question_block in step_data.get('question_blocks', []):
                            if hasattr(question_block, 'question_edit'):
                                question_data = {
                                    "name": question_block.question_edit.text() if hasattr(question_block.question_edit, 'text') else "",
                                    "description": question_block.help_text_edit.toPlainText() if hasattr(question_block.help_text_edit, 'toPlainText') else "",
                                    "question_type": self.map_question_type_to_json_format(question_block.question_type_combo.currentText() if hasattr(question_block.question_type_combo, 'currentText') else "Yes / No"),
                                    "script_name": question_block.script_name_edit.text() if hasattr(question_block.script_name_edit, 'text') else "",
                                    "icon_info": {
                                        "show_icon": question_block.icon_info_checkbox.isChecked() if hasattr(question_block.icon_info_checkbox, 'isChecked') else False,
                                        "title": question_block.icon_title_edit.text() if hasattr(question_block.icon_title_edit, 'text') else "",
                                        "content": question_block.icon_content_edit.toPlainText() if hasattr(question_block.icon_content_edit, 'toPlainText') else ""
                                    },
                                    "screenshot_config": {
                                        "take_screenshot": question_block.take_screenshot_checkbox.isChecked() if hasattr(question_block.take_screenshot_checkbox, 'isChecked') else False,
                                        "expected_lines": question_block.expected_lines_spinner.value() if hasattr(question_block.expected_lines_spinner, 'value') else 0,
                                        "screenshot_name": question_block.screenshot_name_edit.text() if hasattr(question_block.screenshot_name_edit, 'text') else "",
                                        "dir_way": question_block.screenshot_dir_way_combo.currentText() if hasattr(question_block.screenshot_dir_way_combo, 'currentText') else "start"
                                    }
                                }
                                execution_steps_data.append(question_data)
                    except Exception as e:
                        print(f"Error extracting execution step data: {e}")
                        continue
            
            # Combine essential questions and execution step questions into single questions array
            combined_questions = []
            question_id = 1
            
            # Add essential questions first - only if they have scripts
            for question in essential_questions:
                if isinstance(question, dict) and question.get('script_name', '').strip():
                    question_copy = question.copy()
                    question_copy['id'] = question_id
                    combined_questions.append(question_copy)
                    question_id += 1
            
            # Add execution step questions - only if they have scripts and deduplicate by script_name
            seen_scripts = set()
            for step in execution_steps_data:
                if isinstance(step, dict) and step.get('script_name', '').strip():
                    script_name = step.get('script_name', '').strip()
                    
                    # Skip if we've already processed this script
                    if script_name in seen_scripts:
                        continue
                    seen_scripts.add(script_name)
                    
                    # Convert execution step to question format
                    question = {
                        'id': question_id,
                        'question': step.get('name', ''),
                        'help_text': step.get('description', ''),
                        'error_message': f"Failed to execute: {step.get('name', '')}",
                        'question_type': self.map_question_type_to_json_format(step.get('question_type', 'Yes / No')),
                        'script_name': step.get('script_name', ''),
                        'icon_info': step.get('icon_info', {
                            'show_icon': False,
                            'title': '',
                            'content': ''
                        }),
                        'screenshot_line_number': 0,
                        'dir_way': 'start',
                        'placeholder': ''  # Don't generate random placeholders for questions without scripts
                    }
                    
                    # Add screenshot config if available
                    if 'screenshot_config' in step:
                        screenshot_config = step['screenshot_config']
                        question['screenshot_line_number'] = screenshot_config.get('expected_lines', 0)
                        question['dir_way'] = screenshot_config.get('dir_way', 'start')
                        # Use screenshot_name as placeholder if it exists and is not empty
                        screenshot_name = screenshot_config.get('screenshot_name', '')
                        if screenshot_name.strip():
                            question['placeholder'] = screenshot_name
                    
                    combined_questions.append(question)
                    question_id += 1
            
            # Get configuration data
            configuration_data = self.export_code_pages.get_configuration_data()
            
            # Get automatic images data
            automatic_images_data = self.export_code_pages.get_automatic_images_data()
            
            # Get the testcase title from report information
            testcase_title = "NO UNUSED HTTP METHODS"  # Default fallback
            if hasattr(self, 'report_title_edit') and self.report_title_edit.text().strip():
                testcase_title = self.report_title_edit.text().strip()
            
            # Create the new structure
            question_config_data = {
                "ui": {
                    "title": testcase_title
                },
                "questions": combined_questions,
                "metadata": {
                    "total_questions": len(combined_questions),
                    "description": "FortiAP device setup and verification questions",
                    "version": "1.0"
                },
                "configuration": {
                    "fields": configuration_data
                },
                "dependencies": self.get_dependencies_data() or [
                    {
                        "name": ["geckodriver", "python3-tk"],
                        "install": "apt"
                    },
                    {
                        "name": ["netifaces", "pillow", "selenium", "paramiko", "pyautogui", "tk"],
                        "install": "pip"
                    }
                ],
                "Summary": self.get_test_case_results_data(),
                "automatic_images": automatic_images_data
            }
            
            # Generate filename
            filename = "question_config.json"
            file_path = os.path.join(configuration_folder, filename)
            
            # Save JSON file
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(question_config_data, f, indent=2, ensure_ascii=False)
                
            print(f"Generated question_config.json with {len(combined_questions)} questions")
                
        except Exception as e:
            print(f"Error exporting automation JSON to folder: {e}")
            raise
    
    def export_images_to_folder(self, raw_logs_folder):
        """Export images to specific folder"""
        try:
            # Copy images from tmp directory if they exist
            tmp_dir = os.path.join(os.getcwd(), "tmp")
            copied_count = 0
            image_extensions = ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff', '.webp', '.svg']
            
            if os.path.exists(tmp_dir):
                # NEW: Get a list of filenames that have been processed by Section 8 Media Handler
                section8_handled_filenames = set()
                if hasattr(self, 'test_bed_diagram_data') and self.test_bed_diagram_data:
                    for img_info in self.test_bed_diagram_data.get('images', []):
                        if 'filename' in img_info:
                            section8_handled_filenames.add(img_info['filename'])
                
                for root, dirs, files in os.walk(tmp_dir):
                    for file in files:
                        if any(file.lower().endswith(ext) for ext in image_extensions):
                            src_path = os.path.join(root, file)
                            
                            # NEW: Check if this file has already been handled by Section 8 Media Handler
                            if file in section8_handled_filenames:
                                print(f"ℹ️ Skipping general copy for '{file}' as it's handled by Section 8 Media Handler.")
                                continue # Skip copying this file
                            
                            dst_path = os.path.join(raw_logs_folder, file)
                            
                            # Copy file if it doesn't exist or is newer
                            if not os.path.exists(dst_path) or os.path.getmtime(src_path) > os.path.getmtime(dst_path):
                                shutil.copy2(src_path, dst_path)
                                copied_count += 1
                
                print(f"Copied {copied_count} images to {raw_logs_folder}")
                
        except Exception as e:
            print(f"Error exporting images to folder: {e}")
            # Don't raise exception for images as they might not exist
            pass
