    def load_questions_from_new_json(self):
        """Load questions from new_updated.json file"""
        try:
            new_json_path = "new_updated.json"
            if os.path.exists(new_json_path):
                with open(new_json_path, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                
                # Set UI title
                if hasattr(self, 'ui_title_edit'):
                    self.ui_title_edit.setText(data.get('ui', {}).get('title', 'NO CGI OR OTHER SCRIPTING FOR UPLOADS'))
                
                # Clear existing questions first
                for question_info in self.essential_questions[:]:
                    self.remove_essential_question(question_info["widget"], question_info["data"])
                
                # Load questions
                questions = data.get('questions', [])
                for question_data in questions:
                    self.add_essential_question(question_data)
                    
                    # Set additional fields if they exist
                    if self.essential_questions:
                        last_question = self.essential_questions[-1]
                        
                        # Set script_name if it exists and handle script upload
                        if 'script_name' in question_data and question_data['script_name']:
                            # If script_name exists, it means a script was uploaded
                            # Use the actual script name from the data
                            question_widget = last_question['widget']
                            script_filename = question_data['script_name']
                            script_path = os.path.join(os.getcwd(), "scripts", script_filename)
                            if os.path.exists(script_path):
                                question_widget.script_path = script_path
                                question_widget.script_name_edit.setText(script_filename)
                                question_widget.script_status_label.setText(f"✅ {script_filename} uploaded")
                                question_widget.script_status_label.setStyleSheet("color: #4caf50; font-size: 11px;")
                                question_widget.remove_script_btn.setVisible(True)
                        
                        # Set screenshot_config if it exists
                        if 'screenshot_config' in question_data:
                            screenshot_config = question_data['screenshot_config']
                            last_question['take_screenshot_checkbox'].setChecked(screenshot_config.get('take_screenshot', False))
                            last_question['expected_lines_edit'].setText(str(screenshot_config.get('expected_lines', '')))
                            last_question['screenshot_name_edit'].setText(screenshot_config.get('screenshot_name', ''))
                            last_question['description_edit'].setPlainText(screenshot_config.get('description', ''))
                        
                        # Update visibility based on loaded data
                        self.toggle_question_type_fields(last_question, last_question['type_combo'].currentText())
                        self.toggle_screenshot_config_fields(last_question, last_question['take_screenshot_checkbox'].isChecked())
                        
                print(f"Successfully loaded {len(questions)} questions from new_updated.json")
                        
        except Exception as e:
            print(f"Error loading questions from new_updated.json: {e}")
        

        
