        self.essential_questions.append(question_info)
        self.questions_container.addWidget(question_widget)
        
        # Connect checkbox to toggle icon fields visibility
        show_icon_checkbox.toggled.connect(lambda checked, q_info=question_info: self.toggle_icon_fields(q_info, checked))
        
