    def upload_script_for_question(self, question_widget):
        """Upload a script file for a specific question"""
        try:
            # Open file dialog for script selection
            file_path, _ = QFileDialog.getOpenFileName(
                self,
                "Select Script File",
                "",
                "Python Files (*.py);;All Files (*)"
            )
            
            if file_path:
                # Create scripts directory if it doesn't exist
                scripts_dir = os.path.join(os.getcwd(), "scripts")
                os.makedirs(scripts_dir, exist_ok=True)
                
                # Get the original filename
                original_filename = os.path.basename(file_path)
                script_dest_path = os.path.join(scripts_dir, original_filename)
                
                # If a script already exists, remove it first
                if os.path.exists(script_dest_path):
                    os.remove(script_dest_path)
                
                # Copy the new script
                shutil.copy2(file_path, script_dest_path)
                
                # Update the question widget
                question_widget.script_path = script_dest_path
                question_widget.script_name_edit.setText(original_filename)
                question_widget.script_status_label.setText(f"✅ {original_filename} uploaded")
                question_widget.script_status_label.setStyleSheet("color: #4caf50; font-size: 11px;")
                question_widget.remove_script_btn.setVisible(True)
                
                print(f"Script uploaded successfully: {script_dest_path}")
                
        except Exception as e:
            print(f"Error uploading script: {e}")
            QMessageBox.warning(self, "Upload Error", f"Failed to upload script: {str(e)}")
    
    def remove_script_for_question(self, question_widget):
        """Remove the uploaded script for a specific question"""
        try:
            if question_widget.script_path and os.path.exists(question_widget.script_path):
                os.remove(question_widget.script_path)
                print(f"Script removed: {question_widget.script_path}")
            
            # Reset the question widget
            question_widget.script_path = ""
            question_widget.script_status_label.setText("No script uploaded")
            question_widget.script_status_label.setStyleSheet("color: #cccccc; font-size: 11px;")
            question_widget.remove_script_btn.setVisible(False)
            
        except Exception as e:
            print(f"Error removing script: {e}")
            QMessageBox.warning(self, "Remove Error", f"Failed to remove script: {str(e)}")
        
