    def toggle_question_type_fields(self, question_info, question_type):
        """Toggle visibility of script upload section and script name field based on question type"""
        is_command_execution = question_type == "command_execution"
        # Get the script upload layout from the form layout
        form_layout = question_info["widget"].layout().itemAt(1)  # form_layout is the second item
        if form_layout and form_layout.layout():
            # Find the script row in the form layout
            for i in range(form_layout.layout().rowCount()):
                item = form_layout.layout().itemAt(i)
                if item and item.widget():
                    # Check if this is the script label - only QLabel has text() method
                    if hasattr(item.widget(), 'text') and item.widget().text() == "Script:":
                        # The next item should be the field
                        if i + 1 < form_layout.layout().rowCount():
                            field_item = form_layout.layout().itemAt(i + 1)
                            if field_item and field_item.layout():
                                # Show/hide the entire script upload layout
                                for j in range(field_item.layout().count()):
                                    widget = field_item.layout().itemAt(j).widget()
                                    if widget:
                                        widget.setVisible(is_command_execution)
                        break
        
