    def remove_essential_question(self, question_widget, question_data):
        """Remove an essential question"""
        # Clean up uploaded script if it exists
        if hasattr(question_widget, 'script_path') and question_widget.script_path:
            try:
                if os.path.exists(question_widget.script_path):
                    os.remove(question_widget.script_path)
                    print(f"Script removed during question deletion: {question_widget.script_path}")
            except Exception as e:
                print(f"Error removing script during question deletion: {e}")
        
        # Remove from layout
        self.questions_container.removeWidget(question_widget)
        question_widget.deleteLater()
        
        # Remove from list
        for question_info in self.essential_questions[:]:
            if question_info["widget"] == question_widget:
                self.essential_questions.remove(question_info)
                break
        
        # Renumber all remaining questions
        self.renumber_essential_questions()
        
    def renumber_essential_questions(self):
        """Renumber all essential questions to have sequential IDs"""
        for index, question_info in enumerate(self.essential_questions, 1):
            # Update the ID in the question data
            question_info["data"]["id"] = index
            
            # Update the ID in the UI header label (Question button)
            header_layout = question_info["widget"].layout().itemAt(0).layout()
            id_label = header_layout.itemAt(0).widget()
            id_label.setText(f"Question {index}")
            
            # CRITICAL FIX: Also update the Question ID field at the bottom
            if hasattr(question_info["widget"], 'id_edit'):
                question_info["widget"].id_edit.setText(str(index))
                print(f"DEBUG: Updated Question ID field to {index}")
            
            # Store the id_edit reference in question_info for easy access
            if 'id_edit' not in question_info:
                question_info['id_edit'] = question_info["widget"].id_edit
        
    def get_essential_questions_data(self):
        """Get the current essential questions data"""
        questions_data = []
        
        for question_info in self.essential_questions:
            # Get ID from the header label
            header_layout = question_info["widget"].layout().itemAt(0).layout()
            id_label = header_layout.itemAt(0).widget()
            id_text = id_label.text()
            question_id = int(id_text.split()[-1]) if id_text.split()[-1].isdigit() else 0
            
            # Get placeholder from the question widget
            placeholder = ""
            if hasattr(question_info, 'placeholder_edit') and question_info.placeholder_edit:
                try:
                    placeholder = question_info.placeholder_edit.text().strip()
                except RuntimeError:
                    placeholder = ""
            
            question_data = {
                "id": question_id,
                "question": question_info["question_edit"].toPlainText(),
                "help_text": question_info["help_edit"].toPlainText(),
                "error_message": question_info["error_edit"].text(),
                "question_type": question_info["type_combo"].currentText(),
                "placeholder": placeholder,  # Include placeholder in export
                "icon_info": {
                    "show_icon": question_info["show_icon_checkbox"].isChecked(),
                    "title": question_info["icon_title_edit"].text(),
                    "content": question_info["icon_content_edit"].toPlainText()
                }
            }
            
            # Add script_name if script is uploaded (regardless of question type)
            question_widget = question_info["widget"]
            
            # First check if the widget has a script_path (actual uploaded script)
            if hasattr(question_widget, 'script_path') and question_widget.script_path:
                # Use the actual script path
                script_path = question_widget.script_path
                # Extract just the filename for export
                script_name = os.path.basename(script_path)
                question_data["script_name"] = script_name
                print(f"DEBUG: Exporting script '{script_name}' from path '{script_path}'")
            else:
                # Check if script_name_edit has a value (manually entered script name)
                if hasattr(question_info, 'script_name_edit') and question_info.script_name_edit:
                    try:
                        script_name = question_info.script_name_edit.text().strip()
                        if script_name:
                            question_data["script_name"] = script_name
                            print(f"DEBUG: Exporting manually entered script name '{script_name}'")
                        else:
                            question_data["script_name"] = ""
                    except RuntimeError:
                        question_data["script_name"] = ""
                else:
                    question_data["script_name"] = ""
            

            
            # Add screenshot_config if take_screenshot is checked
            if question_info["take_screenshot_checkbox"].isChecked():
                screenshot_config = {
                    "take_screenshot": True,
                    "expected_lines": question_info["expected_lines_spinner"].value(),
                    "screenshot_name": question_info["screenshot_name_edit"].text(),
                    "dir_way": question_info["screenshot_dir_way_combo"].currentText()
                }
                question_data["screenshot_config"] = screenshot_config
            
            questions_data.append(question_data)
        
        # Sort by ID
        questions_data.sort(key=lambda x: x["id"])
        
        # Generate Summary automatically based on Section 1 testcase scenario key
        summary_data = self.generate_summary_from_section_1()
        
        return {
            "ui": {
                "title": self.report_title_edit.text() if hasattr(self, 'report_title_edit') and self.report_title_edit.text().strip() else "NO UNUSED HTTP METHODS"
            },
            "questions": questions_data,
            "metadata": {
                "total_questions": len(questions_data),
                "description": "Automation questions configuration",
                "version": "1.0"
            },
            "configuration": {
                "fields": self.get_dut_config_data()
            },
            "Summary": summary_data
        }
    
    def get_dut_config_data(self):
        """Get the current DUT configuration data"""
        config_data = []
        
        for field_info in self.configuration_fields:
            field_data = {
                "id": int(field_info["id_edit"].text()) if field_info["id_edit"].text().isdigit() else 0,
                "key": field_info["key_edit"].text(),
                "label": field_info["label_edit"].text(),
                "type": field_info["type_combo"].currentText(),
                "required": field_info["required_checkbox"].isChecked(),
                "description": field_info["desc_edit"].text()
            }
            config_data.append(field_data)
        
        # Sort by ID
        config_data.sort(key=lambda x: x["id"])
        
        return config_data
        
    def generate_summary_from_section_1(self):
        """Generate Summary automatically based on Section 1 testcase scenario key"""
        try:
            # Get Section 1 content from the sections_1_7 data
            section_1_content = ""
            if hasattr(self, 'section_1_edit') and self.section_1_edit:
                section_1_content = self.section_1_edit.text().strip()
            
            # If no Section 1 content, try to get from sections_1_7 data
            if not section_1_content and hasattr(self, 'sections_1_7_data'):
                section_1_content = self.sections_1_7_data.get('section_1', {}).get('content', '').strip()
            
            # Extract testcase scenario key from Section 1 content
            # Look for patterns like 1.1.1.1, 1.9.4, etc.
            import re
            scenario_key = "none"
            
            if section_1_content:
                # Look for pattern like 1.1.1.1 or 1.9.4
                pattern = r'\b\d+\.\d+(?:\.\d+)*(?:\.\d+)?\b'
                matches = re.findall(pattern, section_1_content)
                if matches:
                    scenario_key = matches[0]  # Take the first match
                else:
                    # If no numeric pattern found, use the first meaningful text
                    words = section_1_content.split()
                    if words:
                        scenario_key = words[0]
            
            # Generate Summary based on the scenario key
            summary_data = {
                "result_1": scenario_key,
                "remark_1": f"Automatically generated summary based on Section 1 testcase scenario: {scenario_key}"
            }
            
            return summary_data
            
        except Exception as e:
            print(f"Error generating summary from Section 1: {e}")
            # Return default summary if there's an error
            return {
                "result_1": "none",
                "remark_1": "none"
            }
        
