    def remove_configuration_field_clicked(self):
        """Handle remove button click"""
        sender = self.sender()
        if hasattr(sender, 'field_widget') and hasattr(sender, 'field_data'):
            self.remove_configuration_field(sender.field_widget, sender.field_data)
        
    def remove_configuration_field(self, field_widget, field_data):
        """Remove a configuration field"""
        # Remove from layout
        self.config_fields_container.removeWidget(field_widget)
        field_widget.deleteLater()
        
        # Remove from list
        for field_info in self.configuration_fields[:]:
            if field_info["widget"] == field_widget:
                self.configuration_fields.remove(field_info)
                break
        
                # Renumber all remaining fields
        self.renumber_configuration_fields()
        
    def renumber_configuration_fields(self):
        """Renumber all configuration fields to have sequential IDs"""
        for index, field_info in enumerate(self.configuration_fields, 1):
            # Update the ID in the field data
            field_info["data"]["id"] = index
            # Update the ID in the UI
            field_info["id_edit"].setText(str(index))
        
    def get_configuration_data(self):
        """Get the current configuration data"""
        
        config_data = {
            "configuration": {
                "fields": []
            }
        }
        
        for field_info in self.configuration_fields:
            # Check if the required UI elements exist
            required_keys = ["id_edit", "key_edit", "label_edit", "type_combo", "required_checkbox", "desc_edit"]
            missing_keys = [key for key in required_keys if key not in field_info]
            if missing_keys:
                continue
                
            field_data = {
                "id": int(field_info["id_edit"].text()) if field_info["id_edit"].text().isdigit() else 0,
                "key": field_info["key_edit"].text(),
                "label": field_info["label_edit"].text(),
                "type": field_info["type_combo"].currentText(),
                "required": field_info["required_checkbox"].isChecked(),
                "description": field_info["desc_edit"].text()
            }
            config_data["configuration"]["fields"].append(field_data)
        
        # Sort by ID
        config_data["configuration"]["fields"].sort(key=lambda x: x["id"])
        
        return config_data
    
