    def load_execution_questions_from_section_11(self):
        """Load scenarios and execution steps from Section 11 Test Execution only"""
        # Save current state before clearing (to preserve user selections)
        saved_state = self.save_execution_questions_state()
        
        # Save manually added questions before clearing
        manually_added_questions = self.save_manually_added_questions()
        
        # CRITICAL FIX: Don't preserve execution step questions - let the normal loading handle everything
        # This prevents duplicates from being created
        preserved_execution_step_questions = []
        
        # Clear existing content
        for i in reversed(range(self.execution_questions_layout.count())):
            widget = self.execution_questions_layout.itemAt(i).widget()
            if widget:
                widget.setParent(None)
        
        # CRITICAL FIX: Don't clear execution step questions that were created after import
        # Only clear questions that came from imported data
        if hasattr(self, 'execution_step_questions'):
            # Keep only the preserved questions (those created after import)
            self.execution_step_questions = preserved_execution_step_questions.copy()
            print(f"DEBUG: Kept {len(self.execution_step_questions)} preserved execution step questions")
        
        # Initialize execution step questions list if it doesn't exist
        if not hasattr(self, 'execution_step_questions'):
            self.execution_step_questions = []
        
        print("DEBUG: Loading execution questions from Section 11 only")
                                    
        # SECTION 11: Always load all questions (with or without scripts)
        section_11_questions = self.load_section_11_questions()
        
        # Use only Section 11 questions
        all_questions = section_11_questions
        
        # Sort questions to ensure proper ordering
        all_questions = self.sort_questions_for_display(all_questions)
        
        # Create UI for all questions with proper test case numbers
        for index, question_data in enumerate(all_questions, 1):
            question_data['test_case_number'] = index
            # Set question number in case_data for proper display
            if 'case_data' in question_data:
                question_data['case_data']['question_number'] = index
            self.create_execution_question_ui(question_data)
        
        print(f"DEBUG: Loaded {len(all_questions)} total execution questions from Section 11 only")
        
        # Restore manually added questions
        if manually_added_questions:
            self.restore_manually_added_questions(manually_added_questions)
            print(f"DEBUG: Restored {len(manually_added_questions)} manually added questions")
        
        # Restore saved state after rebuilding UI
        if saved_state:
            self.restore_execution_questions_state(saved_state)
    
    def save_execution_questions_state(self):
        """Save the current state of execution questions UI to preserve user selections"""
        saved_state = {}
        
        # If no execution questions exist yet, return empty state
        if not hasattr(self, 'execution_step_questions') or not self.execution_step_questions:
            print("DEBUG: No execution questions to save state for")
            return saved_state
        
        try:
            for step_data in self.execution_step_questions:
                if 'question_blocks' in step_data:
                    for question_block in step_data['question_blocks']:
                        if hasattr(question_block, 'question_edit'):
                            # Create a unique key for this question
                            question_text = question_block.question_edit.text() if hasattr(question_block.question_edit, 'text') else ""
                            script_name = question_block.script_name_edit.text() if hasattr(question_block.script_name_edit, 'text') else ""
                            placeholder = question_block.placeholder_edit.text() if hasattr(question_block.placeholder_edit, 'text') else ""
                            
                            if question_text:
                                # Use a combination of question text, script name, and placeholder to create unique key
                                key = f"question_{question_text}_{script_name}_{placeholder}"
                                
                                # Save the current state of all UI elements
                                saved_state[key] = {
                                    'question_type': question_block.question_type_combo.currentText() if hasattr(question_block.question_type_combo, 'currentText') else "Yes / No",
                                    'script_name': question_block.script_name_edit.text() if hasattr(question_block.script_name_edit, 'text') else "",
                                    'help_text': question_block.help_text_edit.toPlainText() if hasattr(question_block.help_text_edit, 'toPlainText') else "",
                                    'error_message': question_block.error_message_edit.text() if hasattr(question_block.error_message_edit, 'text') else "",
                                    'icon_info_checked': question_block.icon_info_checkbox.isChecked() if hasattr(question_block.icon_info_checkbox, 'isChecked') else False,
                                    'icon_title': question_block.icon_title_edit.text() if hasattr(question_block.icon_title_edit, 'text') else "",
                                    'icon_content': question_block.icon_content_edit.toPlainText() if hasattr(question_block.icon_content_edit, 'toPlainText') else "",
                                    'take_screenshot': question_block.take_screenshot_checkbox.isChecked() if hasattr(question_block.take_screenshot_checkbox, 'isChecked') else False,
                                    'expected_lines': question_block.expected_lines_spinner.value() if hasattr(question_block.expected_lines_spinner, 'value') else 0,
                                    'screenshot_name': question_block.screenshot_name_edit.text() if hasattr(question_block.screenshot_name_edit, 'text') else "",
                                    'screenshot_dir_way': question_block.screenshot_dir_way_combo.currentText() if hasattr(question_block.screenshot_dir_way_combo, 'currentText') else "start",
                                    'placeholder': question_block.placeholder_edit.text() if hasattr(question_block.placeholder_edit, 'text') else ""
                                }
        except Exception as e:
            print(f"DEBUG: Error saving execution questions state: {e}")
        
        return saved_state
    
    def restore_execution_questions_state(self, saved_state):
        """Restore the saved state of execution questions UI"""
        if not saved_state or not hasattr(self, 'execution_step_questions') or not self.execution_step_questions:
            print("DEBUG: No saved state to restore or no execution questions exist")
            return
        
        print(f"DEBUG: Restoring state for {len(saved_state)} questions")
        
        try:
            for step_data in self.execution_step_questions:
                if 'question_blocks' in step_data:
                    for question_block in step_data['question_blocks']:
                        if hasattr(question_block, 'question_edit'):
                            question_text = question_block.question_edit.text() if hasattr(question_block.question_edit, 'text') else ""
                            script_name = question_block.script_name_edit.text() if hasattr(question_block.script_name_edit, 'text') else ""
                            placeholder = question_block.placeholder_edit.text() if hasattr(question_block.placeholder_edit, 'text') else ""
                            
                            if question_text:
                                # Use a combination of question text, script name, and placeholder to create unique key
                                key = f"question_{question_text}_{script_name}_{placeholder}"
                                
                                if key in saved_state:
                                    state = saved_state[key]
                                    
                                    # Restore question type
                                    if hasattr(question_block, 'question_type_combo'):
                                        question_type = state.get('question_type', 'Yes / No')
                                        index = question_block.question_type_combo.findText(question_type)
                                        if index >= 0:
                                            question_block.question_type_combo.setCurrentIndex(index)
                                    
                                    # Restore script name
                                    if hasattr(question_block, 'script_name_edit'):
                                        question_block.script_name_edit.setText(state.get('script_name', ''))
                                    
                                    # Restore help text
                                    if hasattr(question_block, 'help_text_edit'):
                                        question_block.help_text_edit.setPlainText(state.get('help_text', ''))
                                    
                                    # Restore error message
                                    if hasattr(question_block, 'error_message_edit'):
                                        question_block.error_message_edit.setText(state.get('error_message', ''))
                                    
                                    # Restore icon info
                                    if hasattr(question_block, 'icon_info_checkbox'):
                                        question_block.icon_info_checkbox.setChecked(state.get('icon_info_checked', False))
                                    if hasattr(question_block, 'icon_title_edit'):
                                        question_block.icon_title_edit.setText(state.get('icon_title', ''))
                                    if hasattr(question_block, 'icon_content_edit'):
                                        question_block.icon_content_edit.setPlainText(state.get('icon_content', ''))
                                    
                                    # Restore screenshot config
                                    if hasattr(question_block, 'take_screenshot_checkbox'):
                                        question_block.take_screenshot_checkbox.setChecked(state.get('take_screenshot', False))
                                    if hasattr(question_block, 'expected_lines_spinner'):
                                        question_block.expected_lines_spinner.setValue(state.get('expected_lines', 0))
                                    if hasattr(question_block, 'screenshot_name_edit'):
                                        question_block.screenshot_name_edit.setText(state.get('screenshot_name', ''))
                                    if hasattr(question_block, 'screenshot_dir_way_combo'):
                                        dir_way = state.get('screenshot_dir_way', 'start')
                                        index = question_block.screenshot_dir_way_combo.findText(dir_way)
                                        if index >= 0:
                                            question_block.screenshot_dir_way_combo.setCurrentIndex(index)
                                    
                                    # Restore placeholder
                                    if hasattr(question_block, 'placeholder_edit'):
                                        placeholder_value = state.get('placeholder', '')
                                        if placeholder_value:
                                            question_block.placeholder_edit.setText(placeholder_value)
                                            print(f"DEBUG: Restored placeholder '{placeholder_value}' for question: {question_text}")
                                    
                                    print(f"DEBUG: Restored state for question: {question_text}")
        except Exception as e:
            print(f"DEBUG: Error restoring execution questions state: {e}")
    
    def save_manually_added_questions(self):
        """Save manually added questions (those not from Section 11) before clearing"""
        manually_added_questions = []
        
        if not hasattr(self, 'execution_step_questions') or not self.execution_step_questions:
            return manually_added_questions
        
        try:
            for step_data in self.execution_step_questions:
                if 'question_blocks' in step_data:
                    # Only save additional questions (skip the first question which comes from Section 11)
                    for question_index, question_block in enumerate(step_data['question_blocks']):
                        if question_index > 0 and hasattr(question_block, 'question_edit'):  # Skip first question (index 0)
                            question_text = question_block.question_edit.text() if hasattr(question_block.question_edit, 'text') else ""
                            
                            if question_text:  # Only save if question has text
                                # This is a manually added question (additional question)
                                question_data = {
                                    'step_data': step_data,
                                    'question_text': question_text,
                                    'question_type': question_block.question_type_combo.currentText() if hasattr(question_block.question_type_combo, 'currentText') else "Yes / No",
                                    'help_text': question_block.help_text_edit.toPlainText() if hasattr(question_block.help_text_edit, 'toPlainText') else "",
                                    'error_message': question_block.error_message_edit.text() if hasattr(question_block.error_message_edit, 'text') else "",
                                    'script_name': question_block.script_name_edit.text() if hasattr(question_block.script_name_edit, 'text') else "",
                                    'placeholder': question_block.placeholder_edit.text() if hasattr(question_block.placeholder_edit, 'text') else "",
                                    'icon_info_checked': question_block.icon_info_checkbox.isChecked() if hasattr(question_block.icon_info_checkbox, 'isChecked') else False,
                                    'icon_title': question_block.icon_title_edit.text() if hasattr(question_block.icon_title_edit, 'text') else "",
                                    'icon_content': question_block.icon_content_edit.toPlainText() if hasattr(question_block.icon_content_edit, 'toPlainText') else "",
                                    'take_screenshot': question_block.take_screenshot_checkbox.isChecked() if hasattr(question_block.take_screenshot_checkbox, 'isChecked') else False,
                                    'expected_lines': question_block.expected_lines_spinner.value() if hasattr(question_block.expected_lines_spinner, 'value') else 0,
                                    'screenshot_name': question_block.screenshot_name_edit.text() if hasattr(question_block.screenshot_name_edit, 'text') else "",
                                    'screenshot_dir_way': question_block.screenshot_dir_way_combo.currentText() if hasattr(question_block.screenshot_dir_way_combo, 'currentText') else "start"
                                }
                                manually_added_questions.append(question_data)
                                print(f"DEBUG: Saved manually added question: {question_text}")
        except Exception as e:
            print(f"DEBUG: Error saving manually added questions: {e}")
        
        return manually_added_questions
    
    def restore_manually_added_questions(self, manually_added_questions):
        """Restore manually added questions after reloading Section 11 questions"""
        if not manually_added_questions:
            return
        
        try:
            for question_data in manually_added_questions:
                step_data = question_data['step_data']
                
                # Find the corresponding step_data in the current execution_step_questions
                # by matching the step_text and case_data
                target_step_data = None
                for current_step_data in self.execution_step_questions:
                    if (current_step_data['step_text'] == step_data['step_text'] and 
                        current_step_data['case_data'] == step_data['case_data']):
                        target_step_data = current_step_data
                        break
                
                if target_step_data:
                    # Get the next question number for this step
                    next_question_number = len(target_step_data['question_blocks']) + 1
                    
                    # Create new question block
                    new_question_block = self.create_question_block(
                        target_step_data['step_number'],
                        target_step_data['step_text'],
                        target_step_data['case_data'],
                        next_question_number
                    )
                    
                    # Set step_data reference
                    new_question_block.step_data = target_step_data
                    
                    # Restore the question data
                    if hasattr(new_question_block, 'question_edit'):
                        new_question_block.question_edit.setText(question_data['question_text'])
                    if hasattr(new_question_block, 'question_type_combo'):
                        index = new_question_block.question_type_combo.findText(question_data['question_type'])
                        if index >= 0:
                            new_question_block.question_type_combo.setCurrentIndex(index)
                    if hasattr(new_question_block, 'help_text_edit'):
                        new_question_block.help_text_edit.setPlainText(question_data['help_text'])
                    if hasattr(new_question_block, 'error_message_edit'):
                        new_question_block.error_message_edit.setText(question_data['error_message'])
                    if hasattr(new_question_block, 'script_name_edit'):
                        new_question_block.script_name_edit.setText(question_data['script_name'])
                    if hasattr(new_question_block, 'placeholder_edit'):
                        new_question_block.placeholder_edit.setText(question_data['placeholder'])
                    if hasattr(new_question_block, 'icon_info_checkbox'):
                        new_question_block.icon_info_checkbox.setChecked(question_data['icon_info_checked'])
                    if hasattr(new_question_block, 'icon_title_edit'):
                        new_question_block.icon_title_edit.setText(question_data['icon_title'])
                    if hasattr(new_question_block, 'icon_content_edit'):
                        new_question_block.icon_content_edit.setPlainText(question_data['icon_content'])
                    if hasattr(new_question_block, 'take_screenshot_checkbox'):
                        new_question_block.take_screenshot_checkbox.setChecked(question_data['take_screenshot'])
                    if hasattr(new_question_block, 'expected_lines_spinner'):
                        new_question_block.expected_lines_spinner.setValue(question_data['expected_lines'])
                    if hasattr(new_question_block, 'screenshot_name_edit'):
                        new_question_block.screenshot_name_edit.setText(question_data['screenshot_name'])
                    if hasattr(new_question_block, 'screenshot_dir_way_combo'):
                        index = new_question_block.screenshot_dir_way_combo.findText(question_data['screenshot_dir_way'])
                        if index >= 0:
                            new_question_block.screenshot_dir_way_combo.setCurrentIndex(index)
                    
                    # Add to step data
                    target_step_data['question_blocks'].append(new_question_block)
                    
                    # Add to UI
                    if hasattr(self, 'execution_questions_layout'):
                        self.execution_questions_layout.addWidget(new_question_block)
                        print(f"DEBUG: Restored manually added question: {question_data['question_text']}")
                else:
                    print(f"DEBUG: Could not find target step_data for manually added question: {question_data['question_text']}")
        except Exception as e:
            print(f"DEBUG: Error restoring manually added questions: {e}")
    
    def load_section_11_questions(self):
        """Load all questions from Section 11 Test Execution (with or without scripts)"""
        questions = []
        
        # Always try to get from step_widgets first (current state)
        if hasattr(self, 'step_widgets') and self.step_widgets:
            print("DEBUG: Loading Section 11 questions from step_widgets (current state)")
            for step_key, step_data in self.step_widgets.items():
                step_text = step_data.get('step_text', '')
                scenario_key = step_data.get('scenario_key', 'Unknown')
                
                # Extract case_number and step_index from step_key (format: case_number_step_index)
                case_number = 1  # default value
                step_index = 1  # default value
                if '_' in step_key:
                    try:
                        parts = step_key.split('_')
                        case_number = int(parts[0])
                        step_index = int(parts[-1])
                    except (ValueError, IndexError):
                        case_number = 1
                        step_index = 1
                
                # Check if this step was deleted
                deletion_key1 = f"{scenario_key}:{step_text}"
                deletion_key2 = f"Unknown:{step_text}" if scenario_key == "" else f":{step_text}"
                if (hasattr(self, 'deleted_steps') and 
                    (deletion_key1 in self.deleted_steps or deletion_key2 in self.deleted_steps)):
                    print(f"DEBUG: Skipping deleted step: {deletion_key1} or {deletion_key2}")
                    continue
                
                # Check if this step has scripts
                scripts = step_data.get('upload_scripts_list', [])
                
                if scripts:
                    # Create a question entry for each script
                    for script_info in scripts:
                        script_filename = script_info.get('original_filename', script_info.get('filename', ''))
                        screenshot_name = script_info.get('placeholder', script_info.get('description', ''))
                        question_data = {
                            'source_section': 'Section 11',
                            'question_text': step_text,
                            'script_name': script_filename,
                            'has_script': True,
                            'case_number': case_number,
                            'step_index': step_index,
                            'screenshot_name': screenshot_name,
                            'case_data': {
                                'scenario_key': scenario_key,
                                'scenario_description': step_data.get('scenario_description', 'No description')
                            }
                        }
                        questions.append(question_data)
                else:
                    # Create a question entry without script
                    question_data = {
                        'source_section': 'Section 11',
                        'question_text': step_text,
                        'script_name': None,
                        'has_script': False,
                        'case_number': case_number,
                        'step_index': step_index,
                        'case_data': {
                            'scenario_key': scenario_key,
                            'scenario_description': step_data.get('scenario_description', 'No description')
                        }
                    }
                    questions.append(question_data)
        
        # Also try to get from imported config data if available (for fallback)
        elif hasattr(self, '_imported_test_execution_data') and self._imported_test_execution_data:
            print("DEBUG: Loading Section 11 questions from imported config data (fallback)")
            for imported_case in self._imported_test_execution_data:
                if 'steps_data' in imported_case:
                    for step_data in imported_case['steps_data']:
                        if 'step_text' in step_data:
                            step_text = step_data['step_text']
                            scenario_key = imported_case.get('scenario_key', 'Unknown')
                            case_number = imported_case.get('case_number', 1)  # Get case_number from imported data
                            step_index = step_data.get('step_index', 1)  # Get step_index from imported data
                
                # Check if this step was deleted
                # Handle both possible scenario key formats
                deletion_key1 = f"{scenario_key}:{step_text}"
                deletion_key2 = f"Unknown:{step_text}" if scenario_key == "" else f":{step_text}"
                if (hasattr(self, 'deleted_steps') and 
                    (deletion_key1 in self.deleted_steps or deletion_key2 in self.deleted_steps)):
                    print(f"DEBUG: Skipping deleted imported step: {deletion_key1} or {deletion_key2}")
                    continue
                
                # Check if this step has scripts
                scripts = step_data.get('scripts', [])
                
                if scripts:
                    # Create a question entry for each script
                    for script_info in scripts:
                        script_filename = script_info.get('original_filename', script_info['filename'])
                        # Extract placeholder from script_info to use as screenshot_name
                        screenshot_name = script_info.get('placeholder', script_info.get('description', ''))
                        question_data = {
                            'source_section': 'Section 11',
                            'question_text': step_text,
                            'script_name': script_filename,
                            'has_script': True,
                            'case_number': case_number,  # Include case_number for proper grouping
                            'step_index': step_index,  # Include step_index for proper sorting
                            'screenshot_name': screenshot_name,  # Add screenshot_name from placeholder
                            'case_data': {
                                'scenario_key': imported_case.get('scenario_key', 'Unknown'),
                                'scenario_description': imported_case.get('test_case_description', 'No description')
                            }
                        }
                        questions.append(question_data)
                else:
                    # Create a question entry without script
                    question_data = {
                        'source_section': 'Section 11',
                        'question_text': step_text,
                        'script_name': None,
                        'has_script': False,
                        'case_number': case_number,  # Include case_number for proper grouping
                        'step_index': step_index,  # Include step_index for proper sorting
                        'case_data': {
                            'scenario_key': imported_case.get('scenario_key', 'Unknown'),
                            'scenario_description': imported_case.get('test_case_description', 'No description')
                        }
                    }
                    questions.append(question_data)
        
        # Fallback: try to get from test_execution_cases (legacy support)
        elif hasattr(self, 'test_execution_cases') and self.test_execution_cases:
            print("DEBUG: Loading Section 11 questions from test_execution_cases (fallback)")
            for case in self.test_execution_cases:
                if 'execution_steps' in case:
                    for step in case['execution_steps']:
                        step_text = step.get('step_text', '')
                        scenario_key = case.get('scenario_key', 'Unknown')
                        
                        # Check if this step was deleted
                        # Handle both possible scenario key formats
                        deletion_key1 = f"{scenario_key}:{step_text}"
                        deletion_key2 = f"Unknown:{step_text}" if scenario_key == "" else f":{step_text}"
                        if (hasattr(self, 'deleted_steps') and 
                            (deletion_key1 in self.deleted_steps or deletion_key2 in self.deleted_steps)):
                            print(f"DEBUG: Skipping deleted fallback step: {deletion_key1} or {deletion_key2}")
                            continue
                        
                        if step_text:
                            # Check if this step has scripts (from step_widgets)
                            scripts = self.get_scripts_for_step(step_text)
                            
                            if scripts:
                                # Create a question entry for each script
                                for script_filename in scripts:
                                    question_data = {
                                        'source_section': 'Section 11',
                                        'question_text': step_text,
                                        'script_name': script_filename,
                                        'has_script': True,
                                        'case_data': {
                                            'scenario_key': case.get('scenario_key', 'Unknown'),
                                            'scenario_description': case.get('scenario_description', 'No description')
                                        }
                                    }
                                    questions.append(question_data)
                            else:
                                # Create a question entry without script
                                question_data = {
                                    'source_section': 'Section 11',
                                    'question_text': step_text,
                                    'script_name': None,
                                    'has_script': False,
                                    'case_data': {
                                        'scenario_key': case.get('scenario_key', 'Unknown'),
                                        'scenario_description': case.get('scenario_description', 'No description')
                                    }
                                }
                                questions.append(question_data)
        
        print(f"DEBUG: Loaded {len(questions)} Section 11 questions")
        return questions
    
    def load_section_8_questions_with_scripts(self):
        """Load questions from Section 8 Test Plan only if they have scripts uploaded"""
        questions = []
        
        # Check if there are any scripts uploaded in Section 8
        section_8_scripts = self.get_section_8_scripts()
        
        if section_8_scripts:
            print("DEBUG: Loading Section 8 questions with scripts")
            for script_info in section_8_scripts:
                question_text = script_info.get('question_text', '')
                script_filename = script_info.get('script_name', '')
                
                if question_text and script_filename:
                    question_data = {
                        'source_section': 'Section 8',
                        'question_text': question_text,
                        'script_name': script_filename,
                        'has_script': True,
                        'case_data': {
                            'scenario_key': 'Section 8 Test Plan',
                            'scenario_description': 'Test Plan Questions'
                        }
                    }
                    questions.append(question_data)
        
        print(f"DEBUG: Loaded {len(questions)} Section 8 questions with scripts")
        return questions
    
    def get_scripts_for_step(self, step_text):
        """Get scripts uploaded for a specific step"""
        scripts = []
        
        if hasattr(self, 'step_widgets'):
            for step_key, step_data in self.step_widgets.items():
                if step_data.get('step_text') == step_text:
                    if 'upload_scripts_list' in step_data and step_data['upload_scripts_list']:
                        for script_info in step_data['upload_scripts_list']:
                            script_filename = script_info.get('original_filename', script_info['filename'])
                            scripts.append(script_filename)
                    break
        
        return scripts
    
    def get_section_8_scripts(self):
        """Get all scripts uploaded in Section 8 Test Plan"""
        scripts = []
        
        # Check if automation mapper has Section 8 scripts
        if hasattr(self, 'automation_mapper'):
            for script_id, mapping in self.automation_mapper.script_mappings.items():
                if mapping.get('source_tab') == 'Section 8 Test Plan':
                    scripts.append({
                        'question_text': mapping.get('question_text', ''),
                        'script_name': mapping.get('script_name', '')
                    })
        
        return scripts
    
    def get_test_case_number_for_question(self, question_data):
        """Get the actual test case number for a question from Section 11 data"""
        try:
            # Try to get test case number from imported data first
            if hasattr(self, '_imported_test_execution_data') and self._imported_test_execution_data:
                for i, imported_case in enumerate(self._imported_test_execution_data, 1):
                    if 'steps_data' in imported_case:
                        for step_data in imported_case['steps_data']:
                            if step_data.get('step_text') == question_data['question_text']:
                                # Return the test case number in proper format (1.9.4.x)
                                return f"1.9.4.{i}"
            
            # If not found in imported data, try to get from test_execution_cases
            if hasattr(self, 'test_execution_cases') and self.test_execution_cases:
                for i, case in enumerate(self.test_execution_cases, 1):
                    if 'execution_steps' in case:
                        for step in case['execution_steps']:
                            if step.get('step_text') == question_data['question_text']:
                                # Return the test case number in proper format (1.9.4.x)
                                return f"1.9.4.{i}"
            
            # If still not found, use sequential numbering as fallback
            fallback_number = len(self.execution_step_questions) + 1
            return f"1.9.4.{fallback_number}"
            
        except Exception as e:
            print(f"Error getting test case number for question: {e}")
            # Fallback to sequential numbering
            fallback_number = len(self.execution_step_questions) + 1
            return f"1.9.4.{fallback_number}"
    
    def create_execution_question_ui(self, question_data):
        """Create UI for an execution question"""
        try:
            # Get the actual test case number from Section 11 data
            test_case_number = self.get_test_case_number_for_question(question_data)
            
            # Create step data structure
            step_data = {
                'case_data': question_data['case_data'],
                'step_number': test_case_number,  # Use actual test case number instead of sequential
                'step_text': question_data['question_text'],
                'question_blocks': [],
                'source_section': question_data['source_section'],
                'questions_layout': self.execution_questions_layout  # Add questions layout reference
            }
            
            # Add to execution step questions list
            self.execution_step_questions.append(step_data)
            
            # Create question block
            question_block = self.create_question_block(
                step_data['step_number'],
                step_data['step_text'],
                step_data['case_data'],
                step_data['case_data'].get('question_number', 1)  # question number from case_data
            )
            
            # Auto-update Section 12 Test Case Results when Section 8 Test Plan is updated
            if hasattr(self, 'update_test_case_results'):
                self.update_test_case_results()
            
            # Configure question block based on whether it has a script
            if question_data['has_script']:
                # Set up script information
                if hasattr(question_block, 'question_type_combo'):
                    question_block.question_type_combo.setCurrentText("command_execution")
                if hasattr(question_block, 'script_name_edit'):
                    question_block.script_name_edit.setText(question_data['script_name'])
                if hasattr(question_block, 'script_status_label'):
                    question_block.script_status_label.setText(f"✅ {question_data['script_name']} uploaded")
                    question_block.script_status_label.setStyleSheet("color: #4caf50; font-size: 11px;")
                
                # Set screenshot name from placeholder if available
                placeholder = question_data.get('placeholder', '')
                screenshot_name = question_data.get('screenshot_name', '')
                # Use screenshot_name if available, otherwise fall back to placeholder
                final_screenshot_name = screenshot_name if screenshot_name else placeholder
                if final_screenshot_name and hasattr(question_block, 'screenshot_name_edit'):
                    question_block.screenshot_name_edit.setText(final_screenshot_name)
                    print(f"DEBUG: Set screenshot name to '{final_screenshot_name}' from Section 11 (screenshot_name: '{screenshot_name}', placeholder: '{placeholder}')")
            else:
                # Set up for question without script
                if hasattr(question_block, 'question_type_combo'):
                    question_block.question_type_combo.setCurrentText("Yes / No")  # Default type
                if hasattr(question_block, 'script_name_edit'):
                    question_block.script_name_edit.setText("")
                if hasattr(question_block, 'script_status_label'):
                    question_block.script_status_label.setText("No script uploaded")
                    question_block.script_status_label.setStyleSheet("color: #cccccc; font-size: 11px;")
            
            # Set step_data reference in the question block for add/remove functionality
            question_block.step_data = step_data
            
            # Add question block to step data
            step_data['question_blocks'].append(question_block)
            
            # Add to UI
            self.execution_questions_layout.addWidget(question_block)
            
            print(f"DEBUG: Created execution question UI for: {question_data['question_text']}")
            print(f"DEBUG: Source: {question_data['source_section']}, Has script: {question_data['has_script']}")
            
        except Exception as e:
            print(f"Error creating execution question UI: {e}")
            import traceback
            traceback.print_exc()
    
    def apply_script_data_to_execution_questions(self):
        """Apply script data from Section 11 to execution step questions"""
        if not hasattr(self, 'execution_step_questions') or not self.execution_step_questions:
            print("DEBUG: No execution step questions to apply script data to")
            return
        
        print("DEBUG: Applying script data to execution step questions")
        
        # Ensure step widgets are properly initialized
        self.ensure_step_widgets_initialized()
        
        # First, try to get script data from imported config data
        script_data_found = False
        
        if hasattr(self, '_imported_test_execution_data') and self._imported_test_execution_data:
            print("DEBUG: Checking imported config data for scripts")
            for imported_case in self._imported_test_execution_data:
                if 'steps_data' in imported_case:
                    for step_data in imported_case['steps_data']:
                        if 'scripts' in step_data and step_data['scripts']:
                            # Get the first script from this step
                            script_info = step_data['scripts'][0]
                            script_filename = script_info.get('original_filename', script_info['filename'])
                            
                            print(f"DEBUG: Found script '{script_filename}' in imported data")
                            
                            # Find the corresponding execution step question and update it
                            for step_data_exec in self.execution_step_questions:
                                if 'question_blocks' in step_data_exec and step_data_exec['question_blocks']:
                                    question_block = step_data_exec['question_blocks'][0]
                                    
                                    if hasattr(question_block, 'question_type_combo') and hasattr(question_block, 'script_name_edit'):
                                        # Change question type to command_execution
                                        question_block.question_type_combo.setCurrentText("command_execution")
                                        
                                        # Fill the script name field with the script filename
                                        question_block.script_name_edit.setText(script_filename)
                                        
                                        print(f"DEBUG: Applied script '{script_filename}' to execution step question from imported data")
                                        script_data_found = True
                                        break
                            
                            # Only apply to the first script found
                            if script_data_found:
                                break
                
                # Only check the first case with scripts
                if script_data_found:
                    break
        
        # If no script data found in imported data, try step widgets
        if not script_data_found and hasattr(self, 'step_widgets'):
            print("DEBUG: Checking step widgets for scripts")
            for step_key, step_data in self.step_widgets.items():
                if 'upload_scripts_list' in step_data and step_data['upload_scripts_list']:
                    # Get the first script from this step
                    script_info = step_data['upload_scripts_list'][0]
                    script_filename = script_info.get('original_filename', script_info['filename'])
                    
                    print(f"DEBUG: Found script '{script_filename}' in step {step_key}")
                    
                    # Find the corresponding execution step question and update it
                    for step_data_exec in self.execution_step_questions:
                        if 'question_blocks' in step_data_exec and step_data_exec['question_blocks']:
                            question_block = step_data_exec['question_blocks'][0]
                            
                            if hasattr(question_block, 'question_type_combo') and hasattr(question_block, 'script_name_edit'):
                                # Change question type to command_execution
                                question_block.question_type_combo.setCurrentText("command_execution")
                                
                                # Fill the script name field with the script filename
                                question_block.script_name_edit.setText(script_filename)
                                
                                print(f"DEBUG: Applied script '{script_filename}' to execution step question from step widgets")
                                script_data_found = True
                                break
                    
                    # Only apply to the first script found
                    if script_data_found:
                        break
        
        if script_data_found:
            print("DEBUG: Successfully applied script data to execution step questions")
        else:
            print("DEBUG: No script data found in imported data or step widgets")
    
    def ensure_step_widgets_initialized(self):
        """Ensure step widgets are properly initialized after import"""
        if not hasattr(self, 'step_widgets'):
            print("DEBUG: Step widgets not initialized, creating empty dict")
            self.step_widgets = {}
            return
        
        print(f"DEBUG: Step widgets initialized with {len(self.step_widgets)} entries")
        
        # Preserve current scripts before processing
        self.preserve_current_scripts()
        
        # Add a delay to ensure all widgets are properly created before processing imported data
        QTimer.singleShot(200, self._process_imported_data_after_initialization)
    
    def preserve_current_scripts(self):
        """Preserve current scripts and placeholders in global storage to prevent loss during navigation"""
        if hasattr(self, 'step_widgets'):
            for step_key, step_data in self.step_widgets.items():
                # Preserve scripts
                if 'upload_scripts_list' in step_data and step_data['upload_scripts_list']:
                    # Initialize global storage if not exists
                    if not hasattr(self, '_global_step_scripts'):
                        self._global_step_scripts = {}
                    
                    # Store scripts with placeholders
                    self._global_step_scripts[step_key] = []
                    for script_info in step_data['upload_scripts_list']:
                        # Create a copy to avoid reference issues
                        script_copy = script_info.copy()
                        # Ensure placeholder is preserved
                        if 'placeholder' not in script_copy and 'description' in script_copy:
                            script_copy['placeholder'] = script_copy['description']
                        self._global_step_scripts[step_key].append(script_copy)
                    
                    print(f"DEBUG: Preserved {len(step_data['upload_scripts_list'])} scripts for step {step_key}")
                    for script in step_data['upload_scripts_list']:
                        print(f"DEBUG: Preserved script '{script.get('original_filename', script.get('filename', 'unknown'))}' with placeholder '{script.get('placeholder', 'NO_PLACEHOLDER')}'")
                
                # CRITICAL FIX: Also preserve placeholders
                if 'placeholders_list' in step_data and step_data['placeholders_list']:
                    # Initialize global storage if not exists
                    if not hasattr(self, '_global_step_placeholders'):
                        self._global_step_placeholders = {}
                    
                    # Store placeholders
                    self._global_step_placeholders[step_key] = []
                    for placeholder_info in step_data['placeholders_list']:
                        # Create a copy to avoid reference issues
                        placeholder_copy = placeholder_info.copy()
                        # Remove widget references as they can't be serialized
                        if 'widget' in placeholder_copy:
                            del placeholder_copy['widget']
                        if 'remove_btn' in placeholder_copy:
                            del placeholder_copy['remove_btn']
                        self._global_step_placeholders[step_key].append(placeholder_copy)
                    
                    print(f"DEBUG: Preserved {len(step_data['placeholders_list'])} placeholders for step {step_key}")
                    for placeholder in step_data['placeholders_list']:
                        print(f"DEBUG: Preserved placeholder '{placeholder.get('name', 'unknown')}'")
    
    def ensure_scripts_preservation_on_navigation(self):
        """Ensure scripts are preserved when navigating away from Section 11"""
        # Set up a timer to periodically preserve scripts
        if not hasattr(self, '_script_preservation_timer'):
            self._script_preservation_timer = QTimer()
            self._script_preservation_timer.timeout.connect(self.preserve_current_scripts)
            self._script_preservation_timer.start(5000)  # Preserve every 5 seconds
        
        # Also preserve scripts when the page loses focus
        if hasattr(self, 'content_stack'):
            self.content_stack.currentChanged.connect(self.on_page_changed)
    
    def on_page_changed(self, index):
        """Called when the page changes - preserve scripts and text content before navigation"""
        print(f"DEBUG: Page changed to index {index}, preserving scripts and text content")
        self.preserve_current_scripts()
        # Auto-save Section 11 text content when navigating away
        self.auto_save_section_11_content()
        
        # CRITICAL FIX: Preserve scenario descriptions when navigating away
        self.preserve_scenario_descriptions()
        
        # CRITICAL FIX: Ensure scripts are preserved in global storage when navigating away
        # This prevents scripts from being lost when navigating between sections
        if hasattr(self, 'step_widgets') and self.step_widgets:
            print("DEBUG: Preserving scripts in global storage before navigation")
            if not hasattr(self, '_global_step_scripts'):
                self._global_step_scripts = {}
            
            for step_key, step_data in self.step_widgets.items():
                if 'upload_scripts_list' in step_data and step_data['upload_scripts_list']:
                    # Create a deep copy to avoid reference issues
                    scripts_copy = []
                    for script_info in step_data['upload_scripts_list']:
                        script_copy = script_info.copy()
                        # Remove the remove_btn reference as it can't be serialized
                        if 'remove_btn' in script_copy:
                            del script_copy['remove_btn']
                        # Ensure placeholder field is set correctly
                        if 'placeholder' not in script_copy and 'description' in script_copy:
                            script_copy['placeholder'] = script_copy['description']
                        scripts_copy.append(script_copy)
                    
                    self._global_step_scripts[step_key] = scripts_copy
                    print(f"DEBUG: Preserved {len(scripts_copy)} scripts for step {step_key} in global storage")
    
    def _process_imported_data_after_initialization(self):
        """Process imported data after step widgets are fully initialized"""
        print("DEBUG: Processing imported data after step widgets initialization")
        
        # Check if we have imported test execution data that needs to be processed
        if hasattr(self, '_imported_test_execution_data') and self._imported_test_execution_data:
            print("DEBUG: Found imported test execution data, processing...")
            self.populate_test_execution_cases_with_imported_data()
        else:
            print("DEBUG: No imported test execution data found")
    
    def create_scenario_questions_section(self, case_data):
        """Create a section for scenario questions"""
        scenario_group = QGroupBox(f"Scenario {case_data['case_number']}: {case_data['scenario_key']}")
        scenario_group.setStyleSheet("""
            QGroupBox {
                font-weight: bold;
                border: 2px solid #444444;
                border-radius: 5px;
                margin-top: 10px;
                padding-top: 10px;
            }
            QGroupBox::title {
                subcontrol-origin: margin;
                left: 10px;
                padding: 0 5px 0 5px;
                color: #ff9800;
            }
        """)
        scenario_layout = QVBoxLayout(scenario_group)
        
        # Scenario description
        description_label = QLabel(case_data['scenario_description'])
        description_label.setStyleSheet("color: #cccccc; margin-bottom: 10px;")
        description_label.setWordWrap(True)
        scenario_layout.addWidget(description_label)
        
        # Execution steps container
        steps_container = QWidget()
        steps_layout = QVBoxLayout(steps_container)
        
        execution_steps = case_data.get('execution_steps', [])
        
        # Create question controls for each execution step
        if execution_steps:
            for i, step in enumerate(execution_steps):
                # Ensure step is a string
                if isinstance(step, dict):
                    step_text = step.get('step_text', step.get('text', str(step)))
                else:
                    step_text = str(step)
                step_widget = self.create_execution_step_question_controls(i + 1, step_text, case_data)
                steps_layout.addWidget(step_widget)
        else:
            # Add a placeholder message if no execution steps
            no_steps_label = QLabel("No execution steps found for this scenario. Please add steps in Section 8.4 Test Execution Steps.")
            no_steps_label.setStyleSheet("color: #ff6b6b; font-style: italic; padding: 10px;")
            steps_layout.addWidget(no_steps_label)
        
        scenario_layout.addWidget(steps_container)
        self.execution_questions_layout.addWidget(scenario_group)
    
    
    def sort_questions_for_display(self, questions):
        """Sort questions for proper display order"""
        def get_sort_key(question):
            # Sort by source section first (Section 11 before Section 8)
            source_order = {'Section 11': 1, 'Section 8': 2}
            source_priority = source_order.get(question.get('source_section', ''), 3)
            
            # Then sort by scenario key for consistent ordering
            scenario_key = question.get('case_data', {}).get('scenario_key', '')
            
            # For Section 11 questions, sort by case_number first, then step_index to preserve execution order
            # For other sections, fall back to question text for consistent ordering
            if question.get('source_section') == 'Section 11':
                case_number = question.get('case_number', 999)  # Default to end if no case_number
                step_index = question.get('step_index', 999)  # Default to end if no step_index
                return (source_priority, scenario_key, case_number, step_index)
            else:
                question_text = question.get('question_text', '')
                return (source_priority, scenario_key, question_text)
        
        return sorted(questions, key=get_sort_key)

    def create_execution_step_question_controls(self, step_number, step_text, case_data):
        """Create question controls for an execution step with support for multiple questions"""
        step_widget = QWidget()
        step_layout = QVBoxLayout(step_widget)
        
        # Step header
        # Ensure step_text is a string for display
        if not isinstance(step_text, str):
            step_text = str(step_text)
        step_header = QLabel(f"Test Case {step_number}: {step_text}")
        step_header.setStyleSheet("font-weight: bold; color: #ff9800; margin-bottom: 10px;")
        step_layout.addWidget(step_header)
        
        # Container for multiple questions
        questions_container = QWidget()
        questions_layout = QVBoxLayout(questions_container)
        step_layout.addWidget(questions_container)
        
        # Create the first question block (we'll set step_data after creating step_data)
        question_block = self.create_question_block(step_number, step_text, case_data, 1)
        questions_layout.addWidget(question_block)
        
        # Store step data for later access
        step_data = {
            'step_number': step_number,
            'step_text': step_text,
            'case_data': case_data,
            'questions_container': questions_container,
            'questions_layout': questions_layout,
            'question_blocks': [question_block]
        }
        
        # Set step_data reference in the first question block for removal
        question_block.step_data = step_data
        
        # Add to a list for later processing
        if not hasattr(self, 'execution_step_questions'):
            self.execution_step_questions = []
        self.execution_step_questions.append(step_data)
        
        return step_widget
    
