    def get_dependencies_data(self):
        """Get dependencies data from the UI"""
        try:
            apt_text = self.apt_dependencies_edit.toPlainText().strip()
            pip_text = self.pip_dependencies_edit.toPlainText().strip()
            
            apt_packages = [pkg.strip() for pkg in apt_text.split('\n') if pkg.strip()] if apt_text else []
            pip_packages = [pkg.strip() for pkg in pip_text.split('\n') if pkg.strip()] if pip_text else []
            
            dependencies = []
            
            if apt_packages:
                dependencies.append({
                    "name": apt_packages,
                    "install": "apt"
                })
            
            if pip_packages:
                dependencies.append({
                    "name": pip_packages,
                    "install": "pip"
                })
            
            return dependencies
        except Exception as e:
            print(f"Error getting dependencies data: {e}")
            return []
    
    def get_test_case_results_data_for_export(self):
        """Get test case results data from Section 12 for export (with default values for empty fields)"""
        try:
            # Initialize empty results list
            test_case_results = []
            
            # Check if test case result table exists
            if not hasattr(self, 'test_case_result_table'):
                print(f"DEBUG: test_case_result_table not found, returning empty results")
                return test_case_results
            
            # Get data from the test case results table
            for i in range(self.test_case_result_table.rowCount()):
                test_case_result = {
                    'serial_no': i + 1,
                    'test_case_no': '',
                    'pass_fail': '',
                    'remarks': ''
                }
                
                # Get test case number
                test_case_item = self.test_case_result_table.item(i, 1)
                if test_case_item:
                    test_case_result['test_case_no'] = test_case_item.text()
                
                # Get pass/fail (with default value if empty)
                pass_fail_item = self.test_case_result_table.item(i, 2)
                if pass_fail_item:
                    pass_fail_text = pass_fail_item.text().strip()
                    # If empty, use default placeholder value
                    if not pass_fail_text:
                        test_case_result['pass_fail'] = f"result_{i + 1}"
                    else:
                        test_case_result['pass_fail'] = pass_fail_text
                else:
                    # If no item exists, use default placeholder value
                    test_case_result['pass_fail'] = f"result_{i + 1}"
                
                # Get remarks (with default value if empty)
                remarks_item = self.test_case_result_table.item(i, 3)
                if remarks_item:
                    remarks_text = remarks_item.text().strip()
                    # If empty, use default placeholder value
                    if not remarks_text:
                        test_case_result['remarks'] = f"remark_{i + 1}"
                    else:
                        test_case_result['remarks'] = remarks_text
                else:
                    # If no item exists, use default placeholder value
                    test_case_result['remarks'] = f"remark_{i + 1}"
                
                test_case_results.append(test_case_result)
            
            print(f"DEBUG: get_test_case_results_data_for_export - Found {len(test_case_results)} test case results")
            return test_case_results
            
        except Exception as e:
            print(f"Error getting test case results data for export: {e}")
            return []
    
    def get_test_case_results_data(self):
        """Get test case results data from Section 12 for Summary section"""
        try:
            # Determine number of scenarios for dynamic Summary generation
            num_scenarios = 0
            if hasattr(self, 'test_scenarios') and self.test_scenarios:
                num_scenarios = len(self.test_scenarios)
            else:
                num_scenarios = 1  # Default to 1 if no scenarios found
            
            # Generate dynamic Summary section based on scenario count
            summary_data = {}
            for i in range(1, num_scenarios + 1):
                result_key = f"result_{i}"
                remarks_key = f"remarks_{i}"
                summary_data[result_key] = "none"
                summary_data[remarks_key] = "none"
            
            # Check if test case result table exists
            if not hasattr(self, 'test_case_result_table'):
                print(f"DEBUG: test_case_result_table not found, using default values for {num_scenarios} scenarios")
                return summary_data
            
            # Get data from the test case results table
            results = []
            for i in range(self.test_case_result_table.rowCount()):
                # Get pass/fail result
                pass_fail_item = self.test_case_result_table.item(i, 2)
                pass_fail = pass_fail_item.text().strip() if pass_fail_item else ""
                
                # Get remarks
                remarks_item = self.test_case_result_table.item(i, 3)
                remarks = remarks_item.text().strip() if remarks_item else ""
                
                # Only include results that have real user data (not placeholder values)
                if pass_fail and not pass_fail.startswith("result_") and pass_fail != "result_1" and pass_fail != "result_2":
                    results.append({
                        "result": pass_fail,
                        "remarks": remarks if remarks and not remarks.startswith("remarks_") else "No remarks provided"
                    })
                elif remarks and not remarks.startswith("remarks_") and remarks != "remarks_1" and remarks != "remarks_2":
                    # If only remarks are provided, use them with a default result
                    results.append({
                        "result": "Pending",
                        "remarks": remarks
                    })
            
            # Map results to summary fields if we have real data
            for i, result in enumerate(results):
                if i < num_scenarios:
                    result_key = f"result_{i + 1}"
                    remarks_key = f"remarks_{i + 1}"
                    summary_data[result_key] = result["result"]
                    summary_data[remarks_key] = result["remarks"]
            
            print(f"DEBUG: get_test_case_results_data - Found {len(results)} real test results for {num_scenarios} scenarios")
            print(f"DEBUG: Summary data: {summary_data}")
            
            return summary_data
            
        except Exception as e:
            print(f"Error getting test case results data: {e}")
            # Return dynamic error defaults based on scenario count
            num_scenarios = 1
            if hasattr(self, 'test_scenarios') and self.test_scenarios:
                num_scenarios = len(self.test_scenarios)
            
            error_summary = {}
            for i in range(1, num_scenarios + 1):
                result_key = f"result_{i}"
                remarks_key = f"remarks_{i}"
                error_summary[result_key] = "Error"
                error_summary[remarks_key] = f"Failed to retrieve test results: {str(e)}"
            
            return error_summary
    
    def set_dependencies_data(self, dependencies_data):
        """Set dependencies data in the UI"""
        try:
            apt_packages = []
            pip_packages = []
            
            for dep in dependencies_data:
                if dep.get("install") == "apt" and "name" in dep:
                    apt_packages.extend(dep["name"])
                elif dep.get("install") == "pip" and "name" in dep:
                    pip_packages.extend(dep["name"])
            
            self.apt_dependencies_edit.setPlainText('\n'.join(apt_packages))
            self.pip_dependencies_edit.setPlainText('\n'.join(pip_packages))
            
        except Exception as e:
            print(f"Error setting dependencies data: {e}")
    
    def create_files_page(self):
        """Create the Files page"""
        # Initialize the ExportCodeAndFilesPages class if not already done
        if not hasattr(self, 'export_code_pages'):
            self.export_code_pages = ExportCodeAndFilesPages(self)
        
        # Create the files page
        page = self.export_code_pages.create_files_page()
        self.content_stack.addWidget(page)
        
    def on_nav_changed(self, current, previous):
        """Handle navigation change"""
        if current and hasattr(self, 'content_stack'):
            page_name = current.data(Qt.ItemDataRole.UserRole)
            
            # Skip navigation for script_generator_title (it's just a static title)
            if page_name == "script_generator_title":
                return
                
            page_index = {
                'report_info': 0,
                'dut_config': 1,
                'test_plan': 2,
                'sections_1_7': 3,
                'test_execution': 4,
                'test_case_result': 5,
                'preview': 6,
                'export': 7,
                'configuration': 8,
                'essential_questions': 9,
                'execution_step_questions': 10,
                'dependencies': 11,
                'files': 12
            }.get(page_name, 0)
            
            self.content_stack.setCurrentIndex(page_index)
            
            # Load questions when navigating to Execution Step Questions page
            if page_name == 'execution_step_questions':
                print("DEBUG: Navigating to Execution Step Questions page, loading questions...")
                if hasattr(self, 'load_execution_questions_from_section_11'):
                    self.load_execution_questions_from_section_11()
            
            # CRITICAL FIX: Ensure scripts are restored when navigating to Section 11 Test Execution
            if page_name == 'test_execution':
                print("DEBUG: Navigating to Section 11 Test Execution, ensuring scripts are restored...")
                self.ensure_section_11_scripts_restored()
                # Add multiple delayed restoration attempts to ensure scripts are restored after UI is ready
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(500, self.delayed_script_restoration)
                QTimer.singleShot(1500, self.delayed_script_restoration)
                QTimer.singleShot(3000, self.delayed_script_restoration)
            

            # Hide preview panel for configuration and essential questions tabs
            if hasattr(self, 'preview_panel'):
                if page_name in ['configuration', 'essential_questions', 'execution_step_questions', 'dependencies', 'export', 'files']:
                    self.preview_panel.hide()
                    # Adjust splitter to give more space to content area
                    main_splitter = self.preview_panel.parent()
                    if isinstance(main_splitter, QSplitter):
                        main_splitter.setSizes([250, 1083, 0])  # Hide preview panel
                else:
                    self.preview_panel.show()
                    # Restore normal splitter proportions
                    main_splitter = self.preview_panel.parent()
                    if isinstance(main_splitter, QSplitter):
                        main_splitter.setSizes([250, 650, 433])  # Normal proportions
            
            # Update preview if switching to preview page
            if page_name == 'preview':
                self.update_preview()
                # Hide the right preview panel since the middle panel already has embedded editor
                if hasattr(self, 'preview_panel'):
                    self.preview_panel.hide()
                # Update toggle button state - DISABLED AS BUTTON WAS REMOVED
                # if hasattr(self, 'toggle_right_preview_btn'):
                #     self.toggle_right_preview_btn.setChecked(False)
                #     self.toggle_right_preview_btn.setText("👁️ Show Right Panel")
                # Optimize splitter sizes for preview page - give all space to content area
                if hasattr(self, 'main_splitter'):
                    self.main_splitter.setSizes([250, 1083, 0])  # Hide preview panel, give space to content
            
            # Update execution steps if switching to test plan page
            if page_name == 'test_plan' and hasattr(self, 'update_execution_steps'):
                self.update_execution_steps()
            
            # Refresh test execution if switching to test execution page
            if page_name == 'test_execution' and hasattr(self, 'refresh_test_execution_from_plan'):
                self.refresh_test_execution_from_plan()
            
            # Update test case results if switching to test case result page
            if page_name == 'test_case_result' and hasattr(self, 'update_test_case_results'):
                self.update_test_case_results()
            
            # Ensure step widgets are initialized when switching to test execution page
            if page_name == 'test_execution':
                self.ensure_step_widgets_initialized()
         
                

        

        
    def browse_export_path(self):
        """Browse for export directory"""
        directory = QFileDialog.getExistingDirectory(
            self,
            "Select Export Directory",
            self.export_path_edit.text()
        )
        
        if directory:
            self.export_path_edit.setText(directory)
            
    def update_preview(self):
        """Update the document preview with enhanced document generator"""
        try:
            # Check if preview browser exists
            if not hasattr(self, 'preview_browser'):
                return
                
            # Generate enhanced HTML preview using the enhanced document generator
            preview_html = self.generate_preview_html()
            
            # Update both preview panels with enhanced HTML
            self.preview_browser.setHtml(preview_html)
            if hasattr(self, 'main_preview_browser'):
                self.main_preview_browser.setHtml(preview_html)
                
        except Exception as e:
            logging.error(f"Preview update failed: {e}")
            # Fallback to plain text if enhanced preview fails
            try:
                preview_text = self.generate_plain_text_preview()
                self.preview_browser.setPlainText(preview_text)
                if hasattr(self, 'main_preview_browser'):
                    self.main_preview_browser.setPlainText(preview_text)
            except Exception as fallback_error:
                logging.error(f"Fallback preview also failed: {fallback_error}")
    
    def trigger_preview_update_old(self):
        """Old trigger preview update method - deprecated"""
        try:
            # Use a timer to debounce rapid updates
            if hasattr(self, '_preview_update_timer'):
                self._preview_update_timer.stop()
            else:
                self._preview_update_timer = QTimer()
                self._preview_update_timer.setSingleShot(True)
                self._preview_update_timer.timeout.connect(self.update_preview)
            
            # Start the timer (300ms delay)
            self._preview_update_timer.start(300)
            
        except Exception as e:
            logging.error(f"Live preview update failed: {e}")
            # Fallback to immediate update
            self.update_preview()
            
    def generate_plain_text_preview(self):
        """Generate plain text preview of the document (no HTML/CSS)"""
        try:
            text_content = []
            
            # Header
            title = self.report_title_edit.text() or '[Test Case Title]'
            text_content.append(f"TEST REPORT FOR: {title}")
            text_content.append("")
            
            # DUT Details
            if hasattr(self, 'dut_fields'):
                for field_info in self.dut_fields:
                    label = field_info['label_edit'].text()
                    value = field_info['value_edit'].text()
                    if label and value:
                        text_content.append(f"{label}: {value}")
            
            if hasattr(self, 'dut_fields') and self.dut_fields:
                text_content.append("")
            
            # Hash Sections
            if hasattr(self, 'hash_sections') and self.hash_sections:
                for section_info in self.hash_sections:
                    heading = section_info['heading_edit'].text().strip()
                    direct_hash_value = section_info['direct_hash_edit'].text().strip()
                    hash_fields = section_info['hash_fields']
                    
                    if heading and (direct_hash_value or hash_fields):
                        text_content.append(heading)
                        
                        # Add direct hash value if provided
                        if direct_hash_value:
                            text_content.append(direct_hash_value)
                        
                        # Add individual hash fields
                        for hash_info in hash_fields:
                            hash_name = hash_info['hash_name_edit'].text()
                            hash_value = hash_info['hash_value_edit'].text()
                            if hash_name and hash_value:
                                text_content.append(f"{hash_name}: {hash_value}")
                        
                        text_content.append("")
            else:
                # Fallback for when no hash sections exist yet
                text_content.append("[Hash Sections to be added]")
                text_content.append("")
            
            # ITSAR Information
            if hasattr(self, 'itsar_fields') and self.itsar_fields:
                for field_info in self.itsar_fields:
                    key = field_info['key_edit'].text().strip()
                    value = field_info['value_edit'].toPlainText().strip()
                    if key and value:
                        text_content.append(key)
                        
                        # Handle multi-line values
                        lines = value.split('\n')
                        for line in lines:
                            line = line.strip()
                            if line:
                                text_content.append(line)
                        
                        text_content.append("")
            
            # Interface Status
            if hasattr(self, 'interface_table'):
                text_content.append("DUT Interface Status Details")
                text_content.append("Interfaces\tNo. of Ports\tInterface Type\tInterface Name")
                
                for row in range(self.interface_table.rowCount()):
                    row_data = []
                    for col in range(self.interface_table.columnCount()):
                        item = self.interface_table.item(row, col)
                        text = item.text() if item else ""
                        row_data.append(text)
                    text_content.append("\t".join(row_data))
                
                text_content.append("")
            
            # Screenshots
            if self.screenshots:
                text_content.append("Evidence Screenshots")
                for i, screenshot in enumerate(self.screenshots, 1):
                    filename = os.path.basename(screenshot)
                    text_content.append(f"Figure {i}: {filename}")
                text_content.append("")
            
            
            # Requirement Description
            if hasattr(self, 'requirement_description_edit') and self.requirement_description_edit.toPlainText():
                text_content.append("Requirement Description")
                text_content.append(self.requirement_description_edit.toPlainText())
                text_content.append("")
            
            # Test Plan Overview
            if hasattr(self, 'test_plan_overview_edit') and self.test_plan_overview_edit.toPlainText():
                text_content.append("Test Plan Overview")
                text_content.append(self.test_plan_overview_edit.toPlainText())
                text_content.append("")
            
            # Test Scenarios
            if hasattr(self, 'test_scenarios') and self.test_scenarios:
                text_content.append("Test Scenarios")
                for scenario in self.test_scenarios:
                    key = scenario['key_edit'].text()
                    description = scenario['value_edit'].toPlainText()
                    if key and description:
                        text_content.append(f"{key}: {description}")
                text_content.append("")
            
            # Tools Required
            if hasattr(self, 'tools_required') and self.tools_required:
                text_content.append("Tools Required")
                for tool_info in self.tools_required:
                    tool_name = tool_info['tool_edit'].text()
                    if tool_name:
                        text_content.append(f"- {tool_name}")
                text_content.append("")
            
            # Execution Steps
            if hasattr(self, 'test_scenarios') and self.test_scenarios:
                text_content.append("Execution Steps")
                for scenario in self.test_scenarios:
                    key = scenario['key_edit'].text()
                    if key and 'steps' in scenario:
                        text_content.append(f"Steps for {key}:")
                        for step_info in scenario['steps']:
                            step_text = step_info['step_edit'].text()
                            if step_text:
                                text_content.append(f"  - {step_text}")
                        text_content.append("")
            
            # Manual Execution Steps
            if hasattr(self, 'manual_steps') and self.manual_steps:
                text_content.append("Manual Execution Steps")
                for step_info in self.manual_steps:
                    step_text = step_info['step_edit'].text()
                    if step_text:
                        text_content.append(f"- {step_text}")
                text_content.append("")
            
            # Sections 1-7 Data
            if hasattr(self, 'sections_1_7_manager'):
                sections_data = self.sections_1_7_manager.get_sections_1_7_data()
                if sections_data:
                    text_content.append("Sections 1-7 Data")
                    for section_num in range(1, 8):
                        section_key = f'section_{section_num}'
                        if section_key in sections_data:
                            section_data = sections_data[section_key]
                            heading = section_data.get('heading', f'Section {section_num}')
                            content = section_data.get('content', '')
                            if content:
                                text_content.append(f"{heading}: {content}")
                    text_content.append("")
            
            # Remove trailing empty lines
            while text_content and text_content[-1] == "":
                text_content.pop()
            
            # Join all content with newlines
            return "\n".join(text_content)
            
        except Exception as e:
            logging.error(f"Plain text preview generation failed: {e}")
            return "Error generating preview"
    
    def generate_preview_html(self):
        """Generate HTML preview of the document using enhanced document generator"""
        try:
            # Prepare the same data structure that the enhanced document generator uses
            config_data = self.prepare_config_data()
            print(f"DEBUG: prepare_config_data returned: {type(config_data)}")
            if isinstance(config_data, dict):
                print(f"DEBUG: config_data keys: {list(config_data.keys())}")
            else:
                print(f"DEBUG: config_data content: {config_data}")
            
            # Use the enhanced document generator's preview system with prepared data
            from enhanced_document_generator import EnhancedDocumentManager
            # Prepare the data properly using the enhanced document manager
            prepared_data = EnhancedDocumentManager.prepare_enhanced_data(config_data)
            print(f"DEBUG: prepare_enhanced_data returned: {type(prepared_data)}")
            preview_html = EnhancedDocumentManager.generate_enhanced_preview(prepared_data)
            
            return preview_html
            
        except Exception as e:
            logging.error(f"Enhanced preview generation failed: {e}")
            # Fallback to basic preview if enhanced fails
            return self.generate_basic_preview_html()
    
