    def _remove_section_image(self, section_type, image_info):
        """Remove an image from a section"""
        try:
            section_list_name = f"{section_type}_images_list"
            section_layout_name = f"{section_type}_images_layout"

            if hasattr(self, section_list_name):
                section_list = getattr(self, section_list_name)
                if image_info in section_list:
                    # Delete file
                    if os.path.exists(image_info.get('absolute_path', image_info['path'])):
                        os.remove(image_info.get('absolute_path', image_info['path']))

                    # Remove from list
                    section_list.remove(image_info)

                    # Remove from UI
                    if hasattr(self, section_layout_name):
                        section_layout = getattr(self, section_layout_name)
                        for i in range(section_layout.count()):
                            widget = section_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLabel) and image_info['filename'] in widget.findChild(QLabel).text():
                                widget.setParent(None)
                                break

        except Exception as e:
            print(f"❌ Error removing section image: {e}")

    def _remove_section_script(self, section_type, script_info):
        """Remove a script from a section"""
        try:
            section_list_name = f"{section_type}_scripts_list"
            section_layout_name = f"{section_type}_scripts_layout"

            if hasattr(self, section_list_name):
                section_list = getattr(self, section_list_name)
                if script_info in section_list:
                    # Delete file
                    if os.path.exists(script_info.get('absolute_path', script_info['path'])):
                        os.remove(script_info.get('absolute_path', script_info['path']))

                    # Remove from list
                    section_list.remove(script_info)

                    # Remove from UI
                    if hasattr(self, section_layout_name):
                        section_layout = getattr(self, section_layout_name)
                        for i in range(section_layout.count()):
                            widget = section_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLabel) and script_info['filename'] in widget.findChild(QLabel).text():
                                widget.setParent(None)
                                break

        except Exception as e:
            print(f"❌ Error removing section script: {e}")

    def import_configuration_data(self, data):
        """Import configuration data from template JSON"""
        config = data.get('configuration', {})
        print(f"Importing configuration data...")
        print(f"Configuration keys: {list(config.keys())}")
        
        # Import basic fields
        if hasattr(self, 'report_title_edit') and 'report_title' in config:
            self.report_title_edit.setText(config['report_title'])
        
        # Import header configuration
        if hasattr(self, 'header_text_edit') and 'header_text' in config:
            self.header_text_edit.setText(config['header_text'])
        
        if hasattr(self, 'header_start_page_spinbox') and 'header_start_page' in config:
            self.header_start_page_spinbox.setValue(config['header_start_page'])
        
        if hasattr(self, 'template_path_edit') and 'template_path' in config:
            self.template_path_edit.setText(config['template_path'])
        
        if hasattr(self, 'export_path_edit') and 'export_path' in config:
            self.export_path_edit.setText(config['export_path'])
        
        if hasattr(self, 'export_filename_edit') and 'export_filename' in config:
            self.export_filename_edit.setText(config['export_filename'])
        
        # Clear existing DUT fields first
        if hasattr(self, 'dut_fields'):
            for field_info in self.dut_fields[:]:
                self.remove_dut_field(field_info)
        
        # Import DUT fields
        if 'dut_fields' in config and hasattr(self, 'dut_fields'):
            for field_data in config['dut_fields']:
                self.add_dut_field()
                if self.dut_fields:
                    last_field = self.dut_fields[-1]
                    last_field['label_edit'].setText(field_data.get('label', ''))
                    last_field['value_edit'].setText(field_data.get('value', ''))
        
                    # Import images for this DUT field
                    if 'images' in field_data and field_data['images']:
                        for image_data in field_data['images']:
                            # Handle both string paths and dictionary objects
                            if isinstance(image_data, dict):
                                image_path = image_data.get('path', '')
                            else:
                                image_path = str(image_data) if image_data else ''
                            
                            # Resolve the image path properly
                            resolved_path = self._resolve_import_path(image_path)
                            if resolved_path and os.path.exists(resolved_path):
                                image_path = resolved_path
                                # Create image info for the imported image
                                filename = os.path.basename(image_path)
                                image_info = {
                                    'path': image_path,
                                    'absolute_path': image_path,
                                    'filename': filename,
                                    'original_filename': image_data.get('original_filename', filename) if isinstance(image_data, dict) else filename,
                                    'description': image_data.get('description', '') if isinstance(image_data, dict) else '',
                                    'remove_btn': QPushButton("🗑️ Remove")
                                }

                                # Initialize images_list if not exists
                                if 'images_list' not in last_field:
                                    last_field['images_list'] = []
                                last_field['images_list'].append(image_info)

                                # Connect remove button
                                image_info['remove_btn'].clicked.connect(lambda: self.remove_field_image(last_field, image_info))

                                # Create UI widget for the image
                                image_widget = QWidget()
                                image_layout = QHBoxLayout(image_widget)

                                # Filename label
                                filename_label = QLabel(f"📷 {filename}")
                                filename_label.setStyleSheet("color: #17a2b8; font-weight: bold;")
                                image_layout.addWidget(filename_label)

                                # Remove button
                                image_info['remove_btn'].setStyleSheet("""
                                        QPushButton {
                                            background-color: #dc3545;
                                            color: white;
                                            border: none;
                                            border-radius: 4px;
                                            padding: 4px 8px;
                                            font-weight: bold;
                                        }
                                        QPushButton:hover {
                                            background-color: #c82333;
                                        }
                                    """)
                                image_layout.addWidget(image_info['remove_btn'])
                                image_layout.addStretch()

                                # Add to UI if container exists
                                if 'images_container' in last_field and last_field['images_container']:
                                        if hasattr(last_field['images_container'], 'layout'):
                                            last_field['images_container'].layout().addWidget(image_widget)

                    # Import scripts for this DUT field
                    if 'scripts' in field_data and field_data['scripts']:
                        for script_data in field_data['scripts']:
                            if isinstance(script_data, dict) and 'path' in script_data:
                                script_path = script_data['path']
                                # Resolve the script path properly
                                resolved_path = self._resolve_import_path(script_path)
                                if resolved_path and os.path.exists(resolved_path):
                                    script_path = resolved_path
                                    # Create script info for the imported script
                                    filename = os.path.basename(script_path)
