    def _resolve_import_path(self, file_path):
        """
        Resolve file path for import, handling both absolute and relative paths
        
        Args:
            file_path: The file path to resolve (string or dict with 'path' key)
            
        Returns:
            Resolved absolute file path
        """
        # Handle dict vs string input - defensive programming
        if isinstance(file_path, dict):
            file_path = file_path.get('path', '')
        
        if not file_path or not isinstance(file_path, (str, bytes)):
            return ""
        
        # If it's already an absolute path and exists, use it
        if os.path.isabs(file_path) and os.path.exists(file_path):
            return file_path
        
        # Detect the project directory for path resolution
        if hasattr(self, 'import_project_dir'):
            project_dir = self.import_project_dir
        else:
            # Fallback: try to find project directory from current working directory
            project_dir = os.getcwd()
        
        # Try to resolve relative paths
        possible_paths = [
            file_path,  # Original path
            os.path.join(project_dir, file_path),  # Project directory
            os.path.join(project_dir, "tmp", file_path),  # tmp directory
            os.path.join(project_dir, "tmp", "raw_logs", file_path),  # raw_logs directory
            os.path.join(project_dir, "tmp", "code", file_path),  # code directory
        ]
        
        # Handle different path patterns
        if file_path.startswith("code/"):
            # Script file
            filename = file_path[5:]  # Remove "code/" prefix
            possible_paths.extend([
                os.path.join(project_dir, "code", filename),
                os.path.join(project_dir, "tmp", "code", filename)
            ])
        elif file_path.startswith("raw_logs/"):
            # Image file
            filename = file_path[9:]  # Remove "raw_logs/" prefix
            possible_paths.extend([
                os.path.join(project_dir, "raw_logs", filename),
                os.path.join(project_dir, "tmp", "raw_logs", filename)
            ])
        elif file_path.startswith("tmp/"):
            # Handle tmp/1/code/ and tmp/1/raw_logs/ patterns
            possible_paths.extend([
                os.path.join(project_dir, file_path),  # tmp/1/code/ or tmp/1/raw_logs/
                os.path.join(project_dir, "tmp", file_path[4:])  # Remove tmp/ prefix
            ])
            # Also try to extract just the filename and look in common locations
            filename = os.path.basename(file_path)
            possible_paths.extend([
                os.path.join(project_dir, "tmp", "code", filename),
                os.path.join(project_dir, "tmp", "raw_logs", filename),
                os.path.join(project_dir, "code", filename),
                os.path.join(project_dir, "raw_logs", filename)
            ])
        
        for path in possible_paths:
            if os.path.exists(path):
                print(f"DEBUG: Resolved path '{file_path}' to '{path}'")
                return path
        
        # If no path found, return the original path (will be handled by caller)
        print(f"DEBUG: Could not resolve path '{file_path}'")
        return file_path
    
    def import_test_execution_data(self, data):
        """
        Comprehensive import method for Section 11 (Execution Steps) data
        
        This method ensures all Section 11 data is properly restored including:
        - Test execution cases with full metadata
        - Step images with full metadata
        - Step scripts with full metadata (uploaded and pasted)
        - Placeholder handling
        - All file paths and metadata preserved
        """
        config = data.get('configuration', {})
        print("=== IMPORTING SECTION 11 EXECUTION STEPS DATA ===")
        print("25890:", config)
        # Import execution steps (Section 8.4) - these are the base steps from Section 8
        if 'execution_steps' in config and hasattr(self, 'test_scenarios'):
            print(f"DEBUG: Found {len(config['execution_steps'])} execution steps to import")
            for scenario_steps_data in config['execution_steps']:
                # Check if scenario_steps_data is a dictionary before calling .get()
                if isinstance(scenario_steps_data, dict):
                    scenario_key = scenario_steps_data.get('scenario_key', '')
                    scenario_description = scenario_steps_data.get('scenario_description', '')
                    steps = scenario_steps_data.get('steps', [])
                else:
                    print(f"WARNING: Skipping invalid scenario_steps_data: {type(scenario_steps_data)} - {scenario_steps_data}")
                    continue

                # Find the corresponding scenario
                for scenario in self.test_scenarios:
                    if scenario['key_edit'].text() == scenario_key:
                        # CRITICAL FIX: Store scenario description in scenario data for later use
                        # This ensures the description is preserved when update_execution_steps() creates the UI
                        if scenario_description and scenario_description != "Enter scenario description here...":
                            scenario['preserved_scenario_description'] = scenario_description
                            print(f"✅ Stored scenario description for {scenario_key}: {scenario_description}")
                            
                            # Also try to set it on the scenario_edit widget if it exists
