    def restore_scripts_for_step_immediately(self, step_key, step_data):
        """Immediately restore scripts for a step when the step widget is created"""
        try:
            print(f"DEBUG: Checking for scripts to restore immediately for step {step_key}")
            
            # Check if we have global scripts stored for this step
            if hasattr(self, '_global_step_scripts') and self._global_step_scripts:
                if step_key in self._global_step_scripts:
                    scripts_list = self._global_step_scripts[step_key]
                    print(f"DEBUG: Found {len(scripts_list)} scripts in global storage for step {step_key}")
                    
                    # Check if scripts are already restored
                    current_scripts = step_data.get('upload_scripts_list', [])
                    if len(current_scripts) == 0:
                        print(f"DEBUG: No current scripts, restoring {len(scripts_list)} scripts immediately")
                        self.restore_step_scripts(step_key, scripts_list)
                    else:
                        print(f"DEBUG: Scripts already exist for step {step_key}, checking if restoration is needed")
                        # Check if the scripts match what we're trying to restore
                        current_script_names = [s.get('original_filename', s.get('filename', '')) for s in current_scripts]
                        restore_script_names = [s.get('original_filename', s.get('filename', '')) for s in scripts_list]
                        
                        if set(current_script_names) != set(restore_script_names):
                            print(f"DEBUG: Script mismatch detected, restoring from global storage")
                            self.restore_step_scripts(step_key, scripts_list)
                        else:
                            print(f"DEBUG: Scripts match, no restoration needed")
                else:
                    print(f"DEBUG: No scripts found in global storage for step {step_key}")
            else:
                print(f"DEBUG: No global scripts storage found")
                
        except Exception as e:
            print(f"⚠️ Error restoring scripts immediately for step {step_key}: {e}")
            import traceback
            traceback.print_exc()
    
    def delayed_script_restoration(self):
        """Delayed script restoration to ensure widgets are fully created before restoring scripts"""
        try:
            print("DEBUG: ===== DELAYED SCRIPT RESTORATION =====")
            
            # Debug current state
            self.debug_script_state()
            
            # Check if we have global scripts stored
            if hasattr(self, '_global_step_scripts') and self._global_step_scripts:
                print(f"DEBUG: Found {len(self._global_step_scripts)} steps with scripts in global storage")
                
                # Check if step_widgets exist and have the corresponding steps
                if hasattr(self, 'step_widgets') and self.step_widgets:
                    print(f"DEBUG: Found {len(self.step_widgets)} step widgets")
                    
                    for step_key, scripts_list in self._global_step_scripts.items():
                        print(f"DEBUG: Processing step {step_key} with {len(scripts_list)} scripts")
                        
                        if step_key in self.step_widgets:
                            step_data = self.step_widgets[step_key]
                            print(f"DEBUG: Found step_data for {step_key}")
                            
                            # Check if scripts are already restored
                            current_scripts = step_data.get('upload_scripts_list', [])
                            print(f"DEBUG: Current scripts in step_data: {len(current_scripts)}")
                            
                            if len(current_scripts) == 0:
                                print(f"DEBUG: No scripts found in step_data, restoring {len(scripts_list)} scripts")
                                self.restore_step_scripts(step_key, scripts_list)
                            else:
                                print(f"DEBUG: Scripts already exist in step_data, checking if they match global storage")
                                # Check if the scripts match what's in global storage
                                global_script_names = [s.get('original_filename', s.get('filename', '')) for s in scripts_list]
                                current_script_names = [s.get('original_filename', s.get('filename', '')) for s in current_scripts]
                                
                                if set(global_script_names) != set(current_script_names):
                                    print(f"DEBUG: Script mismatch detected, restoring from global storage")
                                    self.restore_step_scripts(step_key, scripts_list)
                                else:
                                    print(f"DEBUG: Scripts match, no restoration needed")
                        else:
                            print(f"DEBUG: Step widget not found for key {step_key}")
                else:
                    print("DEBUG: step_widgets not found or empty")
            else:
                print("DEBUG: No scripts found in global storage")
                
            print("DEBUG: ===== DELAYED SCRIPT RESTORATION COMPLETED =====")
                
        except Exception as e:
            print(f"⚠️ Error in delayed_script_restoration: {e}")
            import traceback
            traceback.print_exc()
    
