    def cleanup_tmp_folder(self):
        """Clean up tmp folder contents when application closes"""
        try:
            import shutil
            import os
            
            # Get the app root directory (same logic as in export_code_and_files_page.py)
            script_dir = os.path.dirname(os.path.abspath(__file__))
            if script_dir.endswith('Report_Generator_Automation-main'):
                app_root = os.path.dirname(script_dir)
            else:
                app_root = script_dir
            
            tmp_dir = os.path.join(app_root, "tmp")
            
            if os.path.exists(tmp_dir):
                print(f"DEBUG: Cleaning up tmp folder: {tmp_dir}")
                
                # Remove all contents of tmp folder (including pushed files)
                for item in os.listdir(tmp_dir):
                    item_path = os.path.join(tmp_dir, item)
                    try:
                        if os.path.isdir(item_path):
                            shutil.rmtree(item_path)
                            print(f"DEBUG: Removed directory: {item}")
                        else:
                            os.remove(item_path)
                            print(f"DEBUG: Removed file: {item}")
                    except Exception as e:
                        print(f"DEBUG: Error removing {item}: {e}")
                
                # Also clean up the pushed files directory if it exists
                pushed_files_dir = os.path.join(tmp_dir, "file", "pushed files")
                if os.path.exists(pushed_files_dir):
                    print(f"DEBUG: Cleaning up pushed files directory: {pushed_files_dir}")
                    try:
                        shutil.rmtree(pushed_files_dir)
                        print("DEBUG: Removed pushed files directory")
                    except Exception as e:
                        print(f"DEBUG: Error removing pushed files directory: {e}")
                
                print("DEBUG: Tmp folder cleanup completed")
            else:
                print("DEBUG: Tmp folder does not exist, nothing to clean up")
                
        except Exception as e:
            print(f"DEBUG: Error during tmp folder cleanup: {e}")

    def closeEvent(self, event):
        """Handle application close"""
        reply = QMessageBox.question(self, "Exit", 
                                   "Are you sure you want to exit?",
                                   QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No)
        
        if reply == QMessageBox.StandardButton.Yes:
            # Clean up tmp folder
            self.cleanup_tmp_folder()
            
            # Close LibreOffice if it's running
            if hasattr(self, 'libreoffice_embedder'):
                self.libreoffice_embedder.close_libreoffice()
            # Save settings
            self.settings.setValue('geometry', self.saveGeometry())
            self.settings.setValue('windowState', self.saveState())
            event.accept()
        else:
            event.ignore()

