    def handle_itsar_enter_key(self, event, text_edit):
        """Handle Enter key press in ITSAR text edit to create numbered lists"""
        if event.key() == Qt.Key.Key_Return or event.key() == Qt.Key.Key_Enter:
            # Get current cursor position
            cursor = text_edit.textCursor()
            current_position = cursor.position()
            
            # Get current text
            current_text = text_edit.toPlainText()
            lines = current_text.split('\n')
            
            # Find the current line number
            current_line_num = 0
            char_count = 0
            for i, line in enumerate(lines):
                if char_count <= current_position <= char_count + len(line):
                    current_line_num = i
                    break
                char_count += len(line) + 1  # +1 for newline
            
            # Check if we're at the end of a line or in the middle
            current_line = lines[current_line_num] if current_line_num < len(lines) else ""
            cursor_in_line = current_position - char_count
            
            # Count existing numbered lines to determine next number
            numbered_lines = 0
            for line in lines:
                if line.strip().startswith(('1.', '2.', '3.', '4.', '5.', '6.', '7.', '8.', '9.')):
                    numbered_lines += 1
            
            # If we're in the middle of a line, split it
            if cursor_in_line < len(current_line):
                # Split the current line at cursor position
                before_cursor = current_line[:cursor_in_line]
                after_cursor = current_line[cursor_in_line:]
                
                # Insert new numbered line
                next_number = numbered_lines + 1
                new_line = f"{next_number}. "
                
                # Update the lines list
                lines[current_line_num] = before_cursor
                lines.insert(current_line_num + 1, new_line + after_cursor)
                
                # Reconstruct text
                new_text = '\n'.join(lines)
                text_edit.setPlainText(new_text)
                
                # Set cursor position after the new number
                new_cursor_position = current_position + len(new_line)
                cursor.setPosition(new_cursor_position)
                text_edit.setTextCursor(cursor)
            else:
                # We're at the end of a line, add new numbered line
                next_number = numbered_lines + 1
                new_line = f"{next_number}. "
                
                # Insert at cursor position
                cursor.insertText('\n' + new_line)
            
            # Prevent default behavior
            event.accept()
        else:
            # Call parent's keyPressEvent for other keys
            QTextEdit.keyPressEvent(text_edit, event)

    def remove_itsar_field(self, field_info):
        """Remove an ITSAR field"""
        if field_info in self.itsar_fields:
            try:
                # Remove from layout
                self.itsar_form_layout.removeRow(field_info['key_edit'])
            except Exception as e:
                print(f"DEBUG: Error removing ITSAR field from layout: {e}")
            
            # Remove from list
            self.itsar_fields.remove(field_info)
            
            # Update preview
            self.update_preview()

