    def save_note_to_config(self, note_text):
        """Save note to template configuration note_section field"""
        try:
            import json
            import os
            
            # Path to template configuration
            config_path = "tmp/test_case/configuration/template_config.json"
            
            # Load existing configuration
            if os.path.exists(config_path):
                with open(config_path, 'r', encoding='utf-8') as f:
                    template_config = json.load(f)
            else:
                print(f"❌ Template config not found: {config_path}")
                return False
            
            # Get configuration data
            config_data = template_config.get('configuration', {})
            execution_steps = config_data.get('execution_steps', [])
            
            # Add note to the first execution step's note_section array
            if execution_steps:
                if 'note_section' not in execution_steps[0]:
                    execution_steps[0]['note_section'] = []
                
                # Add the new note to note_section field
                execution_steps[0]['note_section'].append(note_text)
                
                # Save back to file
                with open(config_path, 'w', encoding='utf-8') as f:
                    json.dump(template_config, f, indent=2, ensure_ascii=False)
                
                print(f"✅ Note saved to note_section field: {note_text}")
                print(f"📝 note_section array: {execution_steps[0]['note_section']}")
                return True
            else:
                print("❌ No execution steps found in configuration")
                return False
                
        except Exception as e:
            print(f"❌ Error saving note to config: {e}")
            return False


