    def update_scenario_placeholder_display(self, scenario_info):
        """Update the placeholder display for a specific scenario"""
        if 'placeholder_display' not in scenario_info:
            return
            
        placeholder_list = scenario_info['placeholder_display']
        placeholder_list.clear()
        
        # Get scenario key for context
        scenario_key = scenario_info['key_edit'].text().strip()
        if not scenario_key:
            scenario_key = "New Scenario"
        
        # Add placeholders that are specific to this scenario
        scenario_specific_placeholders = []
        
        # Check if we have scenario-specific placeholders
        if hasattr(self, 'scenario_placeholders') and scenario_key in self.scenario_placeholders:
            scenario_specific_placeholders = self.scenario_placeholders[scenario_key]
        
        # Display scenario-specific placeholders
        if scenario_specific_placeholders:
            for placeholder_info in scenario_specific_placeholders:
                if isinstance(placeholder_info, dict) and 'placeholder' in placeholder_info:
                    placeholder_name = placeholder_info['placeholder']
                    
                    # Create a custom widget for each placeholder with remove button
                    placeholder_widget = QWidget()
                    placeholder_layout = QHBoxLayout(placeholder_widget)
                    placeholder_layout.setContentsMargins(8, 6, 8, 6)
                    placeholder_layout.setSpacing(8)
                    
                    # Placeholder name label
                    placeholder_label = QLabel(f"📄 {placeholder_name}")
                    placeholder_label.setStyleSheet("""
                        QLabel {
                            color: #ffffff;
                            font-size: 12px;
                            font-weight: bold;
                            padding: 8px;
                            background-color: #3c3c3e;
                            border: 1px solid #555555;
                            border-radius: 4px;
                        }
                    """)
                    placeholder_label.setToolTip(f"Placeholder: {placeholder_name} (for scenario: {scenario_key})")
                    placeholder_layout.addWidget(placeholder_label)
                    
                    # Remove button
                    remove_btn = QPushButton("Remove")
                    remove_btn.setMinimumSize(60, 25)
                    remove_btn.setMaximumSize(80, 25)
                    remove_btn.setStyleSheet("""
                        QPushButton {
                            background-color: #d32f2f;
                            color: #ffffff;
                            border: none;
                            border-radius: 4px;
                            font-size: 10px;
                            font-weight: bold;
                            padding: 4px 8px;
                        }
                        QPushButton:hover {
                            background-color: #b71c1c;
                        }
                        QPushButton:pressed {
                            background-color: #a00000;
                        }
                    """)
                    remove_btn.setToolTip(f"Remove placeholder: {placeholder_name}")
                    remove_btn.clicked.connect(lambda checked, p=placeholder_info, s=scenario_key: self.remove_placeholder_from_scenario(p, s))
                    placeholder_layout.addWidget(remove_btn)
                    
                    placeholder_layout.addStretch()
                    
                    # Create list item with custom widget
                    item = QListWidgetItem()
                    item.setSizeHint(placeholder_widget.sizeHint())
                    placeholder_list.addItem(item)
                    placeholder_list.setItemWidget(item, placeholder_widget)

        # Show empty state if no placeholders
        if not scenario_specific_placeholders:
            empty_item = QListWidgetItem("No placeholders added for this scenario yet")
            empty_item.setData(Qt.ItemDataRole.UserRole, "empty")
            placeholder_list.addItem(empty_item)
    
    def handle_scenario_key_change(self, scenario_info):
        """Handle scenario key changes and update placeholder associations"""
        try:
            # Get the new scenario key
            new_key = scenario_info['key_edit'].text().strip()
            if not new_key:
                new_key = "New Scenario"
            
            # Check if this scenario had a previous key stored
            # FIXED: Use dictionary access instead of attribute access
            if 'previous_key' in scenario_info and scenario_info['previous_key']:
                old_key = scenario_info['previous_key']
                
                # Move placeholders from old key to new key if they exist
                if (hasattr(self, 'scenario_placeholders') and 
                    old_key in self.scenario_placeholders and 
                    old_key != new_key):
                    
                    # Move placeholders to new key
                    if new_key not in self.scenario_placeholders:
                        self.scenario_placeholders[new_key] = []
                    
                    self.scenario_placeholders[new_key].extend(self.scenario_placeholders[old_key])
                    del self.scenario_placeholders[old_key]
                    
                    print(f"DEBUG: Moved placeholders from '{old_key}' to '{new_key}'")
            
            # Store the current key as previous for next change
            # FIXED: Use dictionary assignment instead of attribute assignment
            scenario_info['previous_key'] = new_key
            
            # Update the placeholder display
            self.update_scenario_placeholder_display(scenario_info)
            
        except Exception as e:
            print(f"DEBUG: Error handling scenario key change: {e}")
            # Still update the display even if key change handling fails
            self.update_scenario_placeholder_display(scenario_info)
    
