    def upload_test_bed_image(self):
        """Upload a test bed diagram image"""
        file_path, _ = QFileDialog.getOpenFileName(
            self,
            "Select Test Bed Diagram Image",
            "",
            "Image Files (*.png *.jpg *.jpeg *.gif *.bmp)"
        )
        
        if file_path:
            # Copy file to rawlogs directory to avoid deleting original user file
            original_filename = os.path.basename(file_path)
            rawlogs_dir = self.get_rawlogs_folder_path()
            unique_filename = self.get_unique_filename(rawlogs_dir, original_filename)
            tmp_path = os.path.join(rawlogs_dir, unique_filename)
            
            try:
                import shutil
                shutil.copy2(file_path, tmp_path)
                print(f"Copied {file_path} to {tmp_path}")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to copy file: {e}")
                return
            
            image_info = {
                'path': tmp_path,  # Use the copied file path, not the original
                'filename': original_filename,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create image widget
            image_widget = QWidget()
            image_layout = QHBoxLayout(image_widget)
            
            # Image preview
            image_label = QLabel(f"📷 {image_info['filename']}")
            image_layout.addWidget(image_label)
            
            # Remove button
            image_layout.addWidget(image_info['remove_btn'])
            image_layout.addStretch()
            
            # Connect remove button - use closure to capture image_info by value
            def create_remove_handler(img_info):
                return lambda: self.remove_test_bed_image(img_info)
            image_info['remove_btn'].clicked.connect(create_remove_handler(image_info))
            
            # Add to container
            self.test_bed_images.append(image_info)
            
            # Also add to new structure (this is the main data structure used for export)
            if hasattr(self, 'test_bed_diagram_data'):
                if 'images' not in self.test_bed_diagram_data:
                    self.test_bed_diagram_data['images'] = []
                self.test_bed_diagram_data['images'].append(image_info)
                print(f"✅ Added test bed image to test_bed_diagram_data: {image_info['filename']}")
            
            self.test_bed_images_layout.addWidget(image_widget)
            
    def remove_test_bed_image(self, image_info):
        """Remove a test bed image"""
        print(f"🔍 DEBUG: remove_test_bed_image called with: {image_info}")
        
        # Remove from old structure for backward compatibility
        if hasattr(self, 'test_bed_images'):
            # Try exact match first
            if image_info in self.test_bed_images:
                self.test_bed_images.remove(image_info)
                print(f"✅ Removed from old structure (test_bed_images)")
            else:
                # Try to find by filename if exact match fails
                filename_to_match = image_info.get('filename', '')
                original_filename_to_match = image_info.get('original_filename', '')
                removed_by_filename = False
                
                for existing_image in self.test_bed_images[:]:
                    if (existing_image.get('filename', '') == filename_to_match or 
                        existing_image.get('original_filename', '') == original_filename_to_match or
                        existing_image.get('filename', '') == original_filename_to_match):
                        self.test_bed_images.remove(existing_image)
                        print(f"✅ Removed from old structure (test_bed_images) by filename match: {existing_image.get('filename', 'Unknown')}")
                        removed_by_filename = True
                        break
        
        # Remove from new structure (this is the main data structure used for export)
        if hasattr(self, 'test_bed_diagram_data') and 'images' in self.test_bed_diagram_data:
            # Try exact match first
            if image_info in self.test_bed_diagram_data['images']:
                self.test_bed_diagram_data['images'].remove(image_info)
                print(f"✅ Removed test bed image from test_bed_diagram_data: {image_info.get('filename', 'Unknown')}")
            else:
                # Try to find by filename if exact match fails
                filename_to_match = image_info.get('filename', '')
                original_filename_to_match = image_info.get('original_filename', '')
                removed_by_filename = False
                
                for i, existing_image in enumerate(self.test_bed_diagram_data['images'][:]):
                    if (existing_image.get('filename', '') == filename_to_match or 
                        existing_image.get('original_filename', '') == original_filename_to_match or
                        existing_image.get('filename', '') == original_filename_to_match):
                        self.test_bed_diagram_data['images'].remove(existing_image)
                        print(f"✅ Removed test bed image from test_bed_diagram_data by filename match: {existing_image.get('filename', 'Unknown')}")
                        removed_by_filename = True
                        break
                
                if not removed_by_filename:
                    print(f"⚠️ Image not found in test_bed_diagram_data['images']")
        else:
            print(f"⚠️ test_bed_diagram_data structure not found or missing 'images' key")
        
        # Remove the widget from layout
        if hasattr(self, 'test_bed_images_layout'):
            removed_widget = False
            
            # First try to find widget by remove button reference (most reliable)
            if 'remove_btn' in image_info:
                for i in range(self.test_bed_images_layout.count()):
                    widget = self.test_bed_images_layout.itemAt(i).widget()
                    if widget and widget.findChild(QPushButton) == image_info['remove_btn']:
                        self.test_bed_images_layout.removeWidget(widget)
                        widget.setParent(None)
                        widget.deleteLater()
                        removed_widget = True
                        print(f"✅ Removed test bed image widget from UI by button reference: {image_info.get('filename', 'Unknown')}")
                        break
            
            # If not found by button reference, try filename matching
            if not removed_widget:
                for i in range(self.test_bed_images_layout.count()):
                    widget = self.test_bed_images_layout.itemAt(i).widget()
                    if widget and widget.findChild(QLabel):
                        label = widget.findChild(QLabel)
                        # Check both filename and original_filename to match the widget creation logic
                        filename_to_check = image_info.get('original_filename', image_info.get('filename', ''))
                        if label and filename_to_check in label.text():
                            self.test_bed_images_layout.removeWidget(widget)
                            widget.setParent(None)
                            widget.deleteLater()
                            removed_widget = True
                            print(f"✅ Removed test bed image widget from UI by filename: {image_info.get('filename', 'Unknown')}")
                            break
            
            if not removed_widget:
                print(f"⚠️ Widget not found in layout for removal")
        else:
            print(f"⚠️ test_bed_images_layout not found")
    
    def upload_test_bed_script(self):
        """Upload a script for test bed diagram"""
        file_path, _ = QFileDialog.getOpenFileName(
            self,
            "Select Script File",
            "",
            "Script Files (*.py *.sh *.bat *.ps1 *.js *.php *.rb *.pl *.sql *.txt)"
        )
        
        if file_path:
            # Get the test bed diagram heading for the question text
            field_text = self.test_bed_diagram_heading_edit.text().strip()
            if not field_text:
                field_text = "8.2. Test Bed Diagram"
            
            # Generate script name with incremental numbering
            script_number = self.get_next_script_number()
            script_name = f"script{script_number}.py"
            
            # Create placeholder for the script
            placeholder = f"script_{os.path.basename(file_path).replace('.py', '')}"
            
            script_info = {
                'path': file_path,
                'filename': os.path.basename(file_path),
                'script_name': script_name,
                'remove_btn': QPushButton("🗑️ Remove")
            }
            
            # Create script widget
            script_widget = QWidget()
            script_layout = QHBoxLayout(script_widget)
            
            # Script preview
            script_label = QLabel(f"📁 {script_info['filename']}")
            script_layout.addWidget(script_label)
            
            # Remove button
            script_layout.addWidget(script_info['remove_btn'])
            script_layout.addStretch()
            
            # Connect remove button - use closure to capture script_info by value
            def create_remove_handler(scr_info):
                return lambda: self.remove_test_bed_script(scr_info)
            script_info['remove_btn'].clicked.connect(create_remove_handler(script_info))
            
            # Add to container
            self.test_bed_scripts.append(script_info)
            
            # Also add to new structure (this is the main data structure used for export)
            if hasattr(self, 'test_bed_diagram_data'):
                if 'scripts' not in self.test_bed_diagram_data:
                    self.test_bed_diagram_data['scripts'] = []
                self.test_bed_diagram_data['scripts'].append(script_info)
                print(f"✅ Added test bed script to test_bed_diagram_data: {script_info['filename']}")
            
            self.test_bed_images_layout.addWidget(script_widget)
            
            # Add to Essential Questions
            if hasattr(self, 'add_essential_question_with_script'):
                self.add_essential_question_with_script(field_text, os.path.basename(file_path), placeholder)
            
            # Add to automation mapper
            if hasattr(self, 'automation_mapper'):
                script_id = str(uuid.uuid4())
                # Use the user's actual placeholder instead of generating a new one
                placeholder_name = placeholder  # Use the actual placeholder from user input or skip
                self.automation_mapper.add_script_mapping(
                    script_id, 
                    os.path.basename(file_path), 
                    placeholder_name, 
                    "Section 8 Test Plan", 
                    field_text
                )
            
    def remove_test_bed_script(self, script_info):
        """Remove a test bed script"""
        print(f"🔍 DEBUG: remove_test_bed_script called with: {script_info}")
        
        # Remove from old structure for backward compatibility
        if hasattr(self, 'test_bed_scripts') and script_info in self.test_bed_scripts:
            self.test_bed_scripts.remove(script_info)
            print(f"✅ Removed from old structure (test_bed_scripts)")
        
        # Remove from new structure (this is the main data structure used for export)
        if hasattr(self, 'test_bed_diagram_data') and 'scripts' in self.test_bed_diagram_data:
            if script_info in self.test_bed_diagram_data['scripts']:
                self.test_bed_diagram_data['scripts'].remove(script_info)
                print(f"✅ Removed test bed script from test_bed_diagram_data: {script_info.get('filename', 'Unknown')}")
            else:
                print(f"⚠️ Script not found in test_bed_diagram_data['scripts']")
        else:
            print(f"⚠️ test_bed_diagram_data structure not found or missing 'scripts' key")
        
        # Remove corresponding essential question if it exists
        script_name = script_info.get('script_name', '')
        if script_name and hasattr(self, 'essential_questions'):
            for question_info in self.essential_questions[:]:
                if (question_info.get("script_name_edit") and 
                    question_info["script_name_edit"].text() == script_name):
                    self.essential_questions.remove(question_info)
                    # Remove the question widget from the UI
                    if hasattr(self, 'essential_questions_layout'):
                        for i in range(self.essential_questions_layout.count()):
                            widget = self.essential_questions_layout.itemAt(i).widget()
                            if widget and widget.findChild(QLineEdit) == question_info.get("script_name_edit"):
                                widget.setParent(None)
                                break
                    break
        
        # Remove the widget from layout
        if hasattr(self, 'test_bed_images_layout'):
            removed_widget = False
            for i in range(self.test_bed_images_layout.count()):
                widget = self.test_bed_images_layout.itemAt(i).widget()
                if widget and widget.findChild(QLabel):
                    label = widget.findChild(QLabel)
                    # Check both filename and original_filename to match the widget creation logic
                    filename_to_check = script_info.get('original_filename', script_info.get('filename', ''))
                    if label and filename_to_check in label.text():
                        self.test_bed_images_layout.removeWidget(widget)
                        widget.setParent(None)
                        widget.deleteLater()
                        removed_widget = True
                        print(f"✅ Removed test bed script widget from UI: {script_info.get('filename', 'Unknown')}")
                        break
            if not removed_widget:
                print(f"⚠️ Script widget not found in layout for removal")
        else:
            print(f"⚠️ test_bed_images_layout not found")
    
