    def remove_evidence_item(self, evidence_info):
        """Remove an evidence item"""
        if evidence_info in self.evidence_list:
            self.evidence_list.remove(evidence_info)
            # Remove the widget from layout
            for i in range(self.evidence_layout.count()):
                widget = self.evidence_layout.itemAt(i).widget()
                if widget and widget.findChild(QTextEdit) == evidence_info['evidence_edit']:
                    widget.setParent(None)
                    break
            
            # Show status message
            status_bar = self.statusBar()
            if status_bar:
                status_bar.showMessage(f"Removed evidence item. Total: {len(self.evidence_list)}")

    def create_test_execution_page(self):
        """Create Section 11 Test Execution page"""
        page = QWidget()
        layout = QVBoxLayout(page)
        
        # Page title
        title = QLabel("Section 11 Test Execution")
        title.setStyleSheet("font-size: 18px; font-weight: bold; color: #ff9800; margin-bottom: 20px;")
        layout.addWidget(title)
        
        # Create scroll area for content
        scroll_area = QScrollArea()
        scroll_widget = QWidget()
        scroll_layout = QVBoxLayout(scroll_widget)
        
        # Note about data fetching
        note_label = QLabel("💡 Note: Test cases are automatically generated from Section 8.1 Test Plan scenarios")
        note_label.setStyleSheet("color: #ff9800; font-style: italic; margin-bottom: 15px; padding: 10px; background-color: #2c2c2e; border-radius: 5px;")
        scroll_layout.addWidget(note_label)
        
        # Test Execution Container
        self.test_execution_container = QWidget()
        self.test_execution_layout = QVBoxLayout(self.test_execution_container)
        scroll_layout.addWidget(self.test_execution_container)
        
        # Refresh button to update from Section 8
        refresh_btn = QPushButton("🔄 Refresh from Section 8 Test Plan")
        refresh_btn.clicked.connect(self.refresh_test_execution_from_plan)
        scroll_layout.addWidget(refresh_btn)
        
        # Add a timer to periodically check and restore images and scripts
        from PyQt6.QtCore import QTimer
        self.section_11_timer = QTimer()
        self.section_11_timer.timeout.connect(self.ensure_section_11_images_restored)
        self.section_11_timer.start(2000)  # Check every 2 seconds
        
        # Add a timer to periodically check and restore scripts
        self.section_11_scripts_timer = QTimer()
        self.section_11_scripts_timer.timeout.connect(self.ensure_section_11_scripts_restored)
        self.section_11_scripts_timer.start(3000)  # Check every 3 seconds
        
        # Set up scroll area
        scroll_area.setWidget(scroll_widget)
        scroll_area.setWidgetResizable(True)
        layout.addWidget(scroll_area)
        
        self.content_stack.addWidget(page)
        
        # Automatically populate test execution cases when page is created
        QTimer.singleShot(100, self.refresh_test_execution_from_plan)
        
        # CRITICAL FIX: Add multiple delayed script restoration attempts to ensure scripts are restored
        QTimer.singleShot(1000, self.delayed_script_restoration)
        QTimer.singleShot(3000, self.delayed_script_restoration)
        QTimer.singleShot(5000, self.delayed_script_restoration)
        
        # Ensure scripts are preserved when navigating away
        self.ensure_scripts_preservation_on_navigation()
        
    def refresh_test_execution_from_plan(self):
        """Refresh test execution cases from Section 8 Test Plan scenarios"""
        # Auto-save current text content before clearing
        self.auto_save_section_11_content()
        
        # Preserve uploaded scripts data before clearing
        preserved_scripts = {}
        preserved_images = {}
        preserved_placeholders = {}
        if hasattr(self, 'step_widgets'):
            for step_key, step_data in self.step_widgets.items():
                if 'upload_scripts_list' in step_data and step_data['upload_scripts_list']:
                    preserved_scripts[step_key] = step_data['upload_scripts_list'].copy()
                    print(f"DEBUG: Preserved {len(step_data['upload_scripts_list'])} scripts for step {step_key}")
                if 'upload_images_list' in step_data and step_data['upload_images_list']:
                    preserved_images[step_key] = step_data['upload_images_list'].copy()
                    print(f"DEBUG: Preserved {len(step_data['upload_images_list'])} images for step {step_key}")
                if 'placeholders_list' in step_data and step_data['placeholders_list']:
                    preserved_placeholders[step_key] = step_data['placeholders_list'].copy()
                    print(f"DEBUG: Preserved {len(step_data['placeholders_list'])} placeholders for step {step_key}")
        
        # Also preserve scripts and images in global storage for persistence across page navigation
        if not hasattr(self, '_global_step_scripts'):
            self._global_step_scripts = {}
        self._global_step_scripts.update(preserved_scripts)
        
        if not hasattr(self, '_global_step_images'):
            self._global_step_images = {}
        self._global_step_images.update(preserved_images)
        
        if not hasattr(self, '_global_step_placeholders'):
            self._global_step_placeholders = {}
        self._global_step_placeholders.update(preserved_placeholders)
        
        # CRITICAL FIX: Always ensure global storage is preserved even if step_widgets is empty
        # This handles the case when navigating away and back to Section 11
        if not preserved_scripts and hasattr(self, '_global_step_scripts') and self._global_step_scripts:
            print(f"DEBUG: No local scripts preserved, but found {len(self._global_step_scripts)} scripts in global storage")
            preserved_scripts = self._global_step_scripts.copy()
        
        if not preserved_images and hasattr(self, '_global_step_images') and self._global_step_images:
            print(f"DEBUG: No local images preserved, but found {len(self._global_step_images)} images in global storage")
            preserved_images = self._global_step_images.copy()
        
        if not preserved_placeholders and hasattr(self, '_global_step_placeholders') and self._global_step_placeholders:
            print(f"DEBUG: No local placeholders preserved, but found {len(self._global_step_placeholders)} placeholders in global storage")
            preserved_placeholders = self._global_step_placeholders.copy()
        
        # Clear existing test execution cases
        if hasattr(self, 'test_execution_cases'):
            self.test_execution_cases.clear()
        
        # Clear existing widgets in the container
        for i in reversed(range(self.test_execution_layout.count())):
            widget = self.test_execution_layout.itemAt(i).widget()
            if widget:
                widget.setParent(None)
        
        # Generate test execution cases from scenarios
        if hasattr(self, 'test_scenarios'):
            for i, scenario in enumerate(self.test_scenarios):
                if scenario['key_edit'].text() and self.get_scenario_description(scenario):
                    self.create_test_execution_case(i+1, scenario)
        
        # Restore uploaded scripts after widgets are created
        if preserved_scripts:
            print(f"DEBUG: Restoring {len(preserved_scripts)} step scripts")
            for step_key, scripts_list in preserved_scripts.items():
                self.restore_step_scripts(step_key, scripts_list)
        
        # Also restore scripts from global storage if no local scripts were preserved
        # This is a fallback to ensure scripts are never lost
        if hasattr(self, '_global_step_scripts') and self._global_step_scripts:
            print(f"DEBUG: Checking global storage for additional scripts to restore")
            for step_key, scripts_list in self._global_step_scripts.items():
                # Only restore if not already restored from preserved_scripts
                if step_key not in preserved_scripts:
                    print(f"DEBUG: Restoring {len(scripts_list)} scripts from global storage for step {step_key}")
                    self.restore_step_scripts(step_key, scripts_list)
        
        # Restore uploaded images after widgets are created
        if preserved_images:
            print(f"DEBUG: Restoring {len(preserved_images)} step images")
            for step_key, images_list in preserved_images.items():
                self.restore_step_images(step_key, images_list)
        
        # Also restore images from global storage if no local images were preserved
        elif hasattr(self, '_global_step_images') and self._global_step_images:
            print(f"DEBUG: Restoring {len(self._global_step_images)} images from global storage")
            for step_key, images_list in self._global_step_images.items():
                self.restore_step_images(step_key, images_list)
        
        # Restore uploaded placeholders after widgets are created
        if preserved_placeholders:
            print(f"DEBUG: Restoring {len(preserved_placeholders)} step placeholders")
            for step_key, placeholders_list in preserved_placeholders.items():
                self.restore_step_placeholders(step_key, placeholders_list)
        
        # Also restore placeholders from global storage if no local placeholders were preserved
        elif hasattr(self, '_global_step_placeholders') and self._global_step_placeholders:
            print(f"DEBUG: Restoring {len(self._global_step_placeholders)} placeholders from global storage")
            for step_key, placeholders_list in self._global_step_placeholders.items():
                self.restore_step_placeholders(step_key, placeholders_list)
        
        # Populate test execution cases with imported data if available
        if hasattr(self, '_imported_test_execution_data') and self._imported_test_execution_data:
            self.populate_test_execution_cases_with_imported_data()
        
        # Ensure step widgets are properly initialized
        self.ensure_step_widgets_initialized()
        
        # Restore text content from global storage
        self.restore_section_11_text_content()
        
        # Update figure captions
        self.update_figure_captions()
        
        # Show status message
        status_bar = self.statusBar()
        if status_bar:
            case_count = len([s for s in self.test_scenarios if s['key_edit'].text() and s['value_edit'].toPlainText()])
            status_bar.showMessage(f"Generated {case_count} test execution cases from Section 8.1 scenarios")
        
      
    def restore_step_placeholders(self, step_key, placeholders_list):
        """Restore uploaded placeholders for a specific step"""
        if not hasattr(self, 'step_widgets') or step_key not in self.step_widgets:
            print(f"DEBUG: Step widget not found for key: {step_key}")
            return
        
        step_data = self.step_widgets[step_key]
        
        # Initialize placeholders_list if it doesn't exist
        if 'placeholders_list' not in step_data:
            step_data['placeholders_list'] = []
        
        # Clear existing placeholders from data
        step_data['placeholders_list'].clear()
        
        # Clear existing placeholder widgets from layout
        if 'placeholders_layout' in step_data:
            # Remove all widgets from the layout
            while step_data['placeholders_layout'].count():
                child = step_data['placeholders_layout'].takeAt(0)
                if child.widget():
                    child.widget().setParent(None)
                    child.widget().deleteLater()
        
        print(f"DEBUG: Cleared existing placeholders for step {step_key}")
        
        # Restore each placeholder
        for placeholder_info in placeholders_list:
            # Create placeholder widget
            placeholder_widget = QWidget()
            placeholder_layout = QHBoxLayout(placeholder_widget)
            
            # Placeholder label (match upload display)
            placeholder_name = placeholder_info.get('name', 'placeholder')
            placeholder_label = QLabel(f"📋 {placeholder_name}")
            placeholder_label.setStyleSheet("color: #6f42c1; font-weight: bold;")
            placeholder_layout.addWidget(placeholder_label)
            
            # Remove button
            remove_btn = QPushButton("🗑️ Remove")
            remove_btn.setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            remove_btn.clicked.connect(lambda checked, sd=step_data, ph=placeholder_info: self.remove_section_11_placeholder(sd, ph))
            placeholder_layout.addWidget(remove_btn)
            
            placeholder_layout.addStretch()
            
            # Update placeholder_info with new remove button and widget reference
            placeholder_info['remove_btn'] = remove_btn
            placeholder_info['widget'] = placeholder_widget
            
            # Add to container
            step_data['placeholders_list'].append(placeholder_info)
            if 'placeholders_layout' in step_data:
                step_data['placeholders_layout'].addWidget(placeholder_widget)
            
            print(f"DEBUG: Restored placeholder {placeholder_info.get('name', 'unknown')} for step {step_key}")
        
        # Show placeholder upload toggle as active
        if 'add_placeholder_btn' in step_data:
            step_data['add_placeholder_btn'].setStyleSheet("""
                QPushButton {
                    background-color: #6f42c1;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 6px 12px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #5a32a3;
                }
                QPushButton:pressed {
                    background-color: #4c2d85;
                }
            """)
        
        # Update info label
        if 'upload_info_label' in step_data:
            print("step_data: ", step_data)
            step_data['upload_info_label'].setText("Placeholders added. Click 'Add Placeholder' to add more placeholders.")

    def restore_step_scripts(self, step_key, scripts_list):
        """Restore uploaded scripts for a specific step"""
        if not hasattr(self, 'step_widgets') or step_key not in self.step_widgets:
            print(f"DEBUG: Step widget not found for key: {step_key}")
            return
        
        step_data = self.step_widgets[step_key]
        
        # Initialize upload_scripts_list if it doesn't exist
        if 'upload_scripts_list' not in step_data:
            step_data['upload_scripts_list'] = []
        
        # Clear existing scripts
        step_data['upload_scripts_list'].clear()
        
        # Clear existing script widgets from layout
        if 'upload_scripts_layout' in step_data:
            for i in reversed(range(step_data['upload_scripts_layout'].count())):
                widget = step_data['upload_scripts_layout'].itemAt(i).widget()
                if widget:
                    widget.setParent(None)
        
        # CRITICAL FIX: Check if this step has both images and scripts
        has_images = ('upload_images_list' in step_data and 
                     step_data['upload_images_list'] and 
                     len(step_data['upload_images_list']) > 0)
        has_scripts = scripts_list and len(scripts_list) > 0
        
        if has_images and has_scripts:
            # Both images and scripts exist - show both containers and buttons
            if 'images_container' in step_data:
                step_data['images_container'].show()
            if 'upload_scripts_container' in step_data:
                step_data['upload_scripts_container'].show()
            if 'upload_image_btn' in step_data:
                step_data['upload_image_btn'].show()
            if 'upload_script_btn' in step_data:
                step_data['upload_script_btn'].show()
            
            if 'upload_info_label' in step_data:
                step_data['upload_info_label'].setText(f"Both image and script uploads available. {len(step_data['upload_images_list'])} image(s), {len(scripts_list)} script(s) uploaded.")
            
            print(f"DEBUG: Restored mixed UI state for step {step_key} (images: {len(step_data['upload_images_list'])}, scripts: {len(scripts_list)})")
        elif has_scripts:
            # Only scripts exist - show script mode
            if 'upload_scripts_container' in step_data:
                step_data['upload_scripts_container'].show()
            if 'images_container' in step_data:
                step_data['images_container'].hide()
            if 'upload_script_btn' in step_data:
                step_data['upload_script_btn'].show()
