    def restore_step_images(self, step_key, images_list):
        """Restore uploaded images for a specific step"""
        if not hasattr(self, 'step_widgets') or step_key not in self.step_widgets:
            print(f"DEBUG: Step widget not found for key: {step_key}")
            return
        
