    def restore_case_text_content(self, case_key, text_data):
        """Restore text content for a specific test execution case"""
        try:
            # Extract case number from case_key (e.g., "case_1" -> 1)
            case_number = int(case_key.split('_')[1])
            
            # Find the corresponding case in test_execution_cases
            if hasattr(self, 'test_execution_cases') and len(self.test_execution_cases) >= case_number:
                case_data = self.test_execution_cases[case_number - 1]  # 0-based index
                
                # Restore ITSAR Description
                if 'itsar_edit' in case_data and case_data['itsar_edit']:
                    case_data['itsar_edit'].setText(text_data.get('itsar_description', ''))
                
                # Restore Test Case Description
                if 'case_desc_edit' in case_data and case_data['case_desc_edit']:
                    case_data['case_desc_edit'].setPlainText(text_data.get('test_case_description', ''))
                
                
                # Restore Observations
                if 'observations_edit' in case_data and case_data['observations_edit']:
                    case_data['observations_edit'].setPlainText(text_data.get('observations', ''))
                
                # Restore Evidence
                if 'evidence_edit' in case_data and case_data['evidence_edit']:
                    case_data['evidence_edit'].setPlainText(text_data.get('evidence', ''))
                
                print(f"DEBUG: Restored text content for case {case_key}")
            else:
                print(f"DEBUG: Case {case_key} not found in test_execution_cases")
        except Exception as e:
            print(f"DEBUG: Error restoring text content for case {case_key}: {e}")
        
    def auto_save_section_11_content(self):
        """Auto-save Section 11 text content to global storage"""
        try:
            if not hasattr(self, 'test_execution_cases') or not self.test_execution_cases:
                return
            
            # Initialize global text content storage if it doesn't exist
            if not hasattr(self, '_global_text_content'):
                self._global_text_content = {}
            
            # Save text content for each case
            for i, case_data in enumerate(self.test_execution_cases):
                case_key = f"case_{i+1}"
                
                # Extract text content from the case
                text_content = {
                    'itsar_description': case_data.get('itsar_edit', '').text() if hasattr(case_data.get('itsar_edit', ''), 'text') else '',
                    'test_case_description': case_data.get('case_desc_edit', '').toPlainText() if hasattr(case_data.get('case_desc_edit', ''), 'toPlainText') else '',
                    'observations': case_data.get('observations_edit', '').toPlainText() if hasattr(case_data.get('observations_edit', ''), 'toPlainText') else '',
                    'evidence': case_data.get('evidence_edit', '').toPlainText() if hasattr(case_data.get('evidence_edit', ''), 'toPlainText') else ''
                }
                
                # Update global storage
                self._global_text_content[case_key] = text_content
            
            print(f"DEBUG: Auto-saved text content for {len(self.test_execution_cases)} cases")
        except Exception as e:
            print(f"DEBUG: Error in auto_save_section_11_content: {e}")
    
    def restore_section_11_text_content(self):
        """Restore Section 11 text content from global storage"""
        try:
            if not hasattr(self, '_global_text_content') or not self._global_text_content:
                print("DEBUG: No global text content to restore")
                return
            
            if not hasattr(self, 'test_execution_cases') or not self.test_execution_cases:
                print("DEBUG: No test execution cases to restore text content to")
                return
            
            # Restore text content for each case
            for i, case_data in enumerate(self.test_execution_cases):
                case_key = f"case_{i+1}"
                
                if case_key in self._global_text_content:
                    text_content = self._global_text_content[case_key]
                    
                    # Restore ITSAR description
                    if 'itsar_edit' in case_data and case_data['itsar_edit'] and 'itsar_description' in text_content:
                        case_data['itsar_edit'].setText(text_content['itsar_description'])
                    
                    # Restore Test Case Description
                    if 'case_desc_edit' in case_data and case_data['case_desc_edit'] and 'test_case_description' in text_content:
                        case_data['case_desc_edit'].setPlainText(text_content['test_case_description'])
                    
                    
                    # Restore Observations
                    if 'observations_edit' in case_data and case_data['observations_edit'] and 'observations' in text_content:
                        case_data['observations_edit'].setPlainText(text_content['observations'])
                    
                    # Restore Evidence
                    if 'evidence_edit' in case_data and case_data['evidence_edit'] and 'evidence' in text_content:
                        case_data['evidence_edit'].setPlainText(text_content['evidence'])
                    
                    print(f"DEBUG: Restored text content for case {case_key}")
            
            print(f"DEBUG: Restored text content for {len(self.test_execution_cases)} cases")
        except Exception as e:
            print(f"DEBUG: Error in restore_section_11_text_content: {e}")
        
    def populate_test_execution_cases_with_imported_data(self):
        """Populate test execution cases with imported data"""
        print(f"DEBUG: populate_test_execution_cases_with_imported_data called")
        if not hasattr(self, '_imported_test_execution_data') or not self._imported_test_execution_data:
            print(f"DEBUG: No imported test execution data found")
            return
        
        print(f"DEBUG: Found {len(self._imported_test_execution_data)} imported test execution cases")
        
        try:
            # Match imported data with generated cases by scenario key
            for case_data in self.test_execution_cases:
                scenario_key = case_data.get('scenario_key', '')
                
                # Find matching imported data
                for imported_case in self._imported_test_execution_data:
                    if imported_case.get('scenario_key') == scenario_key:
                        # Populate the case with imported data
                        try:
                            if 'itsar_edit' in case_data and case_data['itsar_edit']:
                                case_data['itsar_edit'].setText(imported_case.get('itsar_description', ''))
                        
                            if 'case_desc_edit' in case_data and case_data['case_desc_edit']:
                                case_data['case_desc_edit'].setPlainText(imported_case.get('test_case_description', ''))
                        
                        
                            if 'observations_edit' in case_data and case_data['observations_edit']:
                                case_data['observations_edit'].setPlainText(imported_case.get('test_observations', ''))
                        
                            if 'evidence_edit' in case_data and case_data['evidence_edit']:
                                case_data['evidence_edit'].setPlainText(imported_case.get('evidence_provided', ''))
                        except Exception as e:
                            print(f"DEBUG: Error populating case data: {e}")
                        
                        # Import execution steps if available
                        if 'steps_data' in imported_case and 'steps' in case_data:
                            for step_index, step_data in enumerate(imported_case['steps_data'], 1):
                                try:
                                    # Add step to the case
                                    self.add_execution_step_to_case(case_data)
                                    if case_data['steps']:
                                        last_step = case_data['steps'][-1]
                                        # Set text immediately instead of using QTimer
                                        if 'step_edit' in last_step and last_step['step_edit']:
                                            last_step['step_edit'].setText(step_data.get('step_text', ''))
                                    
                                    # Import script data if available - use QTimer for multiple scripts
                                    if 'scripts' in step_data and step_data['scripts']:
                                        # Get the step key to find the corresponding step widget
                                        step_key = f"{case_data['case_number']}_{step_index}"
                                        
                                        # CRITICAL FIX: Extract placeholders from scripts and add them to step widgets
                                        self.extract_placeholders_from_scripts(step_key, step_data['scripts'])
                                        
                                        # Use QTimer to populate script data after widget is fully initialized
                                        # Add delay based on step index to avoid race conditions
                                        delay = step_index * 200  # 200ms delay per step
                                        QTimer.singleShot(delay, lambda sk=step_key, scripts=step_data['scripts']: 
                                            self.populate_step_script_data_safe(sk, scripts))
                                    
                                    # Import image data if available
                                    if 'images' in step_data and step_data['images']:
                                        # Get the step key to find the corresponding step widget
                                        step_key = f"{case_data['case_number']}_{step_index}"
                                        
                                        print(f"DEBUG: Found {len(step_data['images'])} images to import for step {step_key}")
                                        print(f"DEBUG: Image data: {step_data['images']}")
                                        
                                        # Use QTimer for image data as well
                                        delay = step_index * 200 + 100  # Additional 100ms delay
                                        QTimer.singleShot(delay, lambda sk=step_key, images=step_data['images']: 
                                            self.populate_step_image_data_safe(sk, images))
                                    else:
                                        print(f"DEBUG: No images found in step_data for step {step_index}")
                                except Exception as e:
                                    print(f"DEBUG: Error populating step {step_index}: {e}")
                        
                        break
            
            # CRITICAL FIX: After populating test execution cases, ensure Section 8 questions with Section 11 scripts
            # are properly mapped to Execution Step Questions
            self._ensure_section8_section11_mapping_after_import()
            
        except Exception as e:
            print(f"DEBUG: Error in populate_test_execution_cases_with_imported_data: {e}")
        
        # Clear the imported data after use
        # self._imported_test_execution_data = []
    
    def extract_placeholders_from_scripts(self, step_key, scripts):
        """Extract placeholder information from scripts and add them to step widgets"""
        try:
            print(f"DEBUG: extract_placeholders_from_scripts called for step_key: {step_key}")
            print(f"DEBUG: Processing {len(scripts)} scripts")
            
            # Check if step_widgets exists and has the step_key
            if not hasattr(self, 'step_widgets') or step_key not in self.step_widgets:
                print(f"DEBUG: Step widget {step_key} not found, creating placeholder extraction for later")
                # Store scripts for later processing when step widget is created
                if not hasattr(self, '_pending_placeholder_extraction'):
                    self._pending_placeholder_extraction = {}
                self._pending_placeholder_extraction[step_key] = scripts
                return
            
            step_widget = self.step_widgets[step_key]
            
            # Initialize placeholders_list if it doesn't exist
            if 'placeholders_list' not in step_widget:
                step_widget['placeholders_list'] = []
            
            # Extract placeholders from scripts
            for script_info in scripts:
                if isinstance(script_info, dict) and 'placeholder' in script_info and script_info['placeholder']:
                    placeholder_name = script_info['placeholder']
                    print(f"DEBUG: Found placeholder '{placeholder_name}' in script: {script_info.get('filename', 'Unknown')}")
                    
                    # Check if placeholder already exists to avoid duplicates
                    existing_placeholder_names = [ph.get('name', '') for ph in step_widget['placeholders_list']]
                    if placeholder_name not in existing_placeholder_names:
                        placeholder_info = {
                            'name': placeholder_name,
                            'type': 'placeholder',
                            'is_placeholder': True
                        }
                        step_widget['placeholders_list'].append(placeholder_info)
                        print(f"DEBUG: Added placeholder '{placeholder_name}' to step widget {step_key}")
                        
                        # Also add to global storage for persistence
                        if not hasattr(self, '_global_step_placeholders'):
                            self._global_step_placeholders = {}
                        if step_key not in self._global_step_placeholders:
                            self._global_step_placeholders[step_key] = []
                        self._global_step_placeholders[step_key].append(placeholder_info.copy())
                        print(f"DEBUG: Added placeholder '{placeholder_name}' to global storage for step {step_key}")
                    else:
                        print(f"DEBUG: Placeholder '{placeholder_name}' already exists in step widget {step_key}")
            
            print(f"DEBUG: Step widget {step_key} now has {len(step_widget['placeholders_list'])} placeholders")
            
        except Exception as e:
            print(f"DEBUG: Error in extract_placeholders_from_scripts: {e}")
    
    def _ensure_section8_section11_mapping_after_import(self):
        """
        CRITICAL FIX: Ensure Section 8 Test Plan questions with corresponding Section 11 Test Execution scripts
        are properly mapped to Execution Step Questions after import.
        
        This method addresses the issue where new questions added in Section 8 and their scripts uploaded in Section 11
        are not appearing in Execution Step Questions after import.
        """
        print("DEBUG: _ensure_section8_section11_mapping_after_import called")
        
        try:
            # Check if we have imported test execution data
            if not hasattr(self, '_imported_test_execution_data') or not self._imported_test_execution_data:
                print("DEBUG: No imported test execution data found for mapping")
                return
            
            # Check if we have step_widgets (Section 11 data)
            if not hasattr(self, 'step_widgets') or not self.step_widgets:
                print("DEBUG: No step_widgets found for mapping")
                return
            
            print(f"DEBUG: Found {len(self._imported_test_execution_data)} imported cases and {len(self.step_widgets)} step widgets")
            
            # Process each imported test execution case
            for imported_case in self._imported_test_execution_data:
                scenario_key = imported_case.get('scenario_key', '')
                case_number = imported_case.get('case_number', 1)
                
                print(f"DEBUG: Processing imported case {case_number} for scenario '{scenario_key}'")
                
                # Check if this case has steps_data with scripts
                if 'steps_data' in imported_case:
                    for step_data in imported_case['steps_data']:
                        step_text = step_data.get('step_text', '')
                        step_index = step_data.get('step_index', 1)
                        
                        if not step_text:
                            continue
                        
                        # Check if this step has scripts
                        if 'scripts' in step_data and step_data['scripts']:
                            print(f"DEBUG: Found {len(step_data['scripts'])} scripts for step: {step_text}")
                            
                            # Process each script
                            for script_info in step_data['scripts']:
                                script_filename = script_info.get('original_filename', script_info.get('filename', ''))
                                placeholder = script_info.get('placeholder', script_info.get('description', ''))
                                
                                if not script_filename:
                                    continue
                                
                                print(f"DEBUG: Processing script '{script_filename}' with placeholder '{placeholder}' for step: {step_text}")
                                
                                # Check if this question already exists in execution step questions
                                question_exists = False
                                for existing_step_data in self.execution_step_questions:
                                    for question_block in existing_step_data.get('question_blocks', []):
                                        if hasattr(question_block, 'question_edit'):
                                            # Handle both QLineEdit and QTextEdit
                                            if hasattr(question_block.question_edit, 'text'):
                                                existing_question_text = question_block.question_edit.text()
                                            elif hasattr(question_block.question_edit, 'toPlainText'):
                                                existing_question_text = question_block.question_edit.toPlainText()
                                            else:
                                                continue
                                            
                                            if existing_question_text.strip() == step_text.strip():
                                                # Check if this script is already associated
                                                if hasattr(question_block, 'script_name_edit'):
                                                    existing_script = question_block.script_name_edit.text()
                                                    if existing_script == script_filename:
                                                        question_exists = True
                                                        print(f"DEBUG: Question with script already exists: {step_text}")
                                                        break
                                
                                if not question_exists:
                                    print(f"DEBUG: Creating new execution step question for: {step_text}")
                                    
                                    # Create new execution step question with script info
                                    new_step_data = {
                                        'case_data': {
                                            'scenario_key': scenario_key,
                                            'scenario_description': imported_case.get('test_case_description', 'No description'),
                                            'question_number': len(self.execution_step_questions) + 1
                                        },
                                        'step_number': len(self.execution_step_questions) + 1,
                                        'step_text': step_text,
                                        'question_blocks': [],
                                        'source_section': 'Section 11'
                                    }
                                    
                                    # Create question block with script info
                                    question_block = self.create_execution_step_question_block(new_step_data, script_filename)
                                    
                                    # Set the placeholder if available
                                    if hasattr(question_block, 'placeholder_edit') and placeholder:
                                        question_block.placeholder_edit.setText(placeholder)
                                        print(f"DEBUG: Set placeholder '{placeholder}' for new question")
                                    
                                    new_step_data['question_blocks'].append(question_block)
                                    
                                    # Add to execution step questions list
                                    self.execution_step_questions.append(new_step_data)
                                    
                                    # Add to UI
                                    if hasattr(self, 'execution_questions_layout'):
                                        self.execution_questions_layout.addWidget(question_block)
                                        print(f"DEBUG: Added new question block to execution questions layout")
                                    
                                    print(f"DEBUG: Successfully created new execution step question with script: {script_filename}")
            
            # Refresh the Execution Step Questions page to show the new questions
            if hasattr(self, 'load_execution_questions_from_section_11'):
                self.load_execution_questions_from_section_11()
                print("DEBUG: Refreshed Execution Step Questions page after mapping")
            
        except Exception as e:
            print(f"DEBUG: Error in _ensure_section8_section11_mapping_after_import: {e}")
            import traceback
            traceback.print_exc()
    
    def _process_pending_test_execution_import(self):
        """Process pending test execution case imports when UI is ready"""
        if not hasattr(self, '_pending_test_execution_imports') or not self._pending_test_execution_imports:
            return
        
        print(f"DEBUG: Processing {len(self._pending_test_execution_imports)} pending test execution imports")
        
        for pending_import in self._pending_test_execution_imports[:]:  # Copy list to avoid modification during iteration
            case_data = pending_import['case_data']
            last_case = pending_import['last_case']
            case_number = pending_import['case_number']
            
            try:
                # Import text fields with proper null checks
                if 'itsar_edit' in last_case and last_case['itsar_edit'] is not None and 'itsar_description' in case_data:
                    last_case['itsar_edit'].setText(case_data['itsar_description'])
                    print(f"DEBUG: Imported itsar_description: {case_data['itsar_description']}")
                else:
                    print(f"DEBUG: itsar_edit field not available or None for case {case_number}")
                
                if 'case_name_edit' in last_case and last_case['case_name_edit'] is not None and 'test_case_name' in case_data:
                    last_case['case_name_edit'].setPlainText(case_data['test_case_name'])
                    print(f"DEBUG: Imported test_case_name: {case_data['test_case_name']}")
                else:
                    print(f"DEBUG: case_name_edit field not available or None for case {case_number}")
                
                if 'case_desc_edit' in last_case and last_case['case_desc_edit'] is not None and 'test_case_description' in case_data:
                    last_case['case_desc_edit'].setPlainText(case_data['test_case_description'])
                    print(f"DEBUG: Imported test_case_description: {case_data['test_case_description']}")
                else:
                    print(f"DEBUG: case_desc_edit field not available or None for case {case_number}")
                
                
                if 'observations_edit' in last_case and last_case['observations_edit'] is not None and 'test_observations' in case_data:
                    last_case['observations_edit'].setPlainText(case_data['test_observations'])
                    print(f"DEBUG: Imported test_observations: {case_data['test_observations']}")
                else:
                    print(f"DEBUG: observations_edit field not available or None for case {case_number}")
                
                if 'evidence_edit' in last_case and last_case['evidence_edit'] is not None and 'evidence_provided' in case_data:
                    last_case['evidence_edit'].setPlainText(case_data['evidence_provided'])
                    print(f"DEBUG: Imported evidence_provided: {case_data['evidence_provided']}")
                else:
                    print(f"DEBUG: evidence_edit field not available or None for case {case_number}")
                
                # Remove from pending list after successful processing
                self._pending_test_execution_imports.remove(pending_import)
                
            except Exception as e:
                print(f"DEBUG: Error processing pending import for case {case_number}: {e}")
                # Remove from pending list even if there was an error to avoid infinite retry
                self._pending_test_execution_imports.remove(pending_import)
    
    def populate_step_script_data_safe(self, step_key, scripts):
        """Safely populate step widget with imported script data with better widget lifecycle management"""
        print(f"DEBUG: populate_step_script_data_safe called for step_key: {step_key} with {len(scripts)} scripts")
        try:
            # Check if step widget exists
            if not hasattr(self, 'step_widgets') or step_key not in self.step_widgets:
                print(f"DEBUG: Step widget not found for key: {step_key}, retrying in 100ms")
                QTimer.singleShot(100, lambda: self.populate_step_script_data_safe(step_key, scripts))
                return
            
            step_data = self.step_widgets[step_key]
            
            # Initialize upload_scripts_list if it doesn't exist
            if 'upload_scripts_list' not in step_data:
                step_data['upload_scripts_list'] = []
            
            # Clear existing scripts safely
            step_data['upload_scripts_list'].clear()
            
            # Clear existing script widgets from layout safely
            if 'upload_scripts_layout' in step_data:
                try:
                    for i in reversed(range(step_data['upload_scripts_layout'].count())):
                        item = step_data['upload_scripts_layout'].itemAt(i)
                        if item and item.widget():
                            widget = item.widget()
                            widget.setParent(None)
                            widget.deleteLater()
                except Exception as e:
                    print(f"DEBUG: Error clearing script widgets: {e}")
            
            # Process scripts one by one with delays
            for i, script_info in enumerate(scripts):
                try:
                    print(f"DEBUG: Processing script {i+1}/{len(scripts)}: {script_info.get('original_filename', script_info.get('filename', 'unknown'))}")
                    
                    # Create a copy of script_info to avoid modifying the original
                    script_info_copy = script_info.copy()
                    
                    # Create script widget with placeholder display
                    script_widget = QWidget()
                    script_layout = QHBoxLayout(script_widget)
                    
                    # Get placeholder from script info
                    placeholder = script_info_copy.get('placeholder', '')
                    description = script_info_copy.get('description', '')
                    
                    # Filename label
                    filename_label = QLabel(f"📄 {script_info_copy.get('original_filename', script_info_copy['filename'])}")
                    filename_label.setStyleSheet("color: #28a745; font-weight: bold;")
                    script_layout.addWidget(filename_label)
                    
                    # Add separator
                    separator_label = QLabel("|")
                    separator_label.setStyleSheet("color: #6c757d; font-weight: bold; margin: 0 8px;")
                    script_layout.addWidget(separator_label)
                    
                    # Placeholder label
                    placeholder_label = QLabel(f"🏷️ {placeholder or description or '(No placeholder)'}")
                    if placeholder or description:
                        placeholder_label.setStyleSheet("color: #007bff; font-weight: bold; background-color: #f8f9fa; padding: 2px 6px; border-radius: 3px; border: 1px solid #dee2e6;")
                    else:
                        placeholder_label.setStyleSheet("color: #6c757d; font-weight: bold; background-color: #f8f9fa; padding: 2px 6px; border-radius: 3px; border: 1px solid #dee2e6; font-style: italic;")
                    script_layout.addWidget(placeholder_label)
                    
                    # Add some spacing
                    script_layout.addSpacing(10)
                    
                    # Script Remove button
                    remove_btn = QPushButton("🗑️ Remove")
                    remove_btn.setStyleSheet("""
                        QPushButton {
                            background-color: #dc3545;
                            color: white;
                            border: none;
                            border-radius: 4px;
                            padding: 4px 8px;
                            font-weight: bold;
                        }
                        QPushButton:hover {
                            background-color: #c82333;
                        }
                    """)
                    remove_btn.clicked.connect(lambda checked, sd=step_data, scr=script_info_copy: self.remove_section_11_script(sd, scr))
                    script_layout.addWidget(remove_btn)
                    
                    # Add remove_btn to script_info_copy for compatibility
                    script_info_copy['remove_btn'] = remove_btn
                    
                    # Placeholder Remove button
                    placeholder_remove_btn = QPushButton("🗑️ Remove Placeholder")
                    placeholder_remove_btn.setStyleSheet("""
                        QPushButton {
                            background-color: #fd7e14;
                            color: white;
                            border: none;
                            border-radius: 4px;
                            padding: 4px 8px;
                            font-weight: bold;
                        }
                        QPushButton:hover {
                            background-color: #e8690b;
                        }
                    """)
                    placeholder_remove_btn.clicked.connect(lambda checked, sd=step_data, scr=script_info_copy, lbl=placeholder_label: self.remove_section_11_script_placeholder(sd, scr, lbl))
                    script_layout.addWidget(placeholder_remove_btn)
                    
                    script_layout.addStretch()
                    
                    # Add to step data
                    step_data['upload_scripts_list'].append(script_info_copy)
                    
                    # Store in global storage for persistence
                    if not hasattr(self, '_global_step_scripts'):
                        self._global_step_scripts = {}
                    
                    # Get the step key for global storage
                    case_number = step_data.get('case_number', 'unknown')
                    step_index = step_data.get('step_index', 1)
                    step_key = f"{case_number}_{step_index}"
                    
                    if step_key not in self._global_step_scripts:
                        self._global_step_scripts[step_key] = []
                    
                    # Check if script already exists in global storage to avoid duplicates
                    script_exists = any(
                        stored_script.get('filename') == script_info_copy.get('filename') and 
                        stored_script.get('path') == script_info_copy.get('path')
                        for stored_script in self._global_step_scripts[step_key]
                    )
                    
                    if not script_exists:
                        self._global_step_scripts[step_key].append(script_info_copy.copy())
                        print(f"DEBUG: Added imported script to global storage for step {step_key}")
                    
                    # Add to layout if available
                    if 'upload_scripts_layout' in step_data:
                        try:
                            step_data['upload_scripts_layout'].addWidget(script_widget)
                        except Exception as e:
                            print(f"DEBUG: Error adding script widget to layout: {e}")
                    
                    print(f"DEBUG: Successfully populated script '{script_info_copy.get('original_filename', script_info_copy['filename'])}' with placeholder '{placeholder or description}' for step {step_key}")
                    
                    # Add a small delay between script processing to avoid widget conflicts
                    if i < len(scripts) - 1:  # Don't delay for the last script
                        QTimer.singleShot(50, lambda: None)  # 50ms delay
                        
                except Exception as e:
                    print(f"DEBUG: Error processing script {i+1}: {e}")
                    
        except Exception as e:
            print(f"DEBUG: Error in populate_step_script_data_safe for step {step_key}: {e}")
    
