    def is_widget_valid(self, widget):
        """Check if a widget is still valid and not deleted"""
        try:
            if widget is None:
                return False
            # Try to access a property to check if widget is still valid
            widget.objectName()
            return True
        except RuntimeError:
            return False
        except Exception:
            return False
    
    def get_widget_text_safely(self, widget):
        """Safely get text from a widget"""
        try:
            if self.is_widget_valid(widget):
                return widget.text()
            return ""
        except RuntimeError:
            return ""
        except Exception as e:
            print(f"DEBUG: Error getting widget text: {e}")
            return ""
    
