    def populate_step_image_data(self, step_key, images):
        """Populate step widget with imported image data"""
        print(f"DEBUG: populate_step_image_data called for step_key: {step_key} with {len(images)} images")
        if not hasattr(self, 'step_widgets') or step_key not in self.step_widgets:
            print(f"DEBUG: Step widget not found for key: {step_key}")
            if hasattr(self, 'step_widgets'):
                print(f"DEBUG: Available step keys: {list(self.step_widgets.keys())}")
            return
        
        step_data = self.step_widgets[step_key]
        
        # Initialize upload_images_list if it doesn't exist
        if 'upload_images_list' not in step_data:
            step_data['upload_images_list'] = []
        
        # Clear existing images
        step_data['upload_images_list'].clear()
        
        # Clear existing image widgets from layout
        if 'images_layout' in step_data:
            for i in reversed(range(step_data['images_layout'].count())):
                widget = step_data['images_layout'].itemAt(i).widget()
                if widget:
                    widget.setParent(None)
        
        # Add imported images
        for image_info in images:
            print(f"DEBUG: Processing image_info: {image_info}")
            
            # Resolve the image path
            image_path = None
            if 'absolute_path' in image_info:
                image_path = image_info['absolute_path']
            elif 'path' in image_info:
                # Try to resolve relative path to absolute path
                relative_path = image_info['path']
                if relative_path.startswith('raw_logs/'):
                    # Look for the file in the current import directory
                    filename = relative_path[len('raw_logs/'):]
                    
                    # Use the import project directory if available
                    if hasattr(self, 'import_project_dir') and self.import_project_dir:
                        project_dir = self.import_project_dir
                    else:
                        # Fallback: try to find project directory from current working directory
                        project_dir = os.getcwd()
                    
                    # Try multiple possible locations
                    possible_paths = [
                        os.path.join(project_dir, "raw_logs", filename),  # Direct in project
                        os.path.join(project_dir, "tmp", "raw_logs", filename),  # In tmp subfolder
                        os.path.join(project_dir, "test_case", "raw_logs", filename),  # In test_case subfolder
                        os.path.join(os.getcwd(), "tmp", "test_case", "raw_logs", filename),  # Current tmp/test_case
                        os.path.join(os.getcwd(), "tmp", "raw_logs", filename),  # Current tmp
                    ]
                    
                    print(f"DEBUG: Looking for image '{filename}' in possible paths:")
                    for path in possible_paths:
                        print(f"DEBUG: Checking path: {path}")
                        if os.path.exists(path):
                            image_path = path
                            print(f"DEBUG: Found image at: {image_path}")
                            break
                    
                    if not image_path:
                        print(f"DEBUG: Could not find image file: {filename}")
                        print(f"DEBUG: Tried paths: {possible_paths}")
                        continue
                else:
                    # Try the path as is
                    image_path = relative_path
            
            if not image_path or not os.path.exists(image_path):
                print(f"DEBUG: Image path not found or doesn't exist: {image_path}")
                continue
            
            # Create image widget
            image_widget = QWidget()
            image_layout = QHBoxLayout(image_widget)
            
            # Filename label
            filename_label = QLabel(f"🖼️ {image_info.get('original_filename', image_info['filename'])}")
            filename_label.setStyleSheet("color: #007bff; font-weight: bold;")
            image_layout.addWidget(filename_label)
            
            # Remove button
            remove_btn = QPushButton("🗑️ Remove")
            remove_btn.setStyleSheet("""
                QPushButton {
                    background-color: #dc3545;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    padding: 4px 8px;
                    font-weight: bold;
                }
                QPushButton:hover {
                    background-color: #c82333;
                }
            """)
            
            # Create a copy of image_info with the resolved path
            resolved_image_info = image_info.copy()
            resolved_image_info['path'] = image_path
            
            remove_btn.clicked.connect(lambda checked, sd=step_data, img=resolved_image_info: self.remove_section_11_image(sd, img))
            image_layout.addWidget(remove_btn)
            
            image_layout.addStretch()
            
            # Add to step data with resolved path
            step_data['upload_images_list'].append(resolved_image_info)
            
            # Add to layout if available
            if 'images_layout' in step_data:
                step_data['images_layout'].addWidget(image_widget)
            
            print(f"DEBUG: Populated image '{image_info.get('original_filename', image_info['filename'])}' for step {step_key}")
            
            # Also store in global storage for persistence
            if not hasattr(self, '_global_step_images'):
                self._global_step_images = {}
            if step_key not in self._global_step_images:
                self._global_step_images[step_key] = []
            self._global_step_images[step_key].append(resolved_image_info)
            print(f"DEBUG: Added image to global storage for step {step_key}")
    
    def add_execution_step_to_case(self, case_data):
        """Add an execution step to a test execution case"""
        # Create a new step entry with proper parent
        step_widget = QWidget()
        step_layout = QHBoxLayout(step_widget)
        
        step_info = {
            'step_edit': QLineEdit(step_widget),  # Set parent to prevent deletion
            'step_skip_button': QPushButton("Skip", step_widget),  # Set parent
            'remove_btn': QPushButton("🗑️ Remove", step_widget),  # Set parent
            'widget': step_widget  # Store the widget reference
        }
        
        # Set up the step UI
        step_info['step_edit'].setPlaceholderText("Enter execution step...")
        
        # Set up skip button
        step_info['step_skip_button'].setMaximumWidth(60)
        step_info['step_skip_button'].setStyleSheet("""
            QPushButton {
                background-color: #28a745;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                padding: 4px 8px;
                font-size: 12px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #218838;
            }
            QPushButton:pressed {
                background-color: #1e7e34;
            }
        """)
        
        # Set up remove button
        step_info['remove_btn'].setStyleSheet("""
            QPushButton {
                background-color: #dc3545;
                color: #ffffff;
                border: none;
                border-radius: 4px;
                padding: 4px 8px;
                font-size: 12px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #c82333;
            }
            QPushButton:pressed {
                background-color: #bd2130;
            }
        """)
        
        step_layout.addWidget(QLabel("Step:"))
        step_layout.addWidget(step_info['step_edit'])
        step_layout.addWidget(step_info['step_skip_button'])
        step_layout.addWidget(step_info['remove_btn'])
        
        # Connect remove button
        step_info['remove_btn'].clicked.connect(lambda: self.remove_execution_step_from_case(case_data, step_info))
        
        # Connect skip button for execution step
        step_info['step_skip_button'].clicked.connect(lambda: self.skip_execution_step_from_case(step_info))
        
        # Add to case's steps
        if 'steps' not in case_data:
            case_data['steps'] = []
        case_data['steps'].append(step_info)
        
        # Add to case's steps layout if it exists
        if 'steps_layout' in case_data:
            case_data['steps_layout'].addWidget(step_widget)
        
        # Ensure the widget is properly parented to prevent deletion
        if 'widget' in case_data:
            step_widget.setParent(case_data['widget'])
        else:
            # If no parent widget exists, parent to the main window
            step_widget.setParent(self)
    
    def remove_execution_step_from_case(self, case_data, step_info):
        """Remove an execution step from a test execution case"""
        if 'steps' in case_data and step_info in case_data['steps']:
            case_data['steps'].remove(step_info)
            # Remove the widget from layout if it exists
            if 'steps_layout' in case_data:
                for i in range(case_data['steps_layout'].count()):
                    widget = case_data['steps_layout'].itemAt(i).widget()
                    if widget and widget.findChild(QLineEdit) == step_info['step_edit']:
                        widget.setParent(None)
                        break
            
            # Properly delete the widget to prevent memory leaks
            if 'widget' in step_info:
                step_info['widget'].deleteLater()
    
    def skip_execution_step_from_case(self, step_info):
        """Skip an execution step in a test execution case"""
        step_info['step_edit'].setText("SKIPPED")
        step_info['step_edit'].setStyleSheet("color: #6c757d; font-style: italic;")
    
    def set_step_text_safely(self, step_info, text):
        """Safely set text for a step edit widget"""
        try:
            if step_info and 'step_edit' in step_info and step_info['step_edit']:
                step_info['step_edit'].setText(text)
        except RuntimeError:
            # Widget was deleted, ignore the error
            pass
        
