    def add_step_script(self, step_number, case_number):
        """Add Python script for a specific step"""
        file_path, _ = QFileDialog.getOpenFileName(
            self,
            f"Select Python Script for Step {step_number}",
            "",
            "Python Files (*.py)"
        )
        
        if file_path:
            # Validate file extension
            if not file_path.lower().endswith('.py'):
                QMessageBox.warning(self, "Invalid File", "Please select a Python script (.py file)")
                return
            
            # Get the step widget data
            step_key = f"{case_number}_{step_number}"
            if hasattr(self, 'step_widgets') and step_key in self.step_widgets:
                step_data = self.step_widgets[step_key]
                
                # Create individual script display widget
                script_display_widget = QWidget()
                script_display_layout = QVBoxLayout(script_display_widget)
                
                # Script info
                script_info = {
                    'step_number': step_number,
                    'case_number': case_number,
                    'script_path': file_path,
                    'filename': os.path.basename(file_path)
                }
                
                # Script filename and controls
                script_header_layout = QHBoxLayout()
                script_header_layout.addWidget(QLabel(f"📄 {script_info['filename']}"))
                
                # Execute script button
                execute_script_btn = QPushButton("▶ Execute")
                execute_script_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #007bff;
                        color: white;
                        border: none;
                        border-radius: 3px;
                        padding: 4px 8px;
                        font-weight: bold;
                    }
                    QPushButton:hover {
                        background-color: #0056b3;
                    }
                    QPushButton:pressed {
                        background-color: #004085;
                    }
                """)
                execute_script_btn.clicked.connect(lambda: self.execute_step_script(script_info))
                script_header_layout.addWidget(execute_script_btn)
                
                # Remove script button
                remove_script_btn = QPushButton("🗑️ Remove")
                remove_script_btn.clicked.connect(lambda: self.remove_step_script(step_number, case_number, script_display_widget, file_path))
                script_header_layout.addWidget(remove_script_btn)
                
                script_display_layout.addLayout(script_header_layout)
                
                # Output display area
                output_label = QLabel("Execution Output:")
                script_display_layout.addWidget(output_label)
                
                output_text = ContextMenuTextEdit()
                output_text.setMaximumHeight(100)
                output_text.setReadOnly(True)
                output_text.setPlaceholderText("Script output will appear here after execution...")
                script_display_layout.addWidget(output_text)
                
                # Store output text reference
                script_info['output_text'] = output_text
                script_info['display_widget'] = script_display_widget
                
                # Add the script display widget to the step's scripts layout
                step_data['scripts_layout'].addWidget(script_display_widget)
                
                # Add to step's scripts list
                step_data['scripts'].append(script_info)
                
                # Add to global scripts collection
                if not hasattr(self, 'step_scripts'):
                    self.step_scripts = []
                self.step_scripts.append(script_info)
                
                # Show success message
                QMessageBox.information(self, "Script Added", f"Script added for Step {step_number} in Case 11.1.{case_number}")
                
                # Update status
                status_bar = self.statusBar()
                if status_bar:
                    status_bar.showMessage(f"Script added: {os.path.basename(file_path)} for Step {step_number}")
            else:
                QMessageBox.warning(self, "Error", "Step widget not found.")
    
    def execute_step_script(self, script_info):
        """Execute a Python script for a specific step"""
        try:
            from script_executor import SafeScriptExecutor
            
            executor = SafeScriptExecutor()
            result = executor.execute_script(script_info['script_path'])
            
            # Update output text
            output_text = script_info['output_text']
            output_text.clear()
            
            if result.success:
                output_text.append("✅ Script executed successfully!\n")
                output_text.append(f"Execution time: {result.execution_time:.2f} seconds\n")
                output_text.append(f"Exit code: {result.exit_code}\n")
                
                if result.stdout:
                    output_text.append("--- STDOUT ---\n")
                    output_text.append(result.stdout)
                
                if result.stderr:
                    output_text.append("--- STDERR ---\n")
                    output_text.append(result.stderr)
            else:
                output_text.append("❌ Script execution failed!\n")
                output_text.append(f"Error: {result.error_message}\n")
                output_text.append(f"Exit code: {result.exit_code}\n")
                
                if result.stderr:
                    output_text.append("--- ERROR OUTPUT ---\n")
                    output_text.append(result.stderr)
            
        except Exception as e:
            script_info['output_text'].append(f"❌ Execution error: {str(e)}\n")
    
    def remove_step_script(self, step_number, case_number, script_display_widget, script_path):
        """Remove script for a specific step"""
        step_key = f"{case_number}_{step_number}"
        if hasattr(self, 'step_widgets') and step_key in self.step_widgets:
            step_data = self.step_widgets[step_key]
            
            # Remove the script display widget
            script_display_widget.setParent(None)
            
            # Remove from step's scripts list
            step_data['scripts'] = [script for script in step_data['scripts'] if script['script_path'] != script_path]
            
            # Remove from global scripts collection
            if hasattr(self, 'step_scripts'):
                self.step_scripts = [script for script in self.step_scripts if script['script_path'] != script_path]
                
    def remove_step_image(self, step_number, case_number, image_display_widget, image_path):
        """Remove image for a specific step"""
        step_key = f"{case_number}_{step_number}"
        if hasattr(self, 'step_widgets') and step_key in self.step_widgets:
            step_data = self.step_widgets[step_key]
            
            # Remove the image display widget
            image_display_widget.setParent(None)
            
            # Remove from step's images list
            step_data['images'] = [img for img in step_data['images'] if img['image_path'] != image_path]
            
