    def edit_section_11_figure_description(self, step_data, image_info):
        """Edit figure description for Section 11 image"""
        current_description = image_info.get('description', '')
        
        dialog = QDialog(self)
        dialog.setWindowTitle("Edit Figure Description")
        dialog.setModal(True)
        dialog.resize(500, 200)
        
        layout = QVBoxLayout(dialog)
        
        # Title
        title_label = QLabel(f"Edit description for figure:")
        title_label.setStyleSheet("font-weight: bold; font-size: 14px; margin-bottom: 10px;")
        layout.addWidget(title_label)
        
        # Filename display
        filename_label = QLabel(f"File: {image_info.get('original_filename', 'Unknown')}")
        filename_label.setStyleSheet("color: #666; font-style: italic; margin-bottom: 10px;")
        layout.addWidget(filename_label)
        
        # Description input
        description_edit = QTextEdit()
        description_edit.setPlainText(current_description)
        description_edit.setPlaceholderText("Enter a description for this figure...")
        description_edit.setMaximumHeight(80)
        layout.addWidget(description_edit)
        
        # Buttons
        button_layout = QHBoxLayout()
        
        cancel_btn = QPushButton("Cancel")
        cancel_btn.clicked.connect(dialog.reject)
        button_layout.addWidget(cancel_btn)
        
        ok_btn = QPushButton("OK")
        ok_btn.setDefault(True)
        ok_btn.clicked.connect(dialog.accept)
        button_layout.addWidget(ok_btn)
        
        layout.addLayout(button_layout)
        
        if dialog.exec() == QDialog.DialogCode.Accepted:
            new_description = description_edit.toPlainText().strip()
            if new_description and new_description != current_description:
                # Update the description
                image_info['description'] = new_description
                
                # Update the caption label
                if 'caption_label' in image_info:
                    figure_number = image_info.get('figure_number', '11.1.1')
                    image_info['caption_label'].setText(f"Figure {figure_number}: {new_description}")
                
                # Update global storage
                case_number = step_data.get('case_number', '1')
                step_index = step_data.get('step_index', 1)
                step_key = f"{case_number}_{step_index}"
                
                if hasattr(self, '_global_step_images') and step_key in self._global_step_images:
                    for stored_image in self._global_step_images[step_key]:
                        if stored_image.get('filename') == image_info.get('filename'):
                            stored_image['description'] = new_description
                            break
                
                print(f"DEBUG: Updated figure description for {image_info.get('original_filename')} to: '{new_description}'")

